(71, 121, 'حسابدار', 'شرکت بازرگانی نماهنگ', 'پاره وقت', 'بازرگانی', '2', 1391, '8', 1395, 0, 'کمتر از 1 میلیون', 'سایر موارد', 'در این شرکت بصورت کاراموزی ، کمک حسابدار (دوران تحصیل در دانشگاه) مشغول بکار بودم\nترک کار به دلیل خدمت سربازی', '2021-11-10 07:59:47', '2021-11-10 07:59:47'),
(72, 121, 'حسابدار', 'شرکت تولیدی و سلولزی حریر', 'تمام وقت', 'تولیدی', '10', 1396, '10', 1397, 0, 'بین 1 تا 2 میلیون', 'پیشرفت کاری', 'در مدت زمانی که در این شرکت مشغول بکار بودم مسول حسابداری انبار و بهای تمام شده و در پاره ای از اوقات اسناد هزینه ای (تنخواه)،ثبت بانک، و پیگیری فاکتور های که مربوط به امور مالیاتی بود برسی و ثبت میکردم\nترک کار به دلیل پیشرفت شغلی ، 6ماه رد نکرن بیمه و تاخیر در پرداخت بیش از حد حقوق', '2021-11-10 08:04:58', '2021-11-10 08:04:58'),
(73, 121, 'سرپرست حسابداری', 'موسسه مالی و مالیاتی ارقام گستر کوشا', 'تمام وقت', 'خدماتی', '10', 1397, '12', 1399, 0, 'بین 5 تا 6 میلیون', 'سایر موارد', 'موسسه ارقام گستر در حوزه پرونده های حسابداری مالیاتی و مشاوره های مالیاتی مشغول به  فعالیت است.\nدر طول مدت فعالیت بیش از 20شرکت (پیمانکاری،بازرگانی و تولیدی) از ثبت اسناد حسابداری تا بستن حساب و تنظیم اظهار نامه عملکرد در این موسسه انجام داده ام و همچنین امور مالیاتی و بیمه ای (اظهار نامه ارزش افزوده ، معاملات فصلی،لیست مالیات حقوق و لیست بیمه ) انجام داده ام و سال اخر در موسسه فوق به عنوان سرپرست مجموعه مشغول به فعالیت بودم.\nدلیل ترک کار : ارتقا و جایگاه شغلی بهتر و همچنین درآمد', '2021-11-10 08:12:13', '2021-11-10 08:12:13'),
(74, 121, 'مدیر مالی', 'پترو فیدار کارو', 'پاره وقت', 'پیمانکاری', '2', 1400, NULL, NULL, 1, 'بین 5 تا 6 میلیون', NULL, 'شرکت پترو فیدار در حوزه نفت و گاز فعالیت میکند.\nمسول امور مالی و مالیاتی', '2021-11-10 08:26:04', '2021-11-10 08:26:04'),
(75, 121, 'مدیر مالی', 'شرکت مهندسی گرما گستر کوهین', 'دور کاری', 'پیمانکاری', '1', 1399, NULL, NULL, 1, 'بین 1 تا 2 میلیون', NULL, 'شرکت فوق در ضمینه تاسیسات موتور خانه مشغول به فعالیت هست و در این شرکت مسول حسابداری مالیاتی(تنظیم اظهار نامه ارزش افزوده ، تنظیم لیست مالیات حقوق،تنظیم اظهار نامه عملکرد و شرکت در رسیدگی مالیات)', '2021-11-10 08:30:26', '2021-11-10 08:30:26'),
