(551, 540, 'کمک حسابدار', 'کارگاه تولیدی کیف و کفش', 'پاره وقت', 'تولیدی', '9', 1398, '9', 1398, 0, 'بین 2 تا 3 میلیون', 'نداشتن بیمه', 'اینجا برای اولین وارد کار حسابداری شدم \nنداشتن بیمه و حقوق پایین و مسافت زیاد', '2021-12-10 13:59:41', '2021-12-10 13:59:41'),
(552, 393, 'حسابدار', 'شرکت چیپس کامل', 'تمام وقت', 'تولیدی', '5', 1397, '7', 1398, 0, 'بین 2 تا 3 میلیون', 'سایر موارد', 'لیست بیمه و مالیات حقوق و نامه های اداری شرکت برعهده من بود علاوه بر موارد حسابداری ثبت سند و فاکتور های روزانه', '2021-12-10 14:23:59', '2021-12-10 14:23:59'),
(553, 525, 'صندوقدار', 'هتل دولتی صبا', 'پاره وقت', 'خدماتی', '4', 1395, '3', 1400, 0, 'بین 3 تا 4 میلیون', 'سایر موارد', 'حقوق ۴ به بالا میگرفتم در هتل صبا \nبعلت تعطیل شدن هتل و طرح بازسازی آن دیگر آنجا مشغول نیستم \nسمت : مدیر خانه داری و پذیرشگر \n۶سال در هتل صبا مشغول بکار بوده ام .', '2021-12-10 17:12:46', '2021-12-10 17:12:46'),
