(557, 559, 'مدیر مالی', 'پارس قائم نوین همراه قشم', 'پاره وقت', 'بازرگانی', '6', 1396, NULL, NULL, 1, 'بیشتر از 10 میلیون', NULL, 'کنترل گزارش معاملات فصلی،اظهارنامه ارزش افزوده،قیمت تمام شده کالاها،اظهارنامه عملکرد ،تحریر دفاتر قانونی و تنظیم و آماده سازی کلیه اسناد و مدارک قانونی و حضور در جلسات رسیدگی اداره امور مالیاتی،ارزش افزوده و حسابرسی بیمه تامین اجتماعی،تنظیم لایحه جهت حضور در هیات های بدوی،تجدید نظر ،شورای عالی مالیاتی و...', '2021-12-11 11:38:41', '2021-12-28 16:46:10'),
(558, 559, 'مشاور مالی', 'گوهر آفرین پویا', 'پاره وقت', 'بازرگانی', '10', 1399, NULL, NULL, 1, 'بیشتر از 10 میلیون', NULL, 'کنترل حواله های ارزی و مسدودی سپرده های بانکی جهت حواله ها،اعتبار سنجی در شعب بانک ها،کنترل گزارشات معاملات فصلی،اظهارنامه ارزش افزوده،قیمت تمام شده کالاها،اظهارنامه عملکرد ،تحریر دفاتر قانونی و تنظیم و آماده سازی کلیه اسناد و مدارک قانونی و حضور در جلسات رسیدگی اداره امور مالیاتی،ارزش افزوده و حسابرسی بیمه تامین اجتماعی،تنظیم لایحه جهت جضور در هیات های بدوی،تجدید نظر ،شورای عالی مالیاتی و...بررسی حساب اعضای هیات مدیره جهت تراکنش های بانکی و تنظیم لایحه مربوطه در اداره امور مالیاتی و ارزش افزوده.', '2021-12-11 11:39:40', '2021-12-28 16:50:52'),
(559, 559, 'مدیر مالی', 'پایادارویه', 'تمام وقت', 'بازرگانی', '2', 1395, '2', 1400, 0, 'بیشتر از 10 میلیون', 'سایر موارد', 'تنظیم و تهیه مدارک کالاهای وارداتی و قیمت گذاری محصولات طبق قوانین سازمان حمایت از مصرف کنندگان و تولیدکنندگان،تنظیم برنامه واردات جهت سال مالی آتی،بررسی شرایط تولیدتامین کنندگان،حمل خارجی و کلیه حواله های ارزی،کنترل ثبت سفارشات خارجی و فعالیت های واحد بازرگانی و فروش،کنترل کلیه اسناد حسابداری،فروش،انبار،کنترل لیست بیمه و مالیات حقوق،ارائه گزارشات مدیریتی،تنظیم و آماده سازی کلیه اسناد و مدارک قانونی و حضور در جلسات رسیدگی اداره امور مالیاتی،ارزش افزوده و حسابرسی بیمه تامین اجتماعی،تنظیم لایحه جهت جضور در هیات های بدوی،تجدید نظر ،شورای عالی مالیاتی و...', '2021-12-11 11:42:10', '2021-12-28 16:47:34'),
(560, 559, 'مدیر مالی', 'پارس هل دارو', 'تمام وقت', 'پخش و توزیع', '2', 1395, '2', 1400, 0, 'بیشتر از 10 میلیون', 'سایر موارد', 'کنترل کلیه اسناد حسابداری،فروش،انبار،کنترل لیست بیمه و مالیات حقوق،ارائه گزارشات مدیریتی،تنطیم ساختار سبد های فروش محصولات و تسهیم محصولات بین کلیه نمایندگان پخش استانی،داروخانه هاو...،پبگیری کالاهای نمونه ،آزمایش محصولات جدید و ضوابط سازمان های مربوطه،تنظیم و آماده سازی کلیه اسناد و مدارک قانونی و حضور در جلسات رسیدگی اداره امور مالیاتی،ارزش افزوده و حسابرسی بیمه تامین اجتماعی،تنظیم لایحه جهت جضور در هیات های بدوی،تجدید نظر و...', '2021-12-11 11:42:47', '2021-12-28 16:46:56'),
