(630, 616, 'سرپرست حسابداری', 'شرکت بلندپایه', 'تمام وقت', 'پیمانکاری', '8', 1384, '12', 1398, 0, 'بیشتر از 10 میلیون', 'سایر موارد', 'از مهرماه ۱۳۹۱ الی پایان اسفندماه ۱۳۹۵ در پروژه ورزشگاه التاجیات و الزوراء بغداد عراق با شرکت بلندپایه همکاری داشته ام.واز تیرماه ۱۴۰۰الی پایان شهریور ۱۴۰۰نیز در بیمارستان ۵۳۱تختخوابی بندرعباس به همراه شرکت ونداژه همکاری داشتم که کارفرمای اصلی با شرکت ونداژه (پیمانکار تاسیسات)در بیمارستان توافق نکردند و پیرو این مشکل شرکت ونداژه نیز با کلیه پرسنل تسویه حساب کردند.', '2021-12-13 12:36:25', '2021-12-13 12:52:45'),
(631, 616, 'مدیر مالی', 'شرکت افق جهان فارس', 'تمام وقت', 'خدماتی', '3', 1387, '12', 1389, 0, 'بین 2 تا 3 میلیون', 'مسافت طولانی', 'سکونت خانواده در عسلویه و پایین بودن امکانات زندگی و...', '2021-12-13 12:41:31', '2021-12-13 12:41:31'),
(632, 617, 'حسابدار', 'موسسه حسابرسی رهیافت وهمکاران', 'تمام وقت', 'تولیدی', '2', 1395, NULL, NULL, 1, 'بین 6 تا 8 میلیون', 'کافی نبودن حقوق', NULL, '2021-12-13 12:46:45', '2021-12-13 12:46:45'),
(633, 616, 'کمک حسابدار', 'بلندآرمان گستر', 'تمام وقت', 'پیمانکاری', '11', 1378, '2', 1383, 0, 'بین 1 تا 2 میلیون', 'سایر موارد', 'از سال ۷۸ الی ۸۳ در شرکت بلندآرمان گستر زیرمجموعه کنسرسیوم پتروپارت در پتروشیمی های قائدبصیر گلپایگان-پتروشیمی بوعلی-پتروشیمی تندگویان در بندرامام ونیز سایت یک و پنج منطقه ویژه پتروشیمی فعال بوده ام.', '2021-12-13 12:47:49', '2021-12-13 12:47:49'),
(634, 618, 'حسابدار', 'لوازم خانگی هاردستون', 'تمام وقت', 'بازرگانی', '7', 1400, '9', 1400, 0, 'بین 6 تا 8 میلیون', 'سایر موارد', 'ثبت اسناد حسابداری، تنخواه، صندوق، حسابداری فروش،تهیه پیش فاکتور و فاکتور، اصلاحات پیش فاکتور و فاکتور، موجودی انبار، ثبت بخشنامه های جدید قیمت، و... نرم افزار شماران سیستم', '2021-12-13 13:19:21', '2021-12-13 19:46:52'),
(635, 618, 'حسابدار', 'بازرگانی چسب نویدی', 'تمام وقت', 'بازرگانی', '1', 1400, '5', 1400, 0, 'بین 6 تا 8 میلیون', 'سایر موارد', 'حسابداری خزانه، کارهای مربوط به چک ها، دریافت و پرداخت، ثبت حساب های بانکی شرکت، مغایرت گیری بانکی، ثبت اسناد دریافت و پرداخت و چک ها ،حسابداری فروش، صدور پیش فاکتور و فاکتور، مغایرت گیری حساب مشتریان، ثبت تمامی اسناد درامد و هزینه، تنخواه گردانی، کار با نرم افزار هلو، موجودی انبار. و...', '2021-12-13 13:33:02', '2021-12-13 19:50:37'),
(636, 618, 'سرپرست حسابداری', 'موسسه گسترش علم و فن جوش', 'تمام وقت', 'بازرگانی', '7', 1392, '11', 1398, 0, NULL, 'سایر موارد', 'ثبت تمامی اسناد حسابداری شامل درآمدها و هزینه ها و حساب های بانکی شرکت و تنخواه و...، مسیول تنخواه گردانی و صندوق، حسابداری خزانه شامل تمامی دریافت ها و پرداخت ها و چک ها و حساب های بانکی و مغایرت گیری آنها و ثبت اسناد آنها، حسابداری فروش، تهیه پیش فاکتور و فاکتور، موجودی انبار، تنظیم قراردادها، اخذ مفاصا حساب بیمه قراردادها، لیست های حقوق و بیمه کارمندان به صورت ماهانه، لیست های پرداخت، محاسبه حقوق پرسنل، صورت معاملات فصلی و اظهارنامه های ارزش افزوده به صورت فصلی، گزارشات مدیریتی و صورت حساب سود و زیان، شرکت در جلسات رسیدگی دارایی و ارزش افزوده و رسیدگی بیمه و انجام دفاعیات مالیاتی، بایگانی اسناد و مدارک به صورت سیستمی و فیزیکی،امور مدیریتی، انجام وظایف و هماهنگی های لازم \nمربوط به دفتر مدیریت، انجام وظایف مدیریت داخلی، مدیریت پرسنل و هرگونه کار مدیریتی،\nتهیه گزارشات و نامه نگاری و تهیه فرم های مربوطه،  کار با Gmail و اینترنت و  word و excel.\nکار با نرم افزار راهبران سیستم و هلو، نرم افزارهای حقوق و دستمزد و بیمه و اظهارنامه ارزش افزوده و صورت معاملات فصلی دارایی', '2021-12-13 13:35:05', '2021-12-13 19:59:16'),
