(1216, 1033, 'حسابدار', 'پیمان مهر شبستان', 'تمام وقت', 'پخش و توزیع', '3', 1387, '3', 1392, 0, 'کمتر از 1 میلیون', 'پیشرفت کاری', 'ثبت فاکتورفروش- مرجوعی- ثبت تنخواه و امور اولیه آن -ثبت اسناد دریافتی از مشتریان- کنترل حساب مشتریان و رفع مغایرت- پیگیری تلفنی مطالبات فروش و چکهای برگشتی- مغایرت گیری بانک(با اتمام قرارداد و کسب تجربه بیشتر در زمینه رشته حسابداری ترک کار کردم)', '2022-01-15 06:55:34', '2022-01-15 07:26:09'),
(1217, 1033, 'حسابدار', 'پارساپلاستیک (پاپکو)', 'تمام وقت', 'تولیدی', '10', 1392, '10', 1397, 0, 'بین 2 تا 3 میلیون', 'پیشرفت کاری', 'ممیزی کلیه دستگاه های ورود و خروج پرسنل-تکمیل پرونده پرسنل-انجام کلیه امور پرسنلی و گزارشات مربوط به آن-پرداخت حقوق پرسنل- چک کردن فاکتورهای خرید مسئولین خرید-ثبت و پرداخت تنخواه-معایرت گیری بانک- پیگیری امور اولیه بیمه و بیمه مسیولیت مدنی پرسنل', '2022-01-15 06:57:30', '2022-01-15 07:23:40'),
(1218, 1033, 'سرپرست حسابداری', 'جهان خوشنام ماکارون', 'تمام وقت', 'تولیدی', '2', 1397, '9', 1399, 0, 'بین 6 تا 8 میلیون', 'مسائل شخصی', 'استخدام و کلیه امور جذب پرسنل- بیمه و مالیات حقوق-کنترل ورود و خروج-مغایرت گیری بانک- محاسبه حقوق و پرداخت حقوق- کلیه ورود خروج انبار و انبارگردانی\n(بدلیل تعویض مدیرمالی شرایط و تعهدات کاری تغییر کرد و باید کار روتین انجام میدادم و ازآنجا که دنبال پیشرفت بودم قطع همکاری کردم)', '2022-01-15 06:58:57', '2022-01-15 07:16:55'),
(1219, 1033, 'حسابدار', 'مهیاپروتئین', 'تمام وقت', 'تولیدی', '9', 1399, '3', 1400, 0, 'بین 8 تا 10 میلیون', 'ساعت کاری طولانی', 'کنترل درخواستهای ثبت شده توسط کلیه واحدها-ممیزی کار مسئولین خرید-ثبت خریدهای مربوط به تنخواه و کلیه امور تنخواه درسیستم مالی-مغایرت گیری هفتگی اسناد انبار- ارتباط بامشتریان جهت کنترل حساب و دریافت فاکتورهای رسمی و ارزش افزوده-(واحد اداری ساعت کاری ۸تا۵بود ولی سرویس نداشت و مجبور بودیم برای برگشت یا هزینه آژانس روزانه ۹۰هزارتومان بدیم یا صبر کنیم تا خط تولید تمام شود که تا۱۰ یا ۱۱ شب طول میکشید و سقف اضافه کاری داشتیم لحاظ نمیشد این تایم انتظار سرویس)', '2022-01-15 07:01:51', '2022-01-15 07:20:42'),
