(1292, 1076, 'حسابدار', 'شرکت پیوند توسعه', 'تمام وقت', 'تولیدی', '3', 1393, '3', 1394, 0, 'بین 1 تا 2 میلیون', 'تاخیر در پرداخت', NULL, '2022-01-16 05:16:31', '2022-01-16 05:16:31'),
(1293, 1075, 'کمک حسابدار', 'شرکت اسپید شاهد', 'دیگر', 'بازرگانی', '4', 1396, '4', 1397, 0, 'کمتر از 1 میلیون', 'سایر موارد', 'من بعنوان کارآموز در این شرکت مشغول شدم و پس از آن بصورت کمک حسابدار و بدون قرار داد کار کردم ولی مدیر عامل تغییر کرد و با من همکاری نشد زیرا مدیر قبلی از اقوام بود.', '2022-01-16 05:24:51', '2022-01-16 05:24:51'),
(1294, 1075, 'کمک حسابدار', 'همکاری با مشاور بیمه شرکت اسپید شاهد', 'دیگر', 'پیمانکاری', '4', 1397, '8', 1397, 0, 'بین 1 تا 2 میلیون', 'سایر موارد', 'مشاور بیمه شرکت اسپید شاهد چون کارم را دیده بود به من پیشنهاد همکاری در امور بیمه شرکت ها برای گرفتن مفاصا حساب را داد که یک پروژه در خدمت ایشان بودم و پس از آن تصمیم گرفتم در زمینه حسابداری فعالیت کنم.', '2022-01-16 05:27:34', '2022-01-16 05:27:34'),
(1295, 1075, 'کمک حسابدار', 'امداد خودرو رفاه ایرانیان', 'دیگر', 'بازرگانی', '8', 1397, '12', 1397, 0, 'بین 1 تا 2 میلیون', 'سایر موارد', 'علت ترک کار بد قولی شدید مدیر عامل بود که بیمه ام نکرد و حقوق را با 3 ماه تاخیر پرداخت میکرد و اضافه کاری نگه میداشت اما پولی بابت آن پرداخت نمیکرد .و همچنین از همکاران شنیده بودم که مشکل اخلاقی دارد.', '2022-01-16 05:29:29', '2022-01-16 05:29:29'),
(1296, 1075, 'صندوقدار', 'جین وست آوا کتان', 'تمام وقت', 'بازرگانی', '4', 1398, '8', 1398, 0, 'بین 2 تا 3 میلیون', 'سایر موارد', 'چون شغل مناسبی پیدا نکردم بصورت موقتی بعنوان صندوق دار در جین وست مشغول شدم که بعد از مدتی پیشنهاد همکاری در حسابداری خشک شویی جین وست را به من دادند ولی چون محل کار دماوند بود قبول نکردم و صندوق داری را دوست نداشتم و همچنین ساعت کاری طولانی بود به همین دلیل استعفا دادم.', '2022-01-16 05:32:06', '2022-01-16 05:32:06'),
(1297, 1075, 'حسابدار', 'آریا حساب', 'تمام وقت', 'تولیدی', '8', 1398, '4', 1399, 0, 'بین 2 تا 3 میلیون', 'سایر موارد', 'شرکت اریا حساب بصورت پروژه ای کار میکرد و پرسنل را به شرکت های مختلف میفرستاد مرا به شرکت پیمانکاری شریف صنعت ابهر فرستادند که برای جانبو کار میکرد و یک هفته ای با من قرارداد بستند اما چون شرکت به شهر قدس رفت و مسافت طولانی بود همکاری نکردم.', '2022-01-16 05:34:38', '2022-01-16 05:34:38'),
(1298, 1075, 'کمک حسابدار', 'یارنیکان صالح', 'تمام وقت', 'تولیدی', '6', 1399, NULL, NULL, 1, 'بین 5 تا 6 میلیون', 'ساعت کاری طولانی', 'چون متاهل شدم تصمیم گرفتم برای مدتی کارم را سبک کنم و بعنوان کمک حسابدار مشغول شوم اما وقتی شرکت فهمید تجربه دارم کارهای بیشتری به من سپرد و در حقیقت کار های حسابدار را انجام میدهم .ساعت کاری بسیار طولانی و حقوق کم باعث شد استعفا دهم.', '2022-01-16 05:36:55', '2022-01-16 05:36:55'),
