(2184, 1513, 'سرپرست حسابداری', 'اکسیر سلامت', 'تمام وقت', 'بازرگانی', '6', 1400, NULL, NULL, 1, 'بیشتر از 10 میلیون', 'پیشرفت کاری', 'به روز رسانی اسناد معوقه و بایگانی،\nایجاد نظم پایه ریزی رویه اصولی حسابداری،\nضمیمه اسکن فاکتورها و اسناد بانکی و دستی به سند حسابداری با وجود بایگانی فیزیکی برای اولین بار', '2022-04-16 09:06:04', '2022-04-16 09:06:29'),
(2185, 1513, 'سرپرست حسابداری', 'درمانگاه و مجموعه کلینیک های مهرزاد', 'تمام وقت', 'خدماتی', '1', 1399, '6', 1400, 0, 'بین 8 تا 10 میلیون', 'پیشرفت کاری', 'ساخت نرم افزار پذیرش برای شعبه شهرری کلینیک های مهرزاد بوسیله userformهای اکسل و با کمک vba و بانک اطلاعاتی MS-Access،\nراه اندازی صدور اسناد پرداختنی چاپی برای اولین بار در درمانگاه مرکزی با نرم افزار سپیدار،\nکنترل و نگهداری حسابها و پیگیری رفع مغایرت بانکی بیش از 15 حساب درمانگاه و شعب،\nمکانیزه کردن برخی امور دستی و سنتی با استفاده از اکسل و توابع اکسل', '2022-04-16 09:07:46', '2022-04-16 09:07:46'),
(2186, 1513, 'حسابدار', 'کاغذ گستران رول', 'تمام وقت', 'تولیدی', '9', 1391, '12', 1398, 0, 'بین 6 تا 8 میلیون', 'سایر موارد', 'حسابداری حقوق و دستمزد،\nحسابداری بازرگانی و فروش با نرم افزار آسان،\nلیست بیمه و مالیات بر حقوق،\nارسال مالیات بر ارزش افزوده و صورت معاملات فصلی،\nصدور اسناد پرداختنی شامل چک،\nخزانه داری کنترل حساب های بانکی و رفع مغایرت', '2022-04-16 09:08:32', '2022-04-16 09:08:32'),
