(2509, 1717, 'مدیر مالی', 'جهان کار پویا', 'تمام وقت', 'بازرگانی', '2', 1397, '12', 1400, 0, 'بیشتر از 10 میلیون', 'سایر موارد', 'بعد از مشاهده توانایی اینجانب علاوه بر کار مالی،چون در عسلویه و مسجد سلیمان نیروگاه ۲۰۰۰ مگاواتی کارون ۳ فعالیت داشتم مدیریت داخلی شرکت،وصول مطالبات و کارهای جانبی که مغایر با رشته کاری ایجانب بود نیز بر عهده اینجانب واگذار گردید که از نظر تایم و زمان کاری به کارهای مالی و رشته کاری خودم نمیتوانستم بپردازم', '2022-06-28 06:37:50', '2022-06-28 06:37:50'),
(2510, 1717, 'مدیر مالی', 'جهان کار پویا', 'تمام وقت', 'بازرگانی', '2', 1396, '12', 1400, 0, 'بیشتر از 10 میلیون', 'مسائل شخصی', 'آواخر همکاری بنده با شرکت مذکور ،مسئولیت های دیگری از جمله مدیریت داخلی ،مسئولیت وصول مطالبات و ماموریت های پی در پی به اینجانب نیز واگذار گردید که این امر باعث گردید از کار اصلی خودم فاصله گرفته و تایم و زمان کافی جهت امور مالی نداشته باشم و همچنین دیگر مسائل شخصی باعث قطع همکاری فی مابین گردید.', '2022-06-28 06:46:45', '2022-06-28 06:46:45'),
