(2899, 1939, 'کمک حسابدار', 'درمانگاه امام رضا', NULL, 'خدماتی', '1', 1391, '1', 1393, 0, 'کمتر از 1 میلیون', 'سایر موارد', 'عمده فعالیت مالی ثبت روییداد های مالی روزانه', '2022-10-09 13:01:31', '2022-10-09 13:09:02'),
(2900, 1939, 'حسابدار', 'شرکت فولاد پارس هفت تپه', 'تمام وقت', 'تولیدی', '8', 1397, '9', 1398, 0, 'بین 2 تا 3 میلیون', 'پیشرفت کاری', 'زمینه های فعالیتم: \n\nحقوق دستمزد\n\nتهیه لیست بیمه و مالیات\n\nتنخواه گردان شرکت\n\nحسابداری خرید وانبار شامل (ثبت فاکتور و ریالی کردن رسید انبار، کنترل حواله ها و کنترل سیستم ثبت تدارکات واحد بازرگانی) \n\nحسابداری فروش (صدور پیش فاکتور، ثبت فاکتور و صدور سند فروش) \n\nمغایرت گیری حساب های بانکی و حساب های تنخواه تدارکات\n\nاظهار نامه ارزش افزوده\n\nمعاملات فصلی\n\nخزانه داری(شامل کنترل سیستم درخواست وجه واحد تدارکات و بازرگانی از بابت نحوه تعریف اشخاص، نحوه تعریف فاکتور از بابت مشخصات فاکتور(ماده ۱۶۹ ق. م. م) وکنترل صحت و نادرستی سفارشات و درخواست های خرید درگیر شده در سیستم درخواست وجه و ثبت و صدور اسناد دریافت پرداخت) \n\nانبار گردانی \n\nتحریر دفاتر روزنامه وکل\n\nبستن حساب شرکت ها (اشخاص حقوقی) و تامین کنندگان(اشخاص حقیقی) و بستن حساب های بدون ماهیت( معلق خربد و واسط دارایی در جریان تکمیل) و انجام تعدیلات سنواتی در پایان سال\n\nنرم افزار: دستیار و نرم افزار نگاه نو', '2022-10-09 13:02:59', '2022-10-09 13:13:02'),
(2901, 1939, 'حسابدار', 'سیما چوب تهران', 'تمام وقت', 'تولیدی', '8', 1399, '8', 1399, 0, 'بین 2 تا 3 میلیون', 'کافی نبودن حقوق', 'زمینه فعالیت مالی خزانه داری و تنخواه گردان\nو نرم افزار مورد استفاده راهکاران سیستم', '2022-10-09 13:04:22', '2022-10-09 13:13:54'),
