(2956, 1993, 'حسابدار', 'ایرانسل', 'تمام وقت', 'خدماتی', '2', 1401, NULL, NULL, 1, 'بین 6 تا 8 میلیون', 'ساعت کاری طولانی', 'درحال حاضر مشغول بکار هستم در شرکت ایرانسل بعلت ساعت کاری غیرقانونی و طولانی و عدم پرداخت اضافه کاری درمازاد ساعت کار قانونی و مدیریت ضعیف مجموعه تمایل دارم تغییر مکان بدم', '2022-12-31 12:35:55', '2022-12-31 12:35:55'),
(2957, 1785, 'کمک حسابدار', 'شرکت 5040', 'تمام وقت', 'بازرگانی', '3', 1398, '11', 1400, 0, 'بین 5 تا 6 میلیون', 'سایر موارد', 'سمت های \n1- مسئول دفتر مالی شرکت ۵۰۴۰ (از آبان ۱۴۰۰ تا بهمن ۱۴۰۰)\nپیگیری اموری مالی از اشخاص و واحد های مختلف هلدینگ، پیگیری جلسات و انجام اموری مرتبط با بخش مالی\n2- مسئول خروج وجه نقد شرکت 5040 (از آبان ۱۴۰۰ تا بهمن ۱۴۰۰)\nبررسی و پیگیری مطالبات و بدهی به طرف های هلدینگ جهت مشخص سازی و برنامه ریزی واریزی\n3- مسئول MIS شرکت ۵۰۴۰ (از فروردین ۱۴۰۰ تا آبان ۱۴۰۰)\nساخت دسترسی های پرتالی و اتوماسیون های اداری\nبررسی و چکینگ نوع دسترسی های فعال و مورد استفاده افراد\nرفع مشکلات مرتبط با دسترسی های ایجاد شده پرتال و اتوماسیون\nایجاد و پیشنهاد ماژول های جدید برای دسترسی های خاص پرتالی\nایجاد تغییرات مرتبط با نوع دسترسی و نوع استفاده بر اساس واحد و بخش های موجود در هلدینگ\n4- مسئول گزارشات و آنالیز شرکت ۵۰۴۰ (از خرداد ۱۳۹۹ تا فروردین ۱۴۰۰)\nتهیه گزارشات آنالیزی از فروش کلیه شرکت های هلدینگ و روش های ارسال و پرداخت\nآمار های مقایسه ای از وضعیت فروش و وصولی شرکت ها\nتهیه گزارشات روتین و غیر روتین\nبررسی و ایجاد آمار های جدید و اعمال تغییرات درخواستی مدیران\n5- مسئول اداری فروش شرکت ۵۰۴۰ (از خرداد ۱۳۹۹ تا شهریور ۱۴۰۰)\nپیگیری امور مرتبط با بخش فروش هلدینگ از جمله قطعی و عدم دسترسی به پرتال کاربری، مطالبات و …\n6- وصول مطالبات (نمایندگان) شرکت ۵۰۴۰ (از تیر ۱۳۹۸ تا خرداد ۱۳۹۹)\nپیگیری وصول مطالبات از نمایندگان ارسال شرکت، تسویه حساب با نمایندگان غیرفعال، بررسی و پیگیری امور اداری نمایندگان مانند ثبت بار و مشکلات ارسال برای مشتریان\n7- کارمند بخش پیگیری و شکایات (CRM) شرکت ۵۰۴۰ (از خرداد ۱۳۹۸ تا تیر ۱۳۹۸)\nپیگیری موارد و مشکلات شتریان\n8- کارمند انبارگردانی موسسه حسابرسی اطمینان بخش (از بهمن ۱۳۹۷ تا اسفند ۱۳۹۷)\nانبارگردانی شرکت زیرساخت مخابرات', '2023-01-02 09:09:53', '2023-01-02 09:09:53'),
