(3453, 668, 'حسابدار', 'نمایندگی مدیران خودرو و بهمن موتور', 'تمام وقت', 'خودروسازی', NULL, 1401, NULL, 1402, NULL, '7 تا 9 میلیون تومان', NULL, NULL, '2023-05-22 22:39:40', '2023-05-22 22:39:40'),
(3454, 2414, 'مدیر مالی', 'بابک شیمی توس (برند فدیشه)', 'تمام وقت', 'بیمه', NULL, 1384, NULL, 1397, NULL, '5 تا 7 میلیون تومان', 'عدم پیشرفت کاری', 'از سال  ۹۷تا ۱۴۰۱درمجموعه تولید تو ن ماهی  اسکارلین مشغول به فعالیت بودم', '2023-06-10 12:00:03', '2023-06-10 12:00:03'),
(3455, 2415, 'حسابدار', 'تالار ورستوران احسان', 'تمام وقت', 'غذا و رستوران ها', NULL, 1401, NULL, NULL, 1, '12 تا 15 میلیون تومان', 'کافی نبودن حقوق', 'شرکت گوارا(کیک وکوچه خدیوپور)ازسال۱۳۷۵تا۱۳۹۴بعنوان حسابدار-انحلال شرکت ، شرکت بهبودگسترسانیا ازسال ۱۳۹۵تااردیبهشت ۱۴۰۱بعنوان حسابدار خزانه وحقوق ودستمزد،هلدینگ صنعتی معدنی عطامتال ازتیرتاآبان ۱۴۰۱ بعنوان  حسابدار حقوق ودستمزد', '2023-06-10 15:30:16', '2023-06-10 15:30:16'),
(3456, 2421, 'مدیر مالی', 'شرکت پیمانکاری اختر طوس', 'پاره وقت', 'معماری و عمران', NULL, 1386, NULL, 1388, NULL, 'توافقی', 'مسائل شخصی', 'شرح وظایف:\n-تهیه صورتهای مالی ، گزارشات بودجه نقدی و عملکرد مالی\n-جمع آوری ، تفسیر و بررسی اطلاعات مالی\n-پیش بینی روند مالی آینده پروژه\n-تولید گزارش های مالی مربوط به بدهی ها، مطالبات ، هزینه ها و غیره\n-کنترل درآمد ، جریان نقدی و هزینه ها\n- توسعه و مدیریت سیستم های مالی\n- سرپرستی و کنترل کارکنان \n- ارتباط با کارمندان و سایر همکاران.\n-مدیریت و کنترل امور مالی و پرسنلی شرکت', '2023-06-11 09:45:16', '2023-06-11 09:45:16'),
(3457, 2421, 'مدیر مالی', 'شرکت توسعه ساختمانی آران', 'پاره وقت', 'معماری و عمران', NULL, 1382, NULL, 1388, NULL, 'توافقی', 'مسائل شخصی', 'شرح وظایف:\n-تهیه صورت های مالی ، گزارش فعالیت های تجاری و پیش بینی های مالی\n-بررسی گزارش های مالی شرکت و پیشنهادات موثر جهت کاهش هزینه های غیر ضروری\n-تجزیه و تحلیل روند بازار جهت فرصت یابی برای گسترش شرکت \n- کمک به مدیریت جهت تصمیم گیری های مالی شرکت', '2023-06-11 09:47:47', '2023-06-11 09:47:47'),
(3458, 2421, 'مشاور مالی', 'شرکت پروژه ای آروند', 'پاره وقت', 'معماری و عمران', NULL, 1383, NULL, 1386, NULL, 'توافقی', 'مسائل شخصی', 'شرح وظایف:\n-مسئول بخش مالی و اداری شامل تهیه و نظارت بر بودجه های شرکت، حسابهای ماهانه ، برنامه ریزی و گزارشگری مالی.\n-تهیه صورتهای مالی ، گزارش فعالیتهای تجاری ، پیش بینی وضعیت مالی\n-بررسی و کنترل گزارش های مالی جهت کاهش هزینه ها\n-مسئول سلامت مالی شرکت\n-تولید گزارش های مالی ، هدایت فعالیت های سرمایه گذاری و تدوین استراتژی ها و برنامه ها برای اهداف مالی بلند مدت سازمان\n -انجام برنامه ریزی مالیاتی و تنظیم بودجه های مالی\n-گزارش به مدیر عامل', '2023-06-11 09:48:37', '2023-06-11 09:48:37'),
(3459, 2421, 'مشاور مالی', 'شرکت همکاران سیستم خراسان', 'پاره وقت', 'معماری و عمران', NULL, 1382, NULL, 1384, NULL, 'توافقی', 'مسائل شخصی', 'شرح وظایف:\n-نصب و پشتیبانی نرم افزار حسابداری برای شرکتهای مختلف شامل نصب ، آموزش ، ورود داده و پشتیبانی \n-تهیه و تحویل گزارشات به مدیریت شامل روند آموزش و پشتیبانی سیستم های مالی شرکتهای مشتری', '2023-06-11 09:49:33', '2023-06-11 09:49:33'),
(3460, 2421, 'مدیر مالی', 'شرکت آریا ابنیه خاوران', 'پاره وقت', 'معماری و عمران', NULL, 1388, NULL, 1392, NULL, 'توافقی', 'مسائل شخصی', 'شرح وظایف:\n-تهیه صورتها و گزارشات مالی \n- کنترل اطلاعات مالی\n-بررسی ، نظارت و مدیریت بودجه\n-جمع آوری ، تهیه و تفسیر گزارشات پرسنلی \n- پیاده سازی و توسعه سیستم های مالی شرکت \n- نظارت بر فعالیت کارکنان', '2023-06-11 09:51:20', '2023-06-11 09:51:20'),
(3461, 2420, 'مدیر مالی', 'حافظ گستر توس', 'تمام وقت', 'منابع انسانی', NULL, 1384, NULL, 1399, NULL, '15 تا 20 میلیون تومان', 'عدم پیشرفت کاری', 'در شرکت سپید گستران از ۹۷ تا ۴۰۰ بصورت فول تایم وپاره تایم مشغول بودم وهم اکنون نیز در بازرگانی ضمیری مشغول بکارم', '2023-06-11 09:55:01', '2023-06-11 09:55:01'),
