(3492, 2443, 'مشاور مالی', 'استیل اخوان .اواگستر اریا.مجتمع پروما', 'تمام وقت', 'منابع انسانی', NULL, 1394, NULL, NULL, 1, '15 تا 20 میلیون تومان', 'تاخیر در پرداخت', 'بنده در مجموعه های اداری و بازرگانی ب مدت۴سال مفید سابقه دارم ک تاخیر در پرداخت یا اصلا پرداخت ماهانه نداشتن مجبور ب ترک محل شدم و در مجموعه های فروشگاهی و پاره وقت خیلی جاها سابقه دارم از همه مهم‌تریناش مرکز های ایرانسل .افق کوروش.وفروشگاه های شخصی', '2023-06-18 11:51:50', '2023-06-18 11:51:50'),
