(3713, 2697, 'سرپرست حسابداری', 'آینه سروش تماشا', 'تمام وقت', 'مالی و اعتباری', NULL, 1400, NULL, 1400, NULL, '9 تا 12 میلیون تومان', 'سایر موارد', NULL, '2023-07-10 10:45:18', '2023-07-10 10:45:18'),
