(3715, 2700, 'مدیر مالی', 'شرکت هلدینگ نیکتین دارو', 'تمام وقت', 'کالای مصرفی و خوراکی', NULL, 1396, NULL, NULL, 1, '30 میلیون و بیشتر', 'سایر موارد', 'کلیه وظایف مالی و اداری در مجموعه شرکت های ذکر شده همزمان\n1-     امور بانک\n2-    حسابداری روزانه\n3-    حسابداری تسهیلات \n4-    سایر امور مالی', '2023-07-10 15:37:22', '2023-07-10 15:37:22'),
(3716, 2700, 'مدیر مالی', 'شرکت دیترون', 'تمام وقت', 'کالای مصرفی و خوراکی', NULL, 1391, NULL, 1395, NULL, '25 تا 30 میلیون تومان', 'سایر موارد', 'کلیه وظایف مالی و اداری\nگزارش روزانه\nتجزیه و تحلیل اهداف\nجلسه با روسای بخش‌ها\nمدیریت و هماهنگی گزارش‌های ماهانه و بودجه بندی\nارائه خدمات دفتری مانند حساب‌های پرداختی، جمع آوری و بررسی حقوق و دستمزد.\nنظارت بر گردش پول\nارتباط با تیم‌های حسابداری', '2023-07-10 15:44:42', '2023-07-10 15:44:42'),
(3717, 2700, 'سرپرست حسابداری', 'بهستان دارو', 'تمام وقت', 'کالای مصرفی و خوراکی', NULL, 1385, NULL, 1391, NULL, '20 تا 25 میلیون تومان', 'سایر موارد', 'نگهداری حساب پرداخت‌ها و هزینه‌های مربوط به تنخواه گردان واحدهای مختلف.\nتهیه دفتر روزانه و پرداخت مالیات و حق بیمه‌ها به مراجع ذیربط.\nانجام کلیه امور مربوط به فرایند مالیاتی( محاسبه، آماده سازی، گزارش دهی و...)\nدریافت، بررسی و تأیید هزینه‌های خرید و تدارکات سازمان.\nنگهداری، پیگیری و صدور اوراق بهادار در فرآیندهای مالی سازمان.\nبایگانی و حفظ اسناد و مدارک مالی و دولتی.\nتهیه گزارش از پیشرفت کارها و نارسائی‌های موجود برای ارائه به مدیر مالی و همکاری و همفکری در پیدا کردن راه حل.', '2023-07-10 15:48:25', '2023-07-10 15:48:25'),
(3718, 2700, 'حسابدار', 'مجموعه شرکت ها', 'تمام وقت', 'کالای مصرفی و خوراکی', NULL, 1368, NULL, 1385, NULL, '15 تا 20 میلیون تومان', 'سایر موارد', 'تهیه و پردازش حقوق و دستمزد ماهیانه و محاسبه سنوات\nتهیه و بررسی هزینه ها، بودجه ها، درآمد، هزینه، فاکتور و سابر اسناد حسابداری\nآماده سازی صورت های سود و زیان و گزارشات ماهانه حسابداری\nتجزیه و تحلیل روند درآمد و هزینه\nجمع آوری و تجزیه و تحلیل اطلاعات مالی برای تهیه گزارش اظهارنامه مالیاتی\nتعامل با حسابرسان داخلی و خارجی شرکت', '2023-07-10 15:51:43', '2023-07-10 15:51:43'),
