(3760, 2719, 'حسابدار', 'مفید دارو', 'تمام وقت', 'خدمات درمانی، پزشکی و سلامت', NULL, 1400, NULL, 1402, NULL, '7 تا 9 میلیون تومان', 'عدم پیشرفت کاری', 'تسلط به حسابداری خرید و فروش و سابقه فعالیت در بیمه کوثر و کارگاه اطلس ( کار با نرم افزار 3d max) را دارا هستم .', '2023-07-16 09:25:03', '2023-07-18 08:12:12'),
(3761, 2635, 'حسابدار', 'شرکت ابارا آسیا', 'پاره وقت', 'مالی و اعتباری', NULL, 1397, NULL, NULL, 1, '7 تا 9 میلیون تومان', NULL, '۶سال در زمینه حسابداری سابقه دارم و با معدل الف در رشته ی حسابداری از دانشگاه خیام فارغ التحصیل شده ام و لیسانس دارم\n۴سال هست در شرکت آسیا(پمپ ابارا )حسابدار هستم \nو۱ساله در تولیدی تریکو در هفده شهریور  حسابدار هستم \n\nمهارت ها:نرم افزار محک،رایورز،نرم افزار ورد،اکسل ،پاور پوینت،انجام مغایرت گیریشرکت ها و افراد،مغایرت گیری بانکی تهیه لیست حقوق،روابط عمومی بالا،منظم بودن و طبق قوانین مربوطه\n\nجهت آموزش ۶ماه در شهرداری ،۶ماه در استانداری،و۶ماه در دانشگاه اسرار کار کرده ام\nو سپس حسابداری در شرکت ها و موسسات به صورت ماهیانه  و دوره ای انجام داده ام.', '2023-07-16 11:30:22', '2023-07-16 11:30:22'),
