(3835, 2773, 'حسابدار', 'ویرتگن', 'پروژه ای', 'معماری و عمران', NULL, 1380, NULL, 1383, NULL, NULL, 'سایر موارد', 'اتمام کار پروژهای کاری واقع در فرودگاه مهر آباد  تهران . بندر لنگه . بندر گناوه  و بندر عسلویه ولی ترک کاری نبودی بلکه جابجائی بین پروژه ها بوده است .', '2023-07-24 09:16:33', '2023-07-24 11:26:35'),
(3836, 2773, 'حسابدار', 'ترمیم راه و ابنیه نوین', 'پروژه ای', 'معماری و عمران', NULL, 1383, NULL, 1386, NULL, NULL, 'مسافت طولانی', 'اتمام پروژه واقع در جنوب ایران . بندر عسلویه و انتقال به پروژه فرودگاه استان اردبیل و پس از آن  پروژه در حال اجرا واقع در  پارس آباد دشت مغان که علت و دلیل جدائی از شرکت هم فقط  به دلیل بعد مسافت بوده است .', '2023-07-24 09:17:51', '2023-07-24 11:27:37'),
(3837, 2773, 'سرپرست حسابداری', 'گروه سرمایه گزاری تات', 'تمام وقت', 'سرمایه گذاری و تحلیل کسب و کار', NULL, 1386, NULL, 1395, NULL, NULL, NULL, 'توضیح بر اینکه گروه،  گروه سرمایه گذاری بسیار بزرگی است و ترک محل کاری از طرف بنده صورت نگرفته بلکه جابجائی داخل سیستمی  بوده است که آن هم به دلیل کثرت بالای شرکت های فعال  درون سیستم  میباشد .', '2023-07-24 09:22:05', '2023-07-24 10:07:55'),
(3838, 2773, 'سرپرست حسابداری', 'زینت تجارت آسیا', 'تمام وقت', 'سرمایه گذاری و تحلیل کسب و کار', NULL, 1395, NULL, NULL, 1, '20 تا 25 میلیون تومان', NULL, 'ترک کاری صورت نگرفته  بلکه انتقالی دروت سازمانی بوده است .\nسیستم دارای شرکت های زیاد و پراکنده ای بوده و جابجائی مابین شرکت ها بوده است .\n از جمله مجموعه بازار های موبل و موبایل ایران  و غیره .', '2023-07-24 09:23:39', '2023-07-24 11:24:12'),
