(4006, 3068, 'حسابدار', 'سرماسازان وستا صنعت', 'تمام وقت', 'تولید و صنایع', NULL, 1401, NULL, NULL, 1, '7 تا 9 میلیون تومان', 'کافی نبودن حقوق', NULL, '2023-12-03 04:06:14', '2023-12-03 04:06:14'),
(4007, 3073, 'کمک حسابدار', 'کابل کنترل خودرو', 'پاره وقت', 'تولید و صنایع', NULL, 1395, NULL, 1397, NULL, 'توافقی', 'نداشتن بیمه', 'در زمان دانشگاه به این کار مشغول بودم.\nکارهایی همچون ثبت فاکتور خرید و فروش و بررسی تنخواه و ثبت و محاسبه و پرداخت حقوق و دستمزد و بیمه و مالیات آن...', '2023-12-03 17:01:06', '2023-12-03 17:01:06'),
(4008, 3073, 'حسابدار', 'موسسه خدمات مالی و مالیاتی متین', 'تمام وقت', 'مالی و اعتباری', NULL, 1398, NULL, 1398, NULL, 'قانون کار', 'کافی نبودن حقوق', 'موسسه فقط در رابطه با پروژه های مشاغل بویژه داروخانه ها فعالیت داشت.\nمحاسبه و ثبت حقوق و دستمزد بیش از ۷۰ داروخانه\n محاسبه و ثبت استهلاک دارایی های داروخانه ها در پایان سال مالی\nثبت فاکتورهای خرید و فروش و هزینه و تنخواه آنها\nپیگیری امور مربوط به ثبت نام داروخانه در سامانه های مالیاتی و انجام امور مالیاتی آنها...', '2023-12-03 17:06:50', '2023-12-03 17:06:50'),
(4009, 3073, 'حسابدار', 'پایا موتور', 'تمام وقت', 'خودروسازی', NULL, 1398, NULL, 1399, NULL, 'توافقی', 'سایر موارد', 'حسابداری خزانه\n( دریافت و پرداخت ها، بانک و مغایرت ها با مشتریان، هزینه ها ، تنخواه گردان ها )\nحسابداری حقوق و دستمزد پرسنل و بیمه و مالیات آنها \nحسابداری خرید و فروش\nپیگیری حضوری امور مالیاتی،بیمه،بانک و تسهیلات،مغایرت گیری با مشتریان', '2023-12-03 17:14:10', '2023-12-03 17:14:10'),
(4010, 3073, 'حسابرس', 'اتو گالری شاهان', 'پروژه ای', 'خودروسازی', NULL, 1401, NULL, 1402, NULL, 'توافقی', 'سایر موارد', 'حسابرسی بانک\n( واریزی ها و پرداخت ها و برداشت های بانکی)\nحسابرسی درستی مندرجات قرارداد های فی مابین صاحبکار و مشتریان\nحسابداری تنخواه \n حسابداری حقوق و دستمزد\nقرارداد با پرسنل \nو...', '2023-12-03 17:19:04', '2023-12-03 17:19:04'),
(4011, 3073, 'حسابدار', 'خدمات مالیاتی شخصی', 'پروژه ای', 'مالی و اعتباری', NULL, 1399, NULL, NULL, 1, 'توافقی', NULL, 'ارائه خدمات مالی و مالیاتی به صاحبین مشاغل به صورت پروژه ای،دور کاری و پارت تایم\n(امورات ثبت نام های سامانه های مالیاتی،ارزش افزوده و گزارشات فصلی،اظهارنامه مالیاتی عملکرد سالانه و تبصره ۱۰۰ ،حقوق و دستمزد،گزارشات مالی و مشاوره مالی و سرمایه گذاری و...)', '2023-12-03 17:24:27', '2023-12-03 17:24:27'),
