(4066, 3144, 'حسابرس', 'موسسه حسابرسی توسعه مدیریت دانا', 'تمام وقت', 'مالی و اعتباری', NULL, 1401, NULL, NULL, 1, 'توافقی', 'ساعت کاری طولانی', 'حسابرسی تمام سرفصل های حسابداری\nتهیه صورت مالی\nکار با اکثر نرم افزار های مالی از جمله \nراهکاران، سپیدار، آسا، آسان، تکرو، تدبیر، الماس، هلو،...\nدفتر نویسی روزنامه و کل\nتهیه گزارش های حسابرسی با اکسل', '2024-01-04 15:11:16', '2024-01-04 15:31:33'),
(4067, 3144, 'حسابدار', 'صنعت مروارید ارم', 'پاره وقت', 'سرمایه گذاری و تحلیل کسب و کار', NULL, 1401, NULL, NULL, 1, 'توافقی', 'سایر موارد', 'ثبت اسناد حسابداری سرمایه گذاری به طور کامل (خرید و فروش سهم ، بهای تمام شده سهم ها و سود و زیان ناشی از فروش سهام و صندوق،....) \nتهیه صورت مغایرت بانکی \nتهیه مدارک برای ارسال به دارایی\nتهیه صورت مالی\nکنترل داخی برای صحت ثبت های حسابداری\nکار با نرم افزار سپیدار\nدفتر نویسی روزنامه و کل\nثبت معاملات فصلی', '2024-01-04 15:15:17', '2024-01-04 15:28:22'),
(4068, 3144, 'حسابدار', 'قابسازی قابیران', 'تمام وقت', 'کالای مصرفی و خوراکی', NULL, 1400, NULL, 1401, NULL, '7 تا 9 میلیون تومان', 'عدم پیشرفت کاری', 'حسابداری یه قابسازی که قاب تولید میکرد\nثبت همه اسناد از جمله فاکتور های فروش و خرید و هزینه ها و گزارش گیری سود و زیان ماهانه برای مدیریت\nکار با نرم افزار شایگان', '2024-01-04 15:22:46', '2024-01-04 15:22:46'),
(4069, 3144, 'کمک حسابدار', 'تعاونی مصرف گمرک کارکنان ج. ا. ا', 'پاره وقت', 'دولتی', NULL, 1396, NULL, 1398, NULL, 'توافقی', 'نداشتن بیمه', 'ثبت اسناد حسابداری درآمدی گمرک، خزانه داری، تهیه صورت مغایرت بانکی، بایگانی، انبارگردانی، دفترنویسی(روزنامه و کل), تهیه گزارش هفتگی به مدیر\nکار با نرم افزار سام', '2024-01-04 15:27:40', '2024-01-04 15:31:09'),
(4070, 3150, 'کمک حسابدار', 'چاپ کیهان', 'تمام وقت', 'تولید و صنایع', NULL, 1397, NULL, 1400, NULL, NULL, 'سایر موارد', 'من بیشتر سوابق شغلیم در زمینه اداری .پرسنلی و گارگزینی بوده.و درچاپ کیهان علاوه بر پرسنلی و کارگزینی یه بخشی ازامور حسابداری با نرم افزار کارا جز وظایفم بود .\nمدتی هم با نرم افزار شایگان کار حسابداری انجام دادم', '2024-01-05 09:45:36', '2024-01-05 09:45:36'),
(4071, 2498, 'کمک حسابدار', 'شرکت راستین', 'تمام وقت', 'کالای مصرفی و خوراکی', NULL, 1402, NULL, 1402, NULL, 'قانون کار', 'مسائل شخصی', '۱_ شرکت قایم راه فروزان  سمت کار پرداز \n۲ _شرکت پویا پلیمهر اریا سمت منشی وکمک حسابدار', '2024-01-06 10:02:33', '2024-01-06 10:02:33'),
