(4100, 3179, 'حسابدار', 'حسابان تفتان آینده', 'پروژه ای', 'مالی و اعتباری', NULL, 1396, NULL, 1401, NULL, 'توافقی', 'نداشتن بیمه', NULL, '2024-01-23 14:45:07', '2024-01-23 14:45:07'),
(4101, 3097, 'مدیر مالی', 'نوین کاوش پاسارگاد', 'تمام وقت', 'تولید و صنایع', NULL, 1400, NULL, NULL, 1, 'توافقی', NULL, 'اذرشال زمینه فعالیت نیروگاه برق.سال فعالیت از سال ۱۳۹۷تا ۱۴۰۰سمت رئیس حسابداری مسلط به کلیه امور حسابداری.\nشرکت آکام تجهیز البرز ۱۳۹۴تا ۱۳۹۷ زمینه فعالیت تولید لوازم پزشکی  سمت رئیس مالی. \nشرکت رزماکاران مدت سابقه ۱ سال و شرکت هونام سفال زمینه فعالیت تولید مصالح ساختمانی سفال مدت سابقه ۳ سال.تولیدی پوشاک فرزکا سمت مدیر مالی مدت سابقه ۲ سال .تولید لوازم خانگی رایا صنعت مدت سابقه ۱ سال.\nمسلط به امور مالیاتی .تهیه بهای تمام شده.تهیه صورت مالی .تهیه گزارش های مدیریتی . اظهارنامه عملکرد و تهیه صورت های مالی .کنترل و برسی اسناد صادره اعم از انبار فروش خزانه و حقوق .سامانه مودیان . دفاع مالیاتی.', '2024-01-24 08:05:01', '2024-01-24 08:05:01'),
