(4134, 3198, 'حسابدار', 'سپاهان سوله', 'تمام وقت', 'تولید و صنایع', NULL, 1402, NULL, 1402, NULL, '5 تا 7 میلیون تومان', 'کافی نبودن حقوق', NULL, '2024-03-24 07:31:02', '2024-03-24 07:31:02'),
(4135, 3199, 'حسابدار', 'تام ایران خودرو', 'تمام وقت', 'خودروسازی', NULL, 1400, NULL, 1402, NULL, '25 تا 30 میلیون تومان', 'عدم پیشرفت کاری', 'رسیدگی سالانه مالیاتی و تهیه کاربرگ های مربوطه و پاسخ به ممیزین مالیاتی\nتهیه اظهارنامه عملکرد ارزش افزوده و معاملات فصلی\nشرکت در هیات های حل اختلاف و لایحه نویسی مربوطه\nتسلط به حسابداری پیمانکاری\nحضور در جلسات مالیاتی\nحسابداری مالی\nقوانین مالیاتی و بیمه\nثبت، محاسبه، صدور مالیات بر ارزش افزوده\nتهیه دیسکت بیمه و مالیات حقوق و.......', '2024-03-24 09:15:41', '2024-03-24 09:15:41'),
(4136, 3205, 'حسابدار', 'مایلوکس', 'تمام وقت', 'واردات و صادرات', NULL, 1400, NULL, NULL, 1, 'توافقی', 'سایر موارد', NULL, '2024-03-24 16:23:20', '2024-03-24 16:24:05'),
(4137, 3206, 'سرپرست حسابداری', 'هلدبنگ یثربی', 'تمام وقت', 'تولید و صنایع', NULL, 1401, NULL, 1402, NULL, NULL, NULL, NULL, '2024-03-24 16:50:40', '2024-03-24 16:50:40'),
(4138, 3206, 'حسابدار', 'توسعه ووشه', 'تمام وقت', 'خدمات درمانی، پزشکی و سلامت', NULL, 1399, NULL, 1401, NULL, '9 تا 12 میلیون تومان', 'مسائل شخصی', NULL, '2024-03-24 16:53:20', '2024-03-24 16:53:20'),
(4139, 3207, 'حسابدار', 'جلوه گر تزئین', 'تمام وقت', 'کالای مصرفی و خوراکی', NULL, 1400, NULL, 1401, NULL, '5 تا 7 میلیون تومان', NULL, 'تهیه گزارش میزان فروش کالا و سود ناخالص.\nکنترل تراز مشتریان.\nثبت اسناد فروش کالا  و برگشت فروش کالا\nهماهنگی با انبار از جهت موجودی ها و کم و کسری ها، هماهنگ بودن با مسئولان انبار در جهت تاریخ فروش کالاها و خروج آنها از انبار بر اساس قوانین داخلی.\nپاسخگویی و ثبت سفارش مشتریان آنلاین و تولید محتوا برای سایت و صفه مجازی اینستاگرام.\nکار با نرم افزار هلو', '2024-03-24 19:37:38', '2024-03-24 19:37:38'),
(4140, 3207, 'حسابدار', 'پوشاک تعطیلات', 'تمام وقت', 'تولید و صنایع', NULL, 1401, NULL, NULL, 1, '12 تا 15 میلیون تومان', NULL, 'آشنایی با امورات بیمه تامین اجتماعی ، ارسال لیست و پیگیری امورات مربوطه.\nتهیه گزارشات مرتبط با بیمه و مالیات.\nپیگیری و بررسی و ثبت و تهیه مدارک اسناد حسابداری.\nکنترل دوره ای حساب های تامین کنندگان و تهیه گزارشات مربوطه.\nآشنایی با امورات و ثبت اسناد خزانه، امورات بانکی ، تهیه صورت مغایرت بانکی.\nآشنایی با امورات تنخواه گردان و پیگیری مسائل شعب.\nمسلط به نرم افزار سپیدار.', '2024-03-24 19:39:39', '2024-03-24 19:39:39'),
