(4185, 3246, 'حسابدار', 'شرکت آریاآرک شرق', 'تمام وقت', 'کشاورزی', NULL, 1400, NULL, NULL, 1, '7 تا 9 میلیون تومان', 'کافی نبودن حقوق', 'کشتارگاه صنعتی دام سبک و سنگین از زمان راه اندازی دراین مجموعه شروع فعالیت کردم با سمت کارشناس حقوق و دستمزد  و در طول مدت مشغول به کار بودن با نرم افزار های مالی ،وجوه ، انبار و فروش این مجموعه که نرم افزار مالی تدوین فرایند میباشد کارکرده ام\nدرامور حسابرسی همکاری با حسابرس داشتم', '2024-03-25 11:19:57', '2024-03-25 11:19:57'),
