(4189, 3249, 'حسابدار', 'شرکت سیم و کابل ابهر(سهامی عام)', 'تمام وقت', 'تولید و صنایع', NULL, 1400, NULL, 1401, NULL, '15 تا 20 میلیون تومان', 'عدم پیشرفت کاری', 'در این شرکت در فیلد حسابداری مدیریت مشغول به کار بودم.تهیه ی گزارشات ماهیانه مدیریتی ، تهیه بودجه.تهیه گزاراشت موردی و همچنین کلیه امور مربوط به حقوق و دستمزد و بیمه ومالیات حقوق را انجام میدادم.', '2024-03-25 12:27:36', '2024-03-25 12:27:36'),
(4190, 3249, 'مدیر مالی', 'انتشارات هیرمند', 'تمام وقت', 'رسانه و انتشارات', NULL, 1400, NULL, NULL, 1, '30 میلیون و بیشتر', 'عدم پیشرفت کاری', 'در این مجموعه ازدی ماه 1400 به صورت پارت تایم به عنوان مشاور مالی در خدمت مجموعه بودم.از ابتدای سال 1401 با پست سازمانی مدیر مالی اداری به صورت تمام وقت با مجموعه همکاری دارم.مدیریت و مسئولیت کلیه امور مالی،مدیریت پرسنل و شرح وظایف ها، مدیریت دریافت وپرداختها،و تهیه کلیه گزارشات دوره ای، صورتهای مالی، تهیه پیش نویس بودجه ی سازمان و..به عهده اینجانب می باشد.', '2024-03-25 12:31:23', '2024-03-25 12:31:23'),
(4191, 2522, 'حسابدار', 'سولیکو کاله', 'تمام وقت', 'کالای مصرفی و خوراکی', NULL, 1402, NULL, NULL, 1, NULL, NULL, NULL, '2024-03-25 12:32:22', '2024-03-25 12:32:22'),
