(4275, 3319, 'حسابدار', 'زیکر', 'تمام وقت', 'کامپیوتر، فناوری اطلاعات و اینترنت', NULL, 1396, NULL, NULL, 1, '15 تا 20 میلیون تومان', 'سایر موارد', '۴ شرکت کار کردم مهندسین مشاور آبگستران میهن با عنوان مسول مالی در شرکت سنگ و کوه به عنوان مسول حسابداری پیمانکاری در شرکت زیکر مسول خزانه داری در شرکت ابسان گستر مسول مالی بودم', '2024-03-26 07:05:00', '2024-03-26 07:05:00'),
(4276, 3320, 'کمک حسابدار', 'توسعه خدمات مهندسی آب و خاک پارس', 'پاره وقت', 'معماری و عمران', NULL, 1390, NULL, 1395, NULL, '9 تا 12 میلیون تومان', 'سایر موارد', 'دلیل ترک کار قبلی اتمام پروژه بوده. \nکار دوم امور مالی بیمارستان آیت اله نبوی دزفول از سال 1395لغایت 1402', '2024-03-26 07:13:51', '2024-03-26 07:13:51'),
(4277, 3323, 'سرپرست حسابداری', 'تجارت الکترونیک دی', 'تمام وقت', 'تبلیغات، بازاریابی و برند سازی', NULL, 1402, NULL, NULL, 1, '20 تا 25 میلیون تومان', 'سایر موارد', 'ثبت و تنظیم فاکتورهای خرید و فروش \nثبت فاکتور و تطبیق و مغایرت گیری فاکتورهای خرید در سامانه مودیان\nثبت اسناد روزانه ، حقوق و دستمزد، دریافت و پرداخت \nمغایرت گیری با تامین کننده ها ماهانه \nارائه گزارش های مدیریتی \nارائه گزارش عملکرد ماهانه\nارائه گزارش های پرسنلی و غیره', '2024-03-26 07:36:29', '2024-03-26 07:36:29'),
(4278, 3323, 'سرپرست حسابداری', 'پترو نیرو صبا', 'تمام وقت', 'نفت و گاز', NULL, 1401, NULL, 1402, NULL, '15 تا 20 میلیون تومان', 'تاخیر در پرداخت', 'ثبت و پییگیری کلیه امور مرروط به حسابداری انبار \nامور مربوط به دریافت و پرداخت بانک\n بررسی نقدینگی و هزینه های تنخواه گردان پروژه \nثبت و بررسی حقوق و دستمزد و مالیات پرسنل\nارسال گزارش منابع و مصارف هفتگی و ماهیانه \nارسال گزارش سود و زیان پروژه بصورت ماهیانه\nارسال بیمه و مالیات حقوق \nارسال اظهارنامه ارزش افزوده و معاملات فصلی\nجمع آوری و تهیه پیش نویس اظهارنامه عملکرد حقوقی شرکت', '2024-03-26 07:45:23', '2024-03-26 07:45:23'),
(4279, 3323, 'سرپرست حسابداری', 'مواد غذایی کیش', 'تمام وقت', 'غذا و رستوران ها', NULL, 1399, NULL, 1401, NULL, '9 تا 12 میلیون تومان', 'کافی نبودن حقوق', '- حسابداری بر اساس تامین کننده ها \n- کنترل و حسابداری دریافت و پرداخت تامین کننده ها \n- حسابداری انبار و انبار گردانی \n- حسابداری حقوق و دستمزد \n- مغایرت گیری بانک \n- ثبت و پیگیری تنخواه \n- ارائه صورتهای سود و زیان ماهانه بر اساس فروش \n- ارائه لیست بیمه تامین اجتماعی و مالیات بر حقوق', '2024-03-26 07:48:39', '2024-03-26 07:48:39'),
(4280, 3323, 'حسابدار', 'همکار صنعت پترو', 'تمام وقت', 'نفت و گاز', NULL, 1397, NULL, 1399, NULL, '7 تا 9 میلیون تومان', 'سایر موارد', '-  ثبت امور حسابداری بر اساس قراردادها و پروژه\n- حسابداری دریافت و پرداخت و مغایرت گیری بانک \n- ثبت و پیگیری ضمانت نامه ها \n- حسابداری حقوق و دستمزد \n- ارسال گزارشات فصلی ، ارزش افزوده \n- ارسال گزارشات بیمه و مالیات بر حقوق', '2024-03-26 07:53:05', '2024-03-26 07:53:05'),
