(4357, 3399, 'حسابدار صنعتی', 'کاشی مرجان اصفهان', 'تمام وقت', 'تولید و صنایع', NULL, 1391, NULL, NULL, 1, '15 تا 20 میلیون تومان', 'مسائل شخصی', 'از سال ۱۳۹۱ کار حسابداری را شروع کردم تا سال ۱۳۹۶ در زمینه حسابداری مالی در شرکت هایی با فعالیت های پیمانکاری، تولیدی و بازرگانی فعالیت داشتم و از سال ۱۳۹۷ تا الان (۱۴۰۳) در شرکت کاشی مرجان در زمینه حسابداری صنعتی_ بهای تمام شده مشغول به کار هستم.', '2024-03-27 14:58:53', '2024-03-27 14:58:53'),
