(4362, 3403, 'حسابدار', 'توسن بارفرابران تهران', 'تمام وقت', 'حمل و نقل، لجستیک و انبارداری', NULL, 1399, NULL, 1403, NULL, '12 تا 15 میلیون تومان', 'عدم پیشرفت کاری', NULL, '2024-03-27 17:59:27', '2024-05-11 05:56:04'),
(4363, 3402, 'حسابدار', 'نقش تندیس آریا', 'تمام وقت', 'تولید و صنایع', NULL, 1402, NULL, NULL, 1, '15 تا 20 میلیون تومان', 'عدم پیشرفت کاری', NULL, '2024-03-27 18:07:09', '2024-03-27 18:07:09'),
(4364, 3404, 'سرپرست حسابداری', 'شرکت حسابداری ارقام محاسب آریا دقیق', 'تمام وقت', 'مالی و اعتباری', NULL, 1387, NULL, 1391, NULL, NULL, NULL, 'خدمات مالی و حسابداری\nبستن حسابها در پایان دوره ، ارسال گزارشات فصلی ، مراجعه به بخش مالیاتی جلسات ، تهیه صورتهای مالی ، گزارش هزینه ، رفتن به جلسات و حسابرسی بیمه حسابرسی مالیات بر ارزش افزوده ،\nانجام حقوق و دستمزد ، حسابداری هزینه ، استهلاک ، صورتهای مالی و اظهارنامه مالیاتی\nمسئول امور بیمه ، معاملات نقدی و بانکی', '2024-03-27 18:34:17', '2024-03-27 18:34:17'),
(4365, 3404, 'سرپرست حسابداری', 'شرکت مهندسی مهاران', 'تمام وقت', 'تولید و صنایع', NULL, 1391, NULL, 1395, NULL, NULL, NULL, 'شرکت فعال در تولید تجهیزات سیگنالینگ و ctc ،\nدر راه آهن و مترو ، فعالیتهای نصب و ضمانت.\nفعالیت من:\nحساب چک مربوط به فروش قراردادهای خارجی ، گزارش ضمانت نامه ها ،\nگزارش موجودی ارز و موجودی حساب ارز ، بررسی تامین کنندگان قبل از پذیرش خرید آنها ، بررسی درخواست خرید مواد اولیه توسط من ،\nتهیه منابع و استفاده از پول نقد در هر ماه ،\nثبت اسناد خرید و واردات خارجی ،\nآشنا به حسابداری و هزینه پروژه ها و پیگیری قرارداد بیمه و پروژه های گارانتی ،\nآشنایی کامل با گزارشات حسابداری در مورد ذخیره سازی و رسیدها و حواله ها از انبار تا تولید یا فروش ،\nتهیه منابع گزارشات و استفاده از پول نقد برای گزارشات مدیریت و نسبتهای مالی برای تصمیمات مدیریت.\nبررسی و کنترل ضمانت های APG و PBG\nبررسی اسناد پروژه صندوق گردان\nتهیه گزارش گردش مواد اولیه', '2024-03-27 18:36:15', '2024-03-27 18:36:15'),
(4366, 3404, 'سرپرست حسابداری', 'شرکت پالایش میعانات گازی نفتی آدیش', 'تمام وقت', 'کامپیوتر، فناوری اطلاعات و اینترنت', NULL, 1395, NULL, 1398, NULL, NULL, NULL, 'هدف از این پروژه جلوگیری از فروش میعانات نفت خام، ایجاد ارزش افزوده، اشتغال و حصول اطمینان از حداکثر تولید میدان گازی پارس جنوبی در قالب هشت پالایشگاه مستقل میعانات گازی با ظرفیت 6000 بشکه در روز با طراحی فرآیند مشابه در منطقه ویژه اقتصادی انرژی است. پارس جنوبی (سایت کنگان 2) بین فازهای 13 تا 19 در حال ساخت است.\n- نظارت بر عملیات مالی روزمره در شرکت، مانند حقوق و دستمزد، صورتحساب و سایر معاملات\n- نظارت بر کارکنان بخش مالی، از جمله حسابداران و انبارها\n- مدیریت برای تهیه مالیات، حسابرسی، بانکداری، سرمایه گذاری، مالیات بر ارزش افزوده و سایر نیازهای مالی در صورت لزوم\n- مدیریت و کنترل امور مالی\n- بررسی سیستم تحویل مواد اولیه از انبار به پروژه\n- کنترل حسابداری انبار ابزار در پروژه کنگان\n- کنترل اسناد حسابداری\n- ارائه گزارشات مدیریتی\n- ارائه لیست بیمه و مالیات\n- ارائه لیست حقوق و دستمزد\n- بررسی سفارشات خرید (PO) به صورت جداگانه EPC+F\n- تأمین مالی\n- تهیه صورتجلسه هیئت مدیره برای افزایش سرمایه، مجمع سالانه، واگذاری سهام، .... طبق قانون تجارت جمهوری اسلامی ایران', '2024-03-27 18:39:45', '2024-03-27 18:39:45'),
(4367, 3404, 'مدیر مالی', 'شرکت سرمایهگذاری پارس آریان (سهامی عام )', 'تمام وقت', 'سرمایه گذاری و تحلیل کسب و کار', NULL, 1398, NULL, NULL, 1, '30 میلیون و بیشتر', NULL, 'شرکت سرمایه گذاری پارس آرین در زمینه سرمایه گذاری در تاسیس بانک پاسارگاد و سرمایه گذاری در شرکت های تابعه و همچنین سرمایه گذاری در بازار سرمایه فعالیت دارد.\n\n1-تهیه صورت های مالی اساسی اجمالی و پایان دره\n2- کنترل گزارش های ماهانه پرتفوی سرمایه گذاری و صورتهای مالی سه ماهه قبل از ارسال در سایت کدال\n3-کنترل حساب های سرمایه گذاری و حق تقدم خرید سهام و تعیین هزینه سرمایه گذاری\n4-بررسی مالیات بر ارزش افزوده\n5-کنترل و بررسی صورت معاملات (169 مکرر)\n6- تهیه اظهارنامه مالیاتی\n7- کنترل پرداخت ها\n8-مدیریت حسابرسی بیمه و رسیدگی به دعاوی اولیه\n9-مدیریت حسابرسی مالیاتی و شرکت در جلسات مالیاتی\n10 -رفتن به هیئت های رسیدگی مالیاتی\n11-برگزاری مجمع عمومی سالانه و فوق العاده و انجام تشریفاتی قانونی مطابق قانون تجارت\n12-تهیه گزارش توجیهی افزایش سرمایه و انجام مراحل دریافت مجوز از سازمان بور و اوراق بهادار\n13- مدیریت حسابرسی های پایان سال', '2024-03-27 18:42:19', '2024-03-27 18:42:19'),
(4368, 3405, 'حسابدار', 'تولیدی و‌صنعتی ریونیز پالتیش آرتان', 'تمام وقت', 'نفت و گاز', NULL, 1397, NULL, NULL, 1, '25 تا 30 میلیون تومان', 'عدم پیشرفت کاری', NULL, '2024-03-27 18:58:44', '2024-03-27 18:58:44'),
