(4403, 3440, 'حسابدار', 'نوشدارو دریا', 'تمام وقت', 'کالای مصرفی و خوراکی', NULL, 1391, NULL, 1397, NULL, 'قانون کار', 'سایر موارد', 'در شرکت نوشدارو دریا به سمت مهندس انفورماتیک مشغول بوده و با حفظ سمت حسابدار حقوق دستمزد و خزانه بوده و به کلیه نرم افزارهای تامین اجتماعی(بیمه پرسنل )و دارایی(مالیات حقوق،ارزش افزوده،فصلی ۱۶۹) تسلط دارم', '2024-03-29 12:43:30', '2024-03-29 12:43:30'),
(4404, 3440, 'سرپرست حسابداری', 'قفس گستران کاسپین', 'تمام وقت', 'کالای مصرفی و خوراکی', NULL, 1398, NULL, 1402, NULL, '15 تا 20 میلیون تومان', 'سایر موارد', 'شرکت در زمینه تولید و فراوری محصولات شیلاتی از جمله ماهی میگو خاویار و ... بوده و صادرات نیز داشته است که اینجانب مسئول واحد مالی و اداری بوده و کلیه امور مربوط به صادرات از جمله صدور گواهی مبدا گواهی قرنطینه اظهارنامه گمرکی و... توسط اینجانب و زیر نظر بده انجام می‌گردید', '2024-03-29 12:47:41', '2024-03-29 12:47:41'),
(4405, 3441, 'حسابدار', 'داتیس بافت', 'تمام وقت', 'کالای مصرفی و خوراکی', NULL, 1398, NULL, 1402, NULL, '5 تا 7 میلیون تومان', 'تاخیر در پرداخت', NULL, '2024-03-29 12:49:35', '2024-03-29 12:49:35'),
(4406, 3444, 'حسابدار', 'موسسه خدمات مالی', 'تمام وقت', 'بیمه', NULL, 1392, NULL, 1402, NULL, '20 تا 25 میلیون تومان', 'عدم پیشرفت کاری', NULL, '2024-03-29 14:58:05', '2024-03-29 14:58:05'),
(4407, 3445, 'سرپرست حسابداری', 'بهین تجارت آریسان', 'تمام وقت', 'تولید و صنایع', NULL, 1400, NULL, NULL, 1, '15 تا 20 میلیون تومان', 'ساعت کاری طولانی', 'حسابداری فروش\nحسابداری هزینه \nحسابداری حقوق و دستمزد \nحسابداری خزانه \nآشنایی با انبارداری \nانجام و پیگیری انبارگردانی های روزانه\nارسال لیست بیمه ماهانه\nارسال لیست مالیات حقوق ماهانه \nارسال اظهارنامه ارزش افزوده \nارسال گزارش معاملات فصلی موضوع ماده 169\nارسال اظهارنامه املاک\nآموزش نیروی جدید و کارآموز \nآشنایی با قوانین - لوایح و هیات مالیاتی\nمسلط به نوشتن دفاتر قانونی\nآشنایی با حسابرسی\nآشنایی با لوایح _ هیئت های بیمه تامین اجتماعی و دفاع\nآشنایی با سامانه جامع تجارت \nسامانه مودیان', '2024-03-29 15:32:24', '2024-03-29 15:44:25'),
(4408, 3445, 'حسابدار', 'تهران اینترنت', 'تمام وقت', 'مخابرات و ارتباطات', NULL, 1396, NULL, 1400, NULL, '7 تا 9 میلیون تومان', 'عدم پیشرفت کاری', 'حسابداری فروش\nحسابداری هزینه\nحسابداری خزانه\nآشنایی با انبارداری \nآموزش نیروی جدید و کارآموز \nمسلط به نوشتن دفاتر قانونی', '2024-03-29 15:35:39', '2024-03-29 15:46:00'),
(4409, 3445, 'حسابدار', 'پیشرو صنعت نفت آسیا', 'پروژه ای', 'تولید و صنایع', NULL, 1398, NULL, 1398, NULL, '30 میلیون و بیشتر', NULL, 'به روز کردن کلیه حسابهای شرکت،ثبت کلیه فاکتورهای خرید و فروش و سند های هزینه ای ،مغایرت گیری بانکی،ارسال لیست بیمه و مالیات حقوق ،ارسال اظهارنامه ارزش افزوده و لیست معاملات فصلی.\nآموزش به نیروی حسابدار مستقر در شرکت.\nعلت ترک کار:  پایان پروژه حسابداری', '2024-03-29 15:39:31', '2024-03-29 15:51:58'),
(4410, 3446, 'حسابدار', 'صنعت پرشین مبنا', 'تمام وقت', 'تولید و صنایع', NULL, 1400, NULL, 1401, NULL, '5 تا 7 میلیون تومان', 'کافی نبودن حقوق', 'تنها حسابدار مجموعه \nارسال معملات فصلی ، ارسال اظهارنامه ارزش افزوده و عملکرد شرکت \nارسال بیمه و مالیات حقوق دستمزد پرسنل\nتهیه گزارشات برای دارایی و مدیریت', '2024-03-29 15:39:31', '2024-03-29 15:54:02'),
