(4500, 3514, 'حسابدار', 'مجموعه اتو خسروانی', 'تمام وقت', 'واردات و صادرات', NULL, 1396, NULL, 1397, NULL, 'توافقی', 'عدم پیشرفت کاری', 'ثبت کلیه اسناد روزانه مالی \nثبت قرارداد های خرید و فروش خودرو\nنرم افزار مورد استفاد \"کاربرد کامپیوتر\"', '2024-04-02 15:27:42', '2024-04-02 15:33:58'),
