(4596, 3604, 'حسابدار', 'خدمات دریایی بندری پتروبار جنوب', 'تمام وقت', 'حمل و نقل، لجستیک و انبارداری', NULL, 1400, NULL, 1402, 0, '15 تا 20 میلیون تومان', NULL, '1. نصب و راه اندازی سیستم حسابداری نوسا و آموزش به حسابداران ماژول های مختلف ( فروش ، دستمزد ، هزینه و . . . )\n2. سندرسی اسناد فروش ، دستمزد ، هزینه ، بارنامه ، اموال و . . . .\n3. آماده سازی سیستم حسابداری جهت تحریر دفاتر شرکت\n4. تنظیم گزارشات سود و زیانی ، صورت های مالی حسابرسی نشده \n5. حضور در هیات های حل اختلاف مالیاتی', '2024-04-09 05:52:20', '2024-04-09 05:52:20');
INSERT INTO `resume_priors` (`id`, `user_id`, `title`, `company_name`, `employment_type`, `activity_type`, `start_month`, `start_year`, `end_month`, `end_year`, `still_busy`, `last_salary`, `leaving_reason`, `description`, `created_at`, `updated_at`) VALUES
(4597, 3604, 'مشاور مالی', 'پارس حساب ماهشهر', 'تمام وقت', 'سرمایه گذاری و تحلیل کسب و کار', NULL, 1398, NULL, 1400, NULL, '9 تا 12 میلیون تومان', NULL, '1. تولید : تهیه و تنظیم جداول و انجام محاسبات لازم به جهت محاسبه بهای تمام شده کالای تولید شده روزانه شرکت های تولیدی \n2. حسابرسی : تهیه و تنظیم صورت های مالی حسابرسی نشده برای شرکت های طرف قرارداد به صورت سه ماهه، شش ماهه و سالیانه و جوابگویی به سوالات حسابرس رسمی جهت انجام حسابرسی رسمی سالیانه برای شرکت های طرف قرارداد \n3. گزینش : مشاوره به مدیران شرکت های طرف قرارداد به جهت اصلاح چارت اداری و استخدام و گزینش پرسنل جدید \n4. راه اندازی اولیه ( استقرار سیستم) : راه اندازی سیستم های مالی و نصب و آموزش نرم افزار حسابداری و همچنین آموزش حسابداران استخدامی و آشنا کردن آنها به رویه ها و وظایف محوله \n5. مشاور حسابداری : همکاری با تیم برنامه نویسی شرکت پارس حساب ماهشهر به جهت آماده سازی نرم افزار حسابداری اختصاصی', '2024-04-09 05:55:40', '2024-04-09 05:55:40'),
(4598, 3604, 'مدیر مالی', 'مجتمع تولیدی ماهران ساحل جنوب', 'تمام وقت', 'تولید و صنایع', NULL, 1396, NULL, 1398, NULL, '5 تا 7 میلیون تومان', NULL, 'انجام تمامی امور مالی و اداری این شرکت به عهده اینجانب بوده. \n1. نامه نگاری های اداری \n2. مراجعه به اداره دارایی و تامین اجتماعی و انجام امور بانکی شرکت \n3. انجام تمامی امور مربوطه به واحد حسابداری مالی اعم از ثبت اسناد و تهیه گزارشات ماهیانه و سالیانه  \n4. پاسخگویی به حسابرس رسمی و ممیز مالیاتی به هنگام رسیدگی مالیاتی شرکت. \n5. حضور در جلسات اعضای هیات مدیره و ارائه گزارشات سود و زیانی و نمودارهای مربوط به عملکرد سالیانه شرکت \n6. حضور در هیات های حل اختلاف مالیاتی و ارائه اسناد و مدارک و نوشتن لوایح \n7. تهیه سیستم محاسبه بهای تمام شده روزانه', '2024-04-09 05:58:26', '2024-04-09 05:58:26'),
(4599, 3604, 'حسابدار', 'پارس حساب ماهشهر', 'تمام وقت', 'سرمایه گذاری و تحلیل کسب و کار', NULL, 1394, NULL, 1396, NULL, 'قانون کار', NULL, 'انجام حسابداری پروژه های مالیاتی و آموزش دیدن در کنار تیم حرفه ای شرکت پارس حساب', '2024-04-09 06:00:00', '2024-04-09 06:00:00'),
