(4609, 3615, 'حسابدار', 'شرکت عمران دخان جنوب', 'تمام وقت', 'کالای مصرفی و خوراکی', NULL, 1398, NULL, 1403, NULL, '9 تا 12 میلیون تومان', 'عدم پیشرفت کاری', 'یک سال سابقه کار در شرکت مالی\nشش ماه سابقه کار در دفتر خرید و فروش شیرآلات', '2024-04-10 17:12:06', '2024-04-10 17:12:06'),
(4610, 3616, 'سرپرست حسابداری', 'بنیاد مسکن انقلاب اسلامی', 'تمام وقت', 'تولید و صنایع', NULL, 1402, NULL, NULL, 1, '30 میلیون و بیشتر', 'سایر موارد', 'موضوع فعالیت ساخت مسکن، تولید مصالح ساختمانی. مسولیت محوله تهیه و تنظیم صورتهای مالی تلفیقی و حسابرسی و اعمال کنترل های داخلی بنیاد مسکن مراکز استانها.', '2024-04-10 22:00:30', '2024-04-10 22:20:14'),
(4611, 3616, 'مدیر مالی', 'فناوری مصالح نوین ایرانیان', 'تمام وقت', 'تولید و صنایع', NULL, 1399, NULL, 1402, NULL, '25 تا 30 میلیون تومان', 'سایر موارد', 'فعالیت مجموعه تولید مصالح نوین ساختمانی. مسولیت محوله انجام تمامی امور مالی و مالیاتی شرکت، تنظیم صورتهای مالی و پاسخگویی به حسابرسی مستقل، تهیه و تنظیم بودجه و مقایسه بودجه و عملکرد. تهیه گزارشات مرتبط با مجمع سالیانه.', '2024-04-10 22:03:04', '2024-04-10 22:21:16'),
(4612, 3616, 'مدیر مالی', 'ساخت آزما', 'تمام وقت', 'معماری و عمران', NULL, 1391, NULL, 1401, NULL, '25 تا 30 میلیون تومان', 'سایر موارد', 'فعالیت مجموعه ساخت مسکن و خدمات پیمانکاری. مسولیت محوله انجام تمامی امور مالی و مالیاتی شرکت، تنظیم صورتهای مالی و پاسخگویی به حسابرسی مستقل، تهیه و تنظیم بودجه و مقایسه بودجه و عملکرد. تهیه گزارشات مرتبط با مجمع سالیانه.', '2024-04-10 22:04:38', '2024-04-10 22:22:05'),
