(4619, 3622, 'حسابدار', 'جهان سنجش نیرو بهاران', 'تمام وقت', 'مالی و اعتباری', NULL, 1402, NULL, 1402, 0, 'قانون کار', 'کافی نبودن حقوق', 'حسابدار در رزن صاف و حسابداران صدیق غرب و الکترو فانوس و کیا سنجش', '2024-04-12 09:20:16', '2024-04-12 09:20:16'),
(4620, 3623, 'حسابدار', 'شیمی فرآور مریک', 'تمام وقت', 'تولید و صنایع', NULL, 1401, NULL, NULL, 1, '20 تا 25 میلیون تومان', 'عدم پیشرفت کاری', 'یک شرکت تولیدی خدماتی بازرگانی هستش که وظیفه من حسابدار در کنار سه حسابدار دیگر ثبت اسناد مربوطه خرید فروش خزانه تنخواه و محاسبه حقوق و دستمزد و ارسال بیمه مالیات و اظهارنامه های مالیاتی و گزارشات ماهانه مدیریتی هستش \nدر این شرکت مواد اولیه تولید را از کشور خارجی وارد میکنیم که وظیفه ثبت واردات را بر عهده دارم\nبنده وظیفه ارسال اظهارنامه سال گذشته این شرکت را داشتم', '2024-04-12 09:43:46', '2024-04-12 09:43:46'),
(4621, 3623, 'سرپرست حسابداری', 'چیچک دنیز', 'تمام وقت', 'واردات و صادرات', NULL, 1400, NULL, 1401, NULL, '9 تا 12 میلیون تومان', 'سایر موارد', 'ارسال اظهارنامه عملکرد   \nارسال معاملات فصلی 169\n ارسال ارزش افزوده \nمحاسبه حسابداری ارزی و واردات کالا و بهایابی\nارسال و محاسبه مالیات حقوق.\nارسال بیمه و محاسبه حقوق .\nانجام عملیات پایان سالمو بستن حساب و صدور سند افتتاحیه و اختتامیه.\nهمکاری با حسابرسان و مدارک مورد نیاز شرکت ها .', '2024-04-12 09:50:32', '2024-04-12 09:50:32'),
(4622, 3623, 'حسابدار', 'پیشرو توسعه هوشمند فاخر', 'تمام وقت', 'کامپیوتر، فناوری اطلاعات و اینترنت', NULL, 1396, NULL, 1400, NULL, NULL, 'سایر موارد', 'ثبت حساب دریافت و پرداخت \nثبت فاکتور فروش\nثبت فاکتور خرید انجام محاسبات حقوق و دستمزد\nارسال لیست بیمه\nارسال لیست مالیات\nمغایرت گیری با طرف حساب ها\nکمک به بستن حساب ها و ارسال اظهارنامه', '2024-04-12 09:55:05', '2024-04-12 09:55:05'),
