(4651, 3659, 'حسابدار', 'شرکت طلوع ایده و روش', 'تمام وقت', 'معماری و عمران', NULL, 1399, NULL, 1400, NULL, 'توافقی', 'سایر موارد', 'ثبت و رسیدگی به اسناد مربوط به انبار ها(خرید و فروش)،ثبت و نگهداری واحد خزانه داری و واحد های مربوطه از جمله حقوق و دستمزد، انجام تکالیف مربوط به مالیات های مستقیم و مالیات بر ارزش افزوده و هم چنین تکالیف مربوط به بیمه و سازمان تامین اجتماعی.', '2024-04-20 18:31:25', '2024-04-20 18:31:25'),
(4652, 3659, 'حسابرس', 'موسسه حسابرسی آتیه اندیش نمودگر', 'تمام وقت', 'استاندارد و کنترل کیفیت', NULL, 1400, NULL, 1401, NULL, 'توافقی', 'سایر موارد', 'حسابرسی و رسیدگی صورت های مالی و صورت های مالی تلفیقی در شرکت های بزرگ و کوچک در سراسر کشور. که عبارتند از:  1) شرکت رتبه بندی برهان(تحت نظارت سازمان بورس و اوراق بهادار )  2) شرکت شیر پاستوریزه پگاه تبریز، ارومیه (سهامی عام) 3)  شرکت قند هگمتان و قزوین (سهامی عام) 4) مجموعه شرکت های بزرگ زلال ایران(سهامی خاص)', '2024-04-20 18:33:09', '2024-04-20 18:33:09'),
