(4736, 3714, 'صندوقدار', 'فروشگاه بهمن', 'تمام وقت', 'فرهنگی و ورزشی', NULL, 1397, NULL, 1399, NULL, 'قانون کار', 'ساعت کاری طولانی', 'مجموعه فروشگاه های بهمن واقع در استان البرز در شعبه یک این مجموعه فعالیت خود را اغاز کردم در بخش کتب دانشگاهی فعالیت کردم و پس از 3 ماه ترفی گرفته و به سمت سوپروایزر مجموعه پیوستم به دلیل ساعات کاری 13 ساعته از 8 صبح الی 9 شب و بدون تعطیلی حتی ایام نوروز در سال 1399 استعفا داده ام', '2024-04-24 11:37:12', '2024-04-24 11:37:12'),
(4737, 3714, 'حسابدار', 'می تک', 'تمام وقت', 'کامپیوتر، فناوری اطلاعات و اینترنت', NULL, 1399, NULL, 1401, NULL, '5 تا 7 میلیون تومان', 'مسائل شخصی', 'در سال 1399 مرداد ماه به مجموعه می تک که شرکت فروش عمده لوازم جانبی موبایل و... بوده است فعالیت خودم به عنوان حسابدار شروع کردم و با نرم افزار هلو که از اولخود خریداری کردم و تمام کار های حسابداری انجام داده افتتاح حساب ،ورود کالاها،ورود حساب ها،ورود طرف حساب هاو....به دلیل تغییر ماهیت از شرکت به فروشگاه و درو شدن نسبت محل زندگی قطع همکاری کرده در تاریخ اردیبهشت سال 1401', '2024-04-24 11:42:19', '2024-04-24 11:42:19'),
(4738, 3714, 'حسابدار', 'آویژه', 'تمام وقت', 'تولید و صنایع', NULL, 1401, NULL, 1401, NULL, '5 تا 7 میلیون تومان', 'مسافت طولانی', 'درتاریخ خرداد 1401 وارد شرکت آویژه شده و سمت خود را در حسابداری فروش شروع کرده این شرکت در زمینه لوستر و دکوراتیو منزل فعالیت داشته وبعد از  4ماه به دلیل تغییر محل سکونت از کرج به تهران قطع همکاری داشته در تاریخ مهر 1401', '2024-04-24 11:45:15', '2024-04-24 11:45:15'),
(4739, 3714, 'حسابدار', 'توسعه ارتباط یکتا گستران رایان (تایگر)', 'تمام وقت', 'واردات و صادرات', NULL, 1401, NULL, 1402, NULL, '7 تا 9 میلیون تومان', 'مسائل شخصی', 'در تاریخ مهرماه 1401 وارد شرکت تایگر شده در بخش حسابداری فروش مشغول به کار شده و پس از یک سال به دلیل خستگی از شغل حسابداری و فشار سنگین کار و تغییر شغل به حیطه زیبایی استعفا داده در تاریخ مهر 1402', '2024-04-24 11:50:01', '2024-04-24 11:50:01'),
