(4827, 3817, 'کمک حسابدار', 'دفتر خدمات مالی ارقام محاسب', 'کارآموزی', 'مالی و اعتباری', NULL, 1400, NULL, 1400, NULL, 'توافقی', 'نداشتن بیمه', 'کار با نرم افزار شایگان،ارسال معاملات فصلی و ارزش افزوده،صدور اسناد حسابداری و فاکتورهای خرید و فروش', '2024-05-03 15:31:44', '2024-05-03 15:31:44'),
(4828, 3817, 'حسابدار', 'نوآوران فناوری اسپاد', 'تمام وقت', 'تبلیغات، بازاریابی و برند سازی', NULL, 1400, NULL, 1402, NULL, '9 تا 12 میلیون تومان', 'عدم پیشرفت کاری', 'کار با نرم افزار هلو و سپیدار\nارسال لیست بیمه و مالیات حقوق\nامور مربوط به تنخواه گردانی و بایگانی اسناد', '2024-05-03 15:34:15', '2024-05-03 15:34:15'),
(4829, 3817, 'حسابدار', 'نوید طب آپادانا', 'تمام وقت', 'خدمات درمانی، پزشکی و سلامت', NULL, 1402, NULL, NULL, 1, '12 تا 15 میلیون تومان', 'مسائل شخصی', 'کار با نرم افزار سپیدار و تسلط به ماژول های مرتبط با کار بازرگانی\nتحریر دفاتر قانونی\nتسلط به امور‌ مربوط به چک و سامانه صیاد', '2024-05-03 15:37:05', '2024-05-03 15:37:05'),
