(4833, 3822, 'حسابدار', 'شرکت حسابرسی آترینا', 'کارآموزی', 'مالی و اعتباری', NULL, 1402, NULL, 1403, NULL, 'توافقی', 'سایر موارد', '۵ ماه در شرکت کار آموز بودم به دلیل تغیر محل سکونت  ادامه همکاری نداشتیم', '2024-05-04 10:30:41', '2024-05-04 10:30:41'),
(4834, 3823, 'کمک حسابدار', 'حسابداری و حسابرسی وهومن', 'کارآموزی', 'مالی و اعتباری', NULL, 1398, NULL, 1400, NULL, 'قانون کار', 'سایر موارد', 'پس از اتمام تحصیل بصورت حرفه ای در شرکت استادم که یک شرکت حسابداری و حسابرسی بود جهت انجام امور مربوط به شرکت ها مشغول به کار شدم.در این شرکت با نرم افزارهای حسابداری زیادی آشنا شدم.از جمله سیترا،دلفین،هلو،صنعت یار و.....', '2024-05-04 11:39:19', '2024-05-04 11:39:19'),
(4835, 3823, 'حسابدار', 'انتشارات جنگل', 'تمام وقت', 'رسانه و انتشارات', NULL, 1400, NULL, 1401, NULL, '7 تا 9 میلیون تومان', 'سایر موارد', 'بعد از کسب تجربه به نسبت کافی تصمیم گرفتم برای ارتقای اطلاعات و کسب تجربه های بیشتر جهت رسیدن به هدفی که دارم به تهران بیام و در شهریور 1400 در انتشارات جنگل بصورت یک حسابدار رسمی استخدام شدم.\nشرح شغل من در این شرکت:\nمسلط به حسابداری سفارشات و فروش و قراردادها\nثبت و صدور اسناد حسابداری و فروش\nتهیه گزارشات فصلی و ارزش افزوده\nتهیه صورت های مالی و رفع مغایرت موجود\nجنگل یک شرکت تولیدی بود و فرصت خوبی بود که با نحوه کار حسابداری تولیدی آشنا بشم.', '2024-05-04 11:40:52', '2024-05-04 11:44:26'),
(4836, 3823, 'حسابدار', 'هلدینگ توسعه تجارت زرین گستر رامان', 'تمام وقت', 'کالای مصرفی و خوراکی', NULL, 1400, NULL, NULL, 1, '20 تا 25 میلیون تومان', NULL, 'بعد از یکسال و دوماه کارکردن توی انتشارات جنگل برای کسب تجربه بیشتر تصمیم گرفتم که در یک شرکت بازرگانی مشغول کار بشم و به استخدام یکی از شرکت های هلدینگ زرین گستر رامان درآمدم و شرح شغلم در این شرکت(زرین دانه مایا):\nثبت و اسناد سفارشات خرید و فروش\nتنظیم معاملات فصلی و ارزش افزوده\nبررسی و رفع مغایرت های موجود بین شرکت ها\nتهیه تایید حسابرسی برای شرکت ها\nرفع مغایرت های موجود بین سیستم و حساب ها\nبعد از ۶ ماه کار در یکی از شرکت های هلدینگ رامان بعنوان کارشناس مالی فروش،به تصمیم مدیران هلدینگ بعنوان حسابدار ارشد به یکی دیگر از شرکت های این هلدینگ(اطلس تجارت دنیز) فرستاده شدم و مسئولیت کلی مالی شرکت اعم از ثبت اسناد روزانه،خزانه،سامانه مودیان،بیمه،مالیات،حقوق دستمزد و .... و امور مختصری از منابع انسانی را عهده دار شدم', '2024-05-04 11:43:47', '2024-05-04 11:43:47'),
