(4855, 3841, 'کمک حسابدار', 'دفتر خدمات مالی معصومیان', 'تمام وقت', 'واردات و صادرات', NULL, 1387, NULL, 1390, NULL, 'قانون کار', 'سایر موارد', 'ازسال ۹۰ تا ۹۳ شرکت تولیدی و صنعتی ژیتال .حسابدار انبار.حقوق دستمزد.وهمزمان در شرکت اکسیژن صدور سند حسابداری و دفتر نویسی.از ۹۳ به بعد تا سال ۹۶ به دلیل بیماری فقط چند شرکت کوچک اونم به صورت پاره وقت داشتم.از ۹۶ تا کنون هم در شرکت کاروتامین در بخش خدمات مشغول به کارم', '2024-05-05 21:31:09', '2024-05-05 21:31:09'),
(4856, 3842, 'صندوقدار', 'داروخانه', 'تمام وقت', 'خدمات درمانی، پزشکی و سلامت', NULL, 1399, NULL, 1401, NULL, 'توافقی', 'عدم پیشرفت کاری', NULL, '2024-05-05 22:53:08', '2024-05-05 22:53:08'),
(4857, 3845, 'کمک حسابدار', 'موسسه حسابرسی سامان اندیشان یکتا', 'تمام وقت', 'مالی و اعتباری', NULL, 1401, NULL, NULL, 1, '9 تا 12 میلیون تومان', NULL, 'بارگذاری گزارشات و قرارداد ها در سامانه های مربطه.\nانجام امور دفتری و دارای و بیمه و پیگیری آنها.\nتایپ قراردادها و گزارشات.\nتوانایی پیگیری مطالبات، نامه های اداری ، بیمه و ...\nانجام امور مربوط به سامانه های جامع ، سحر و اتوماسیون های اداری .\nتهیه و ارسال لیست مالیات حقوق ، بیمه حقوق و مفاصا حساب .', '2024-05-06 07:23:25', '2024-05-06 07:24:12'),
