(5005, 4043, 'حسابدار', 'خدمات حسابداری میزان محاسبان مهر پایدار', 'تمام وقت', 'مالی و اعتباری', NULL, 1400, NULL, NULL, 1, 'قانون کار', 'سایر موارد', NULL, '2024-06-10 20:18:22', '2024-06-10 20:18:22'),
(5006, 4044, 'حسابدار', 'شرکت مهندسی صنایع عمرانی باربد فن آور', 'تمام وقت', 'معماری و عمران', NULL, 1400, NULL, 1401, NULL, 'قانون کار', 'عدم پیشرفت کاری', 'ثبت اسناد حسابداری مربوط به خرید و فروش و بانک ها و صورت مغایرت بانک ها و ثبت صورتخلاصه تنخواه و ....', '2024-06-10 20:26:51', '2024-06-10 20:26:51'),
(5007, 4044, 'سرپرست حسابداری', 'هلدینگ تولیدی طب پلاستیک نوین', 'تمام وقت', 'تولید و صنایع', NULL, 1401, NULL, NULL, 1, '20 تا 25 میلیون تومان', NULL, '-مسلط به محاسبه بهای تمام شده \n- مسلط به انبار و تدارکات\n-مسلط به دارایی ثابت\n-مسلط به سیستم همکاران سیستم\n-مسلط به سامانه مودیان و قانون پایانه های فروشگاهی\n-پیگیری سفارشات و ریالی کردن و صدور اسناد خریدهای خارجی\n-ریالی کردن رسید خرید داخلی و صدور اسناد فاکتور خرید\n-تهیه موازنه مصرف و تولید و کنترل و مغایرتگیری مصرف مواد \n-مسلط به تهیه امارتولید ماهانه و اثبات از انبار و رد کردن در سامانه جامع تجارت\n_تایید و تهیه مستندات دستورپرداخت ها\n-انجام تمامی کارهای مربوط به بهای تمام شده\n-کنترل اسناد حسابداری نیروهای حسابداری صنعتی\n-ارائه گزارش هیئت مدیره و سود و زیان به صورت ماهانه\n-بستن و قیمت گذاری و صدور اسناد انبار به صورت ماهانه\n_چک کردن سرفصل هزینه ها\n-بستن حساب ها و پیگیری پیش پرداخت های باز\n-گزارشات ارزش افزوده و معاملات فصلی\n-ارائه گزارش های محوله شده از طرف مدیر مالی و هیئت مدیره', '2024-06-10 20:50:21', '2024-06-10 20:50:21'),
(5008, 4045, 'حسابدار', 'ماهان تجارت ثمین', 'تمام وقت', 'خودروسازی', NULL, 1400, NULL, NULL, 1, 'توافقی', 'ساعت کاری طولانی', 'با سلام بنده از سال 1402 تا به امروز در یک شرکت بازرگانی مربوط به بسته بندی تخممرغ که صادرات انجام می دهد مشغول هستم.\n\nو فعالیت های مربوط به مرغداری و پرورش پولت را هم انجام می دهم.', '2024-06-11 11:01:44', '2024-06-11 11:01:44'),
