(5124, 4206, 'حسابدار', 'مدیریت ۱۰تالار بزرگ', 'تمام وقت', 'غذا و رستوران ها', NULL, 1402, NULL, 1403, NULL, '20 تا 25 میلیون تومان', 'سایر موارد', NULL, '2024-08-13 06:30:52', '2024-08-13 06:30:52'),
(5125, 4208, 'حسابدار', 'مقیاس گستر توس', 'پاره وقت', 'استاندارد و کنترل کیفیت', NULL, 1400, NULL, 1402, NULL, 'قانون کار', 'عدم پیشرفت کاری', 'حوزه فعالیت : شرکت خدماتی بازرسی استاندارد\n•مسئولیت تمامی امور دریافت‌ها و پرداخت‌ها: مدیریت و نظارت بر تمامی وجوه دریافتی و پرداختی شرکت.\n\n•امور تنخواه گردان: مدیریت و کنترل تنخواه گردان شامل رسیدگی به هزینه‌ها و تهیه گزارش‌های مربوطه.\n\n•صدور فاکتورهای فروش و خرید: تهیه و صدور فاکتورهای مربوط به فروش و خرید کالاها و خدمات.\n\n•ثبت لیست بیمه: ثبت و مدیریت لیست بیمه کارکنان و ارسال به سازمان‌های مربوطه.\n\n•تهیه لیست معاملات فصلی و اظهارنامه: تهیه و تنظیم لیست معاملات فصلی و اظهارنامه مالیاتی.\n•تحریر دفاتر قانونی: نوشتن و به‌روز رسانی دفاتر قانونی شامل دفاتر روزنامه و کل.\n\n•همکاری با مدیر مالی در زمان بستن حساب‌ها و تهیه اظهارنامه عملکرد: همکاری با مدیر مالی در پایان سال مالی برای بستن حساب‌ها و تهیه اظهارنامه مالیاتی عملکرد.', '2024-08-13 09:54:12', '2024-08-13 09:54:12'),
(5126, 4209, 'حسابدار', 'مبل طراحان', 'تمام وقت', 'تولید و صنایع', NULL, 1400, NULL, 1401, NULL, '9 تا 12 میلیون تومان', 'سایر موارد', NULL, '2024-08-13 10:08:18', '2024-08-13 10:08:18'),
