(5159, 4287, 'حسابدار', 'شرکت  حسابداری کامه آوین و آیدین', 'تمام وقت', 'مالی و اعتباری', NULL, 1398, NULL, 1402, NULL, '12 تا 15 میلیون تومان', 'مسافت طولانی', NULL, '2024-09-07 09:21:54', '2024-09-07 09:21:54'),
(5160, 4289, 'حسابدار', 'ایران اشبنت (هلدینگ آذین خودرو)', 'تمام وقت', 'خودروسازی', NULL, 1400, NULL, 1403, NULL, 'توافقی', 'مسائل شخصی', 'حسابداری انبار و تمامی عملیات های مربوط به انبار (انبارگردانی-ثبت رسید و حواله _ مغایرت گیری _ کنترلی و...) \nمحاسبات و گزارشات بهای تمام شده \nگزارشات مدیریت (انحرافات-ضایعات-تولید-تحلیل داده و...)\nحسابداری خرید و ثبت خرید های خارجی و داخلی\nمسلط به امور اعتبارات،امور بانکی، شرایط ارائه تسهیلات و خرید دین توسط کلیه بانکها و پیگیریهای مربوطه\nثبت تنخواه ها و سفارشات خارجی (تنخواه خارجی مربوط به واردات و...)\nحسابداری دریافت و پرداخت و امور خزانه\n گزارشات فصلی و ارزش افزوده\nآشنایی با سامانه مودیان', '2024-09-09 13:39:48', '2024-09-09 13:48:25'),
(5161, 4289, 'حسابدار', 'گروه صنعتی برنز', 'تمام وقت', 'خودروسازی', NULL, 1398, NULL, 1400, NULL, '9 تا 12 میلیون تومان', 'سایر موارد', 'عملیات های مربوط به حسابداری فروش و گزارش مطالبات  \nثبت اسناد و فاکتور های فروش\nثبت تنخواه', '2024-09-09 13:42:07', '2024-09-09 13:42:07'),
(5162, 4291, 'کمک حسابدار', 'شرکت تولیدی گلزا', 'تمام وقت', 'تولید و صنایع', NULL, 1402, NULL, 1402, NULL, 'قانون کار', 'سایر موارد', 'کاربر سیستمی اداره دامپزشکی خرید و فروش دام وطیور سابقه کاری۵سال....مدیرفروش نمایندگی ایرانخوردو ۲سال سابقه کار', '2024-09-11 21:37:55', '2024-09-11 21:43:57'),
(5164, 4267, 'کمک حسابدار', 'آرشیدا', 'تمام وقت', 'مالی و اعتباری', NULL, 1403, NULL, NULL, 1, '9 تا 12 میلیون تومان', 'عدم پیشرفت کاری', 'به مدت چند ماه در پیشخوان دولت کار کرده و در حال حاضر در یک شرکت تولیدی بازگانی مشغول بکار هستم', '2024-09-28 20:01:40', '2024-09-28 20:01:40'),
(5165, 4297, 'حسابدار', 'شرکت ریل پرداز آریا', 'تمام وقت', 'حمل و نقل، لجستیک و انبارداری', NULL, 1389, NULL, 1390, NULL, 'قانون کار', 'مسافت طولانی', 'شرکت فوق در زمینه حمل و نقل ریلی و جاده ایی فعال بود.\nمحل شرکت در کرج در خیابان استاندارد بود.\nفعالیت بنده در زمینه محاسبه حقوق و خرج راه راننده ها و تنخواه نمایندگی بود.\nشرکت در سال 1395 منحل و بسته شد.', '2024-09-29 08:25:51', '2024-09-29 08:25:51'),
(5166, 4297, 'حسابدار', 'شرکت خدمات کالای یاس', 'تمام وقت', 'کالای مصرفی و خوراکی', NULL, 1390, NULL, 1392, NULL, 'قانون کار', 'سایر موارد', 'شرکت در زمینه خدمات فروشگاه زنجیره ایی مربوط به بنیاد تعاون ناجا فعال بوده.\nبنده کارشناس مالی قراردادهای قطعی شرکت بودم و ثبت فاکتور فروش و مغایرت گیری و ثبت تنخواه ها و بایگانی اسناد را انجام میدادم.\nبه دلیل تعدیل نیرو اتمام کار انجام شد.', '2024-09-29 08:29:27', '2024-09-29 08:29:27'),
(5167, 4297, 'سرپرست حسابداری', 'شرکت بازرسی آریا سینا کنترل', 'تمام وقت', 'استاندارد و کنترل کیفیت', NULL, 1392, NULL, 1393, NULL, 'قانون کار', 'کافی نبودن حقوق', 'شرکت فوق نماینده اداره استاندارد در گمرکات بود.\nبنده در این شرکت تمام امور جاری یک شرکت خدماتی از جمله ثبت فاکتور خرید و فروش و هزینه و گزارشات قانونی را انجام میدادم و 5 نیرو در ایران و 10 نیرو در کشورهای دبی-ارمنستان-انگلیس-آلمان-کویت-آمریکا زیر دستم داشتم.\n\nعلت قطع همکاری بنده حقوق خیلی کم با توجه به حجم بالای کاری بوده', '2024-09-29 08:33:40', '2024-09-29 08:33:40'),
(5168, 4297, 'حسابدار', 'شرکت چاپ نفیس نگار', 'تمام وقت', 'رسانه و انتشارات', NULL, 1395, NULL, 1400, NULL, '5 تا 7 میلیون تومان', 'مسائل شخصی', 'شرکت فوق در زمینه چاپ و بسته بندی فعال بوده.\nحسابداری امور جاری از ثبت فاکتور تا تهیه گزارش را انجام میدادم.\n\nدلیل قطع همکاری بنده به دلیل نداشتن بیمه کاری و همچنین اختلاف بین 2 مدیر مجموعه(برادر بودند) بوده که واقعا شرایط کاری را بد کرده بود.', '2024-09-29 08:37:59', '2024-09-29 08:37:59'),
(5169, 4297, 'سرپرست حسابداری', 'شرکت خانه سازی پارسمان سازه', 'تمام وقت', 'معماری و عمران', NULL, 1400, NULL, NULL, 1, '12 تا 15 میلیون تومان', 'مسائل شخصی', 'شرکت در زمینه تولید گوی و وافل ساختمانی و همچنین تولید مواد افزودنی فوم فعالیت دارد.\nبنده در زمینه نظارت بر تراز شرکت و ثبت فاکتورهای فروش و خرید و هزینه ها و کمک به بستن حسابها و تهیه اظهارنامه فعالیت دارم.\nپاسخگویی به حسابرسها هم انجام دادم.\n\nعلت قطع همکاری به دلیل کم شدن نقدینگی شرکت خود مدیریت عامل مجموعه درخواست تعدیل نیرو دادند و بنده هم پذیرفتم.', '2024-09-29 08:43:00', '2024-09-29 08:43:00'),
(5170, 4300, 'مدیر مالی', 'ایمن پیشرو سام', 'تمام وقت', 'بیمه', NULL, 1397, NULL, NULL, 1, '30 میلیون و بیشتر', NULL, 'بصورت پاره وقت در شرکت ارس گوهر فاتح سمنگان و ایستا سازه بعنوان مشاور مالیاتی همکاری دارم', '2024-10-04 21:46:40', '2024-10-04 21:46:40'),
