(5172, 4302, 'حسابدار', 'شرکت حسابداری', 'تمام وقت', 'سرمایه گذاری و تحلیل کسب و کار', NULL, 1402, NULL, 1403, NULL, '9 تا 12 میلیون تومان', 'مسائل شخصی', 'کار در کلینیک دندانپزشکی \nترک کار :حقوق پایین', '2024-10-07 20:30:24', '2024-10-07 20:30:24'),
