(5178, 4313, 'صندوقدار', 'قنادی و لوازم تحریری', 'تمام وقت', 'نیرو', NULL, 1402, NULL, 1402, NULL, 'توافقی', 'سایر موارد', 'به دلیل مسافت طولانی محل کار و تایم کاری زیاد \nبصورت دو شیفت سختی کار از لحاظ فیزیکی و عدم نظافت و رعایت نکات بهداشتی و پرداخت حقوق کم', '2024-10-21 19:27:42', '2024-10-21 19:27:42'),
