(5189, 4335, 'کمک حسابدار', 'کوشا صنعت صحرا', 'پاره وقت', 'تولید و صنایع', NULL, 1402, NULL, 1402, NULL, 'توافقی', 'سایر موارد', 'به مدت یکماه در این شرکت به عنوان کمک حسابدار مشغول بودم و به علت پیشنهاد شغلی حسابدار از شرکت خارج شدم.', '2024-11-18 21:12:18', '2024-11-18 21:12:18'),
(5190, 4335, 'حسابدار', 'سپیدیار حساب آراد', 'تمام وقت', 'کامپیوتر، فناوری اطلاعات و اینترنت', NULL, 1402, NULL, 1403, NULL, 'توافقی', 'کافی نبودن حقوق', 'به مدت چهارماه در شرکت مذکور با عنوان حسابدار مشغول به کار بودم و به علت نداشتن بیمه، ساعت کاری طولانی و حقوق بسیار پایین از شرکت خارج شدم.', '2024-11-18 21:15:19', '2024-11-18 21:15:19'),
(5191, 4335, 'حسابدار', 'بهین همراه آینده روشن', 'تمام وقت', 'کامپیوتر، فناوری اطلاعات و اینترنت', NULL, 1403, NULL, NULL, 1, '12 تا 15 میلیون تومان', 'سایر موارد', 'در شرکت بهین همراه آینده روشن در موقعیت شغلی حسابدار مشغول به کار هستم و به دلایلی مایل به خروج از مجموعه مذکور می باشم.', '2024-11-18 21:17:57', '2024-11-18 21:17:57'),
