(5334, 4477, 'حسابدار', 'شرکت آکوصنعت تجارت آریا', 'تمام وقت', 'تولید و صنایع', NULL, 1401, NULL, 1403, NULL, '25 تا 30 میلیون تومان', 'سایر موارد', 'آشنا با امور قراردادهای خرید و فروش .کنترل بررسی نحوه فروش نقد یا نسیه به مشتری و اعتبار سنجی ایشان قبل از فروش\n \n تطبیق و بررسی حساب مشتریان و بانک ها. مدیریت حساب‌های دریافتی و پرداختی. \nتحریر دفاتر قانونی و انجام ثبت پلمپ دفاتر قانونی شرکت.جمع آوری اسناد و مدارک مالی و پاسخگویی به حسابرسان مستقل و \nبیمه کنترل مستندات فروش کالا .تطبیق فاکتور فروش با درخواست فروش، حواله انبار،بارنامه و برگه تحویل کالا.\nمهارت های ثبت و تدوین دریافتنی ها شامل واریزی های نقدی و ثبت دریافت چکهای صیادی مشتریان و اعتبار سنجی چک های مشتریان از طریق سامانه استعلام چک صیاد بانک مرکزی و همکاری با تیم‌های مختلف برای بهبود فرآیندها. \n آشنا به سامانه مودیان وبیمه تامین اجتماعی سامانه جامع تجارت', '2025-04-04 23:02:57', '2025-04-04 23:12:46'),
(5335, 4477, 'حسابدار', 'بازرگانی نیکان فرآیند نواندیش', 'تمام وقت', 'تولید و صنایع', NULL, 1396, NULL, 1400, NULL, '15 تا 20 میلیون تومان', 'سایر موارد', 'تهیه و تنظیم گزارش صورت معاملات فصلی و ارزش افزوده و  تهیه و ارسال اظهارنامه های مالیاتی و کنترل حساب شرکت و تطبیق و بررسی حساب مشتریان و بانک ها. مدیریت حساب‌های دریافتی و پرداختی.', '2025-04-04 23:05:45', '2025-04-04 23:12:23'),
(5336, 4477, 'حسابدار', 'گسترش و توسعه صنایع بهپرور', 'تمام وقت', 'کالای مصرفی و خوراکی', NULL, 1394, NULL, 1396, NULL, '12 تا 15 میلیون تومان', 'سایر موارد', 'حل و فصل مغایرت های بانکی و نگهداری و کنترل حساب های بانکی شرکت . صدور و دریافت و تطبیق اسناد قابل دریافت و پرداخت . گزارش مالی مثل صندوق ها و وضعیت چک های معوقه و برگشتی به مدیریت و نظارت بر منابع مالی سازمان همکاری با تیم‌های مختلف برای بهبود فرآیندها رعایت قوانین و مقررات مالی و حسابرسی', '2025-04-04 23:08:19', '2025-04-04 23:13:49'),
(5337, 4477, 'حسابدار', 'شرکت صنعتی دریایی ایران -صدرا', 'تمام وقت', 'نفت و گاز', NULL, 1389, NULL, 1393, NULL, '9 تا 12 میلیون تومان', 'سایر موارد', 'بایگانی اسناد و ضمانت نامه ها و حفظ و نگهداری آنها .رفع مغایرت بانکی ، مغایرت حساب اشخاص .بررسی و ثبت تراکنش‌های مالی روزانه \nبررسی و انجام امور تنخواه .گزارش اسناد به مدیریت و دسته بندی اسناد برای تایید مدیر مالی .همکاری با حسابرسان داخلی و خارجی', '2025-04-04 23:10:58', '2025-04-04 23:10:58'),
(5338, 4444, 'سرپرست حسابداری', 'شرکت مهندسی صنعت دوام شیمی', 'تمام وقت', 'تولید و صنایع', NULL, 1402, NULL, 1403, 0, NULL, NULL, 'شرکت مهندسی صنعت دوام شیمی \n(تهیه صورت های مالی -تهیه اظهارنامه مالیاتی -کنترل گزارشات معاملات فصلی-کنترل اظهارنامه ارزش افزوده- کنترل سامانه مودیان- تهیه جداول و محاسبات تسهیلات مالی- تهیه گزارشات انبار و بهای کالای مصرفی و محاسبات بهای تمام شده -تهیه بهای تمام شده سفارشات خارجی-کنترل جداول دارایی ثابت و محاسبات استهلاک  - تهیه گزارشات مدیریتی و حسابرسی)', '2025-04-05 09:44:52', '2025-04-05 10:04:59'),
(5339, 4444, 'سرپرست حسابداری', 'شرکت گروه طراحان صنعت آژینه', 'پاره وقت', 'تولید و صنایع', NULL, 1401, NULL, 1402, NULL, NULL, NULL, 'شرکت گروه طراحان صنعت آژینه \n( انجام کلیه امور حسابداری مالی-تهیه گزارشات انبار و بهای کالای مصرفی و محاسبات بهای تمام شده -تهیه و ارسال اظهارنامه های ارزش افزوده و معاملات فصلی- حضور در جلسات رسیدگی مالیاتی و هیأت بدوی عملکرد و ارزش افزوده)', '2025-04-05 09:50:49', '2025-04-05 10:05:13'),
(5340, 4444, 'سرپرست حسابداری', 'شرکت کشاورزی و دامداری چالتاسیان', 'تمام وقت', 'کشاورزی', NULL, 1398, NULL, 1400, NULL, NULL, NULL, 'شرکت کشاورزی و دامداری چالتاسیان \n( رئیس حسابداری مالی – تهیه اظهارنامه مالیاتی -تهیه صورتهای مالی -تهیه گزارشات معاملات فصلی-تهیه جداول و محاسبات تسهیلات مالی-تهیه جداول دارایی ثابت و محاسبات استهلاک -تهیه گزارش هیأت مدیره به مجمع عمومی-آنالیز حسابهای دریافتنی و پرداختنی به صورت جداول سنی-تهیه گزارشات نقدینگی -تحریر دفاتر قانونی )', '2025-04-05 09:53:01', '2025-04-05 09:53:01'),
(5341, 4444, 'مدیر مالی', 'شرکت بهین تجهیز فراب', 'پاره وقت', 'تولید و صنایع', NULL, 1400, NULL, NULL, 1, NULL, NULL, 'شرکت بهین تجهیز فراب\n( انجام کلیه امور حسابداری-راه اندازی سیستم مالی سپیدار-ارسال لیست بیمه و مالیات-حضور در جلسات رسیدگی مالیاتی )', '2025-04-05 09:56:58', '2025-04-05 09:56:58'),
(5342, 4444, 'حسابرس', 'موسسه حسابرسی  آزمون حساب تدبیر', 'تمام وقت', 'خدمات حسابداری', NULL, 1391, NULL, 1398, NULL, NULL, NULL, 'موسسه حسابرسی و خدمات مالی آزمون حساب تدبیر\n( بررسی کلیه سرفصل های حسابداری – تهیه صورت مالی و پیش نویس گزارش حسابرسی )', '2025-04-05 09:59:01', '2025-04-05 09:59:01'),
(5343, 4444, 'حسابرس', 'موسسه حسابرسی و خدمات مالی ایران مشهود', 'تمام وقت', 'خدمات حسابداری', NULL, 1401, NULL, 1401, NULL, NULL, NULL, 'موسسه حسابرسی و خدمات مالی ایران مشهود\nمشارکت در پیاده سازی کنترل های داخلی به روز و قابل اتکا مناسب با اجزای صورت های مالی در سیستم اطلاعات حسابداری و بررسی و ارزیابی مداوم آنها', '2025-04-05 10:00:27', '2025-04-05 10:00:27'),
