(5364, 4548, 'مدیر مالی', 'َشرکت توسعه ارتباطات وداد', 'تمام وقت', 'خدمات حسابداری', NULL, 1400, NULL, NULL, 1, 'توافقی', NULL, '1 سال به عنوان انباردار سیستمی و کمک حسابدار از سال 95 تا 96\n4 سال به عنوان حسابدار شرکت خدماتی و چند شغل پاره وقت از سال 96 تا 1400\nبه علاقه به شرکتهای پیمانکاری وارد حوزه پیمانکاری شدم\nاز سال 1400 تا به امروز در سمت مدیر مالی این مجموعه و چند مجموعه دیگر مشغول بکار هستم', '2025-04-23 14:38:42', '2025-04-23 14:38:42'),
(5365, 4549, 'حسابدار', 'موسسه حسابداري پويا تراز پيشتاز', 'تمام وقت', 'خدمات حسابداری', NULL, 1403, NULL, 1403, NULL, 'قانون کار', 'عدم پیشرفت کاری', NULL, '2025-04-24 02:39:45', '2025-04-24 02:39:45'),
(5366, 4551, 'سرپرست حسابداری', 'ارمغان گستر نوید', 'تمام وقت', 'حسابداری', NULL, 1398, NULL, 1404, NULL, '30 میلیون و بیشتر', 'عدم پیشرفت کاری', NULL, '2025-04-25 19:57:10', '2025-04-25 19:57:10'),
(5367, 4553, 'حسابرس', 'موسسه حسابرسی منفرد و همکاران', 'تمام وقت', 'خدمات حسابداری', NULL, 1391, NULL, 1391, NULL, 'توافقی', 'سایر موارد', 'در این موسسه  کارهای مربوط به شناسایی و ثبت هزینه های غیر قابل قبول در نرم افزار حسابرسی و کمک به حسابرسان در جهت جمع آوری اطلاعات و تهیه گزارش های حسابرسی را انجام می دادم', '2025-04-26 11:11:26', '2025-04-26 11:13:17'),
(5368, 4553, 'کمک حسابدار', 'عمرانی کوزو پارس', 'پروژه ای', 'معماری و عمران', NULL, 1392, NULL, 1403, NULL, '15 تا 20 میلیون تومان', 'سایر موارد', 'در این شرکت کارهای مربوط به بررسی فاکتورها و ثبت آنها و شناسایی هزینه ها و ثبت آنها و مسائل مربوط به تنخواه گردان و امور بانکی را انجام میدادم', '2025-04-26 11:16:51', '2025-04-26 11:16:51'),
(5369, 4556, 'حسابدار', 'ژرف اندیشان فیروزی', 'تمام وقت', 'حسابداری', NULL, 1400, NULL, NULL, 1, 'توافقی', NULL, NULL, '2025-04-27 09:55:06', '2025-04-27 09:55:06'),
(5370, 4559, 'حسابدار', 'پردازش اطلاعات و ارتباطات هاماوران آسیا', 'تمام وقت', 'حسابداری', NULL, 1396, NULL, 1398, NULL, 'توافقی', 'سایر موارد', 'ثبت اسناد حسابداری جاری \nتحریر دفاتر\nارسال اظهارنامه ارزش افزوده و معاملات فصلی\nارسال لیست مالیات حقوق و بیمه \nفروش و خزانه داری\nنرم افزار فرا رایانه', '2025-04-28 12:49:00', '2025-04-28 12:50:28'),
(5371, 4559, 'حسابدار', 'مهرآب بهشت', 'تمام وقت', 'حسابداری', NULL, 1398, NULL, 1399, NULL, NULL, 'مسافت طولانی', 'نرم افزار حسابداری رایورز\nحسابداری خزانه و حقوق و دستمزد\nثبت اسناد حسابداری به صورت روزانه\nانبار گردانی\nارسال اظهارنامه ارزش افزوده و معاملات فصلی\nتهیه گزارشات نقدینگی جهت ارائه به سهامداران', '2025-04-28 12:50:12', '2025-04-28 12:50:12'),
(5372, 4559, 'سرپرست حسابداری', 'افق نیکو متحد', 'تمام وقت', 'حسابداری', NULL, 1398, NULL, 1403, NULL, '30 میلیون و بیشتر', 'سایر موارد', 'انجام و نظارت کلیه امور مالی \nارسال اظهارنامه عملکرد\nارسال اظهارنامه ارزش افزوده و معاملات فصلی\nانجام امور مربوط به سامانه مودیان\nتهیه فهرست حقوق و دستمزد پرسنل \nارسال لیست مالیات حقوق و بیمه پرسنل \nورود و خروج انبار و محاسبه بهای تمام شده هر محصول \nآماده سازی کلیه مدارک جهت ارائه به ممیزان و حسابرسان مالیاتی و آشنا با حضور در جلسات رسیدگی مالیاتی\nبه صورت پیشرفته با نرم افزار سپیدار آشنا هستم', '2025-04-28 12:52:47', '2025-04-28 12:58:48'),
