(5442, 4612, 'حسابرس', 'موسسه حسابرسی ارقام نگر اریا', 'تمام وقت', 'خدمات حسابداری', NULL, 1393, NULL, NULL, 1, '30 میلیون و بیشتر', NULL, 'سال ۹۳ الی ۹۶ به عنوان حسابرسی شرکت فولاد خوزستان در موسیه دایارهیافت و سپس از سال ۹۶ الی ۹۸ با همان سمت در فولاد خوزستان مشغول بودم  و اکنون هم به عنوان حسابرسی در موسیه ارقام نگر اریا مشغول می‌باشم', '2025-05-24 10:12:06', '2025-05-24 10:12:06'),
