(5444, 4615, 'حسابدار', 'شرکت فروشگاه های زنجیره ای فامیلی مدرن', 'تمام وقت', 'حسابداری', NULL, 1402, NULL, 1403, NULL, NULL, 'سایر موارد', 'بدلیل استخدام در آموزش پرورش مجبور به ترک شغل شدم', '2025-05-25 10:42:46', '2025-05-25 10:42:46'),
(5445, 4617, 'حسابدار', 'توسعه فناوری های هوشمند نوابغ جوان', 'تمام وقت', 'حسابداری', NULL, 1403, NULL, NULL, 1, '25 تا 30 میلیون تومان', 'سایر موارد', NULL, '2025-05-26 13:30:31', '2025-05-26 13:30:31'),
(5446, 4620, 'سرپرست حسابداری', 'توسعه فناوری های هوشمند نوابغ جوان', 'تمام وقت', 'سرمایه گذاری و تحلیل کسب و کار', NULL, 1403, NULL, NULL, 1, '30 میلیون و بیشتر', 'سایر موارد', 'اصلاح و به‌روزرسانی کلیه فعالیت‌ها و رویه‌های مالی و سیستم حسابداری شرکت از سال ۱۴۰۲ تا کنون. همچنین سرفصل‌های سیستم حسابداری را اصلاح و طبقه‌بندی کرده و احکام حقوق و دستمزد پرسنل را به‌روزرسانی نموده‌ام. علاوه بر این، پیگیری پرونده‌های باز مالیاتی شرکت نیز از وظایف اصلی من است تا اطمینان حاصل شود که مسائل مالیاتی به‌موقع و دقیق رسیدگی می‌شوند', '2025-05-27 13:30:38', '2025-05-27 23:53:20'),
(5447, 4620, 'سرپرست حسابداری', 'هلدینگ ارزش آفرینان فدک(قطارهای فدک)', 'تمام وقت', 'حمل و نقل، لجستیک و انبارداری', NULL, 1395, NULL, 1403, NULL, '25 تا 30 میلیون تومان', 'کافی نبودن حقوق', 'با راه‌اندازی بخش حسابداری فروش، مسئول طراحی و تدوین فرم‌ها و رویه‌های مرتبط بوده‌ام. وظایفم شامل ارسال گزارشات خرید و فروش فصلی، اظهارنامه ارزش افزوده، و صورت‌حساب در سامانه مودیان است. همچنین در راه‌اندازی سامانه مودیان و تهیه صورت‌های مالی مشارکت فعال داشته‌ام و پاسخگویی به حسابرس و ممیز مالیاتی نیز از مسئولیت‌های من است.', '2025-05-27 13:43:27', '2025-05-27 23:56:03'),
(5448, 4620, 'حسابدار', 'مبتکران شهر صنعت (پیمانکار معادن)', 'پروژه ای', 'معماری و عمران', NULL, 1389, NULL, 1395, NULL, 'توافقی', 'مسافت طولانی', NULL, '2025-05-27 16:12:03', '2025-05-27 16:12:03'),
