(5452, 4628, 'حسابدار', 'پردیس سرام پاژ', 'تمام وقت', 'تولید و صنایع', NULL, 1402, NULL, 1404, 0, '15 تا 20 میلیون تومان', 'عدم پیشرفت کاری', 'از سال ۹۹ تا اواسط ۴۰۰ کمک حسابدار شرکت پیشرو تایر بوده ام.', '2025-05-28 17:04:44', '2025-11-11 18:43:28'),
(5453, 4629, 'حسابدار', 'مجتمع های تفریحی و توریستی', 'تمام وقت', 'گردشگری و هتل ها', NULL, 1396, NULL, 1400, NULL, NULL, NULL, 'از سال ۱۳۹۶ تا ۱۴۰۰ حسابدار مجتمع های تفریحی توریستی و شرکت‌های حسابداری \n\nاز سال ۱۴۰۰ تا ۱۴۰۳ شرکت‌های پخش سراسری دارو', '2025-05-28 17:40:33', '2025-05-28 17:40:33'),
(5454, 4630, 'حسابدار', 'کلینک دندان پزشکی', 'تمام وقت', 'حسابداری', NULL, 1401, NULL, 1404, NULL, '12 تا 15 میلیون تومان', 'عدم پیشرفت کاری', 'کاری که به رشته تحصیلی مرتبط باشد و کارهای سیستمی یاد بگیرم', '2025-05-28 18:42:07', '2025-05-28 18:42:07'),
(5455, 4632, 'کمک حسابدار', 'مرکز همودیالیز موعود', 'پاره وقت', 'حسابداری', NULL, 1395, NULL, 1397, NULL, 'قانون کار', 'عدم پیشرفت کاری', 'دراین‌مجموعه مسئول مکاتبه های اداری ودفتری جمع کردن بیمه های نسخ پزشکان وارسال و بارگذاری ان درسایت مربوط \nوحساب کردن حقوق صاحبان سهام ودرصد پزشکان  ازجمله وظایف بنده بوده', '2025-05-30 02:01:41', '2025-05-30 02:01:41'),
(5456, 4632, 'حسابدار', 'انتشارات سرمشق', 'پاره وقت', 'حسابداری', NULL, 1397, NULL, 1399, NULL, 'قانون کار', 'سایر موارد', '•	پیگیری مطالبات نمایندگان و ثبت اسناد خزانه\n	•	کنترل موجودی انبار، پیگیری سفارشات\n	•	تهیه مکاتبات اداری و ثبت اسناد مالی و انبارداری', '2025-05-30 02:24:10', '2025-05-30 02:24:10'),
(5457, 4632, 'حسابدار', 'شرکت بازرگانی  سلیمی  وشرکا', 'تمام وقت', 'حسابداری', NULL, 1400, NULL, NULL, 1, 'توافقی', NULL, '•	مسئول حسابداری فروش، مغایرت‌گیری فاکتورها و اسناد دریافتی\n	•	مدیریت خزانه: دریافت و پرداخت، واگذاری چک، کنترل وجوه\n	•	کنترل حساب‌های مشتریان و تأمین‌کنندگان\n	•	ثبت اسناد مالی در نرم‌افزارهای سپیدار', '2025-05-30 02:26:37', '2025-05-30 02:26:37'),
(5458, 4632, 'حسابدار', 'هامانا', 'تمام وقت', 'حسابداری', NULL, 1402, NULL, 1403, NULL, '25 تا 30 میلیون تومان', 'سایر موارد', '•	انجام کلیه امور مالیاتی: ثبت در سامانه مودیان، اظهارنامه ارزش افزوده، معاملات فصلی\n	•	ثبت اسناد خزانه و دریافت/پرداخت، مغایرت‌گیری حساب‌ها\n	•	ارسال لیست بیمه و مالیات حقوق پرسنل\n	•	تهیه گزارش‌های مالی مدیریتی', '2025-05-30 02:35:32', '2025-05-30 02:51:19'),
(5459, 4632, 'حسابدار', 'اعتماد مودیان', 'پاره وقت', 'خدمات حسابداری', NULL, 1403, NULL, 1404, NULL, '20 تا 25 میلیون تومان', 'نداشتن بیمه', 'فعالیت در یک شرکت خدمات حسابداری نوپا که به مودیان مالیاتی مشاوره و خدمات ارائه می‌داد. مسئول ثبت لیست بیمه و مالیات حقوق کارکنان و آماده‌سازی بستر اطلاعاتی جهت تهیه گزارشات مالیاتی مودیان، شامل سامانه مودیان، معاملات فصلی و اظهارنامه ارزش افزوده.', '2025-05-30 02:39:41', '2025-05-30 02:44:05'),
(5460, 4633, 'حسابدار', 'همکار دانش فرداد', 'تمام وقت', 'حسابداری', NULL, 1401, NULL, NULL, 1, 'توافقی', NULL, NULL, '2025-05-30 13:04:51', '2025-05-30 13:04:51'),
