(5464, 4648, 'حسابرس', 'حسابرسی مالیاتی', 'پاره وقت', 'خدمات حسابداری', NULL, 1402, NULL, 1403, NULL, 'توافقی', 'مسائل شخصی', NULL, '2025-06-08 14:22:27', '2025-06-08 14:22:27'),
(5465, 4653, 'حسابدار', 'دورنا باتری پایا', 'تمام وقت', 'حسابداری', NULL, 1402, NULL, 1403, NULL, '15 تا 20 میلیون تومان', 'سایر موارد', 'به دلیل اینکه خواهرم مرخصی زایمان گرفته بود جایگزین او شدم و بعد از اتمام مرخصی ترک کار نموده و خواهرم به کار خود برگشت', '2025-06-09 18:51:36', '2025-06-09 18:51:36'),
(5466, 4653, 'حسابدار', 'لوازم یدکی آکو یدک', 'تمام وقت', 'حسابداری', NULL, 1403, NULL, 1403, NULL, '12 تا 15 میلیون تومان', 'عدم پیشرفت کاری', 'چک کردن فاکتور های خرید و فروش و برگشتی ها-ثبت دریافتی و پرداختی ها -مغایرت گیری روزانه -وصول چک ها -ثبت و تایید چک -واگذاری چک ها -بایگانی کردن اسناد -صدور اسناد حسابداری-پیگیری کردن مطالبات مشتریان-محاسبه حقوق و دستمزد -ثبت پورسانت ها - محاسبه سود و زیان', '2025-06-09 18:58:00', '2025-06-09 18:58:00'),
(5467, 4653, 'حسابدار', 'دنیای طعم و رنگ درخشان مهر توس', 'تمام وقت', 'حسابداری', NULL, 1403, NULL, 1404, NULL, '12 تا 15 میلیون تومان', 'تاخیر در پرداخت', 'به طور کامل امور خزانه داری را به عهده گرفته‌ام، شامل ثبت دریافت و پرداخت، رسیدگی به چک‌های پرداختنی و دریافتنی، بایگانی مستندات مالی، پیگیری مطالبات مشتریان و تامین‌کنندگان، صدور فاکتور رسمی و غیررسمی، و واگذاری چک', '2025-06-09 19:02:27', '2025-06-09 19:02:27'),
(5468, 4655, 'ناظر مالیاتی', 'متنوع', 'پاره وقت', 'حسابداری', NULL, 1391, NULL, NULL, 1, NULL, NULL, 'من در همه زمینه های کاری مجری و مشاور مالیاتی و مالی بوده ام\nو در پیاده سازی سیستم و گزارش گیری متخصص هستم', '2025-06-09 20:51:32', '2025-11-17 10:42:22'),
