(5499, 4680, 'سرپرست حسابداری', 'شرکت تولیدی fj', 'تمام وقت', 'حسابداری', NULL, 1402, NULL, NULL, 1, '25 تا 30 میلیون تومان', 'سایر موارد', 'حسابدار انبار و فروش و مالی\nبخش تولید محصول سپیدار کامل یاد دارم\nفرمول دهی بابت تولید\nبستن انبار تولید\nگزارش دهی بابت تولید محصولاتی ک موجودیشون در انبار کم هست\nگزارش دهی بابت سود و زیان تولید و فروش هر محصول', '2025-06-30 17:42:40', '2025-06-30 17:46:51'),
(5500, 4680, 'حسابدار', 'شرکت پتروگستر سپهر', 'تمام وقت', 'حسابداری', NULL, 1402, NULL, 1402, NULL, '9 تا 12 میلیون تومان', 'عدم پیشرفت کاری', 'یادگیری بیشتر موارد مالیاتی و بیمه ای\nیادگیری سامانه مودیان\nصفر تا صد انبار گردانی و بستن انبار انجام میدهم\nانجام روکش سند\nصورت مغایرت بانکی\nثبت اسناد حسابداری\nرد کردن اظهارنامه عملکرد\nآشنایی با سیستم crm (پیام گستر)', '2025-06-30 17:43:32', '2025-06-30 17:47:12'),
(5501, 4680, 'حسابدار', 'شهربازی کیانستر ۲', 'تمام وقت', 'حسابداری', NULL, 1401, NULL, 1402, NULL, '9 تا 12 میلیون تومان', 'ساعت کاری طولانی', '۱.توانایی ثبت با سرعت بالا در سپیدار به دلیل حجم بالای کارهای روزانه\n۲.آشنایی با گزارش سود و زیان\n۳.آشنایی با نرم افزار ساکوآ (نرم افزار مربوط به شهربازی)', '2025-06-30 17:44:28', '2025-06-30 17:47:32'),
(5502, 4680, 'حسابدار', 'شرکت تنها ایمن شرق', 'تمام وقت', 'حسابداری', NULL, 1400, NULL, 1401, NULL, 'قانون کار', 'عدم پیشرفت کاری', 'تهیه لیست بیمه\nرد کردن لیست بیمه\nرد کردن مالیات حقوق\nتهیه و رد کردن ارزش افزوده و گزارش فصلی\nیادگیری نرم افزار سپیدار', '2025-06-30 17:45:11', '2025-06-30 17:47:54'),
(5503, 4681, 'حسابدار', 'پخش پارسیان', 'تمام وقت', 'حسابداری', NULL, 1403, NULL, 1403, NULL, 'قانون کار', 'سایر موارد', NULL, '2025-07-01 00:59:20', '2025-08-02 23:59:52'),
