(5600, 4819, 'کمک حسابدار', 'دفتر اسناد رسمی', 'کارآموزی', 'خدمات حسابداری', NULL, 1403, NULL, 1403, NULL, 'قانون کار', 'سایر موارد', 'یک دوره ۱ ماهه جهت کاراموزی \nاما به دلیل مهارت بالا به عنوان کمک حسابدار \nبا سایت پست و مالیات کار انجام دادم', '2025-07-30 14:36:32', '2025-07-30 14:36:32'),
(5601, 4830, 'حسابدار', 'بیمارستان نور اسفندیار', 'تمام وقت', 'خدمات درمانی، پزشکی و سلامت', NULL, 1386, NULL, NULL, 1, NULL, NULL, 'از سال ۸۶ لغایت ۹۲ در شعبه نور مطهری\nاز سال ۹۲ لغایت ۹۸ در شعبه نور اسفندیار\nاز سال ۹۹ لغایت ۱۴۰۱ بعنوان رییس حسابداری در شعبه نور البرز\nاز سال ۱۴۰۱ مجددا در شعبه نور اسفندیار همچنان مشغول هستم', '2025-07-31 10:43:45', '2025-07-31 10:56:03'),
