(5607, 4581, 'مدیر مالی', 'نوین تجارت فولاد زرین پایا', 'تمام وقت', 'واردات و صادرات', NULL, 1404, NULL, NULL, 1, 'بیش از 40 میلیون تومان', 'مسافت طولانی', NULL, '2025-07-31 17:03:09', '2025-07-31 17:03:09'),
(5608, 4844, 'حسابدار', 'زرافشان تجارت هستی', 'تمام وقت', 'حسابداری', NULL, 1400, NULL, 1403, NULL, '12 تا 15 میلیون تومان', 'عدم پیشرفت کاری', 'مودیان(خرید و فروش)\nاشنا به حقوق و دستمزد \nاشنا به ارسال معاملات فصلی \nثبت اسناد تنخواهگردان\nارسال مالیات حقوق\nارسال لیست بیمه\nدریافت و پرداخت اسناد روزانه\nمغایرت گیری بانکی\nپیگیری و وصول مطالبات\nخزانه و چک صیادی', '2025-08-01 13:32:44', '2025-08-01 13:40:13'),
(5609, 4844, 'حسابدار', 'درافزا شیمی', 'تمام وقت', 'حسابداری', NULL, 1403, NULL, 1404, NULL, '25 تا 30 میلیون تومان', 'سایر موارد', 'آشنابه ثبت فاکتورهای خرید و فروش و مدیریت انبار\nآشنا با سامانه مودیان و سامانه 169\n انجام امور بیمه کارکنان\n تحریر دفاتر قانونی  \n آشنایی با انواع گزارشات مالی از جمله ارزش افزوده و اظهارنامه.', '2025-08-01 13:33:37', '2025-08-01 13:40:43'),
(5610, 4846, 'مدیر مالی', 'آرکا', 'تمام وقت', 'خدمات حسابداری', NULL, 1396, NULL, NULL, 1, 'بیش از 40 میلیون تومان', NULL, NULL, '2025-08-01 14:41:48', '2025-08-01 14:41:48'),
(5611, 4848, 'مدیر مالی', 'شرکت ساختمانی پاوان', 'تمام وقت', 'حسابداری', NULL, 1386, NULL, NULL, 1, 'بیش از 40 میلیون تومان', 'مسائل شخصی', NULL, '2025-08-01 18:05:00', '2025-08-01 18:05:00'),
(5612, 4850, 'سرپرست حسابداری', 'آوا گستر اروند', 'تمام وقت', 'حسابداری', NULL, 1403, NULL, 1403, NULL, '25 تا 30 میلیون تومان', 'تاخیر در پرداخت', 'حدود یک سال در شرکت پیمانکاری اوا گستر اروند مشغول به فعالیت بودم .به دلیل عدم پرداخت حقوق به موقع و بیمه مجبور به ترک‌کار شدم .\nکلیه امور حسابداری اعم از :\nسامانه مودیان ،ارزش افزوده و معاملات فصلی \nاظهارنامه عملکرد\nانبار و قیمت گذاری انبار در سیستم راهکاران\nمغایرت گیری بانک و ثبت اسناد مربوط به ان\nدریافت و پرداخت و کلیه اسناد مربوط به خزانه \nارسال لیست بیمه و مالیات حقوق پرسنل\nمحاسبات حقوق و دستمزد و پرداخت ان \nثبت و بررسی صورت وضعیت پیمانکاران و بررسی قراردادهای پیمان', '2025-08-02 01:39:20', '2025-08-02 02:24:48'),
(5613, 4850, 'سرپرست حسابداری', 'هرمز گاز خلیج فارس', 'پاره وقت', 'حسابداری', NULL, 1402, NULL, 1402, NULL, '15 تا 20 میلیون تومان', 'سایر موارد', 'برای شرکت های زیر مجموعه شرکت هرمز گاز خلیج فارس پروژه مالیاتی انجام می دادم.\nثبت و بررسی خرید و فروش در سامانه مودیان \nبررسی ارزش افزوده و ارسال اظهارنامه ارزش افزوده و معاملات فصلی \nمغایرت گیری گردش بانک', '2025-08-02 01:43:45', '2025-08-02 02:09:25'),
(5614, 4850, 'سرپرست حسابداری', 'تاج قطعه آریا', 'تمام وقت', 'حسابداری', NULL, 1401, NULL, 1401, NULL, '9 تا 12 میلیون تومان', 'کافی نبودن حقوق', 'به مدت بک سال در شرکت تاج قطعه اریا فعالیت داشتم ،محیط پویا و پراز تجربه های ارزشمند بود .\nامور محول شده :\nبررسی امور خزانه،دریافت و پرداخت \nثبت چک در سامانه صیاد \nبررسی ارزش افزوده خرید و فروش \nبررسی حقو ق های ثبت شده و پرداخت حقوق \nبررسی لیست بیمه ارسالی \nبررسی مالیات حقوق پرسنل', '2025-08-02 01:56:04', '2025-08-02 02:05:50'),
(5615, 4850, 'حسابدار صنعتی', 'سوئیت افر', 'تمام وقت', 'حسابداری', NULL, 1397, NULL, 1401, NULL, '9 تا 12 میلیون تومان', 'سایر موارد', 'کلیه امور حسابداری اعم از :\nامور اداری و بیمه کارگاه \nحقوق و دستمزد \nبهای تمام شده محصولات \nانبار و قیمت گذاری انبار\nفروش و‌خرید \nارزش افزوده \nمغایرت گیری بانک', '2025-08-02 02:01:28', '2025-08-02 02:01:28'),
(5616, 4850, 'حسابدار', 'پخش استیل البرز', 'پاره وقت', 'حسابداری', NULL, 1394, NULL, 1397, NULL, 'توافقی', 'مسائل شخصی', 'به دلیل مهاجرت', '2025-08-02 02:16:44', '2025-08-02 02:16:44'),
(5617, 4850, 'حسابدار', 'نمایندگی و پخش محصولات اپادانا', 'پاره وقت', 'حسابداری', NULL, 1391, NULL, 1394, NULL, 'قانون کار', 'کافی نبودن حقوق', 'دریافت و پرداخت ،ارسال دیسکت بیمه و محاسبات حقوق و دستمزد \nپیگیری مطالبات و ثبت اسناد خرید و فروش و ثبت اسناد خزانه\nمغایرت گیری بانک', '2025-08-02 02:29:16', '2025-08-02 02:29:16'),
