(5717, 5009, 'حسابدار', 'های وب', 'تمام وقت', 'حسابداری', NULL, 1397, NULL, 1403, NULL, '20 تا 25 میلیون تومان', 'کافی نبودن حقوق', NULL, '2025-08-12 14:30:03', '2025-08-12 14:30:03'),
(5718, 4946, 'سرپرست حسابداری', 'فعالیت در شرکت‌های معتبر پیمانکاری', 'تمام وقت', 'نفت و گاز', NULL, 1384, NULL, NULL, 1, NULL, NULL, '۲۱ سال سابقه در پروژه‌های استراتژیک و کلیدی صنعت نفت، گاز و انرژی،\nاز پتروشیمی‌های مطرح، پروژه‌های عظیم پارس جنوبی و عسلویه، تا سد منجیل و شرکت‌های بزرگ نفتی مانند ایرانول و بهرام.\nتجربه همکاری در شرکت‌های حسابرسی معتبر و مدیریت پروژه‌های بین‌المللی در ایروان، ترکیه، ارمنستان و مناطق مختلف ایران از جمله میگون و سلمانشهر.\nدر حال حاضر مسئولیت ۹ پروژه همزمان را در یک شرکت پیمانکاری پیشرو بر عهده دارم.\nتجربه‌ای فراتر از شرح وظایف، بر پایه تعهد و تخصص، با بار سنگین پروژه‌های بزرگ.\nجزئیات بیشتر و عمق این مسیر را ترجیح می‌دهم در جلسه حضوری ارائه دهم.', '2025-08-12 18:28:16', '2025-08-12 18:28:16'),
(5719, 5021, 'حسابدار', 'شرکت ساختمانی ماگما', 'تمام وقت', 'حسابداری', NULL, 1400, NULL, 1401, NULL, NULL, 'تاخیر در پرداخت', NULL, '2025-08-13 16:52:08', '2025-08-13 16:52:08'),
