(5753, 5050, 'حسابدار', 'موسسه مالی', 'تمام وقت', 'خدمات حسابداری', NULL, 1403, NULL, 1403, NULL, 'توافقی', 'سایر موارد', 'به مدت ۵ماه در موسسه مالی مشغول به یادگیری و کار شدم \n_ثبت سند هزینه _تنخواه_بانک_خرید و فروش_حقوق و دستمزد _\n_مغایرت گیری گردش مالی \n_ارسال لیست بیمه و حقوق دستمزد \n_ارسال فاکتور فروش در مودیان \n_سامانه معاملات فصلی \nآشنایی با نرم افزار کیسان امیسا و .....', '2025-08-17 19:04:55', '2025-08-17 19:08:33'),
(5754, 5050, 'حسابدار', 'بابام ارقام فرتاک', 'تمام وقت', 'حسابداری', NULL, 1403, NULL, 1404, NULL, 'توافقی', 'سایر موارد', '۶ماه در موسسه مالی مشغول به یادگیری و کار شدم \n_مغایرت گردش مالی و ثبت سند بانک \n_ثبت سند های هزینه /خرید و فروش/تنخواه/حقوق و دستمزد \n_ثبت فاکتور فروش در سامانه مودیان و پیگیری \n_زونکن های مالیاتی و مالی \n_بایگانی اسناد \nارسال لیست بیمه و حقوق دستمزد', '2025-08-17 19:08:04', '2025-08-17 19:08:04'),
(5755, 5050, 'کمک حسابدار', 'جهان پارت', 'کارآموزی', 'حسابداری', NULL, 1402, NULL, 1403, NULL, 'توافقی', 'سایر موارد', 'در شرکت جهان پارت مشغول به یادگیری شدم \n_ثبت فاکتور فروش و پیگیری فاکتور های خرید \n_بایگانی اسناد\n_آشنایی با نرم افزار راهکاران و سپیدار', '2025-08-17 19:10:17', '2025-08-17 19:10:17'),
