(5781, 4860, 'سرپرست حسابداری', 'قارچ سایه رس', 'تمام وقت', 'حسابداری', NULL, 1403, NULL, NULL, 1, '30 تا 40 میلیون تومان', 'تاخیر در پرداخت', 'طی 6 ماه فعالیت در این شرکت \nکلیه امور مالی شامل خرانه و انبار و حقوق و دستمزد و فروش و سامانه مودیان و گزارشات فصلی و اظهار نامه گزارشات انجام شد....', '2025-08-19 12:06:26', '2025-08-19 12:06:26'),
