(5984, 5304, 'حسابرس', 'موسسه اعتباری فردوسی', 'تمام وقت', 'مالی و اعتباری', NULL, 1390, NULL, 1398, NULL, '9 تا 12 میلیون تومان', 'سایر موارد', 'دارای سی سال سابقه کار در سیستم بانکی کشور در مقاطع : رییس دایره حسابداری شعبه ، مدیر شعبه ، بازرس ، مدیر دایره بازرسی ، مدیر حسابرسی و بازرسی منطقه', '2025-08-27 15:55:34', '2025-08-27 15:55:34'),
(5985, 3963, 'حسابدار', 'آلیاژ های نشکن', 'تمام وقت', 'تولید و صنایع', NULL, 1403, NULL, 1404, NULL, '25 تا 30 میلیون تومان', 'عدم پیشرفت کاری', 'حسابداری مالی و تهیه گزارش های مدیریتی ( گزارش نقدینگی)-محاسبه حقوق و دستمزد، ارسال لیست\nمالیات و بیمه-ثبت خرید و فروش، ارزش افزوده، معامات فصلی و فعالیت در سامانه مودیان-\nمغایرت گیری حسابهای بانکی و سایر حساب ها-خزانه داری، تنخواه گردانی و ثبتهای\nمرتبط-تسلط بر امور بانکی، قوانین چک و ثبت حسابداری تسهیلات-آشنایی کامل با\nنرم افزارهای حسابداری  آرپا- ثبت اسناد مرتبط با فروش اقساطی و تسهیلات بانکی-آشنایی کامل با سامانه مودیان و فرآیندهای مرتبط', '2025-08-27 17:40:29', '2025-08-27 19:32:36'),
(5986, 5309, 'حسابرس', 'موسسه حسابرسی وانیا نیم تدبیر', 'تمام وقت', 'خدمات حسابداری', NULL, 1394, NULL, 1400, NULL, NULL, 'عدم پیشرفت کاری', NULL, '2025-08-27 18:36:24', '2025-08-27 18:36:24'),
