(5993, 5314, 'مدیر مالی', 'پویا سپهر', 'پاره وقت', 'خدمات حسابداری', NULL, 1401, NULL, NULL, 1, '15 تا 20 میلیون تومان', NULL, NULL, '2025-08-27 21:01:40', '2025-08-27 21:01:40'),
(5995, 5260, 'رییس حسابداری', 'محور پزشکی آسیا', 'تمام وقت', 'تولید و صنایع', NULL, 1395, NULL, 1399, NULL, NULL, NULL, 'ارزیابی و آموزش واحد مالی\nارسال و نظارت بر لیست بیمه، مالیات، اظهارنامه ارزش افزوده و صورت معاملات فصلی\nتهیه و تنظیم اظهارنامه مالیات بر عملکرد، صورت های مالی و صورت سود(زیان)\nکنترل اسناد و مدیریت دریافت و پرداخت و هزینه های شرکت\nشرکت در جلسات رسیدگی مالیاتی و تامین اجتماعی', '2025-08-27 22:21:22', '2025-08-27 22:21:22'),
(5996, 5260, 'رییس حسابداری', 'بازار طب نوتریکا', 'تمام وقت', 'تولید و صنایع', NULL, 1396, NULL, 1399, NULL, NULL, NULL, 'تهیه و تدوین اظهارنامه های مالیات بر عملکرد، ارزش افزوده و معاملات فصلی و دفاتر قانونی\nهمکاری در تدوین سیاست های مالی داخلی شرکت\nحضور در جلسات رسیدگی مالیاتی و تامین اجتماعی\nتهیه گزارشات مالی و کنترل انحراف بودجه ای', '2025-08-27 22:22:32', '2025-08-27 22:22:32'),
(5997, 5260, 'مشاور مالی', 'خدمات مالی و مشاوره ای آروین سیستم مشاور', 'تمام وقت', 'خدمات حسابداری', NULL, 1399, NULL, 1401, NULL, NULL, NULL, 'ساماندهی ، استقرار و بهینه سازی فرآیندهای مالی و بهای تمام شده در شرکت های تولیدی صنایع غذایی فدلک(مکنزی)، شرکت هلدینگ صنایع غذایی یک و یک(شرکت های تولیدی مائده، قطران گل، نیکان شهد)، شرکت تولیدی کفش پاما، شرکت تولیدی کمال آفرین یزدان راد، شرکت قطعه سازی تجهیز گستر البرز و شرکت قطعه سازی پیچ کوبان\n و همکاری و نظارت بر کنترل پروژه های تولیدی و پشتیبانی از تصمیم سازی و رویه های مالی', '2025-08-27 22:23:56', '2025-08-27 22:31:49'),
(5998, 5260, 'مدیر مالی', 'سپیدارنو', 'پاره وقت', 'تولید و صنایع', NULL, 1399, NULL, NULL, 1, NULL, NULL, 'نظارت و ارزیابی واحد مالی و آموزش پرسنل\nتهیه صورت سود و زیان و ارائه بودجه جامع\nاستقرار سامانه مودیان و تهیه و ارسال اظهارنامه های عملکرد، ارزش افزوده، مالیات حقوق و بیمه\nتهیه و تنظیم صورت های مالی مطابق با استاندارد های حسابداری ایران\nتنظیم لوایح مالیاتی و تعامل با حسابرسان داخلی و ممیزان مالیاتی', '2025-08-27 22:24:54', '2025-08-27 22:24:54'),
(5999, 5260, 'مدیر مالی', 'مهندسی سلامت سرزمین مادری', 'پاره وقت', 'تولید و صنایع', NULL, 1399, NULL, NULL, 1, NULL, NULL, 'کنترل عملیات مالی، طراحی رویه های حسابداری و نظارت بر کلیه فرآیند های مالی\nاصلاح ساختار مالی، استقرار سامانه مودیان و کنترل انطباق با قوانین جدید\nمشارکت در بودجه بندی و کنترل هزینه ها و بهینه سازی ساختار بهای تمام شده\nهدایت تیم حسابداری،آموزش پرسنل و بهبود و بهینه سازی گزارشات داخلی\nتهیه و ارسال گزارش های مالیاتی، بیمه، مالیات حقوق، اظهارنامه عملکرد و ارزش افزوده\nتهیه صورت های مالی مطابق با استانداردهای حسابداری ایران\nتحلیل سود و زیان عملیاتی شرکت و ارائه گزارش های تحلیلی به هیات مدیره', '2025-08-27 22:26:00', '2025-08-27 22:26:00'),
(6000, 5260, 'مدیر مالی', 'تولید فرآورده های شیمیایی ایران(پلیکم)', 'پاره وقت', 'تولید و صنایع', NULL, 1400, NULL, NULL, 1, NULL, NULL, 'طراحی و استقرار ساختار مالی جامع مطابق با استاندارد های حسابداری\nپیاده سازی فرآیندهای تولید، BOM ، زمان سنجی ها و مراکز هزینه جهت ارائه دقیق بهای تمام شده محصولات ساخته شده و نیمه ساخته و قیمت گذاری محصولات بر اساس بهای بدست آمده و تورم نقطه به نقطه\nهدایت فرآیند بودجه بندی سالانه و تحلیل انحراف از عملکرد واقعی\nکاهش هزینه های سربار تا 15% از طریق باز مهندسی فرآیند های مالی و بهای تمام شده و حذف هزینه های تکراری\nمدیریت موفق فرآیند رسیدگی مالیاتی و کاهش جرائم و برآوردهای غیر واقعی تا 35%\nاستقرار و بهینه سازی سامانه های مودیان، جامع تجارت،جامع انبارها و هم راستا کردن آن ها با سیستم های داخلی\nآموزش و رهبری تیم مالی با تمرکز بر نتیجه محوری و کاهش نرخ خطای گزارش ها به کمتر از 2%\nتنظیم اظهارنامه های مالیاتی عملکرد، ارزش افزوده، معاملات فصلی\nتهیه و ارائه صورت های مالی مطابق با استانداردهای حسابرسی ایران\nهمکاری نزدیک با حسابرسان داخلی و ممیزان مالیاتی با رویکرد شفاف سازی کامل\nتهیه گزارش های تحلیلی پیشرفته برای هیات مدیره جهت پشتیبانی از تصمیم گیری های کلان', '2025-08-27 22:26:56', '2025-08-27 22:26:56'),
(6001, 5260, 'مدیر مالی', 'مهندسین بنیان تابلو', 'پاره وقت', 'تولید و صنایع', NULL, 1402, NULL, NULL, 1, NULL, NULL, 'طراحی ساختار مالی شرکت و استقرار کامل فرآیندهای حسابداری و بهای تمام شده بر مبنای هر پروژه\nنظارت بر پیاده سازی سامانه مودیان و کنترل انطباق با قوانین جدید\nبودجه بندی و کنترل هزینه ها\nتهیه و تنظیم لیست حقوق، بیمه، مالیات حقوق و اظهارنامه عملکرد و ارزش افزوده\nآموزش پرسنل مالی و بهبود گزارشات مدیریتی\nشرکت در جلسات رسیدگی مالیاتی و موفقیت در مورد قبول قرار دادن مالیات ابرازی با کمترین جرائم ممکنه', '2025-08-27 22:28:16', '2025-08-27 22:28:16'),
(6002, 5326, 'مدیر مالی', 'بازار گستر پگاه منطقه 2', 'تمام وقت', 'کالای مصرفی و خوراکی', NULL, 1394, NULL, NULL, 1, 'بیش از 40 میلیون تومان', 'سایر موارد', NULL, '2025-08-28 14:56:06', '2025-08-28 14:56:06'),
(6003, 5328, 'سرپرست حسابداری', 'کیان', 'تمام وقت', 'تولید و صنایع', NULL, 1400, NULL, NULL, 1, '30 تا 40 میلیون تومان', 'سایر موارد', 'صفر تا صد حسابداری این شرکت که در زمینه تولید ورق و کارتن فعالیت دارند عهده دار هستم بجز ارسال اظهار نامه عملکرد . \nکلیه امور حسابداری و مالی و فروش و بازرگانی \nنرم افزار سپیدار', '2025-08-28 15:52:10', '2025-08-28 16:13:10'),
(6004, 5328, 'حسابدار', 'آرمان همراه', 'تمام وقت', 'واردات و صادرات', NULL, 1400, NULL, 1400, NULL, NULL, 'سایر موارد', 'از خرداد الی بهمن ۱۴۰۰ \nحسابدار فروشگاه شرکت در علاالدین \nفروش موبایل و اکسسوری\nنرم افزار شایگان \nحسابداری فروش', '2025-08-28 16:01:32', '2025-08-28 16:13:37'),
(6005, 5328, 'رییس حسابداری', 'زیگما', 'تمام وقت', 'حسابداری', NULL, 1400, NULL, NULL, 1, NULL, NULL, 'بعنوان سرپرست و حسابدار مالیاتی\nحسابدار مالیاتی (ارسال مودیان و تنظیم و ارسال ارزش افزوده ) شرکت بازرگانی که متعلق به مدیران شرکت کیان میباشد', '2025-08-28 16:09:58', '2025-08-28 16:14:21'),
(6006, 5334, 'مشاور مالی', 'رامین گستر شرق', 'پاره وقت', 'تولید و صنایع', NULL, 1402, NULL, 1404, NULL, '25 تا 30 میلیون تومان', 'تاخیر در پرداخت', NULL, '2025-08-28 20:55:53', '2025-08-28 20:55:53'),
(6007, 5334, 'مشاور مالی', 'شرکت های مختلف از سال ۸۰ الی ۱۴۰۳', 'پاره وقت', 'تولید و صنایع', NULL, 1380, NULL, 1402, NULL, 'بیش از 40 میلیون تومان', 'سایر موارد', NULL, '2025-08-28 20:57:40', '2025-08-28 20:57:40'),
