(6009, 5337, 'سرپرست حسابداری', 'تیوا شیشه', 'تمام وقت', 'تولید و صنایع', NULL, 1401, NULL, NULL, 1, 'بیش از 40 میلیون تومان', 'تاخیر در پرداخت', NULL, '2025-08-28 23:10:30', '2025-08-28 23:10:30'),
(6010, 5337, 'حسابدار', 'آهن پود شریف', 'تمام وقت', 'نیرو', NULL, 1396, NULL, 1401, NULL, '15 تا 20 میلیون تومان', 'سایر موارد', NULL, '2025-08-28 23:12:40', '2025-08-28 23:12:40'),
(6011, 5341, 'حسابدار', 'شرکت صدای آب دریا', 'تمام وقت', 'حسابداری', NULL, 1401, NULL, NULL, 1, '30 تا 40 میلیون تومان', NULL, 'ثبت های روزانه شمل بانک ها،تنخواه،واریز و پرداخت و ....\nثبت تمامی سندهای مالیاتی،ارسال فاکتور در سامانه مودیان،گزارش گیری و مغایرت گیری فصلی صورتحساب ها\nصدور تمامی اسناد مربوط به انبار،قیمت گذاری ماهانه انبار،تهیه گزارش بهای تمام شده فروش', '2025-08-29 00:49:25', '2025-08-29 00:49:25'),
(6012, 5341, 'حسابدار', 'شرکت پردیس طلوع هستی', 'تمام وقت', 'حسابداری', NULL, 1399, NULL, 1400, NULL, '9 تا 12 میلیون تومان', 'کافی نبودن حقوق', 'انجام کلیه ثبت های مربوط به حسابداری تولیدی،ورود و خروج انبار،قیمت گذاری انبار،گزارش بهای تمام شده فروش\nثبت اسناد مالیاتی و تهیه گزارش های مالیاتی و مغایرت گیری گزارش های مالیاتی مثل(گزارش های ارسال شده مودیان)\nثبت اسناد مربوط به حقوق و دستمزد و هزینه ها(ثابت و روزمره و تنخواه ها)', '2025-08-29 00:55:25', '2025-08-29 00:55:25'),
(6013, 5341, 'حسابدار', 'شرکت ایستگاه تاسیسات و استخر', 'پاره وقت', 'حسابداری', NULL, 1402, NULL, NULL, 1, '20 تا 25 میلیون تومان', NULL, 'ثبت صورت وضعیت ها و فاکتور های درآمدی پیمانکاری\nثبت اسناد روزانه مثل بانک ها و صندوق و تنخواه ها و مغایرت گیری بانک ها و ...\nثبت اسناد مالیاتی و ارسال فاکتورها و صورت وضعیت های پیمانکاری در سامانه\nتهیه گزارش های مالی و مالیاتی و گزارش های فصلی و ...\nتهیه گزارش بهای تمام شده پروژه ها با جزئیات \nثبت اسناد مربوط به حقوق و دستمزد بیمه پیمان ها و ...', '2025-08-29 00:59:45', '2025-08-29 00:59:45'),
(6014, 5341, 'حسابدار', 'شرکت لئوفیکس', 'پاره وقت', 'حسابداری', NULL, 1402, NULL, NULL, 1, '15 تا 20 میلیون تومان', NULL, 'ثبت و انجام کلیه امور مربوط به فروش و خرید(ثبت فاکتور فروش ثبت فاکتور خرید ورود و خروج انبار)\nثبت اسناد روزانه مثل هزینه ها،بانک ها،صندوق و مغایرت گیری بانک و صندوق و مانده تنخواه ها\nثبت اسناد انبار و قیمت گذاری ماهانه انبار و تهیه گزارش بهای تمام شده\nثبت اسناد مربوط به حقوق و دستمزد', '2025-08-29 01:02:08', '2025-08-29 01:02:08'),
(6015, 5345, 'حسابدار', 'یکتا کارن بهشاد', 'تمام وقت', 'کالای مصرفی و خوراکی', NULL, 1403, NULL, NULL, 1, '30 تا 40 میلیون تومان', 'عدم پیشرفت کاری', '-از سال ۱۳۹۳ تا سال ۱۳۹۹ در مجموعه گروه مکی (داروخانه رامین) به عنوان حسابدار\n- از سال ۱۳۹۹ تا سال ۱۴۰۱ در شرکت روژین فارمد به عنوان خزانه دار\n- از سال ۱۴۰۱ تا سال ۱۴۰۳ در شرکت آرشه کار و آرسام پیشرو به عنوان سرپرست خزانه داری', '2025-08-29 08:25:47', '2025-08-29 08:25:47'),
