(6047, 5354, 'حسابدار', 'پیشگام لوله شرق', 'تمام وقت', 'تولید و صنایع', NULL, 1393, NULL, 1399, NULL, 'توافقی', 'سایر موارد', 'نظارت بر ۱۲۰ حساب بانکی و مدیریت سه تنخواه‌دار\nانجام حسابداری حقوق و دستمزد و ارائه گزارش‌های تحلیلی\nآشنایی با سیستم های انبار و فروش سیستم پایا', '2025-08-30 17:52:15', '2025-08-30 17:52:15'),
(6048, 5354, 'مدیر مالی', 'پژوهشکده هواخورشید', 'تمام وقت', 'دولتی', NULL, 1399, NULL, NULL, 1, 'بیش از 40 میلیون تومان', NULL, 'اجرای سیستم حسابداری آنلاین پژوهشکده برای ارائه گزارش‌های تفکیکی به مدیران و ...\nبهینه‌سازی فرآیندهای مالی برای کاهش هزینه‌های عملیاتی و افزایش بازدهی\nمدیریت چالش‌های مالی پیچیده و ارائه راهکارهای نوآورانه\nنظارت بر تخصیص منابع مالی در پروژه‌های استراتژیک\nمهارت‌های کلیدی من شامل:\nمدیریت نقدینگی و تحلیل مالی\nبرنامه‌ریزی و بودجه‌بندی پروژه‌ها\nتسلط بر نرم‌افزارهای مالی نظیر Excel و ...\nارائه گزارش‌های مدیریتی و تحلیلی دقیق\nهمواره تلاش من بر این بوده است که با نگرش حرفه‌ای، استفاده از ابزارهای نوین مالی و به‌کارگیری رویکردهای تحلیلی، سازمان را در مسیر توسعه و پیشرفت یاری رسانم.', '2025-08-30 17:55:07', '2025-08-30 18:00:22'),
