(6132, 5440, 'رییس حسابداری', 'شرکت بازرگانی پیشرو سیاحت', 'تمام وقت', 'کالای مصرفی و خوراکی', NULL, 1382, NULL, 1385, NULL, 'توافقی', 'کافی نبودن حقوق', 'حسابدارارشددرشرکت بازرگانی پیشروسیاحت از سال ۱۳۸۲\n\nرئیس حسابداری د رشرکت بازرگانی پیشرو سیاحت تا سال ۱۳۸۵', '2025-09-05 07:17:58', '2025-09-05 07:17:58'),
(6133, 5440, 'مدیر مالی', 'شرکت توسعه فن آوری تژ برتر', 'تمام وقت', 'مخابرات و ارتباطات', NULL, 1385, NULL, 1395, NULL, 'توافقی', 'مسائل شخصی', 'حسابدارارشد درشرکت توسعه فن آوری تژبرتر از سال ۱۳۸۵تا سال ۱۳۸۷\n\nمدیر مالی واداری درشرکت توسعه فن آوری تژبرتراز سال ۱۳۸۷ الی ۱۳۹۵', '2025-09-05 07:22:47', '2025-09-05 07:22:47'),
(6134, 5440, 'مدیر مالی', 'شرکت چشم هوشمند ایرانیان', 'تمام وقت', 'مخابرات و ارتباطات', NULL, 1395, NULL, 1397, NULL, NULL, NULL, 'از تاریخ ۱۳۹۵/۰۳/۰۱ الی ۱۳۹۷/۰۷/۰۱ شرکتی سهامی خاص در زمینه سیستمهای حفاظتی و امنیتی تاسیس کردم که امور شرکت (دفتری و مالی ) توسط بنده و امور نصب توسط یکی از همکاران انجام شد ولی به دلایل افزایش قیمت دلار در ان مقطع و پایین اومدن سطح درآمد مجبور به انحلال شرکت گرفتنم', '2025-09-05 07:32:01', '2025-09-05 07:32:01');
