(6153, 5465, 'حسابدار', 'بن کافی', 'تمام وقت', 'غذا و رستوران ها', NULL, 1402, NULL, 1404, NULL, '30 تا 40 میلیون تومان', 'سایر موارد', 'مسلط به حسابداری فروش و انبار \nمغایرت گیری بانک \nتنخواه \nمسلط به اکسل \nمعاملات فصلی و ارزش افزوده', '2025-09-06 13:44:53', '2025-09-06 13:55:42'),
