(6156, 5473, 'کمک حسابدار', 'دیبا نقش الماس', 'تمام وقت', 'خدمات حسابداری', NULL, 1402, NULL, 1403, NULL, '9 تا 12 میلیون تومان', 'سایر موارد', NULL, '2025-09-06 15:38:38', '2025-09-06 15:38:38'),
(6157, 5472, 'حسابدار', 'ممتاز پمپ پویا', 'تمام وقت', 'حسابداری', NULL, 1397, NULL, 1403, NULL, NULL, NULL, '(نرم افزار حسابداری سپیدار و رایمون)\nارسال معاملات فصلی\nسامانه مودیان\nارسال فاکتور فروش در سامانه\nماژول فروش\nماژول دارایی ثابت\nماژول دریافت و پرداخت\nماژول انبار\nجمع آوری مدارک حسابرسی\nصدور اسناد مالی\nتهیه لیست حقوق و دستمزد\nارسال لیست بیمه و مالیات حقوق\nتهیه کاربرگ تسهیلات\nآشنایی با امور بانکی\nسامانه جامع تجارت\nثبت سفارش واردات کالا', '2025-09-06 15:39:19', '2025-09-06 15:53:49'),
(6158, 5472, 'سرپرست حسابداری', 'تجارت چاوش آرین', 'تمام وقت', 'حسابداری', NULL, 1403, NULL, 1404, NULL, NULL, NULL, '(نرم افزار حسابداری سپیدار )\nارسال معاملات فصلی\nسامانه مودیان\nارسال فاکتور فروش در سامانه\nارسال اظهارنامه ارزش افزوده\nماژول فروش\nماژول دریافت و پرداخت\nماژول انبار\nجمع آوری مدارک حسابرسی\nصدور اسناد مالی\nتنظیم عوامل حقوق و دستمزد\nتهیه لیست حقوق و دستمزد\nارسال لیست بیمه و مالیات حقوق\nتهیه کاربرگ تسهیلات\nآشنایی با امور بانکی\nخزانه\nآشنایی با سیستم ارزی و کنترل مانده ارزی مغایرت گیری بانک و حسابها \nسامانه جامع تجارت\nثبت سفارش واردات کالا\nآشنایی با اداره مالیاتی\nکنترل صحت مدارک ضمیمه اسناد حسابداری', '2025-09-06 15:40:07', '2025-09-06 15:56:43'),
(6159, 5473, 'حسابدار', 'آژانس نغمه سفر اریای', 'تمام وقت', 'حسابداری', NULL, 1404, NULL, 1404, NULL, '12 تا 15 میلیون تومان', 'سایر موارد', NULL, '2025-09-06 16:02:56', '2025-09-06 16:02:56'),
(6160, 5478, 'حسابدار', 'آتین بهزیست نگر', 'تمام وقت', 'حسابداری', NULL, 1396, NULL, 1398, NULL, NULL, 'عدم پیشرفت کاری', 'انجام کلیه امور حسابداری', '2025-09-06 22:27:32', '2025-09-06 22:42:11'),
(6161, 5478, 'رییس حسابداری', 'فرآزما تحقیق', 'تمام وقت', 'واردات و صادرات', NULL, 1398, NULL, NULL, 1, 'بیش از 40 میلیون تومان', NULL, 'ابتدا به عنوان حسابدار سپس به عنوان سرپرست تیم مالی شرکت مشغول به فعالیت هستم\nازجمله تلاش های من در این سازمان(علاوه بر انجام کلیه امور مربوط با حسابداری و گزارش دهی و انجام تکالیف مالیاتی و...):\nآموزش پرسنل \nایجاد فرآیند های سازمانی جهت تسهیل و مستند سازی سیستمی\nبررسی و عارضه یابی در روند های کاری\nو بهبود پروسه های کاری و تطبیق بهتر و بیشتر با قوانین مالیاتی بیمه و وزارت کار و...', '2025-09-06 22:28:43', '2025-09-06 22:48:24'),
(6162, 5478, 'سرپرست حسابداری', 'رابین تشخیص', 'پاره وقت', 'واردات و صادرات', NULL, 1401, NULL, NULL, 1, NULL, NULL, 'در این شرکت به صورت پاره وقت مشغول به کارم پس از ایجاد سیستم مالی و ایجاد فرآیند ها و دستورالعمل های مورد نیاز ، کار های  حسابدار مجموعه را کنترل و امور مالیاتی و ارسال گزارشات را به عهده دارم', '2025-09-06 22:33:23', '2025-09-06 22:33:23'),
(6163, 5478, 'سرپرست حسابداری', 'فرابین تجهیز', 'پاره وقت', 'واردات و صادرات', NULL, 1402, NULL, NULL, 1, NULL, NULL, 'در این شرکت به صورت پاره وقت مشغول به کارم پس از ایجاد سیستم مالی و ایجاد فرآیند ها و دستورالعمل های مورد نیاز ، کار های  حسابدار مجموعه را کنترل و امور مالیاتی و ارسال گزارشات را به عهده دارم', '2025-09-06 22:34:07', '2025-09-06 22:34:07'),
