(6191, 5511, 'مدیر مالی', 'صنایع دفع', 'تمام وقت', 'حسابداری', NULL, 1367, NULL, NULL, 1, 'توافقی', 'سایر موارد', 'دلیل ترک کار بنده از صنایع دفاع بازنشستگی بوده و بعد از باز نشستگی تا الان توی واحد خصوصی که فعالیتشان واردات چوب از روسیه و فروش داخلی و بخشی از واردات شوند را به کشور عراق انجام میداند و با توجه به اینکه صاحبان شرکت دو تا برادر بودن و به دلایل ش هم صی خودشان به اختلاف خوردند و به همین دلیل هم بنده دیگر نتونستم در آن واحد ادامه فعالیت داشته باشم', '2025-09-09 11:28:29', '2025-09-09 11:28:29'),
(6192, 5513, 'حسابدار', 'سیب طلایی هوشمند', 'تمام وقت', 'واردات و صادرات', NULL, 1400, NULL, NULL, 1, 'بیش از 40 میلیون تومان', NULL, 'امور جاری خزانه ، اموال ، انبار ، سفارشات خارجی ، تسهیلات\nامور قانونی مربوط به تکالیف مالیاتی و حسابرسی مستقل', '2025-09-09 12:01:33', '2025-09-09 12:01:33'),
(6193, 5513, 'مدیر مالی', 'شرکت دانی نور درخشان', 'پاره وقت', 'تولید و صنایع', NULL, 1402, NULL, NULL, 1, '20 تا 25 میلیون تومان', NULL, 'استقرار سیستم ، بهای تمام شده تولید به روش سفارش کار، گزارشات مدیریت و بودجه بندی و BOM\nتمامی تکالیف مالیاتی (اظهارنامه ها ) و رسیدگی ها\nامور مربوط به حسابرسی و صورت های مالی', '2025-09-09 12:02:36', '2025-09-09 12:02:36'),
(6194, 5513, 'حسابدار', 'شرکت آسان همراه هوشمند', 'پاره وقت', 'واردات و صادرات', NULL, 1403, NULL, NULL, 1, '9 تا 12 میلیون تومان', NULL, 'به صورت ثبت و نگهداری حسابها و تراز رسمی مجموعه \nامور مربوط به بستن حسابها و اظهانامه', '2025-09-09 12:03:34', '2025-09-09 12:03:34'),
(6195, 5513, 'سرپرست حسابداری', 'تولیدی ای پلاس (+A)', 'پاره وقت', 'تولید و صنایع', NULL, 1400, NULL, 1403, NULL, '9 تا 12 میلیون تومان', 'سایر موارد', 'راه اندازی و استقرار سیستم \nطراحی کدینگ و رویه حسابداری\nامور مربوط به بهای تمام شده تولید به صورت برون سپاری و پیش پرداخت ها\nامرو مربوط به انبار\n(دلیل ترک کاراتمام پروژه)', '2025-09-09 12:05:24', '2025-09-09 12:05:24'),
(6196, 5513, 'حسابدار', 'شریف ترابر', 'پاره وقت', 'واردات و صادرات', NULL, 1401, NULL, 1403, NULL, '9 تا 12 میلیون تومان', NULL, 'اسناد جاری مربوط به زیر سیستم ارزی\nاستیتمنت های تراستی ثبت خرید و فروش ارز (غیر رسمی)\n(دلیل ترک کاراتمام پروژه)', '2025-09-09 12:06:52', '2025-09-09 12:06:52'),
(6197, 5513, 'حسابدار', 'شرکت گل طعم شیمی', 'تمام وقت', 'واردات و صادرات', NULL, 1398, NULL, 1400, NULL, '9 تا 12 میلیون تومان', 'عدم پیشرفت کاری', 'از مرداد سال 98 تا بهمن سال 99 به عنوان حسابدار مسئول کارهای از قبیل خزانه ، خرید و فروش و انبار و ثبت سفارشات و بهای تمام شده بازرگانی و .... بودم.\nبعد از آن به مدت 8 ماه در بخش فروش (مواد اولیه شیمیایی) مشغول به کار بودم.\n(پایان همکاری به دلیل پایین بودن حقوق)', '2025-09-09 12:07:48', '2025-09-09 12:07:48'),
(6198, 5513, 'حسابدار', 'شرکت گسترش نوآوران آکام الکترونیک', 'تمام وقت', 'واردات و صادرات', NULL, 1395, NULL, 1398, NULL, '9 تا 12 میلیون تومان', 'تاخیر در پرداخت', 'درابتدا به عنوان کمک حسابدار در این مجموعه استخدام شدم و بعد ها امور مربوط به خرید و فروش ، بهای تمام شده بازرگانی ، انواع ثبت های انبار و امور مربوط ، مشارکت در تهیه گزارشات صورت معاملات و ارزش افزوده \n(پایان همکاری به دلیل دیر کرد درپرداخت حقوق)', '2025-09-09 12:09:30', '2025-09-09 12:09:30'),
(6199, 5513, 'حسابدار', 'شرکت طلوع پلاستیک دوستان', 'تمام وقت', 'حمل و نقل، لجستیک و انبارداری', NULL, 1394, NULL, 1395, NULL, 'قانون کار', 'ساعت کاری طولانی', 'در ابتدا قسمت اداری انبار این شرکت مشغول به حسابداری فروش بودم ، بعد از گذشت چند ماه به سمت سرپرست انبار ادامه کار دادم. \n(پایان همکاری به دلیل ادامه تحصیل)', '2025-09-09 12:10:55', '2025-09-09 12:10:55'),
