(6214, 5537, 'حسابدار', 'الماس ترنم پاسارگاد', 'تمام وقت', 'کامپیوتر، فناوری اطلاعات و اینترنت', NULL, 1394, NULL, 1396, NULL, 'توافقی', 'سایر موارد', 'من دراین شرکت درسمت مدیر فروش،وصول مطالبات،بیمه ،مدیر اداری،انبار \nبدلیل عدم پرداخت حقوق پس از شش ماه ناچارا مجبور به ترک کار شدم البته پایان قراردادم بود تا پایان قرارداد صبر کردم ولی تمدید نکردم.\nمیزان حقوق دریافتی پایه 900 هزارتومن بود ولی قرارداد بنده باتوجه به ساعت کاری ماهانه 2100 دریافت بود', '2025-09-11 19:38:47', '2025-09-11 19:38:47'),
(6215, 5537, 'کمک حسابدار', 'کابین 121', 'تمام وقت', 'خدمات حسابداری', NULL, 1396, NULL, 1397, NULL, 'توافقی', 'سایر موارد', 'درمجموعه آسانسوری کابین 121،مدیریت مالی را برعهده داشتم (استخدام ،بیمه،حساب‌های مالی،مالیات ،وصول مطالبات،صدور فاکتور و...)\nدرسال 97 بدلیل سرطان کارفرما مجموعه تعطیل شد.', '2025-09-11 19:42:32', '2025-09-11 19:42:32'),
(6216, 5537, 'صندوقدار', 'ایران کیش', 'تمام وقت', 'کامپیوتر، فناوری اطلاعات و اینترنت', NULL, 1398, NULL, 1398, NULL, 'قانون کار', 'سایر موارد', 'شرکت برای فرار مالیاتی از برای هریک پرسنل ی حساب بدون دسترسی باز کرده بود و مبلغ حقوق قانون کار را آنجا واریز و بعد برداشت می‌کرد و حقوق کمتری برای پرسنل واریز میکرد', '2025-09-11 19:47:41', '2025-09-11 19:47:41'),
