(6257, 5578, 'مدیر مالی', 'امن افزا نوین گستر', 'تمام وقت', 'خدمات حسابداری', NULL, 1391, NULL, 1402, NULL, NULL, 'سایر موارد', 'این شرکت با بیش از 1500نفر پرسنل و 10 نفر پرسنل مالی در زمینه بازرگانی و تامین نیرو و پیمانکاری حوزه امنیت فعالیت می کند', '2025-09-14 12:20:24', '2025-09-14 12:20:24'),
(6258, 5578, 'مدیر مالی', 'مهندسی استخراج مواد معدنی ایران نوین', 'تمام وقت', 'خدمات حسابداری', NULL, 1403, NULL, 1403, NULL, NULL, 'سایر موارد', 'این شرکت تازه تاسیس و اینجانب نسبت به استقرار سیستم مالی و ایین نامه های مالی و ایجاد کدینگ حسابداری اقدام نمودم ولی به دلیل بازنشستگی و منع بکاری گیری نیروی بازنشسته قطع همکاری نمودم', '2025-09-14 12:23:22', '2025-09-14 12:23:22'),
(6259, 5582, 'کمک حسابدار', 'پاکان تجهیز مهر آرا', 'تمام وقت', 'تولید و صنایع', NULL, 1403, NULL, 1403, NULL, '15 تا 20 میلیون تومان', 'مسافت طولانی', 'همکاری در بخش های فروش و انبار و پشتیبانی فرآیندهای مالی مرتبط \r\n- تهیه و تنظیم لیست بیمه و گزارش معاملات فصلی \r\n- کار با نرم افزار سپیدار برای ثبت و مدیریت اطالاعات مالی\nانجام امور بایگانی اسناد مالی\n - ثبت و مدیریت تنخواه \r\n- انجام سفارش گذاری و هماهنگی های مرتبط\n - ثبت ورود و خروج انبار \r\n- انجام مغایرت گیری انبار\n - مدیریت مانده حساب تأمین کنندگان', '2025-09-14 17:14:45', '2025-09-14 17:14:45'),
(6260, 5581, 'حسابدار صنعتی', 'میراب سازه آرین', 'تمام وقت', 'تولید و صنایع', NULL, 1403, NULL, NULL, 1, '30 تا 40 میلیون تومان', 'سایر موارد', 'تغییر مدیر مالی و تیم جدید', '2025-09-14 17:18:40', '2025-09-14 17:22:49'),
