(6262, 5581, 'حسابدار صنعتی', 'صدراستون', 'تمام وقت', 'تولید و صنایع', NULL, 1399, NULL, 1401, NULL, '25 تا 30 میلیون تومان', 'عدم پیشرفت کاری', NULL, '2025-09-14 17:24:50', '2025-09-14 17:24:50'),
(6263, 5585, 'حسابدار', 'ایماژ بنای پیشتاز', 'پاره وقت', 'خدمات حسابداری', NULL, 1403, NULL, 1404, NULL, 'توافقی', 'مسافت طولانی', NULL, '2025-09-14 17:59:03', '2025-09-14 17:59:03'),
(6264, 5584, 'کمک حسابدار', 'فروشگاه یاسین', 'تمام وقت', 'واردات و صادرات', NULL, 1404, NULL, 1404, 0, 'توافقی', NULL, 'کمک حسابدار/ کارآموزی \n\nفروشگاه اتصالات و هیدرولیک یاسین\n\nخرداد ۱۴۰۴ - مشغول به کار 3 ماهه مشغول یودم\n\nبا انجام امور فروش و صدور فاکتور، پاسخگویی به مشتریان و ارائه مشاوره در خرید، مدیریت موجودی و کمک در انبارداری، وظایف اداری و هماهنگی های روزانه، نقش موثری را ایفا کردم.', '2025-09-14 18:00:39', '2025-09-14 18:00:39'),
(6265, 5586, 'حسابدار', 'عمران اروند', 'تمام وقت', 'حسابداری', NULL, 1402, NULL, 1404, NULL, '15 تا 20 میلیون تومان', 'عدم پیشرفت کاری', NULL, '2025-09-14 19:54:52', '2025-09-14 19:54:52'),
(6266, 5582, 'حسابدار', 'سپهر تهویه آریا', 'تمام وقت', 'تولید و صنایع', NULL, 1403, NULL, NULL, 1, '20 تا 25 میلیون تومان', 'نداشتن بیمه', 'راه اندازی سیستم بایگانی مالی از صفر و سازمان دهی اسناد \n- تنظیم و راه اندازی کامل نرم افزار سپیدار برای مدیریت مالی شرکت \n- پشتیبانی از فرآیندهای حسابداری و بهبود دقت و کارایی سیستم مالی \n- بارگذاری فاکتور های رسمی در سامانه مودیان \n-تهیه،تنظیم و ارسال اظهارنامه ارزش افزوده در سامانه مودیان\n- ارسال گزارش خرید ،فروش و صورت وضعیت در سامانه معامالت فصلی \n- مدیریت تنخواه شرکت\n - انجام سفارش گذاری \n- ثبت اسناد مالی \n- کسب تجربه و آشنایی با چالشهای شرکت های تولیدی و پیمانکاری تازه تأسیس', '2025-09-14 21:37:15', '2025-09-14 21:37:15'),
