(6274, 5596, 'مدیر مالی', 'فرآورده های بتنی مهریز', 'تمام وقت', 'تولید و صنایع', NULL, 1401, NULL, 1403, NULL, 'بیش از 40 میلیون تومان', 'تاخیر در پرداخت', NULL, '2025-09-15 19:57:24', '2025-09-15 19:57:24'),
(6275, 5597, 'سرپرست حسابداری', 'پرنیان گسترپرتوسنج', 'تمام وقت', 'تولید و صنایع', NULL, 1402, NULL, 1404, NULL, '30 تا 40 میلیون تومان', 'سایر موارد', 'ارسال لیست بیمه و مالیات حقوق پرسنل‌ .ارزش افزوده و معاملات فصلی. سامانه مودیان. ثبت واردات وصادرات .حقوق و دستمزد .نرم افزار سپیدار', '2025-09-15 20:29:13', '2025-09-15 20:29:13'),
(6276, 2816, 'حسابدار', 'دارویی', 'تمام وقت', 'تولید و صنایع', NULL, 1401, NULL, NULL, 1, '25 تا 30 میلیون تومان', 'عدم پیشرفت کاری', NULL, '2025-09-15 20:43:20', '2025-09-15 20:43:20'),
(6277, 5604, 'حسابدار', 'نو اندیشان تراز ازما', 'تمام وقت', 'حسابداری', NULL, 1397, NULL, 1398, NULL, 'قانون کار', 'کافی نبودن حقوق', 'شروع بسیار خوبی در زمینه حسابداری مالیاتی پس از پایان تحصیل در مقطع دیپلم فنی حرفه ای برام بود \nاما با گذشت یک سال  ( حجم کاری سرسام آور . مسافت طولانی غرب به شرق و عدم تمکین کارفرما به افزایش حقوق ) ترجیح دادم رشد رو جایی دیگری دنبال کنم و قطع همکاری کردم', '2025-09-16 11:41:10', '2025-09-16 11:41:10'),
(6278, 5604, 'حسابدار', 'خدمات مالی و حسابداری آتیه ارقام نگر', 'تمام وقت', 'حسابداری', NULL, 1398, NULL, 1399, NULL, 'توافقی', 'عدم پیشرفت کاری', 'تجربه بسیار عالی در یادگیری و به کارگیری آموزه هام بود اما پس از مدتی موسسه دچار ضعف و از دست دادن مشتری ها به صورت مکرر شد و احساس کردم نیاز به تغییر دارم', '2025-09-16 11:43:04', '2025-09-16 11:43:04'),
(6279, 5604, 'سرپرست حسابداری', 'نورترازان معین', 'تمام وقت', 'حسابداری', NULL, 1404, NULL, NULL, 1, '20 تا 25 میلیون تومان', NULL, 'در حال حاضر به عنوان سرپرست حسابداری مشغول به کارم', '2025-09-16 11:47:23', '2025-09-16 11:47:23'),
(6280, 5610, 'رییس حسابداری', 'اعداد ورایانه پارسیان', 'تمام وقت', 'خدمات حسابداری', NULL, 1378, NULL, 1404, NULL, 'بیش از 40 میلیون تومان', 'سایر موارد', 'همکاری با شخصیت‌های حقیقی و حقوقی  \nفعالیت در انواع شرکت‌های (سهامی | مسئولیت محدود | تعاونی)\nبا موضوع فعالیت: خدماتی | تولیدی | بازرگانی | پیمانکاری | کشاورزی و دامپروری | فرهنگی و هنری | آموزشی و پژوهشی | پزشکی و سلامت \nحمل‌ونقل و لجستیک | شرکت‌های دانش‌بنیان و استارتاپ‌ها | اتاق‌های اصناف و اتحادیه‌های صنفی و اعضای تحت پوشش (مشاغل) \nمؤسسات خیریه | بانک‌های قرض‌الحسنه \n\nتوضیح من برنامه نویس هم هستم ...اینکه مجموعه با نرم افزاری کار میکنه مهم نیست ....ساختار و الگوریتم یکی است .با چند روز کار نقشه راه را میتوانم بدست آورم .\nلینک دانلود رزومه :\nhttps://naseriyan.ir/wp-content/uploads/2025/09/rsume_Dnaseriyan_09301077828.pdf', '2025-09-16 12:15:24', '2025-09-16 12:27:39'),
(6281, 5613, 'حسابدار', 'شرکت راون سازه - پیمانکاری', 'تمام وقت', 'خدمات حسابداری', NULL, 1381, NULL, 1389, NULL, 'بیش از 40 میلیون تومان', 'سایر موارد', 'جابجایی به پارک فن اوری پردیس', '2025-09-16 21:46:48', '2025-09-16 21:46:48'),
