(6335, 5523, 'حسابدار', 'شیمی گستران صبا', 'تمام وقت', 'واردات و صادرات', NULL, 1404, NULL, NULL, 1, 'توافقی', NULL, 'انجام کلیه امور سامانه مودیان (کارپوشه) شامل ارسال فاکتور، ثبت اعلامیه پرداخت/دریافت وجه و مغایرت‌گیری با دفاتر\nانجام امور سامانه جامع تجارت (بخش تجارت داخلی)\nارسال لیست بیمه و مالیات حقوق کارکنان\nتهیه و ارسال اظهارنامه ارزش افزوده\nتهیه و ارسال گزارشات معاملات فصلی\nتهیه و ارسال اظهارنامه عملکرد سالانه شرکت\nثبت و کنترل اسناد روزانه شامل عملیات بانکی، هزینه‌ها و تنخواه\nثبت فاکتورهای خرید و فروش و پیگیری امور مرتبط', '2025-09-19 21:31:27', '2025-10-31 15:32:50'),
(6336, 5523, 'حسابدار', 'فروشگاه کریستال اخلاقی', 'تمام وقت', 'کالای مصرفی و خوراکی', NULL, 1396, NULL, 1403, NULL, 'توافقی', 'عدم پیشرفت کاری', 'ثبت فاکتورهای خرید و فروش و پیگیری امور مرتبط\nانجام سفارش خرید و امور مربوط به فروش\nدفترداری و رسیدگی به اسناد مالی روزانه\nدریافت، پرداخت و وصول چک‌ها و پیگیری مطالبات', '2025-09-19 21:33:28', '2025-10-31 15:31:27'),
(6337, 5544, 'حسابدار', 'رستوران آتا', 'تمام وقت', 'غذا و رستوران ها', NULL, 1401, NULL, 1402, NULL, 'توافقی', 'نداشتن بیمه', NULL, '2025-09-20 10:58:28', '2025-09-20 11:01:04'),
(6338, 5544, 'حسابدار', 'رستوران شبانه روزی میثم', 'پاره وقت', 'غذا و رستوران ها', NULL, 1402, NULL, 1403, NULL, 'توافقی', 'سایر موارد', NULL, '2025-09-20 10:59:24', '2025-09-20 11:01:12'),
(6339, 5544, 'حسابدار', 'کیا کافی کستر پارسا', 'تمام وقت', 'حسابداری', NULL, 1403, NULL, NULL, 1, '15 تا 20 میلیون تومان', NULL, NULL, '2025-09-20 11:00:46', '2025-09-20 11:00:46'),
(6340, 5658, 'مدیر مالی', 'پرنیان گستر پرتوسنج', 'تمام وقت', 'خدمات حسابداری', NULL, 1400, NULL, NULL, 1, 'بیش از 40 میلیون تومان', 'سایر موارد', 'مدیریت کلیه امور جاری و مالیاتی، تهیه و تحلیل صورتهای مالی ، حسابرسی داخلی، تهیه گزارشات مدیریتی و مالیاتی، بودجه بندی و برنامه ریزی مالی، تسلط بر قوانین مالیاتی ایران، تهیه کلیه جداول بهای تمام شده محصولات تولیدیف مدیریت انبار', '2025-09-20 12:13:49', '2025-09-20 13:23:24'),
(6341, 5658, 'مدیر مالی', 'صنایع چوبی پاسار روجین آریا', 'پاره وقت', 'خدمات حسابداری', NULL, 1390, NULL, 1403, NULL, 'بیش از 40 میلیون تومان', 'سایر موارد', 'در ابتدا به عنوان حسابدار شروع  به کار و پس از گذشت چند سال کلیه امور مالیاتی شامل تحریر دفاتر مالیاتی ارسال اظهارنامه مالیاتی عملکرد ، ارزش افزوده ، گزارشات فصلی ، انجام امور روزانه و انبار انجام می گردید', '2025-09-20 12:18:15', '2025-09-20 12:23:59'),
(6342, 5658, 'مدیر مالی', 'شرکت تابا دارو', 'پاره وقت', 'خدمات حسابداری', NULL, 1394, NULL, 1400, NULL, '30 تا 40 میلیون تومان', 'سایر موارد', 'به صورت پروژه ایی با این شرکت فعالیت داشته و کارهای تحریر دفاتر ، ارسال ارزش افزوده و گزارشات فصلی و تهیه اظهارنامه عملکرد و در نهایت حضور در جلسات دفاع مالیاتی و گرفتن برگ قطعی', '2025-09-20 12:28:02', '2025-09-20 12:28:02'),
(6343, 5659, 'سرپرست حسابداری', 'صداوسیما', 'تمام وقت', 'رسانه و انتشارات', NULL, 1374, NULL, 1397, NULL, '30 تا 40 میلیون تومان', 'سایر موارد', '۲۵ سال خدمت در سازمان صداوسیما و بازنشستگی', '2025-09-20 12:43:23', '2025-09-20 12:43:23');
