(6345, 5658, 'سرپرست حسابداری', 'آفرین دارو', 'پاره وقت', 'خدمات حسابداری', NULL, 1394, NULL, 1395, NULL, '9 تا 12 میلیون تومان', 'سایر موارد', 'به صورت پارت تایم با این شرکت فعالیت داشته و امور جاری و کارهای تحریر دفاتر ، ارسال ارزش افزوده و گزارشات فصلی و تهیه اظهارنامه عملکرد و در نهایت حضور در جلسات دفاع تامین اجتماعی ، مالیاتی و گرفتن برگ قطعی', '2025-09-20 13:16:55', '2025-09-20 13:16:55'),
(6346, 5658, 'مدیر مالی', 'شرکت شکوه بنیان', 'پاره وقت', 'خدمات حسابداری', NULL, 1395, NULL, 1398, NULL, '20 تا 25 میلیون تومان', 'سایر موارد', 'فعالیت این شرکت در مورد انجام امور مالی و مالیاتی شرکتها به صورت پروژه ایی بود که من به عنوان سرپرست پرسنلی که در این مجموعه فعالیت داشتن بودم که به صورت کامل تا رد کردن اظهارنامه عملکرد ارزش افزوده و آماده کردن مدارک جهت رسیدگی مالیاتی و بیمه ای به کار نظارت و مدیریت می کردم.', '2025-09-20 13:23:04', '2025-09-20 13:23:04'),
