(6366, 5697, 'سرپرست حسابداری', 'راشا پارس رایان ( ماکسیم )', 'تمام وقت', 'خدمات حسابداری', NULL, 1404, NULL, NULL, 1, 'بیش از 40 میلیون تومان', 'مسائل شخصی', NULL, '2025-09-23 13:30:17', '2025-09-23 13:30:17'),
(6367, 5698, 'حسابدار', 'زاجیتال', 'تمام وقت', 'حسابداری', NULL, 1400, NULL, 1401, NULL, 'توافقی', 'عدم پیشرفت کاری', 'این شرکت در زمینه فروش محصولات دیجیتال مشغول بودند که بیشتر در رابطه با کنترل انبار و خرید و فروش کالا کار میکردیم.', '2025-09-23 13:31:15', '2025-09-23 13:31:15'),
(6368, 5697, 'حسابدار', 'تدبیر اقتصاد مجد', 'تمام وقت', 'خدمات حسابداری', NULL, 1396, NULL, 1399, NULL, '20 تا 25 میلیون تومان', 'سایر موارد', NULL, '2025-09-23 13:32:07', '2025-09-23 13:32:07'),
(6369, 5698, 'حسابدار', 'مدرسه سلام منان', 'تمام وقت', 'حسابداری', NULL, 1401, NULL, 1402, NULL, '9 تا 12 میلیون تومان', 'عدم پیشرفت کاری', 'حسابدار مدرسه منان حسابداری خدمات هست که از جمله وظایف حسابدار در این مدرسه ثبت چک و تایید آن و فرستادن به بانک برای وصول ، بیمه ، مالیات حقوق، تنخواه ،گزارش شهریه ، ثبت همه اسناد حسابداری و درست کردن لیست حقوق ومغایرت گیری و غیره می باشد.', '2025-09-23 13:32:08', '2025-09-23 13:32:08'),
(6370, 5698, 'حسابدار', 'مدیریت انرژی تاو', 'تمام وقت', 'حسابداری', NULL, 1402, NULL, 1403, NULL, '20 تا 25 میلیون تومان', 'مسائل شخصی', 'در این شرکت من به صورت حسابدار مستقل وظیفه حسابداری 4 شرکت را برعهده داشتم در این شرکت ها گزارش ارزش افزوده و معاملات فصلی تهیه کردم و رد کردم ، محاسبه حقوق دستمزد و عیدی و سنوات انجام دادم ، اظهارنامه عملکرد فرستادم ، مفاصا حساب انجام دادم ، اعتراض مالیاتی ثبت کردم ، تنخواه زدم ، انواع سند حسابداری زدم ، با سیستم انبار به صورت پایه کار کردم ، با چک کار کردم . بیمه و مالیات حقوق رد کردم . انواع گزارش تهیه کردم .', '2025-09-23 13:33:13', '2025-09-23 13:33:13'),
(6371, 5698, 'حسابدار', 'توسعه و سازه های جاوید فرد', 'تمام وقت', 'حسابداری', NULL, 1403, NULL, 1403, NULL, '25 تا 30 میلیون تومان', 'مسائل شخصی', 'توسعه سازهای جاوید فرد هلدینگ فعال در زمینه های ساخت و ساز ، فروش ماشین و آژانس هواپیمایی می‌باشد ، اینجانب در این شرکت به صورت پروژه برای دوماه  مشغول به کار شده و مشغول به فعالیت‌های حقوق دستمزد ، بیمه و مالیات حقوق ، ثبت سند ، مغایرت گیری ، دریافت دفاتر قانونی ، سامانه مودیان ، ثبت اسناد خرید و فروش و کنترل ترازنامه و ( تمامی وظایف یک حسابدار ) بعهده داشتم .', '2025-09-23 13:34:35', '2025-09-23 13:34:35'),
(6372, 5697, 'حسابدار', 'طرح و اندیشه بهساز ملت', 'تمام وقت', 'خدمات حسابداری', NULL, 1393, NULL, 1396, NULL, '15 تا 20 میلیون تومان', 'سایر موارد', NULL, '2025-09-23 13:36:02', '2025-09-23 13:36:02'),
(6373, 5698, 'حسابدار', 'شرکت نوران انرزی سبز خاورمیانه', 'تمام وقت', 'حسابداری', NULL, 1404, NULL, NULL, 1, 'بیش از 40 میلیون تومان', NULL, 'هلدینگ نوران شامل 14 شرکت زیرمجموع می باشد که در رابطه با واردات ، تولید و نصب دستگاه های خورشدی فعالیت دارد ، من در این شرکت فعالیت های مغایرت گیری حساب ها ، اصلاح مغایرت ها و حساب های خلاف ماهیت ، اصلاح سند های سال های گذشته ، کمک در تهیه صورت های مالی و اظهارنامه 1404 و حقوق و دستمزد و بیمه و مالیات فعالیت داشتم .\nنرم افزار این شرکت راهکارن می باشد', '2025-09-23 13:36:28', '2025-09-23 13:36:28'),
(6374, 5697, 'حسابدار', 'تدبیر ملت', 'تمام وقت', 'خدمات حسابداری', NULL, 1389, NULL, 1391, NULL, '12 تا 15 میلیون تومان', 'سایر موارد', NULL, '2025-09-23 13:36:53', '2025-09-23 13:36:53'),
(6375, 5702, 'حسابدار', 'رنگین شهر الیزه', 'تمام وقت', 'حسابداری', NULL, 1402, NULL, 1404, NULL, '20 تا 25 میلیون تومان', 'مسافت طولانی', 'آشنایی با سامانه های مالیاتی (مودیان و معاملات فصلی)\n\nتهیه و ارسال لیست بیمه و مالیات حقوق\n\nاشنایی با ادارات مالیاتی تهران\n\nانجام مغایرت گیری بانک و حساب ها\n\nانجام ثبت و بایگانی اسناد مالی\n\nمسلط به گزارش فصلی (اظهارنامه ارزش افزوده)\n\nاشنایی با مکاتبات اداری و رسمی\n\nپیگیری مطالبات مالی\n\nکنترل و تطبیق حساب ها', '2025-09-23 19:32:51', '2025-09-23 19:32:51'),
