(6385, 5738, 'سرپرست حسابداری', 'صنایع الکترونیک پایا انرژی مهام', 'تمام وقت', 'مالی و اعتباری', NULL, 1402, NULL, NULL, 1, NULL, NULL, NULL, '2025-09-25 15:21:32', '2025-09-25 15:21:32'),
(6386, 5746, 'حسابدار', 'کلر پارس تبریز', 'تمام وقت', 'تولید و صنایع', NULL, 1380, NULL, 1390, NULL, 'توافقی', 'عدم پیشرفت کاری', 'سال تجربه حسابداری در شرکت کلرپارس تبریز و تهیه صورت های مالی و گزارش فعالیت هیات مدیره مطابق با استانداردهای مدون سازمان', '2025-09-25 18:08:14', '2025-09-25 18:08:14'),
(6387, 5746, 'مدیر مالی', 'ناب هلدینگ', 'تمام وقت', 'تولید و صنایع', NULL, 1390, NULL, 1402, NULL, 'بیش از 40 میلیون تومان', 'مسافت طولانی', 'در مرحله اول ساماندهی امور مالی شرکت و راه اندازی تمامی ماژول های راهکاران سیستم علی الخصوص راه اندازی موفق ماژول بهای تمام شده در شرکت تولید شمش فولادی.آموزش نیروی کار متخصص و به کارگیری از ظرفیتها. بررسی و تحلیل هزینه ها و راهکارهای کنترل هزینه و بهای تمام شده  و تهیه و تنظیم گزارش های مدیریتی جهت دستیابی به مصرف استاندارد مواد اولیه و کمکی و کاهش ضایعات تولیدی.  تهیه صورت های مالی و گزارش فعالیت هیات مدیره و تهیه تنظیم اظهارنامه های مالیاتی و لوایح مربوطه', '2025-09-25 18:10:26', '2025-09-25 18:10:26'),
(6388, 5746, 'مدیر مالی', 'هلدینگ دقیقی', 'تمام وقت', 'تولید و صنایع', NULL, 1402, NULL, 1404, NULL, 'بیش از 40 میلیون تومان', 'مسائل شخصی', 'تجربه 2 ساله در هلدینگ دقیقی در بکار گیری قوانین مالی و مالیاتی در بنگاههای اقتصادی و تنظیم لوایح مالیاتی . بررسی ریسک های عملیاتی جهت مدیریت ریسک. کنترل نقدینگی و تجزیه و تحلیل دریافتنی و پرداختنی با تدوین راهکارهای منابع و مصارف نقدینگی و کنترل و بررسی تجزیه سنی دریافتنی و پرداختنی و اعمال تکالیف حاکم در امور مربوطه.شکار فرصت های تامین نقدینگی در راستای بهینه سازی و توسعه کسب و کار و کار آفرینی از فرصت های ایجاد شده. بودجه نویسی و بررسی و کنترل عملکرد و عملیاتی و تحلیل فروش و بازار و راهکارهای توسعه بازار', '2025-09-25 18:11:58', '2025-09-25 18:11:58'),
(6389, 5747, 'رییس حسابداری', 'شرکت صنعت قند کردستان', 'تمام وقت', 'حسابداری', NULL, 1401, NULL, NULL, 1, '30 تا 40 میلیون تومان', NULL, 'در شرکت پخش مواد غذایی آشتی بخ مدت ۱۲ سال و ۶ ماه سابقه داشته  و ۲ سال در فروشگاه های زنجیره ای پدر سالار بصورت پاره وقت سابقه داشته', '2025-09-25 18:25:36', '2025-09-25 18:25:36'),
(6390, 5722, 'حسابدار', 'تحارت فراداده کوشا', 'پروژه ای', 'کامپیوتر، فناوری اطلاعات و اینترنت', NULL, 1387, NULL, NULL, 1, 'توافقی', NULL, 'به صورت پروژهای کار می کنم', '2025-09-25 18:28:23', '2025-09-25 18:28:23'),
