(6405, 5719, 'حسابدار', 'شرکت فنی مهندسی دقیق سازه پایدار ایلیا', 'تمام وقت', 'تولید و صنایع', NULL, 1403, NULL, 1403, NULL, '12 تا 15 میلیون تومان', 'عدم پیشرفت کاری', 'ثبت و پردازش اسناد مالی و حسابداری مطابق با استاندارد های حسابداری\nمدیریت حساب های دریافتنی و پرداختنی(کنترل مطالبات و بدهی ها)\nتهیه صورت های مالی شامل تراز نامه،صورت سود و زیان و جریان وجوه نقد\nبررسی و تطبیق مغایرت های بانکی و اسناد حسابداری\nکنترل هزینه ها و درآمدها برای بهبود عملکرد مالی سازمان', '2025-09-26 12:36:37', '2025-09-26 12:36:37'),
(6406, 5719, 'حسابدار', 'شرکت فروآلیاژ زاگرس', 'تمام وقت', 'تولید و صنایع', NULL, 1403, NULL, 1403, NULL, '12 تا 15 میلیون تومان', 'مسائل شخصی', 'ثبت و پردازش اسناد مالی و حسابداری مطابق با استاندارد های حسابداری\nمدیریت حساب های دریافتنی و پرداختنی(کنترل مطالبات و بدهی ها)\nتهیه صورت های مالی شامل تراز نامه،صورت سود و زیان و جریان وجوه نقد\nبررسی و تطبیق مغایرت های بانکی و اسناد حسابداری\nکنترل هزینه ها و درآمدها برای بهبود عملکرد مالی سازمان', '2025-09-26 12:37:36', '2025-09-26 12:37:36'),
(6407, 5719, 'حسابدار', 'شرکت نقش مارکت', 'تمام وقت', 'معماری و عمران', NULL, 1404, NULL, 1404, NULL, '15 تا 20 میلیون تومان', 'مسائل شخصی', 'ثبت و رسیدگی به اسناد حسابداری\nکنترل و ثبت فاکتورها (خرید،فروش،برگشتی ها)\nتهیه گزارش های مالی دوره ای(ماهانه،فصلی،سالانه)\nمدیریت حساب های دریافتنی و پرداختنی\nبررسی مغایرت های بانکی و تهیه صورت مغایرت بانکی\nصدور و پیگیری فیش های واریزی و چک ها\nکنترل موجود کالا و انبار از نظر حسابداری\nبایگانی اسناد مالی و نگهداری آرشیو حسابداری\nارائه مشاوره مالی به مدیریت در تصمیم گیری های اقتصادی', '2025-09-26 12:39:23', '2025-09-26 12:39:23'),
(6408, 5719, 'ناظر مالیاتی', 'شرکت آسان حساب ملل', 'پروژه ای', 'خدمات حسابداری', NULL, 1404, NULL, NULL, 1, 'توافقی', NULL, 'پیگیری و انجام کلیه خدمات مالیاتی\nاظهارنامه مالیات اشخاص و شرکت ها\nارائه راهکار اجرایی جهت کاهش مالیات\nپیگیری معافیت ها و جلوگیری از جرایم\nبررسی و رسیدگی به پرونده‌های مالیاتی\nارسال گزارشات فصلی و ارزش افزوده\nاستقرار سیستم کنترل داخلی مالیاتی', '2025-09-26 12:41:00', '2025-09-26 12:41:00'),
