(6423, 5787, 'مدیر مالی', 'گروه گلستان شرکت سیستم کیفیت فنون', 'تمام وقت', 'استاندارد و کنترل کیفیت', NULL, 1398, NULL, 1404, NULL, 'بیش از 40 میلیون تومان', 'سایر موارد', 'تهیه اظهارنامه عملکرد -دفاع در رسیدگی مالیاتی -دفاع در رسیدگی های ارزش افزوده و بیمه- تهیه و تنظیم صورتهای مالی -تهیه و نظارت بر گزارشات درخواستی-تعامل و پاسخگویی به حسابرس مستقل و داخلی - آنالیز و بررسی سامانه مودیان-تهیه و تنظیم گزارشات فصلی و ارزش افزوده- ارائه گزارشات مدیریتی ماهانه، فصلی و سالانه- تدوین بودجه سالانه و مقایسه آن با فعالیت تحقق یافته-آنالیز وبررسی قرارداهای شرکت قبل از انعقاد و بعد از انجام-ارائه راهکار جهت کاهش هزینه ها - همفکری و همکاری در اخذ گواهینامه های فعالیت و دانش بنیان جهت پیشرفت شرکت\nنظارت بر: صدور اسناد مالی در ماژول های حسابداری ، خزانه ، انبار ، دارایی ثابت، فروش ، حقوق و دستمزد - تطبیق حساب،کارکرد پرسنل،قراردادهای پرسنلی، مفاصاحساب های بیمه و مالیات- اخذ پوشش های مناسب بیمه ای،تحریر دفاتر و...', '2025-09-27 23:53:11', '2025-09-27 23:53:11'),
(6424, 5787, 'رییس حسابداری', 'ایمن نهاد پارسیان-ایمن رویال ایرانیان', 'تمام وقت', 'نفت و گاز', NULL, 1394, NULL, 1398, NULL, '9 تا 12 میلیون تومان', 'مسافت طولانی', 'تهیه اظهارنامه عملکرد -دفاع در رسیدگی مالیاتی -دفاع در رسیدگی های ارزش افزوده و بیمه- تهیه و تنظیم صورتهای مالی- پاسخگویی به حسابرس - تهیه و تنظیم گزارشات مدیریتی -تهیه و تنظیم گزارشات فصلی و ارزش افزوده-  اخذ مفاصاحساب بیمه -نظارت بر صدور اسناد مالی، مغایرت گیری بانک و حسابها - تحریر دفاتر- تنظیم لیستهای کارکرد، حقوق و دستمزد و بیمه و مالیات -تنظیم قرارداد های پرسنلی - تکمیل اسنادو مدارک مناقصه و ارائه پیشنهاد مالی', '2025-09-27 23:55:49', '2025-09-27 23:55:49'),
(6425, 5787, 'رییس حسابداری', 'سحرسازه بلندپایه', 'تمام وقت', 'معماری و عمران', NULL, 1392, NULL, 1394, NULL, '9 تا 12 میلیون تومان', 'تاخیر در پرداخت', 'تهیه و تنظیم گزارشات مدیریتی -تهیه و تنظیم گزارشات فصلی و ارزش افزوده- اخذ مفاصاحساب بیمه - صدور اسناد مالی، مغایرت گیری بانک و حسابهای تنخواه و طرف های مقابل - تنظیم لیستهای کارکرد، حقوق و دستمزد و بیمه و مالیات -تنظیم قرارداد های پرسنلی', '2025-09-27 23:59:07', '2025-09-27 23:59:07'),
(6426, 5787, 'حسابدار', 'بلندپایه', 'تمام وقت', 'معماری و عمران', NULL, 1389, NULL, 1392, NULL, 'قانون کار', 'سایر موارد', 'صدور اسناد مالی ،حقوق،خزانه، انبار و اموال - تهیه گزارشات درون سازمانی و برون سازمانی- نظارت بر نگهداری اموال شرکت- کنترل موجودی انبار - مغایرت گیری های بانک / تنخواه / موجودی کالا - تهیه و تنظیم لیست حقوق و دستمزد/ بیمه / مالیات', '2025-09-28 00:03:44', '2025-09-28 00:03:44'),
(6427, 5790, 'رییس حسابداری', 'نمایندگی لاستیک بارز', 'پاره وقت', 'حسابداری', NULL, 1404, NULL, NULL, 1, '25 تا 30 میلیون تومان', 'عدم پیشرفت کاری', 'اینجانب از سال1385 در شرکتهای مختلف اعم از تولیدی کرپی /نمایندگی ماشین و شرکت مواد غذایی مشغول به فعالیت در بخش مالی و خزانه بوده اشنایی با لیست بیمه /مالیات حقوق/حقوق دستمزد  و مودیان دارم و با نرم افزارهای تدبیر همکاران سازه حساب کار کردم', '2025-09-28 07:56:47', '2025-09-28 08:00:10'),
(6428, 3544, 'حسابدار', 'موسسه حسابداری آرکا انگارش', 'تمام وقت', 'خدمات حسابداری', NULL, 1403, NULL, 1404, NULL, '20 تا 25 میلیون تومان', 'مسائل شخصی', 'ثبت فاکتور خرید و فروش، \nمغایرت گیری بانک ها، \nآماده کردن فایل اکسل مغایرت خرید و فروش با سامانه مودیان و سیستم حسابداری، \nتهیه لیست حقوق و دستمزد، \nکار با سامانه حقوق، \nکار با سامانه جامع تجارت، \nبایگانی اسناد و مدارک شرکت ها، \nآماده کردن روکش اسناد شرکت ها، \nکار با سامانه مودیان نرم افزار نوآوران', '2025-09-28 10:16:25', '2025-09-28 10:27:49'),
(6429, 3544, 'حسابدار', 'شرکت تاپ طب', 'تمام وقت', 'تبلیغات، بازاریابی و برند سازی', NULL, 1403, NULL, 1403, NULL, '9 تا 12 میلیون تومان', 'مسافت طولانی', 'ثبت فاکتور های خرید و فروش، \nثبت بانک، \nمغایرت گیری حساب بانک، \nمعاملات فصلی، \nپیگیری وصول مطالبات، \nبایگانی اسناد و مدارک', '2025-09-28 10:17:39', '2025-09-28 10:28:30'),
(6430, 3544, 'حسابدار', 'شکوه صنعت اسپادان', 'تمام وقت', 'نفت و گاز', NULL, 1399, NULL, 1402, NULL, '12 تا 15 میلیون تومان', 'مسائل شخصی', 'ثبت لیست بیمه پرسنل در سامانه حقوق، \nاظهارنامه ارزش افزوده، \nمعاملات فصلی 169،\nثبت اسناد حسابداری در نرم افزار پارسیان و هلو، \nبایگانی اسناد و مدارک، \nمغایرت گیری بانک، \nثبت لیست بیمه پرسنل در نرم افزار تامین اجتماعی (list disk) و سامانه بیمه(eservices)، \nثبت حقوق و دستمزد پرسنل، \nامور تنخواه گردانی، \nثبت فاکتور های خرید و فروش در نرم افزار اکسل', '2025-09-28 10:18:33', '2025-09-28 10:29:16'),
