(6498, 5905, 'حسابرس', 'هوشیار بهمند', 'تمام وقت', 'خدمات حسابداری', NULL, 1401, NULL, 1401, NULL, '9 تا 12 میلیون تومان', 'سایر موارد', 'حسابرسی شرکت ها\nگزارش گیری\nتحلیل اطلاعات', '2025-10-06 19:46:59', '2025-12-29 05:12:49'),
(6499, 5905, 'حسابدار', 'شرکت پخش مدبران کوشای ایرانیان', 'تمام وقت', 'حسابداری', NULL, 1401, NULL, 1404, NULL, '25 تا 30 میلیون تومان', 'سایر موارد', 'حسابداری بخش خرید - مغایرت گیری با تامین کنندگان - ثبت فاکتور های خرید و فروش - کمک خزانه - گزارش روزانه بانکی - مغایرت گیری\nحسابداری حقوق و دستمزد -\nارسال لیست بیمه و مالیات پرسنل\nتهیه گزارشات جهت حسابرسی\nتعامل با حسابرس\nحسابداری بخش فروش\nارسال اطلاعات فروش و خرید به سامانه مودیان کنترل و مغایرت گیری سامانه با دفاتر\nثبت اصلاعات با نرم افزار واسط کیسان\nتهیه گزارشات فصلی و ارزش افزوده', '2025-10-06 19:47:46', '2025-12-29 05:16:23'),
(6500, 5905, 'حسابدار', 'تولید و توسعه', 'تمام وقت', 'حسابداری', NULL, 1404, NULL, NULL, 1, '30 تا 35 میلیون تومان', NULL, 'حسابداری بخش حقوق و دستمزد تهیه لیست بیمه و مالیات پرسنل\nحسابداری پیمانی پرسنل - مغایرت گیری با کارفرما - تهیه مفاصا حساب از بیمه\nحسابداری صندوق ارزی - تسعیر ارز و محاسبه ماموریت های خارجی', '2025-10-06 19:48:20', '2025-12-29 05:18:45'),
(6501, 5846, 'حسابدار', 'ستاره سهیل اورامان', 'پاره وقت', 'حسابداری', NULL, 1403, NULL, NULL, 1, 'توافقی', NULL, NULL, '2025-10-07 08:47:18', '2025-10-07 08:47:18'),
(6502, 5914, 'سرپرست حسابداری', 'تعاوی مرغداران استان گیلان', 'تمام وقت', 'کشاورزی', NULL, 1401, NULL, 1403, NULL, NULL, 'مسافت طولانی', 'افزایش و تثبیت فروش مرغ پرکنده قابل توجه در بحبوحه گرانی مرغ پرکنده در سال 1402\nراه اندازی و بکار گیری نرم افزار سامانه مودیان جهت ارسال صورت حساب های فروش در کل سال 1402\nمغایرت گیری معاملات فصلی ماده ۱۶۹ با دفاتر حسابداری\nافزایش بهره وری پرسنل خط تولید کشتارگاه با مزایای انگیزشی با محدودترین منابع در بحران 1402 \nایجاد قدرت تاثیر گذاری در بازار مرغ پرکنده با وجود بزرگان صنعت دام و طیور و نقش تنظیم بازار در بحران 1402 همراه با سود قابل توجه\nگزارش گیری در چک ها در جریان وصول دریافتنی و پرداختی\nشرکت در رسیدگی های حسابرسی بیمه و مالیاتی و حسابرسی پایان سال\nتهیه گزارش معوقات مشتریان به همراه تطبیق حساب های بزرگ و پرتراکنش و سنگین\nتهیه گزارش تولید خط کشتار براساس آمار ارسالی از مسئول کشتارگاه\nتنظیم ورود و خروج وجه نقد CASH FLOW \nتطبیق حساب مشتریان و تامین کنندگان \nسیستم سازی برای پخش مویرگی در نرم افزار راهکاران برای اولین بار در کشور\nاصلاح ساختار های سازمانی در بخش تولید و حسابداری\nساختن بازاریاب با تسلط به مبانی مالی و استراتژیک فروش و تامین', '2025-10-07 12:49:52', '2025-10-07 12:49:52'),
(6503, 5914, 'حسابدار', 'گروه پارس', 'تمام وقت', 'تولید و صنایع', NULL, 1403, NULL, 1404, NULL, NULL, 'سایر موارد', 'مغایرت گیری سامانه های مالیاتی ، بانک ها ، مشتریان و تامین کنندگان و رفع آن\nبروزرسانی عقب افتادگی اسناد خرید و فروش و اسناد خرید بورسی\nاصلاح برخی ساختار های سازمانی در مدت فعالیت\nبروز رسانی حقوق و دستمزد عقب افتاده پرداخت نشده پنج ماهه', '2025-10-07 12:51:11', '2025-10-07 12:51:11'),
