(6664, 6184, 'حسابدار', 'کیان تهویه', 'تمام وقت', 'خدمات حسابداری', NULL, 1403, NULL, NULL, 1, '15 تا 20 میلیون تومان', 'تاخیر در پرداخت', 'شرکت آیسان تجارت،ماکان بافت،سلوتکس،شرکت معدن کاران پیشبرد نوین افرا،شرکت نرم افزار مهک\nالان در حال حاضر در شرکت کیان تهویه مشغول به کارم و اینکه من بیمه نمی‌خوام چون از بیمه ی پدرم استفاده میکنم', '2025-10-16 20:02:14', '2025-10-16 20:02:14'),
(6666, 6005, 'مدیر مالی', 'سیمان', 'تمام وقت', 'تولید و صنایع', NULL, 1388, NULL, NULL, 1, '45 تا 50 میلیون تومان', 'تاخیر در پرداخت', 'سابقه کار در هر سطحی از جمله خزانه،جبران خدمات و حسابداری صنعتی ،ریس حسابداری ، مدیرمالی داشته ام .اظهارنامه(ارزش افزوده و عملکرد) انجام داده ام و صورت مالی ، فعالیت هیات مدیره ، تاییدیه مدیران ، بودجه ومقایسه بودجه و عملکرد تخصصی کار کرده ام جهت اضافه کاری و ماموریت حتی برای مدت طولانی مشکلی ندارم و از کار کردن در رشته حسابداری لذت میبرم و به این شغل بی نهایت علاقه دارم .توانایی اداره یک واحد یا مجموعه مالی و تربیت حسابدار جهت شرکت یا مجموعه ها را دارم و در کار گروهی موفق بوده ام', '2025-10-17 02:13:27', '2025-10-17 02:13:27'),
(6667, 6194, 'کمک حسابدار', 'ذوب اهن سقز', 'تمام وقت', 'حسابداری', NULL, 1400, NULL, 1402, NULL, '9 تا 12 میلیون تومان', 'سایر موارد', 'بنده در  این شرکت امورات دفتری و کمک در امورات حسابداری از جمله ثبت هزینه ها و بایگانی کردن اسناد و امورات بیمه تامین اجتماعی پرسنل و حسابداری حقوق و دستمزد رو انجام میدادم', '2025-10-17 13:20:21', '2025-10-17 13:20:21'),
(6668, 6194, 'کمک حسابدار', 'حمل و نقل خلیج فارس', 'پروژه ای', 'حمل و نقل، لجستیک و انبارداری', NULL, 1403, NULL, 1403, NULL, '12 تا 15 میلیون تومان', 'سایر موارد', 'بنده در این شرکت کار اپراتوری صدور بارنامه و هماهنگی با رانندگان رو انجام میدا‌م.', '2025-10-17 13:22:53', '2025-10-17 13:22:53'),
