(6715, 6225, 'حسابدار', 'معین احیا سپاهان', 'تمام وقت', 'حسابداری', NULL, 1403, NULL, NULL, 1, '40 تا 45 میلیون تومان', 'سایر موارد', '✓تهیه اسناد مربوط به رسیدگی و حسابرسی\n  ✓مشارکت در تهیه صورت¬های مالی و عملکرد و بودجه¬بندی\n✓  معاملات فصلی\n✓  ارزش افزوده\n✓  تمامی امور مربوط به سامانه مودیان\n✓ ثبت پیش فاکتور و فاکتورهای خرید و فروش و انبار\n✓ محاسبه حقوق و دستمزد و مزایا، عیدی و سنوات، تسویه حساب\n✓ رد کردن بیمه و مالیات بر حقوق پرسنل\n  ✓محاسبه بهای تمام شده کالای وارداتی و قیمت¬گذاری\n  ✓محاسبات مربوط به استهلاک دارایی¬ها\nمراجعات برون سازمانی-سازمان امور مالیاتی و بیمه تامین اجتماعی✓  \n  ✓ پیگیری مالیاتی و مکاتبات در رابطه با بخشودگی، کارت بازرگانی و بدهی¬های مالیاتی و سامانه مودیان\n✓ ثبت اسناد و پرینت های بانکی در نرم افزار سپیدار\n✓  مغایرت¬گیری بانکی و صورت تطبیق بین شرکت¬ها\n  ✓صدور تمامی فیش¬های بانکی\n  ✓امور مربوط به تمامی واریزی¬ها و صدور و وصول چک¬های صیادی\n  ✓بایگانی مدارک و روکش اسناد\n  ✓تایپ نامه¬های اداری و مکاتبات\n  ✓ساعات کارکرد پرسنل\nعلت ترک کار: مشغول به کار', '2025-10-18 13:53:36', '2025-12-15 22:50:21'),
(6716, 6225, 'حسابدار', 'ارمیا بین الملل اسپادانا', 'تمام وقت', 'حسابداری', NULL, 1402, NULL, 1403, NULL, '15 تا 20 میلیون تومان', 'سایر موارد', '✓ ثبت اسناد و پرینت های بانکی در نرم افزار سپیدار\r\n✓ ثبت پیش فاکتور و فاکتورهای خرید و فروش و انبار\r\n✓ محاسبه حقوق و دستمزد\r\n✓ رد کردن بیمه و مالیات بر حقوق پرسنل\r\n✓  رد کردن معاملات فصلی\r\n✓  رد کردن ارزش افزوده\r\n✓  ثبت فاکتورهای فروش در سامانه مودیان\r\n  ✓بایگانی\r\n  ✓تایپ نامه¬های اداری و مکاتبات\r\n✓ انجام امور بانکی\r\n✓ مراجعات برون سازمانی اعم از سازمان تامین اجتماعی و اداره پست\r\n✓ ارسال و پیگیری فاکتورهای فروش برای درج مهر شرکت های مربوطه\r\nعلت ترک کار: انتقال بین شرکت های همگروه هلدینگ احیا', '2025-10-18 13:55:09', '2025-12-15 22:51:43'),
