(6737, 5979, 'کمک حسابدار', 'فروشگاه لوازم خانگی', 'تمام وقت', 'کالای مصرفی و خوراکی', NULL, 1403, NULL, 1404, NULL, '15 تا 20 میلیون تومان', 'تاخیر در پرداخت', 'فروشگاه لوازم خانگی کمک حسابدار \nثبت چک ها دریافت وپرداخت \nدریافت وپرداخت روزانه صندوق ووجه نقدوبانک\nثبت فاکتور خریدوفروش...', '2025-10-19 10:43:03', '2025-10-19 10:43:03'),
