(6758, 6270, 'مدیر مالی', 'استانقدس رضوی', 'تمام وقت', 'حسابداری', NULL, 1383, NULL, 1392, NULL, NULL, NULL, 'دراین مدت در شرکت معادن استانقدس و موسسه جوانان و مشاوره استانقدس و شرکت کاشی سنتی استانقدس فعالیت داشته ام', '2025-10-20 12:10:06', '2025-10-20 12:16:37'),
(6759, 6270, 'مدیر مالی', 'شرکت ساختمانی علاقه مند سازان', 'پاره وقت', 'حسابداری', NULL, 1393, NULL, 1404, NULL, NULL, NULL, 'شرکت ساختمانی علاقه مند سازان یک گروه ساختمانی انبوه ساز بوده که عمدتا قرادادهای عمرانی با سازمانهای دولتی نظیر دانشگاه علوم پزشکی مشهد - شهرداری مشهد - مسکن و شهرسازی در خصوص ساخت مسکن ملی فعالیت دارد', '2025-10-20 12:11:02', '2025-10-20 12:19:29'),
(6760, 6270, 'مشاور مالی', 'شرکت زعفران ملل', 'پاره وقت', 'حسابداری', NULL, 1398, NULL, 1404, NULL, NULL, NULL, 'شرکت زعفران ملل دارای یک کارخانه تولید نبات و سالن بسته بندی زعفران و ... میباشد و دارای چندیم فروشگاه در مشهد و تهران', '2025-10-20 12:12:12', '2025-10-20 12:17:50'),
(6761, 6270, 'مدیر مالی', 'شرکت حسابداری و حسابرسی فرزام محاسب', 'تمام وقت', 'حسابداری', NULL, 1379, NULL, 1383, NULL, NULL, NULL, NULL, '2025-10-20 12:13:26', '2025-10-20 12:13:26'),
(6762, 6272, 'مدیر مالی', 'شرکت سپهرتجارت', 'تمام وقت', 'حسابداری', NULL, 1392, NULL, NULL, 1, '45 تا 50 میلیون تومان', 'سایر موارد', 'از سال 1388 به عنوان حسابدار در شرکت سپهرتجارت مشغول به کار شده و در سال 1392 به عنوان مدیرمالی مجموعه انتخاب و همچنان در مجموعه فوق مشغول به کار هستم.\nاز سال 1386 تا 1388 در شرکت مازند حساب به عنوان حسابدار مشغول به کار شده بودم.\nدر سال 1393 به عنوان حسابرس در شرکت ارقام نگر ایرانیان به عنوان کمک حسابرس به کار پاره وقت مشغول شدم و در سال 1396 به عنوان حسابرس در آن مجموعه تا سال 1400 مشغول به فعالیت بوده ام.', '2025-10-20 12:30:35', '2025-10-20 12:30:35'),
(6763, 6275, 'سرپرست حسابداری', 'شیرآلات صنعتی ویستابرزین', 'تمام وقت', 'حسابداری', NULL, 1403, NULL, 1404, NULL, '60 تا 70 میلیون تومان', 'سایر موارد', 'باز تعریف کنترل‌های داخلی و گردش عملیات مالی به منظور کاهش ریسک ذاتی.\nباز تعریف ساختار مالی و طبقه بندی حساب‌ها براساسGAAP ارائه شده توسط FASB و آخرین تغییرات استانداردهای حسابداری ایران متناسب با IFRS ارائه شده توسط IASB.\nکنترل و رسیدگی به سوابق مجموعه در نهادهای عمومی از جمله سازمان تامین اجتماعی و سازمان امور مالیاتی کشور.\nبروز رسانی و کنترل وضعیت مجموعه در سامانه مودیان و پایانه های فروشگاهی.', '2025-10-20 12:56:47', '2025-10-20 12:56:47'),
(6764, 6275, 'سرپرست حسابداری', 'هلدینگ رونما', 'تمام وقت', 'حسابداری', NULL, 1401, NULL, 1402, NULL, '25 تا 30 میلیون تومان', 'سایر موارد', 'مسئول هدایت و کنترل تیم مالی.\nاصلاح طبقه بندی حساب‌ها متناسب با استانداردهای حسابداری و همچنین آخرین بخشنامه‌ها و ابلاغیه های سازمان حسابرسی.\nتهیه صورت‌های مالی اساسی.\nانجام امورات مربوط به سامانه جامع تجارت.\nتنظیم لوایح و حضور در جلسات و هیات های رسیدگی مالیاتی.\nانجام امور ثبتی و حقوقی.\nانجام امور اداری کارکنان از قبیل تهیه و تنظیم قراردادهای کاری متناسب با گروه و عنوان شغلی در ساختار سازمان مطابق با قانون کار ، تامین اجتماعی و سایر قوانین و مقررات موضوعه و همچنین امورات مربوط به تسویه حساب.', '2025-10-20 12:58:23', '2025-10-20 12:58:23'),
(6765, 6276, 'رییس حسابداری', 'فن آوران', 'تمام وقت', 'تولید و صنایع', NULL, 1389, NULL, 1391, NULL, 'قانون کار', 'سایر موارد', NULL, '2025-10-20 12:58:34', '2025-10-20 13:01:16'),
