(6860, 6377, 'رییس حسابداری', 'شکلات برنوتی', 'تمام وقت', 'تولید و صنایع', NULL, 1394, NULL, 1399, NULL, '15 تا 20 میلیون تومان', 'کافی نبودن حقوق', NULL, '2025-10-25 23:35:07', '2025-10-25 23:35:07'),
(6861, 6379, 'حسابدار', 'شرکت نایلون سپید', 'تمام وقت', 'تولید و صنایع', NULL, 1394, NULL, 1395, NULL, 'قانون کار', 'نداشتن بیمه', 'انجام کلیه امور حسابداری فروش\nتهیه و ارسال معاملات فصلی و ارزش افزوده\nگزارشات به مدیریت و حسابرس\nهمکاری در تهیه صورت های مالی', '2025-10-26 00:10:21', '2025-10-26 12:53:42'),
(6862, 6379, 'حسابدار صنعتی', 'شرکت کشت و صنعت و مجتمع شیرو گوشت محیا', 'تمام وقت', 'کشاورزی', NULL, 1395, NULL, 1398, NULL, '9 تا 12 میلیون تومان', 'مسافت طولانی', 'تهیه گزارشات ماهانه،\nکنترل اسناد خرید و انبار ،قیمت گذاری اسناد انبار ،\nصدور و ثبت اسناد حسابداری مربوط به ماژول فروش انبار،\nجمع آوری اطلاعات کارکرد ماهیانه پرسنل و محاسبات مربوط به حقوق دستمزدو تهیه لیست های بیمه،مالیات حقوق،\nثبت و صدور اسناد مالی، تهیه گزارشات فصلی و ارزش افزوده،\nحضور در انبارگردانی های دوره ای،مشارکت در پاسخگویی مالیاتی،مشارکت در تهیه صورت مالی.\nتجزیه و تحلیل هزینه‌ها و محاسبه بهای تمام شده محصولات\nتهیه گزارش‌های مالی و مدیریتی برای تصمیم‌گیری‌های استراتژیک\nبرقراری سیستم‌های کنترل داخلی و بهبود فرآیندهای انبارداری', '2025-10-26 00:11:38', '2025-10-26 12:52:50'),
(6863, 6379, 'حسابدار صنعتی', 'گروه صنعتی سپاهان', 'تمام وقت', 'تولید و صنایع', NULL, 1399, NULL, 1400, NULL, '9 تا 12 میلیون تومان', 'سایر موارد', 'تهیه و ارسال گزارشات بورس(کدال)\nتهیه گزارشات تحلیلی بازار بورس\nتهیه گزارشات مجمع\nتهیه گزارشات ماهانه هیئت مدیره\nکنترل اسناد انبار،کنترل و قیمت گذاری سفارشات خارجی\n،تهیه گزارشات بهای تمام شده\nتهیه و کنترل بودجه و محاسبات مربوطه\nمشارکت در تهیه صورت های مالی', '2025-10-26 00:13:47', '2025-10-26 12:51:28'),
(6864, 6379, 'حسابدار صنعتی', 'توسعه فناوری اطلاعات خوارزمی', 'تمام وقت', 'کامپیوتر، فناوری اطلاعات و اینترنت', NULL, 1400, NULL, 1402, NULL, '15 تا 20 میلیون تومان', 'سایر موارد', 'سرپرست حسابداری انبار\nتهیه کلیه گزارشات بورس و مدیریتی\nکنترل حسابهای امانی و قیمت گذاری انبار\nارسال گزارشات فصلی\nحسابداری مالی\nآموزش و راهنمایی تیم مالی در زمینه‌های شیوه‌های حسابداری بهای تمام شده', '2025-10-26 00:15:30', '2025-10-26 12:50:48'),
(6865, 6379, 'حسابدار صنعتی', 'شرکت زمزم ایران', 'تمام وقت', 'تولید و صنایع', NULL, 1403, NULL, NULL, 1, '35 تا 40 میلیون تومان', 'سایر موارد', 'حسابداری بهای تمام شده\nکنترل و قیمت گذاری اسناد انبار\nکنترل و قیمت گذاری اسناد صادرات و واردات\nتهیه گزارسات مربوط به بهای تمام شده\nهمکاری با تیم تولید برای محاسبه بهای تمام شده محصولات و خدمات\nآموزش و راهنمایی کارآموزان در زمینه حسابداری صنعتی و نرم افزارهای مربوطه', '2025-10-26 00:16:24', '2025-10-26 12:49:54'),
