(6905, 6436, 'سرپرست حسابداری', 'زیر ساخت مرکز داده ارم', 'تمام وقت', 'کامپیوتر، فناوری اطلاعات و اینترنت', NULL, 1403, NULL, 1404, NULL, '50 تا 60 میلیون تومان', 'سایر موارد', '1_استقرار نرم افزار مالی\n2_تعریف الگو های کنترلی انبار و اموال و اسناد مالی \n3_کنترل اسناد مالی و انبار \n4_کنترل سامانه مودیان و ارائه گزارش ارزش افزوده و فصلی \n5_کنترل صورتخلاصه تنخواه و بررسی گردش کار \n6_بررسی قرارداد ها و تهیه فایل های کنترلی قراردادها \n7_بررسی فاکتور های فروش و حواله های انبار و B O M\n8_بررسی اسناد خرید و قیمت گذاری های انبار \n9_تغییرات ساختاری کنترل اسناد و تهیه فایل های کنترلی \n10_تهیه فایل های بهای تمام شده \n11_تهیه کاربرگ های رسیدیگی بیمه و مالیات \n12_تطبیق حساب ها و مغایرت گیری پروژه ای \n13_بستن حساب ها و تهیه گزارشات کنترل هزینه پایان سال \n14_تهیه فایل بودجه عملیاتی و نقدی به تفکیک پروژه \n15_ارائه روش اجرایی در ماژول های مختلف مالی \n16_یکپارچه سازی ساختار بایگانی اسناد مطابق با نیاز واحد مالی \n17_بررسی اسناد وارده از نظر بیمه و مالیات و ارجاع کار به واحد ها \n18_تهیه چک لیست های پایان سال مالی و عملیات بستن حساب \n19_همکاری در تهیه صورتهای مالی و 6020\nبصورت کاملا حرفه ای در همه ماژول های راهکاران \nبه دنبال موقعیت شغلی بهتر هستم', '2025-10-27 22:29:30', '2025-10-27 22:29:30'),
(6906, 6436, 'سرپرست حسابداری', 'مصنوعات فلزی سنگین', 'تمام وقت', 'تولید و صنایع', NULL, 1401, NULL, 1402, NULL, '50 تا 60 میلیون تومان', 'سایر موارد', '1_کنترل اسناد مالی خرید \n2 _ کنترل اسناد انبار \n3_تهیه گزارشات کنترلی  مدیریتی (انبار_دفترکل)\n4_کنترل اسناد واردات و تهیه کاربرگ وارداتی \n5_کنترل اسناد بیمه ای و تهیه کاربرگ رسیدگی \n6_کنترل اسناد صورت خلاصه تنخواه \n7_استقرار ساختار انبار (در سطوح مختلف پروژه)\n8_ محاسبات بهای تمام شده خرید و نرخ گذاری انبار \n9_کنترل مغایرت انبار و کنترل اسناد ورود و خروج انبار \n10_کنترل امول و پلاک گذاری واستقرار مراکز \n11_کنترل سامانه جامع مودیان\n12_تهیه کاربرگ گردش کار انبار و حسابداری\n13_کنترل سامانه مودیان و تهیه کاربرگ \n14_تهیه گزارشات کنترلی و گزارشات مدیریتی \nبه دنبال موقیت شغلی بالاتر می باشم\nعلت قطع همکاری :موقعیت شغلی بهتر و تغییرات بیمه ای', '2025-10-27 22:31:08', '2025-10-27 22:31:28'),
(6907, 6436, 'حسابدار صنعتی', 'دژپاد', 'تمام وقت', 'تولید و صنایع', NULL, 1399, NULL, 1401, NULL, '45 تا 50 میلیون تومان', 'سایر موارد', '1_کنترل و ثبت فاکتور های خرید و ریالی نمودن انبار \n2_کنترل تنخواه و ثبت صورت خلاصه \n3_کنترل و ثبت سفارشات وارداتی  \n4_کنترل و مغایرت گیری خدمات کارمزدی (ماده 38 قانون تامین اجتماعی )\n5_تهیه و ارائه گزارشات آماری مدیریتی \n6_تهیه و ارائه گزارش ارزش افزوده و معاملات فصلی \n7_کنترل و محاسبات حقوق مشاوران شرکتی و گزارشات مالیاتی (مالیات تبصره 86)\n8_هزینه یابی و ارائه گزارشات بهای تمام شده \n9_تهیه گزارشات انبار گردانی و مغایرت گیری \n10_کنترل اسناد مالی و کنترل انبار \nدر حال حاضر در سمت سرپرستی و کنترل اسناد مالی فعالیت دارم', '2025-10-27 22:33:24', '2025-10-27 22:33:56'),
