(7060, 6588, 'حسابدار', 'اطلس فولاد شرق', 'پاره وقت', 'حسابداری', NULL, 1402, NULL, 1404, NULL, 'قانون کار', 'عدم پیشرفت کاری', 'ز آبان 1402 تا تیر 1404 در بازار آهن در زمینه امور خزانه داری و فروش مشغول به کار بودم و به دلیل تمایل به کار\nدر محیطی بهتر و پیشرفت از کار خود استعفا دادم.\nتنظیم لیست حقوق و دستمزد پرسنل\nمغایرت گیری حساب های بانکی\nثبت اسناد هزینه و درآمد در نرم افزار حسابداری\nانجام امور خزانه داری و کنترل وجوه نقد\nصدور و ثبت فاکتور های خرید و فروش\nهمکاری در تهیه گزارش های مالی\nآشنایی با قوانین مالیات بر حقوق\nآشنایی با قوانین لیست بیمه\nکار کردن با نرم افزار های سکان و آرپا', '2025-11-02 21:18:07', '2025-11-02 21:18:07'),
(7061, 6581, 'حسابدار', 'شرکت اینترنتی ماکی کالا', 'تمام وقت', 'خدمات درمانی، پزشکی و سلامت', NULL, 1402, NULL, 1404, NULL, '25 تا 30 میلیون تومان', 'سایر موارد', 'ثبت اسناد حسابداری فروش \nثبت فاکتور و پیش فاکتور فروش\nپیگیری وصول مطالبات مشتریان\nنگهداری اسناد فروش\nتهیه و تنظیم گزارشات مربوطه\nمغایرت گیری فاکتورهای فروش بامشتریان وبانک\n ثبت فروش اینترنتی و سایت\nتنخواه \nسفارش گرفتن از مشتریان و پیگیری ارسال محصولات و کالاها از زمان درخواست مشتری تا زمان تحویل کالا\nآشنابی با میزیتو و ارتباط با مشتریان و crm\nثبت وارزی های بانک و خزانه داری\n شرکت تعدیل نیرو کردن به خاطره ورشکستگی', '2025-11-02 21:33:40', '2025-11-02 21:33:40'),
(7062, 6581, 'حسابدار', 'موُسسه فرهنگی و آشپزی ساناز سانیا', 'تمام وقت', 'غذا و رستوران ها', NULL, 1400, NULL, 1402, NULL, '20 تا 25 میلیون تومان', 'سایر موارد', '1.تسلط کامل با تعریف کالا در انبار \n\n2.آشنایی با مراحل و مدارک لازم معاملات فصلی و ارزش افزوده و سامانه مودیان آماده سازی مدارک مورد نیاز\n\n3.تسلط به دفتر نویسی \n4.مسلط به خزانه داری و امور مربوط به  چکهای دریافتی و پرداختی \n\n5. ارائه گزارش بودجه و مغایرت گیری بانکها.\n\n6.گزارشات امور مالی و مدیران\n\n7.حسابداری فروش شامل ثبت فاکتورهای فروش،وصول مطالبات از مشتریان ،فروش های سایت و اینترنتی ،مغایرت گیری حساب با مشتریان\n\nشرکت به خاطره واگذاری به شرکت کاله تعدیل نیرو کردن', '2025-11-02 21:44:19', '2025-11-02 21:44:19'),
(7063, 6590, 'مدیر مالی', 'آلوم كابل كاوه', 'تمام وقت', 'خدمات حسابداری', NULL, 1403, NULL, NULL, 1, 'بیش از 80 میلیون تومان', 'سایر موارد', NULL, '2025-11-02 21:49:11', '2025-11-02 21:49:11'),
(7064, 6581, 'حسابدار', 'مجموعه فرهنگی ورزشی اریکه ایرانیان', 'تمام وقت', 'فرهنگی و ورزشی', NULL, 1397, NULL, 1399, NULL, '15 تا 20 میلیون تومان', 'سایر موارد', '1.تسلط کامل به ثبت سند حسابداری \n2. تسلط کامل با مغایرت گیری بانکی \n3. تسلط کامل بایگانی اسناد\n4.تسلط کامل بانرم افزار راهکاران . نماد . سپیدار \n5.تسلط کامل با امورقانون ومقرارت مالیاتی\n6.تسلط کامل با امور اداری و اتوماسیون و وب کارت و نامه نگرای \n7.آشنایی کامل با بستن حسابها \n8. تجربه کار حسابرسی و جمع آوری مدارک و اطلاعات مالی و اسناد حسابداری در ارائه به دارایی\n\nمن چون کار رو پروژه ای تحویل گرفتم قرارداد کاریم تاریخ و زمان خاص خودش را داشت و به همان دلیل از شرکت خارج شدم', '2025-11-02 21:51:47', '2025-11-02 21:51:47'),
(7065, 6581, 'حسابدار', 'شرکت تولیدی بازرگانی رویین صافی فیلتر', 'تمام وقت', 'خودروسازی', NULL, 1394, NULL, 1397, NULL, '12 تا 15 میلیون تومان', 'سایر موارد', '1.صدور ثبت اسناد حسابداری \n2. مغایرت بانکی \n3. ریالی کردن انبار \n4.تسلط با اصول مطالبات\n5. تسلط کامل نامه نگرایی اداری و مالی \n6. بایگانی اسناد\n7. کنترل فاکتورهای فروش و ثبت اسناد آن \n8.وصول مطالبات.\n9. تسلط با امور خزانه داری شامل بانک و بودجه و گردش حساب\nبا پایان یافتن قرارداد از شرکت خارج شدم', '2025-11-02 21:58:34', '2025-11-02 21:58:34'),
