(7182, 6670, 'حسابدار', 'هتل پارمیس کیش', 'تمام وقت', 'حسابداری', NULL, 1404, NULL, 1404, 0, 'توافقی', 'سایر موارد', 'به دلیل دوری از خانواده و محل زندگی ترک کار میکنم', '2025-11-07 17:04:11', '2025-11-07 17:04:36'),
(7183, 6672, 'ناظر مالیاتی', 'شرکت دانش بنیان فراتوسعه دانیال', 'دورکاری', 'خدمات حسابداری', NULL, 1399, NULL, NULL, 1, 'توافقی', NULL, '1. بررسی و تأیید صحت اظهارنامه‌های مالیاتی شرکت‌ها و افراد.\n2. نظارت بر اجرای دقیق قوانین و مقررات مالیاتی.\n3. شناسایی خطاها، مغایرت‌ها و موارد مشکوک در اسناد مالی.\n4. ارائه گزارش‌های تحلیلی به مدیریت مالیاتی یا مدیرعامل.\n5. همکاری با حسابرسان و مأموران مالیاتی برای حل اختلافات و پرونده‌ها.', '2025-11-07 18:14:14', '2025-11-07 18:55:17'),
(7184, 6672, 'مشاور مالی', 'هتل حیات شرق', 'پروژه ای', 'خدمات حسابداری', NULL, 1400, NULL, NULL, 1, 'توافقی', NULL, '1. تحلیل وضعیت مالی شرکت یا فرد و ارائه راهکار بهینه.\n2. ارائه مشاوره مالیاتی و حسابداری برای کاهش ریسک و جرایم.\n3. کمک به مدیریت در تصمیم‌گیری‌های استراتژیک و بودجه‌بندی.\n4. بررسی و اصلاح اشتباهات مالی و مالیاتی گذشته.\n5. آموزش و اطلاع‌رسانی قوانین مالی و مالیاتی به مدیران و کارکنان.', '2025-11-07 18:15:45', '2025-11-07 18:52:36'),
(7185, 6672, 'مدیر مالی', 'شرکت ثمین پایدار مهر ایرانیان', 'دورکاری', 'خدمات حسابداری', NULL, 1401, NULL, NULL, 1, 'توافقی', NULL, '1. برنامه‌ریزی و بودجه‌بندی سالانه سازمان.\n2. مدیریت نقدینگی و کنترل هزینه‌ها برای حفظ تعادل مالی.\n3. تحلیل صورت‌های مالی و ارائه گزارش‌های تصمیم‌ساز به هیأت‌مدیره.\n4. نظارت بر واحد حسابداری، خزانه‌داری و امور مالیاتی.\n5. برنامه‌ریزی تأمین مالی پروژه‌ها و ارزیابی سرمایه‌گذاری‌ها.', '2025-11-07 18:16:50', '2025-11-07 18:53:51'),
(7186, 6672, 'مشاور مالی', 'شرکت ساینا توس فناور', 'دورکاری', 'خدمات حسابداری', NULL, 1402, NULL, NULL, 1, 'توافقی', NULL, '1. تحلیل وضعیت مالی شرکت یا فرد و ارائه راهکار بهینه.\n2. ارائه مشاوره مالیاتی و حسابداری برای کاهش ریسک و جرایم.\n3. کمک به مدیریت در تصمیم‌گیری‌های استراتژیک و بودجه‌بندی.\n4. بررسی و اصلاح اشتباهات مالی و مالیاتی گذشته.\n5. آموزش و اطلاع‌رسانی قوانین مالی و مالیاتی به مدیران و کارکنان.', '2025-11-07 18:17:43', '2025-11-07 18:52:58'),
(7187, 6672, 'ناظر مالیاتی', 'شرکت استحکام سازان سیمان خراسان', 'پروژه ای', 'خدمات حسابداری', NULL, 1403, NULL, NULL, 1, 'توافقی', NULL, '1. بررسی و تأیید صحت اظهارنامه‌های مالیاتی شرکت‌ها و افراد.\n2. نظارت بر اجرای دقیق قوانین و مقررات مالیاتی.\n3. شناسایی خطاها، مغایرت‌ها و موارد مشکوک در اسناد مالی.\n4. ارائه گزارش‌های تحلیلی به مدیریت مالیاتی یا مدیرعامل.\n5. همکاری با حسابرسان و مأموران مالیاتی برای حل اختلافات و پرونده‌ها.', '2025-11-07 18:18:38', '2025-11-07 18:55:24'),
(7188, 6672, 'مشاور مالی', 'شرکت آرمان سازان طنین سلامت', 'دورکاری', 'خدمات حسابداری', NULL, 1403, NULL, NULL, 1, 'توافقی', NULL, '1. تحلیل وضعیت مالی شرکت یا فرد و ارائه راهکار بهینه.\n2. ارائه مشاوره مالیاتی و حسابداری برای کاهش ریسک و جرایم.\n3. کمک به مدیریت در تصمیم‌گیری‌های استراتژیک و بودجه‌بندی.\n4. بررسی و اصلاح اشتباهات مالی و مالیاتی گذشته.\n5. آموزش و اطلاع‌رسانی قوانین مالی و مالیاتی به مدیران و کارکنان.', '2025-11-07 18:19:53', '2025-11-07 18:53:12'),
(7189, 6672, 'ناظر مالیاتی', 'شرکت دانش بنیان استعداد گستران فرتاک', 'دورکاری', 'خدمات حسابداری', NULL, 1404, NULL, NULL, 1, 'توافقی', NULL, '1. بررسی و تأیید صحت اظهارنامه‌های مالیاتی شرکت‌ها و افراد.\n2. نظارت بر اجرای دقیق قوانین و مقررات مالیاتی.\n3. شناسایی خطاها، مغایرت‌ها و موارد مشکوک در اسناد مالی.\n4. ارائه گزارش‌های تحلیلی به مدیریت مالیاتی یا مدیرعامل.\n5. همکاری با حسابرسان و مأموران مالیاتی برای حل اختلافات و پرونده‌ها.', '2025-11-07 18:21:34', '2025-11-07 18:55:31'),
(7190, 6672, 'مشاور مالی', 'شرکت افرا تجارت کهن پاسارگاد', 'دورکاری', 'خدمات حسابداری', NULL, 1404, NULL, NULL, 1, 'توافقی', NULL, '1. تحلیل وضعیت مالی شرکت یا فرد و ارائه راهکار بهینه.\n2. ارائه مشاوره مالیاتی و حسابداری برای کاهش ریسک و جرایم.\n3. کمک به مدیریت در تصمیم‌گیری‌های استراتژیک و بودجه‌بندی.\n4. بررسی و اصلاح اشتباهات مالی و مالیاتی گذشته.\n5. آموزش و اطلاع‌رسانی قوانین مالی و مالیاتی به مدیران و کارکنان.', '2025-11-07 18:22:38', '2025-11-07 18:53:19'),
