(7209, 6304, 'مدیر مالی', 'هرمز دژ', 'پاره وقت', 'نیرو', NULL, 1404, NULL, NULL, 1, '20 تا 25 میلیون تومان', NULL, 'شرکت پیمانکاری ، همکاری با دهیاری ها بابت تامین نیرو\n\nو کار دوم همین مجموعه، تولید زغال صادراتی', '2025-11-08 17:25:05', '2025-11-08 17:25:05'),
(7210, 6304, 'مدیر مالی', 'هلدینگ', 'پاره وقت', 'خدمات درمانی، پزشکی و سلامت', NULL, 1403, NULL, 1404, NULL, NULL, 'سایر موارد', 'مجموعه هلدینگ\nیک درمانگاه\nو سه موسسه خیریه جداگانه\n\n\nبا پرونده های مالی و مالیاتی جدا\nرسیدگی به امور پرونده ها و ابلاغیه های دارایی و تامین اجتماعی، لایحه نویسی، شرکت درهیات ها،..\n\nمدیریت پرسنل زیرمجموعه و تقسیم و نظارت برکارها\nکنترل ثبت ها، مغایرت گیری ها، گزارشات مدیریتی، حقوق، بیمه، مالیات حقوق، اظهارنامه ها', '2025-11-08 17:29:15', '2025-11-08 17:40:07'),
(7211, 6304, 'مدیر مالی', 'الماس', 'تمام وقت', 'کالای مصرفی و خوراکی', NULL, 1401, NULL, 1403, NULL, '20 تا 25 میلیون تومان', 'کافی نبودن حقوق', 'شرکت پخش داروی دامپزشکی\n\nکنترل و مغایرت گیری های بانک و فروش و مشتریان و تامین کنندگان\n\nحقوق، بیمه، مالیات حقوق، اظهارنامه های فصلی و ارزش افزوده، مودیان، عملکرد، اجازه\n\nدفاتر\nپیگیریهای دارایی و دفاعیات، لایحه نویسی\n\nانتقال و اصلاح حسابهای در نرم افزار قانونی', '2025-11-08 17:34:14', '2025-11-08 17:34:14'),
(7212, 6304, 'کمک حسابدار', 'آترا', 'پاره وقت', 'تولید و صنایع', NULL, 1401, NULL, 1402, NULL, '15 تا 20 میلیون تومان', 'سایر موارد', 'ترک کار به علت جابجایی و رفتن به خارج از شهر\n\nنظارت بر کار نیروی مالی\nکنترل کامل حسابها\nانتقال به قانونی و اصلاحیات و دفاتر\n\nحقوق، بیمه،مالیات حقوق، اظهارنامه ها\n\nشرکت در جلسات هیات و دفاعیات و لایحه نویسی،', '2025-11-08 17:39:44', '2025-11-08 17:39:44'),
(7213, 6304, 'سرپرست حسابداری', 'نمایندگی سایپا ورزنده', 'تمام وقت', 'خودروسازی', NULL, 1399, NULL, 1401, NULL, '12 تا 15 میلیون تومان', 'ساعت کاری طولانی', 'نمایندگی سایپاورزنده\nفروش و خدمات پس از فروش خودرو\n\nکنترل برکارهای پرسنل مالی\nتهیه لیست حقوق، مالیات ، بیمه\nاظهارنامه ها، دفاتر', '2025-11-08 17:42:59', '2025-11-08 17:42:59'),
(7214, 6304, 'رییس حسابداری', 'کارخانه آرد', 'تمام وقت', 'تولید و صنایع', NULL, 1396, NULL, 1399, NULL, 'قانون کار', 'سایر موارد', 'انجام کلیه امور مالی شرکت بصورت گردشی\nانبار، فروش، خزانه، حقوق، مالیات، بیمه، ارزش افزوده، فصلی، دفاتر، اصلاحات قانونی، ...', '2025-11-08 17:46:43', '2025-11-08 17:46:43'),
(7215, 6304, 'حسابدار', 'خوشنام', 'تمام وقت', 'تولید و صنایع', NULL, 1394, NULL, 1396, NULL, 'قانون کار', 'عدم پیشرفت کاری', NULL, '2025-11-08 17:47:57', '2025-11-08 17:47:57'),
(7216, 6304, 'حسابدار', 'مهندسی جم', 'تمام وقت', 'کامپیوتر، فناوری اطلاعات و اینترنت', NULL, 1380, NULL, 1394, NULL, 'توافقی', 'مسائل شخصی', 'کلیه امور حسابداری و مالی بصورت تک نفره انجام میشد', '2025-11-08 17:49:16', '2025-11-08 17:49:16'),
(7217, 6304, 'حسابدار', 'ساختمانی', 'دورکاری', 'معماری و عمران', NULL, 1393, NULL, NULL, 1, 'توافقی', NULL, 'از سال 93 تا هم اکنون، بصورت دورکاری کارهای حسابداری پروژه های بزرگ ساختمانی شخص حقیقی رو عهده دار هستم، در مشهد و طرقبه و پروژه های ویلاسازی در شهرهای شمالی', '2025-11-08 17:53:47', '2025-11-08 17:53:47'),
(7218, 6304, 'مدیر مالی', 'کارینگ', 'پاره وقت', 'غذا و رستوران ها', NULL, 1401, NULL, 1404, NULL, NULL, NULL, NULL, '2025-11-08 17:56:00', '2025-11-08 17:56:00'),
(7219, 6688, 'رییس حسابداری', 'هلدینگ امیراد', 'تمام وقت', 'تبلیغات، بازاریابی و برند سازی', NULL, 1401, NULL, NULL, 1, NULL, NULL, 'هلدینگ امیراد با ۱۳ شرکت زیر مجوعه شامل ۳ شرکت بازرگانی در زمینه آهن آلات - ۱ شرکت در زمینه فعالیت معدن - ۳ شرکت در زمینه فعالیت عمران و ساختمان و دیگر شرکت ها در زمینه سرمایه گذاری که سرپرستی و پیاده سازی تمام تیم مالی و شرکتها با بنده می باشد .', '2025-11-09 03:32:23', '2025-11-09 03:32:23'),
(7220, 6688, 'مدیر مالی', 'پارس کاغذ مشهد', 'تمام وقت', 'تولید و صنایع', NULL, 1400, NULL, 1401, NULL, NULL, 'مسائل شخصی', 'شرکت در زمینه تولید کاغذ فعالیت دارد', '2025-11-09 03:34:12', '2025-11-09 03:34:24'),
(7221, 6688, 'رییس حسابداری', 'صنایع بسته بندی اطلس چناران', 'تمام وقت', 'تولید و صنایع', NULL, 1395, NULL, 1400, NULL, NULL, 'مسافت طولانی', 'شرکت در زمینه تولید کارتن های ۳ لایه و ۵ لایه و ورق های لمینیتی فعالیت دارد .', '2025-11-09 03:36:11', '2025-11-09 03:36:11'),
(7222, 6688, 'حسابدار', 'شهرداری مشهد', 'تمام وقت', 'دولتی', NULL, 1393, NULL, 1395, NULL, NULL, 'سایر موارد', NULL, '2025-11-09 03:38:01', '2025-11-09 03:38:01'),
(7223, 6688, 'سرپرست حسابداری', 'مهندسین مشاور سروش آرمان کویر', 'تمام وقت', 'نفت و گاز', NULL, 1391, NULL, 1393, NULL, NULL, NULL, 'طراحی و اجرای خطوط نفت و گاز در سطح کشور', '2025-11-09 03:39:30', '2025-11-09 03:39:30'),
(7224, 6688, 'سرپرست حسابداری', 'ساختمان و راهسازی آگر مشهد', 'تمام وقت', 'معماری و عمران', NULL, 1387, NULL, 1391, NULL, NULL, NULL, 'با توجه به گرید ۱ ساختمان سازی همزمان در برج ۱۲۰ واحدی مسکونی آب و خاک و ۳۲۷ واحد در گلبهار فعالیت داشت', '2025-11-09 03:42:28', '2025-11-09 03:42:45'),
(7225, 6692, 'حسابدار', 'کیمه سازان کهن', 'تمام وقت', 'حسابداری', NULL, 1403, NULL, 1404, 0, '20 تا 25 میلیون تومان', 'تاخیر در پرداخت', 'کارشناس مالی حسابداری پیمانکاری در شرکت کیمه سازان کهن', '2025-11-09 15:28:59', '2025-11-09 15:29:33'),
(7226, 6692, 'حسابدار', 'کارگزاری رسمی بیمه برخط کیسون', 'تمام وقت', 'حسابداری', NULL, 1404, NULL, NULL, 1, '25 تا 30 میلیون تومان', NULL, NULL, '2025-11-09 15:30:38', '2025-11-09 15:30:38'),
(7227, 6362, 'حسابدار', 'کفش طبی پاتکان', 'تمام وقت', 'تولید و صنایع', NULL, 1394, NULL, 1398, NULL, '15 تا 20 میلیون تومان', 'عدم پیشرفت کاری', 'شرکت لوتوس کمک حسابدار و همکاری در فروش\nشرکت قارچ طلایی حسابدار و پیگیری مطالبات و امور اداری \nشرکت لوازم خودرو دینا پارت  کمک حسابدار', '2025-11-09 16:13:13', '2025-11-09 16:13:13'),
(7228, 6693, 'حسابدار', 'اتحاد لنت پیشرو صنعت', 'تمام وقت', 'تولید و صنایع', NULL, 1404, NULL, NULL, 1, '15 تا 20 میلیون تومان', 'کافی نبودن حقوق', NULL, '2025-11-09 17:08:48', '2025-11-09 17:08:48'),
(7229, 6695, 'حسابدار', 'همگن صنعت توس', 'تمام وقت', 'حسابداری', NULL, 1402, NULL, NULL, 1, '20 تا 25 میلیون تومان', 'سایر موارد', 'ثبت اسناد حسابداری روزانه شامل دریافت و پرداخت‌ها، ثبت فاکتورهای خرید و فروش، مغایرت‌گیری بانک و حساب مشتریان و تأمین‌کنندگان، تهیه لیست حقوق و دستمزد، تنظیم لیست بیمه تأمین اجتماعی، تهیه گزارش ارزش افزوده و کار با سامانه مودیان', '2025-11-09 21:05:04', '2025-11-09 21:14:44'),
(7230, 6695, 'حسابدار', 'آریو پوشش سارینا شرق', 'تمام وقت', 'حسابداری', NULL, 1401, NULL, 1402, NULL, 'قانون کار', 'نداشتن بیمه', 'ثبت فاکتورهای خرید و فروش، ثبت دریافت‌ها و پرداخت‌ها، تهیه و تنظیم لیست ارزش افزوده، ثبت اسناد حسابداری در نرم‌افزار مالی شرکت و مغایرت‌گیری بانکی.', '2025-11-09 21:06:24', '2025-11-09 21:06:24'),
(7231, 6695, 'حسابدار', 'درمانگاه باران', 'تمام وقت', 'حسابداری', NULL, 1398, NULL, 1400, NULL, 'توافقی', 'مسائل شخصی', 'ثبت بیمه هاوارسال به اداره بیمه طرف قرارداد\n\nگزارش مغایرت بانک وترازمالی\n\nمحاسبه حقوق پرسنل', '2025-11-09 21:08:00', '2025-11-09 21:08:00'),
(7232, 6700, 'رییس حسابداری', 'کارخانه آلوم کابل کاوه', 'تمام وقت', 'حسابداری', NULL, 1403, NULL, 1404, NULL, NULL, 'مسائل شخصی', 'درخواست کار پاره وقت داشتم', '2025-11-10 10:13:35', '2025-11-10 10:13:35'),
