(7311, 6772, 'حسابدار', 'شرکت آرمان آداک', 'تمام وقت', 'معماری و عمران', NULL, 1403, NULL, 1404, NULL, 'توافقی', NULL, 'بعنوان حسابدار و کمک حسابدار تنظیم لیست تنخواه در excell وسند زدن در سیستم سپیدار و نوآوران،ثبت فاکتورهای خرید تائید فاکتورها در سامانه جامع تجارت و مودیان ،تایپ نامه های اداری وبایگانی اسناد', '2025-11-13 18:17:18', '2025-11-13 18:38:30'),
(7312, 6772, 'حسابدار', 'شرکت کیان تهویه مهر', 'تمام وقت', 'تولید و صنایع', NULL, 1402, NULL, 1403, NULL, 'قانون کار', NULL, 'بعنوان حسابدارحقوق و دستمزد\nمحاسه حقوق ودستمزد و ثبت اسناد خزانه (اسناد دریافتنی و پرداختنی و ثبت چکهای صیادی در سامانه)،انجام مغایرت گیری بانکها در نرم افزارآرپا سیستم  و پارسیان', '2025-11-13 18:32:19', '2025-11-13 18:39:10'),
(7313, 6772, 'حسابدار', 'مواد غذایی آبشار', 'تمام وقت', 'غذا و رستوران ها', NULL, 1400, NULL, 1402, NULL, 'قانون کار', NULL, 'بعنوان حسابدار فروش\nثبت و صدور فاکتورهای خرید و فروش در نرم افزار آساسیستم وهمکاران', '2025-11-13 18:36:18', '2025-11-13 18:39:53'),
(7314, 6772, 'حسابدار', 'روغن ماشین اترود', 'تمام وقت', 'نفت و گاز', NULL, 1392, NULL, 1397, NULL, 'قانون کار', NULL, 'بعنوان حسابدار انبار و خزانه \nزدن اسناد خرانه وانبار گردانی،ارسال لیست بیمه،\nبرقراری ارتباط باافراد و ثبت تسناد درسیستم فراگستر', '2025-11-13 18:43:18', '2025-11-13 18:43:18'),
