(7323, 6788, 'حسابدار', 'کارخانه پولاد نصر', 'تمام وقت', 'تولید و صنایع', NULL, 1402, NULL, 1404, NULL, '40 تا 45 میلیون تومان', 'سایر موارد', 'ثبت فاکتورهای خرید و فروش و کنترل اسناد حسابداری روزانه•ثبت و کنترل تنخواه و تهیه لیست بیمه، حقوق و دستمزد•کار با سامانه مؤدیان و ارسال اطلاعات مالی\n•مغایرت‌گیری و تطبیق حساب‌ها با دفاتر و اسناد بانکی\n•همکاری در بستن حساب‌ها و تهیه گزارش‌های پایان دوره مالی', '2025-11-14 15:03:05', '2025-11-14 15:03:05'),
(7324, 6788, 'حسابدار', 'پدید آب ارومیه', 'تمام وقت', 'معماری و عمران', NULL, 1398, NULL, 1402, NULL, '20 تا 25 میلیون تومان', 'سایر موارد', 'ثبت اسناد حسابداری روزانه و کنترل تنخواه\n•همکاری در تهیه تراز آزمایشی و گزارش‌های مالی دوره‌ای\n•مشارکت در انطباق حساب‌ها', '2025-11-14 15:06:16', '2025-11-14 15:06:16'),
(7325, 6788, 'حسابدار', 'شرکت پویا سازه دورانتاش', 'تمام وقت', 'کالای مصرفی و خوراکی', NULL, 1394, NULL, 1398, NULL, '9 تا 12 میلیون تومان', 'مسائل شخصی', 'ثبت فاکتورهای خرید و فروش و کنترل اسناد حسابداری•ثبت و بررسی تنخواه‌های پرداختی\n•مغایرت‌گیری حساب‌های بانکی و کنترل موجودی انبار\n•همکاری در انبارگردانی و بستن حساب‌های پایان سال', '2025-11-14 15:08:35', '2025-11-14 15:08:35'),
(7326, 6790, 'کمک حسابدار', 'شرکت آذین', 'تمام وقت', 'حسابداری', NULL, 1402, NULL, 1404, NULL, '25 تا 30 میلیون تومان', NULL, 'ثبت داده ها در نرم افزار سپیدار، ثبت حضور و غیاب کارکنان در\nنرم افزار و اکسل، ثبت اطلاعات کارمند، طرف حساب، تامین کننده،\nمشتری، چک ،دریافت وپرداخت ، بانک، انبار و کالا در نرم افزار، تهیه صورتحساب برای\nمشتریان و تامین کنندگان، انجام عملیات تنخواه، اجرای انبارگردانی و مغایرت گیری .\nتعریف کدها و طبقه بندی کالا .پیش فاکتور و فاکتور خرید و غیره', '2025-11-14 16:45:37', '2025-12-03 13:36:35'),
(7327, 6790, 'کمک حسابدار', 'نوین روش حکمت', 'تمام وقت', 'حسابداری', NULL, 1399, NULL, 1402, NULL, NULL, NULL, NULL, '2025-11-14 16:47:13', '2025-11-14 16:47:13'),
(7328, 6790, 'کمک حسابدار', 'فیلتر کاج', 'تمام وقت', 'حمل و نقل، لجستیک و انبارداری', NULL, 1395, NULL, 1399, NULL, NULL, NULL, 'کنترل دقیق موجودی انبار، تهیه گزارشات منظم عملکرد انبار،\nمدیریت ارتباط با تامین کنندگان جهت تامین مواد اولیه به موقع،\nنظارت بر ثبت سفارشات و پیگیری تحویل کالا، امور برنامه ریزی\nو ساماندهی انبار، تعامل موثر با تیم فروش و تولید برای هماهنگی\nنیازهای آنها، حل مسایل و چالش ها در بخش انبار، آموزش پرسنل\nانبار و ارتقا سطح کیفی کار .\nانبارگردانی و مغایرت گیری', '2025-11-14 16:51:45', '2025-12-03 13:41:58'),
(7329, 6795, 'حسابدار', 'صنایع فولاد اخگر اصفهان', 'تمام وقت', 'حسابداری', NULL, 1403, NULL, NULL, 1, '25 تا 30 میلیون تومان', NULL, 'سند زدن ، حقوق و دستمزد , بیمه ، مودیان ، مغایرت گیری بانکی ، فروش \nو مشاور حسابرسی مالیاتی و بیمه ای', '2025-11-15 00:04:52', '2025-11-15 00:08:40'),
(7330, 6795, 'حسابدار', 'شرکت ریخته گری آلیاژی پیشرو سپاهان', 'دورکاری', 'حسابداری', NULL, 1403, NULL, NULL, 1, '20 تا 25 میلیون تومان', NULL, 'سند زدن ، حقوق و دستمزد , بیمه ، مودیان ، مغایرت گیری بانکی ، فروش \nو مشاور حسابرسی مالیاتی و بیمه ای \nصفر تا صد حسابداری این شرکت با خودم می باشد', '2025-11-15 00:05:44', '2025-11-15 00:09:10'),
(7331, 6794, 'حسابدار', 'بیمارستان آپادانا', 'تمام وقت', 'خدمات درمانی، پزشکی و سلامت', NULL, 1390, NULL, 1391, NULL, NULL, NULL, 'صدور اسناد حسابداری\nگزارش گیری و تهیه کارکرد پزشکان\nوصول مطالبات از شرکت های بیمه طرف قرارداد\nصندوق دار . یک روز در ماه', '2025-11-15 00:10:34', '2025-11-15 00:10:34'),
(7332, 6794, 'حسابدار', 'صنایع پنتان شیمی', 'تمام وقت', 'تولید و صنایع', NULL, 1391, NULL, 1392, NULL, NULL, NULL, 'صدور اسناد حسابداری\nضمانتنامه های بانکی\nتنخواه گردان', '2025-11-15 00:12:52', '2025-11-15 00:12:52'),
(7333, 6794, 'حسابرس', 'آی سودا', 'تمام وقت', 'تولید و صنایع', NULL, 1393, NULL, 1393, NULL, NULL, NULL, 'نظارت به نحوه صدور اسناد حسابداری\nتهیه گزارشات مدیریتی', '2025-11-15 00:14:42', '2025-11-15 00:14:42'),
(7334, 6794, 'حسابدار', 'سابیر بین الملل', 'تمام وقت', 'معماری و عمران', NULL, 1394, NULL, 1396, NULL, NULL, NULL, 'صدور اسناد حسابداری\nصدور اسناد تنخواه گردان ها\nحقوق و دستمزد\nارسال لیست بیمه و مالیات حقوق\nکنترل و ریالی کردن اسناد انبار', '2025-11-15 00:17:17', '2025-11-15 00:17:17'),
(7335, 6794, 'رییس حسابداری', 'دنیای تاپ پخش', 'تمام وقت', 'تبلیغات، بازاریابی و برند سازی', NULL, 1397, NULL, 1401, NULL, NULL, NULL, 'نظارت و کنترل اسناد انبار\nحسابداری انبار\nمغایرت گیری با تامین کنندگان\nانبارگردانی و صدور اسناد و تنظیم صورتجلسه\nنظارت بر امور خزانه\nمغایرت بانکی\nحقوق و دستمزد\nانجام کلیه تکالیف قانونی بیمه و مالیات\nاظهارنامه ارزش افزوده و معامالت فصلی و عملکرد\nتهیه صورت های مالی\nبستن حسابها', '2025-11-15 00:20:47', '2025-11-15 00:20:47'),
(7336, 6794, 'رییس حسابداری', 'هلدینگ یگانه اندیش سرمایه', 'تمام وقت', 'سرمایه گذاری و تحلیل کسب و کار', NULL, 1401, NULL, NULL, 1, '45 تا 50 میلیون تومان', 'تاخیر در پرداخت', 'صدور و کنترل اسناد حسابداری\nکنترل تخصیص و دستور پرداخت های شرکت های همگروه طبق آئین نامه داخلی هلدینگ\nکنترل اسناد انبار از صدور تا ریالی شدن و انبارگردانی\nکنترل اسناد تنخواه گردان ها\nسامانه مودیان و مغایرت گیری با دفاتر\nسامانه جامع تجارت\nبودجه بندی سالانه شرکت های همگروه\nتنظیم قراردادهای اولیه پرسنلی\nتنظیم قراردادهای فی مابین شرکت های گروه\nحقوق و دستمزد\nانجام کلیه تکالیف قانونی . بیمه و مالیات ماهانه . ارزش افزوده . معامالت فصلی . اظهارنامه عملکرد و ...\nمفاصاحساب بیمه و مالیات\nمغایرت بانکی\nشرکت های در هیات های مالیاتی و بیمه\nلایحه نویسی\nتهیه صورت های مالی\nبستن حسابها', '2025-11-15 00:24:53', '2025-11-15 00:24:53'),
(7337, 6801, 'حسابدار', 'تحلیل و سیستم مفید', 'پاره وقت', 'خدمات حسابداری', NULL, 1396, NULL, 1400, NULL, '12 تا 15 میلیون تومان', 'سایر موارد', 'مهاجرت به گیلان', '2025-11-15 12:07:47', '2025-11-15 12:10:35'),
