(7348, 6816, 'حسابدار', 'کارخانه موکت نگین مشهد', 'تمام وقت', 'حسابداری', NULL, 1402, NULL, NULL, 1, '25 تا 30 میلیون تومان', NULL, 'کارشناس مالیاتی.تهیه و تنظیم اظهارنامه عملکرد و ارزش افزوده و معاملات فصلی\nهمکاری با موسسه حسابرسی در طول دوره رسیدگی', '2025-11-15 18:36:38', '2025-11-15 18:42:31'),
