(7351, 6816, 'حسابدار', 'ماره وقت', 'پاره وقت', 'حسابداری', NULL, 1400, NULL, NULL, 1, '15 تا 20 میلیون تومان', NULL, 'راه اندازی سیستم مالی و بهای تمام شده و کدینگ حسابداری شرکت ها و کارگاه تولیدی\n\nهمکاری با موسسه حسابرسی بابت تهیه و تنظیم گزارشات کارشناس رسمی دادگستری', '2025-11-15 18:40:52', '2025-11-15 18:40:52'),
(7352, 6818, 'حسابدار', 'زعفران بدیعی', 'تمام وقت', 'حسابداری', NULL, 1404, NULL, NULL, 1, '20 تا 25 میلیون تومان', 'ساعت کاری طولانی', 'حسابدار مالیاتی شرکت \nدو دفتر بودن صفر تا صد مالیاتی دست خودم بود', '2025-11-15 19:13:02', '2025-11-15 19:13:02'),
(7353, 6818, 'حسابدار', 'هلدینگ امید نور', 'تمام وقت', 'خدمات حسابداری', NULL, 1401, NULL, 1404, NULL, '15 تا 20 میلیون تومان', 'تاخیر در پرداخت', 'هفت تا شرکت \nپیمانکاری بازرگانی و تولید', '2025-11-15 19:14:02', '2025-11-15 19:14:02'),
(7354, 2765, 'حسابدار صنعتی', 'مجتمع غذایی دشت دوین', 'تمام وقت', 'کالای مصرفی و خوراکی', NULL, 1403, NULL, 1404, NULL, '25 تا 30 میلیون تومان', 'کافی نبودن حقوق', 'چک و کنترل سیستم انبارهای کارخانه و مالی بعهده داشتم و ارائه راه حل های جدید برای بهبود و پیشرفت کار بعهده داشتم.گزاراشات مالی بعهده داشتم.و عملیات حسابداری یک شرکت از هلدینگ مجموعه از ابتدا و انتهای کار برای سال مالی ۱۴۰۳ و ۱۴۰۴ ثبت و کنترل و ارائه گزارشات سود و زیان به مدیریت بعهده داشتم.', '2025-11-15 22:07:59', '2025-11-15 23:10:39'),
