(7369, 6847, 'حسابدار', 'موسسه حسابداری اطمینان محاسب', 'تمام وقت', 'خدمات حسابداری', NULL, 1398, NULL, 1400, NULL, 'قانون کار', 'مسائل شخصی', 'کارشناس مالی و مالیاتی', '2025-11-16 12:21:56', '2025-11-16 12:21:56'),
(7370, 6847, 'حسابدار', 'شرکت فولاد صبا', 'تمام وقت', 'حسابداری', NULL, 1400, NULL, 1401, NULL, 'قانون کار', 'سایر موارد', 'قبولی در ازمون استخدامی بنیاد مسکن از ۱۴۰۱ تا کنون هم در بنیاد مسکن مشغول میباشم', '2025-11-16 12:23:22', '2025-11-16 12:25:07'),
(7371, 6852, 'حسابدار', 'هلدینگ بین المللی راگا', 'تمام وقت', 'نفت و گاز', NULL, 1402, NULL, 1404, NULL, '35 تا 40 میلیون تومان', 'سایر موارد', 'شرکت صنعتی ، تولیدی ، بازرگانی صنعت نفت راگا در حوضه تولید مشتقات نفتی .\nارائه کلیه خدمات شامل :\n- تنظیم و نگهداری اسناد و مدارک مالی منظم و دقیق\n\n- ثبت روزانه رویدادهای مالی \n\n- ثبت اسناد روزانه  خزانه \n\n-مدیریت جامع فرآیندهای انبار شامل کنترل اسناد، گردش کالا، انبارگردانی، کاردکس و سایر امور مرتبط، با هدف بهینه‌سازی عملیات و افزایش دقت موجودی\n- تهیه و بررسی صورت مغایرت های بانکی\n- تسلط به حسابداری فروش \n- تسلط به سامانه مودیان و صدور صورتحساب رسمی \n-  آشنایی با سامامانه جامع تجارت و سامانه گمرک و ثامن\n- آشنایی با اضهارنامه ارزش افزوده و معاملات فصلی\n- تهیه لیست بیمه و مالیات حقوق\n- تسلط بر ارسال معاملات فصلی\n- مسلط به حقوق و دستمزد و تهیه لیست حقوق دستمزد تهیه گزارش‌های مالی مرتبط\n- آشنایی با قوانین مالیات های مستقیم \n- آشنایی با قوانین ارزش افزوده\n- آشنایی با تهیه صورتهای مالی طبق استاندارد های حسابداری\n_آشنایی با استاندارد های حسابداری\n- آشنایی با تجزیه و تحلیل صورت های مالی با استفاده از نسبت های مالی', '2025-11-16 14:01:26', '2025-11-16 19:57:44'),
(7372, 6852, 'رییس حسابداری', 'اندیشه سازان فرتاک پویا', 'پاره وقت', 'خدمات حسابداری', NULL, 1403, NULL, NULL, 1, '15 تا 20 میلیون تومان', NULL, 'شرکت اندیشه سازان فرتاک پویا حوضه فعالیت در زمینه نوشت افزار :\n -مدیریت و نظارت کامل بر سیستم مالی و حسابداری شرکت\n -محاسبه و پرداخت حقوق و دستمزد کارکنان و ارسال لیست بیمه و مالیات حقوق و تهیه گزارش‌های مالی مرتبط\n -ثبت، کنترل و اصلاح اسناد حسابداری\n -تهیه و ارسال اظهارنامه‌های مالیاتی عملکرد و مالیات بر ارزش افزوده\n -کنترل گردش و ثبت موجودی مواد و کالا، مدیریت انبار و بررسی گردش کالا\n -تهیه و ارسال گزارش‌های فصلی خرید و فروش مطابق با الزامات قانونی\n -ارائه گزارش‌های مالی و تحلیلی جهت تصمیم‌گیری مدیریت\n -اطمینان از رعایت قوانین مالیاتی و مقررات حسابداری در کلیه فرآیندهای مالی\n-مدیریت و کار با سامانه مؤدیان مالیاتی و انجام مغایرت‌گیری خرید و فروش\n -تهیه و تنظیم گزارش‌های تحلیلی و کاربردی مالی جهت ارائه به مدیریت\n-همکاری در فرآیند حسابرسی و تهیه مستندات و گزارش‌های مورد نیاز حسابرسان\n-تنظیم و ارسال انواع اظهارنامه‌های مالیاتی\n-کنترل ، اصلاح و به‌روزرسانی اسناد مالی در سیستم‌های حسابداری\n-پشتیبانی از تیم مالی و بهبود دقت داده‌ها در فرآیندهای حسابداری', '2025-11-16 14:03:15', '2025-11-16 14:03:15'),
(7373, 6856, 'کمک حسابدار', 'تولیدی یراق آلات اومادا', 'تمام وقت', 'خدمات حسابداری', NULL, 1402, NULL, 1402, NULL, '9 تا 12 میلیون تومان', 'مسافت طولانی', NULL, '2025-11-16 15:21:51', '2025-11-16 15:21:51'),
