(7422, 6893, 'حسابدار', 'حکمت ایرانیان', 'تمام وقت', 'مالی و اعتباری', NULL, 1389, NULL, 1395, NULL, '9 تا 12 میلیون تومان', 'کافی نبودن حقوق', 'اینجانب به عنوان کارشناس سرمایه گذاری و کارشناس در زمینه امور قراردادها، مناقصات، مغایرت گیری تنخواه گردان، حساب بانکها، امور قراردادها(خرید، پیمان)، چرخه انبار در شرکتهای بازرگانی (خرید، رسید انبار، حواله فروش، رسید برگشت از فروش، انبارگردانی و . . . )خلاقیتهای زیادی را در سیستم پیاده نمودم.', '2025-11-17 13:01:51', '2025-11-17 13:05:53'),
(7423, 6893, 'حسابرس', 'موسسات حسابرسی', 'تمام وقت', 'خدمات حسابداری', NULL, 1395, NULL, 1399, NULL, '12 تا 15 میلیون تومان', 'کافی نبودن حقوق', 'تجربیات مفیدی در ارتباط با کشف اشتباهات حسابداری، کنترلهای داخلی شرکت، اسناد، تهیه صورتهای مالی، اظهارنظر به گزارشهای مالی، نامه مدیریت، در شرکتهای تولیدی، بازرگانی، پیمانکاری، بانکها، موسسات مالی کسب کردم.', '2025-11-17 13:04:36', '2025-11-17 13:04:36'),
(7424, 6893, 'رییس حسابداری', 'شرکت پارس', 'تمام وقت', 'نفت و گاز', NULL, 1399, NULL, 1402, NULL, '15 تا 20 میلیون تومان', 'کافی نبودن حقوق', 'حسابدار مدیریت( حسابداری پیمانکاری)، شرکت استیل مدیر مالی(تولیدی، بازرگانی)، در زمینه گزارشات ماهانه هلدینگ، تهیه صورتهای مالی، بودجه سالانه، گزارشات فصلی، ارزش افزوده، حسابرسی بیمه، دفاتر قانونی، انجام امور مالیاتی(لایحه، هیئت، تهیه مدارک)، مغایرت گیری، تعدیلات حسابها، سامانه های مختلف، نرم افزار راهکاران،', '2025-11-17 13:10:11', '2025-11-17 13:10:11'),
(7425, 6893, 'مدیر مالی', 'شرکت رایکا هوشیار، شرکت فیروز بسپار', 'تمام وقت', 'تولید و صنایع', NULL, 1403, NULL, 1404, NULL, '30 تا 35 میلیون تومان', 'کافی نبودن حقوق', 'تهیه صورتهای مالی، بودجه سالانه، گزارشات فصلی، ارزش افزوده، حسابرسی بیمه، دفاتر قانونی، انجام امور مالیاتی(لایحه، هیئت، تهیه مدارک)، مغایرت گیری، تعدیلات حسابها، سامانه های مختلف، نرم افزار های نوسا، مالیران، سپیدار، تدبیر، تراز سامانه', '2025-11-17 13:12:36', '2025-11-17 13:12:36'),
