(7616, 6843, 'حسابدار', 'خدمات مالی و مالیاتی پیشداد', 'تمام وقت', 'خدمات حسابداری', NULL, 1400, NULL, 1402, NULL, NULL, NULL, 'انجام امور مالی و اداری شامل ثبت اسناد، کنترل پرداخت‌ها و امور پرسنلی\n\nتهیه و ارسال لیست بیمه و مالیات حقوق\n\nتنظیم قراردادها و مدیریت اسناد مالی و اداری\n\nثبت تمامی اسناد هزینه و قراردادها', '2025-11-21 12:16:57', '2025-11-21 12:18:29'),
(7617, 6843, 'حسابدار', 'موسسه غیردولتی حمایت از کودکان بی پناه', 'تمام وقت', 'حسابداری', NULL, 1402, NULL, 1403, NULL, NULL, NULL, 'انجام کلیه امور مالیاتی شامل اظهارنامه عملکرد اشخاص حقوقی، اظهارنامه مالیات بر ارزش افزوده (VAT) و گزارشات فصلی معاملات (TTMS)\n\nثبت و ارسال اطلاعات در سامانه مؤدیان و صدور صورت‌حساب الکترونیکی\n\nتهیه و ارائه گزارش‌های مالی و مدیریتی به هیئت‌مدیره\n\nتنظیم دفاتر قانونی (روزنامه و کل) و کنترل مغایرت‌ها\n\nهمکاری مستقیم با ممیزین مالیاتی در زمان رسیدگی پرونده‌ها', '2025-11-21 12:18:14', '2025-11-21 12:18:14'),
(7618, 6843, 'حسابدار', 'بازرگانی اورانوس', 'تمام وقت', 'حسابداری', NULL, 1403, NULL, 1403, NULL, NULL, NULL, 'مسلط به ماژول مشتریان و فروش\nتامین کنندگان و انبار\nدریافت و پرداخت\nحسابداری\nثبت تمامی فاکتور های ارزی و قیمت گذاری\nثبت و کنترل اسناد مالی خرید، فروش، هزینه و انبار\nمحاسبه بهای تمام‌شده کالاهای تولیدی\nمغایرت‌گیری حساب‌های بانکی و نقدینگی\nحقوق و دستمزد\nبیمه و مالیات حقوق\nسامانه مودیان\nمغایرت بانکی', '2025-11-21 12:21:08', '2025-11-21 12:21:08'),
(7619, 5200, 'حسابدار', 'شرکت...', 'پاره وقت', 'خدمات حسابداری', NULL, 1400, NULL, NULL, 1, 'توافقی', 'سایر موارد', 'باعرض سلام وخسته نباشید\nبنده از سال ۱۴۰۰ که وارد بازارکار شدم تابه حال ۲بار محل کار و شرکتی که کارمیکردم رو تغیر دادم فقط بخاطر اینکه بتونم تجربه کسب کنم و چالش جدید داشته باشم. ولی الان خداروشکر به مرحله ای رسیدم که بتونم تعدادی کار بگیرم و همش رو هندل کنم برا همین اینجا درخدمت شما هستم \nممنون از وقتی که گزاشتین باتشکر', '2025-11-21 12:21:57', '2025-11-21 12:21:57'),
(7620, 6843, 'حسابدار', 'افق توسعه', 'تمام وقت', 'حسابداری', NULL, 1403, NULL, NULL, 1, NULL, NULL, 'ریالی کردن رسید انبار\nقیمت گذاری صادره های انبار دریافت نرم افزار فراپیام\nثبت تخصیص صادره ها مربوط به هر پروژه \nثبت  قرارداد \nثبت تنخواه ها و پیگیری کارهای 50 تنخواه دار\nثبت ریالی رسید انبار \nثبت و پیگیری های کارهای مربوط به تولید و تحویل محصول\nثبت فاکتور فروش و خدمات \nپیگیری کارهای مربوط به درخواست صدور چک', '2025-11-21 12:22:12', '2025-11-21 12:22:12'),
(7621, 7138, 'حسابدار', 'موسسه خدمات حسابداری آتیه', 'تمام وقت', 'خدمات حسابداری', NULL, 1403, NULL, NULL, 1, NULL, NULL, NULL, '2025-11-21 13:15:07', '2025-11-21 13:15:07'),
