(7630, 7158, 'مدیر مالی', 'کاخانجات شوینده اتکا', 'تمام وقت', 'تولید و صنایع', NULL, 1380, NULL, 1386, NULL, '12 تا 15 میلیون تومان', 'سایر موارد', 'کارخانجات شوینده و بهداشتی اتکا سیستم نرم افزاری همکاران سیستم نصب و راه اندازی تولید و سیستم بهای تمام شده و تهیه صورتهای مالی اساسی ERP', '2025-11-22 15:14:11', '2025-11-22 15:14:11'),
