(7652, 7170, 'حسابدار', 'شرکت روئین صنعت نوین', 'تمام وقت', 'حسابداری', NULL, 1393, NULL, NULL, 1, '15 تا 20 میلیون تومان', 'سایر موارد', 'حسابدار ارشد\n١٣٩٣ - اكنون\nشركت روئين صنعت نوين\nتسلط كامل به حسابدارى مالى وفروش ، تسلط كامل به نرم افزار نواوران و پارسيان ، سلط كامل به سامانه جامع تجارت و موديان ، معاملات فصلى\nحسابدار\n١٣٩٣ - ١٣٩١\nحسابدارى با نرم افزار نوآوران\nنما يندكَى ال جى', '2025-11-23 02:40:25', '2025-11-23 02:40:25'),
(7653, 7172, 'حسابدار', 'یادمان ارک', 'تمام وقت', 'حسابداری', NULL, 1400, NULL, 1403, NULL, '15 تا 20 میلیون تومان', 'ساعت کاری طولانی', 'قبل از اونجام ۲ سال تو شرکت پیمانکاری دیگه ای به نام ساختمان سازان معروف ستاره کار کردم،ویدونه م شرکت  ابتکار اوران رنجبر که یه سال هم اونجا فعالیت داشتم.عارض شوم خدمتتون که از سال ۱۴۰۳ هم با چند تا شرکت به صورت پاره وقت کار میکنم و شرکت طلایه داران نظم،ویرا سازه اطلس و پترونام از شرکت هایی هستن که من بابت کارهای مالیاتی دارایی و بیمه ای و هم چنین حسابداری داخلی باهاشون همکاری میکنم', '2025-11-23 09:30:54', '2025-11-23 09:30:54'),
(7654, 7173, 'حسابرس', 'گروه صنعتی معدنی زرین', 'تمام وقت', 'تولید و صنایع', NULL, 1404, NULL, NULL, 1, '60 تا 70 میلیون تومان', 'سایر موارد', 'موضوع اصلی فعالیت مدیریت حسابرسی داخلی بود که در گزینه های این سایت نیست.', '2025-11-23 09:41:46', '2025-11-23 09:43:50'),
