(7657, 7173, 'مدیر مالی', 'گسترش و نوسازی صنایع ایرانیان مانا', 'تمام وقت', 'معماری و عمران', NULL, 1389, NULL, 1395, NULL, '25 تا 30 میلیون تومان', 'سایر موارد', 'البته در این شرکت مدتی بعنوان حسابدار ارشد ومدیریت فعالیت داشتم و در سال آخر بعنوان مدیر مالی و اداری یکی از پروژه ها در شهر طبس انجام وظیفه نمودم.', '2025-11-23 09:47:20', '2025-11-23 09:47:20'),
(7658, 5229, 'مدیر مالی', 'شرکت پسته مهر پارت', 'تمام وقت', 'حسابداری', NULL, 1396, NULL, 1404, NULL, '25 تا 30 میلیون تومان', 'مسائل شخصی', NULL, '2025-11-23 10:44:30', '2025-11-23 10:44:30'),
(7659, 6956, 'کمک حسابدار', 'تجهیز نیروی زنگان )سهامی عام (', 'تمام وقت', 'حسابداری', NULL, 1397, NULL, 1398, NULL, 'قانون کار', 'نداشتن بیمه', 'مدیریت وظایف روزانه دفتری و اداری\nتنظیم و ثبت اسناد مالی از جمله فاکتورها،\nپیش فاکتورها و چک ها\nمدیریت و بررسی حقوق و دستمزدهای\nپرسنل و پوشش بیمه ها\nمدیریت و ثبت اسناد مالی و معاملات\nروزانه در نرم افزارهای حسابداری\nتهیه و تنظیم گزارش های مالی ماهانه و\nسالانه برای کمک به تصمیم گیری مدیریتی\nپاسخگویی به استعلام ها و درخواست های\nاطلاعات مالی از سوی مشتریان و\nتأمین کنندگان', '2025-11-23 11:03:27', '2025-11-23 11:06:43'),
(7660, 6956, 'حسابدار', 'شرکت اطلس استیل', 'تمام وقت', 'حسابداری', NULL, 1398, NULL, 1400, NULL, 'قانون کار', 'سایر موارد', 'پردازش تراکنش های مالی و صدور\nفاکتورهای فروش\nهمکاری در تهیه گزارشهای مالی سالانه و\nجستجوی خطاها و اشکالات مالی\nتهیه و تنظیم صورت های مالی ماهانه و\nسالانه\nمدیریت و نظارت بر حساب های بانکی و\nتطبیق صورت های حساب\nثبت و بررسی مدارک حسابداری و\nفاکتورها در سیستم حسابداری\nبایگانی کلیه اسناد حسابداری به ترتیب\nتاریخ روز', '2025-11-23 11:06:08', '2025-11-23 11:06:08'),
(7661, 6956, 'حسابدار', 'بهینه ترابر آژور', 'تمام وقت', 'حسابداری', NULL, 1401, NULL, 1403, NULL, '12 تا 15 میلیون تومان', 'سایر موارد', 'تهیه و ثبت دفاتر حسابداری روزانه\nارائه گزارشات مالی به مدیر عامل شرکت\nپیگیری و تسویه حساب های مشتریان و\nتامین کنندگان\nمدیریت و حفظ فایل های مالی و مستندات\nحسابداری\nمدیریت ثبت و پردازش تراکنش های مالی\nبا دقت و صحت بالا\nتهیه و تنظیم گزارش های مالی ماهانه و\nسالانه برای ارزیابی عملکرد مالی شرکت\nارسال بیمه های کارکنان توسط نرم افزار\nلیست دیسک و سپیدار\nآموزش و هدایت کارآموزان حسابداری در\nزمینه نرم افزارهای حسابداری و رویه های مالی', '2025-11-23 11:08:55', '2025-11-23 11:08:55'),
