(7744, 7218, 'سرپرست حسابداری', 'شرکت توسعه فناوری باتیس پارت', 'پاره وقت', 'کامپیوتر، فناوری اطلاعات و اینترنت', NULL, 1397, NULL, NULL, 1, NULL, NULL, 'شرکت توسعه فناوری باتیس پارت فعال در زمینه بازرگانی ، خرید و فروش سروهای HP می باشد. در این شرکت به عنوان مسئول مالی به صورت پارت تایم مشغول به فعالیت می باشم. مسئولیت کل امور مالی شرکت از جمله اظهارنامه ارزش افزوده و معاملات فصلی وسامانه مودیان و مالیات حقوق و بیمه و اظهار نامه عملکرد را بر عهده دارم. نرم افزار مالی این شرکت سامان تحت ویندوز است.', '2025-11-25 17:08:44', '2025-11-25 17:08:44'),
(7745, 7218, 'سرپرست حسابداری', 'شرکت بین الملل عمران سریر', 'تمام وقت', 'معماری و عمران', NULL, 1400, NULL, 1402, NULL, NULL, NULL, 'شرکت پیمانکاری بین الملل عمران سریر فعال در زمینه احدث خط مترو و راه و ابنیه می باشد ، در طی این مدت به عنوان کارشناس مالی ارشد ، مسئولیت کنترل سندهای صادره از حسابداران 4 پروژه که به عهده اینجانب بوده است و تطبیق گرفتن با کارفرماین اصلی و اخذ مفاصا حساب بیمه ماده 38 و نیز آماده سازی مدارک جهت اظهارنامه عملکرد ، رسیدگی مالیاتی و حسابرس مستقل بر عهده اینجانب بوده است.نرم افزار مالی این شرکت راهکاران تحت وب است.', '2025-11-25 17:11:12', '2025-11-25 17:26:00'),
(7746, 7218, 'سرپرست حسابداری', 'شرکت بلند پایه یادمان', 'تمام وقت', 'معماری و عمران', NULL, 1399, NULL, 1400, NULL, NULL, NULL, 'شرکت پیمانکاری بلند پایه یادمان فعال در زمینه راه و ابنیه می باشد ، در طی این مدت مسئولیت کنترل حسابداران پروژه و تطبیق گرفتن با کارفرماین اصلی و نیز آماده سازی مدارک جهت اظهارنامه عملکرد ، رسیدگی مالیاتی و رسیدگی حسابرسی مستقل بر عهده اینجانب بوده است. نرم افزار مالی این شرکت سام تحت وب است.', '2025-11-25 17:12:38', '2025-11-25 17:12:38'),
(7747, 7218, 'سرپرست حسابداری', 'شرکت هلدینگ سیار آبان', 'تمام وقت', 'کامپیوتر، فناوری اطلاعات و اینترنت', NULL, 1395, NULL, 1399, NULL, NULL, NULL, 'شرکت سیار آبان فعال در زمینه IT و برنامه نویسی ، پشتیبانی و تولید محتوا می باشد ، دارای 4 شرکت زیر مجموعه می باشد. طی دوره همکاری در شرکت مادر (سیار آبان) کلیه امور حسابداری جاری از جمله سندزدن و شناسایی، تهیه صورت مغایرت بانکی ، خزانه ، محاسبه حقوق و دستمزد، ارسال مالیات حقوق ، بیمه ، ارزش افزوده ، معاملات فصلی و نیز آماده سازی جهت رسیدگی حسابرس بیمه و مالیاتی و اخذ مفاصا حساب بیمه ماده 38 و نیز  حضور در جلسات بیمه جهت اخذ مفاصا حساب با ضریب صفر و آشنایی با قوانین 14 درآمدی بیمه در خصوص شرکتهای آی تی . نرم افزار مالی این شرکت نوآوران تحت ویندوز است.', '2025-11-25 17:14:39', '2025-11-25 17:14:39'),
(7748, 7218, 'حسابدار', 'شرکت سیستمهای صنعتی تاکستان', 'تمام وقت', 'نفت و گاز', NULL, 1394, NULL, 1395, NULL, NULL, NULL, 'شرکت سیستمهای صنعتی تاکستان فعال در احداث ایستگاه های گاز و مخازن تحت فشار است. در این شرکت از شناسایی سندهای مالی و تحریر دفاتر و معاملات فصلی جز کارهای انجام گرفته می باشد.نرم افزار مالی این شرکت همکاران بوده است.', '2025-11-25 17:16:08', '2025-11-25 17:16:08'),
(7749, 7218, 'حسابدار', 'شرکت افزار پرداز باتیس پارت', 'تمام وقت', 'کامپیوتر، فناوری اطلاعات و اینترنت', NULL, 1392, NULL, 1394, NULL, NULL, NULL, 'شرکت افزار پرداز باتیس پارت فعال در زمینه بازرگانی ، خرید و فروش سروهای HP بوده است و این شرکت در حال حاضر غیر فعال می باشد که در طی این مدت مسئولیت کل امور مالی شرکت از جمله ارسال بیمه و زدن سندهای روزانه و مغایرت بانکی و اماده سازی مدارک بابت رسیدگی مالیاتی اظهارنامه بر عهده اینجانب بوده است.', '2025-11-25 17:17:26', '2025-11-25 17:17:26'),
(7750, 5564, 'حسابدار', 'تکمیل اظهارنامه مالیاتی در کافی نت', 'پروژه ای', 'خدمات حسابداری', NULL, 1395, NULL, 1395, NULL, 'توافقی', 'سایر موارد', NULL, '2025-11-25 19:13:06', '2025-11-25 19:13:06'),
(7751, 5564, 'حسابدار', 'راهکار بلوط', 'پروژه ای', 'خدمات حسابداری', NULL, 1396, NULL, 1397, NULL, 'توافقی', 'سایر موارد', 'انجام ثبت شرکت در اداره ثبت شرکتها وثبت نام مالیات برارزش افزوده و مالیاتی عملکرد و دریافت کد گارگاه و درخواست صدور کارت بازگانی و ثبت رویداد های مالی اعم از خرید و فروش و دریافت و پرداخت -تهیه لیست حقوق دستمزد -ارسال ارزش افزوده -صورت معاملات فصلی -اظهارنامه عملکرد - دفتر نویسی -نرم افزار بیمه و مالیات حقوق بصورت همزمان با سرمایگان', '2025-11-25 19:17:30', '2025-11-25 19:17:30'),
(7752, 5564, 'حسابدار', 'ویراپردازش سخن', 'پروژه ای', 'خدمات حسابداری', NULL, 1395, NULL, 1400, NULL, 'توافقی', 'سایر موارد', 'ثبت رویداد های مالی -ارسال ارزش افزوده -صورت معاملات فصلی -اظهارنامه عملکرد - دفتر نویسی بصورت همزمان با سرمایگان', '2025-11-25 19:19:41', '2025-11-25 19:19:41'),
