(7814, 7261, 'حسابدار', 'علمو‌صنعت نوید', 'تمام وقت', 'تولید و صنایع', NULL, 1384, NULL, 1391, NULL, 'توافقی', 'عدم پیشرفت کاری', NULL, '2025-11-30 11:48:56', '2025-11-30 11:48:56'),
(7815, 7261, 'حسابدار', 'شرکت تشک رویا', 'تمام وقت', 'تولید و صنایع', NULL, 1392, NULL, 1400, NULL, '9 تا 12 میلیون تومان', 'کافی نبودن حقوق', 'نسبت به کارهایی که انجام میدادم حفوق کمی دریافت میکردم \nمسئول خزانه ، ثبت اسناد بازرگانی و‌کنترل و کزارش \nارسال گزارش ارزش افزوده\nپرداخت حقوق\nپرداخت بیمه و مالیات \nگزارش کیری مدیران \nتنخواه دار', '2025-11-30 11:53:26', '2025-11-30 11:53:26'),
(7816, 7270, 'کمک حسابدار', 'تاسیکو', 'تمام وقت', 'خدمات حسابداری', NULL, 1403, NULL, 1403, NULL, '12 تا 15 میلیون تومان', 'سایر موارد', NULL, '2025-11-30 17:18:55', '2025-11-30 17:18:55'),
(7817, 7277, 'کمک حسابدار', 'شرکت روکاسرام یزد', 'تمام وقت', 'تولید و صنایع', NULL, 1401, NULL, NULL, 1, '20 تا 25 میلیون تومان', NULL, NULL, '2025-11-30 20:10:17', '2025-11-30 20:12:31'),
(7818, 7282, 'حسابدار', 'شرکت نبود دفتر بود', 'تمام وقت', 'خدمات حسابداری', NULL, 1400, NULL, 1404, NULL, '9 تا 12 میلیون تومان', 'مسائل شخصی', 'انجام کلیه امور مرتبط با تهیه، تنظیم و ارسال اظهارنامه‌های مالیاتی عملکرد، ارزش افزوده، معاملات فصلی و صورت‌های مالی.\n\nبررسی و کنترل اسناد و مدارک مالی جهت محاسبه صحیح مالیات و اطمینان از انطباق با قوانین و مقررات سازمان امور مالیاتی.\n\nپیگیری و رسیدگی به پرونده‌های مالیاتی در ادارات دارایی و تعامل مؤثر با کارشناسان مالیاتی برای حل اختلاف‌ها و اخذ مفاصاحساب.\n\nتهیه و تنظیم گزارش‌های مالیاتی دوره‌ای و ارائه تحلیل‌های لازم به مدیریت ارشد برای تصمیم‌گیری دقیق‌تر.\n\nبه‌روزرسانی دانش در زمینه آخرین بخشنامه‌ها، مقررات و تغییرات قانون مالیات‌ها و اعمال آن‌ها در روند عملیات مالی شرکت.\n\nنظارت بر دفاتر قانونی و اطمینان از صحت ثبت‌ها جهت جلوگیری از جرایم مالیاتی.\n\nهمکاری نزدیک با واحد حسابداری مالی و واحد حسابرسی برای ارائه مستندات و گزارش‌های موردنیاز.', '2025-11-30 22:23:59', '2025-11-30 22:24:56'),
(7819, 7283, 'حسابدار', 'دریاگشت', 'تمام وقت', 'گردشگری و هتل ها', NULL, 1397, NULL, 1399, NULL, NULL, 'سایر موارد', 'مغایرت بانکی\nحسابداری فروش و مشتریان', '2025-11-30 22:42:06', '2025-11-30 22:42:06'),
(7820, 7283, 'سرپرست حسابداری', 'آپادانا تک', 'تمام وقت', 'واردات و صادرات', NULL, 1399, NULL, 1403, NULL, '15 تا 20 میلیون تومان', 'سایر موارد', 'انجام کلیه امور مالی و ارسال اظهارنامه ارزش افزوده، معاملات فصلی، سامانه مودیان،اسناد حسابداری و گزارش گیری، مغایرت بانکی و مشتریان، امور مالیاتی، بیمه و مالیات حقوق، حقوق و دستمزد، ارسال اظهارنامه املاک، اظهارنامه اشخاص حقوقی به همراه مشاور', '2025-11-30 22:44:26', '2025-11-30 22:44:26'),
(7821, 7283, 'ناظر مالی', 'ایده سرام طاها', 'پروژه ای', 'واردات و صادرات', NULL, 1402, NULL, 1402, NULL, '9 تا 12 میلیون تومان', 'تاخیر در پرداخت', 'امور مالی و ارسال ارزش افزوده، معاملات فصلی، سامانه مودیان و آموزش پرسنل مالی\nفعال در حوزه کاشی و سرامیک', '2025-11-30 22:47:25', '2025-11-30 22:47:25'),
