(7909, 7380, 'حسابدار', 'پرتوسازه سازان قدرت', 'تمام وقت', 'منابع انسانی', NULL, 1403, NULL, 1404, NULL, '15 تا 20 میلیون تومان', 'مسافت طولانی', 'محاسبه حقوق دستمزد بصورت ماهانه \nارسال لیست بیمه تامین اجتماعی \nارسال لیست مالیات حقوق \nمغایرت گیر با طرف حساب ها بصورت ماهانه \nبروز کردن بانک ها سیستم و مغایرت گیری\nنظارت بر روی تنخواه دار ها \nتوانایی کار کردن با سامانه صیادی', '2025-12-03 12:54:08', '2025-12-03 12:54:08'),
(7910, 7380, 'حسابدار', 'کارگزاری رسمی مستقیم بر خط بیمه', 'تمام وقت', 'بیمه', NULL, 1404, NULL, 1404, NULL, '20 تا 25 میلیون تومان', 'عدم پیشرفت کاری', 'محاسبه حقوق دستمزد بصورت ماهانه \nارسال لیست بیمه تامین اجتماعی \nارسال لیست مالیات حقوق \nمغایرت گیری بانک ها به صورت روزانه \nمدیریت و شناسایی بر روی هزینه ها و اقساط\nمدیریت بر روی تنخواه دار ها \nثبت اسناد حسابداری روزانه \nثبت چک در سامانه صیادی بانک ها', '2025-12-03 12:59:40', '2025-12-03 12:59:40'),
