(7920, 6664, 'حسابدار', 'سانا میزان کردستان', 'تمام وقت', 'خدمات حسابداری', NULL, 1401, NULL, NULL, 1, '20 تا 25 میلیون تومان', NULL, NULL, '2025-12-03 15:13:12', '2025-12-03 15:13:12'),
(7921, 7391, 'مدیر مالی', 'هلدینگ بازرگانی و تولیدی ونوس تجارت اکام', 'تمام وقت', 'واردات و صادرات', NULL, 1400, NULL, NULL, 1, NULL, 'کافی نبودن حقوق', 'تهیه صورت‌های مالی و تجزیه  و تحلیل آنها -بودجه‌بندی -مدیریت چرخه وجه نقد - مدیریت سرمایه در گردش - بهای تمام شده تولید و واردات - قیمت گذاری محصولات - پیش بینی سود - مدیریت هزینه -ارائه راهکارهای موثر برای مدیریت ریسک و ارتقای بهره وری. ارزیابی طرح های سرمایه گذاری -سندرسی -آموزش پرسنل در حوزه‌های مالیاتی و حسابداری. -تهیه گزارشات مدیریتی جامع و تحلیلی برای ارائه به سطوح مختلف مدیریت. لایحه نویسی و حضور در هیات‌های حل اختلاف مالیاتی و بیمه ای جهت دفاع از منافع شرکت', '2025-12-03 16:41:25', '2025-12-03 16:41:25'),
(7922, 7391, 'مدیر مالی', 'بازرگانی و تولیدی کاوان تجارت کیاسام', 'تمام وقت', 'واردات و صادرات', NULL, 1397, NULL, 1399, NULL, NULL, 'تاخیر در پرداخت', 'آموزشی پرسنل در زمینه‌های مالیاتی و حسابداری. تهیه و تجزیه و تحلیل صورت‌های مالی، و ارائه گزارشات تحلیلی به سطوح مختلف مدیریت. بودجه‌بندی دقیق و کنترل هزینه‌ها جهت دستیابی به اهداف مالی شرکت. محاسبه بهای تمام شده سفارشات خارجی و ارائه آنالیز قیمت‌گذاری با دقت بالا. نگارش لایحه‌های قانونی و حضور در هیات‌های حل اختلاف مالیاتی و بیمه ای جهت حفاظت از منافع شرکت.', '2025-12-03 17:17:21', '2025-12-03 17:17:21'),
(7923, 7391, 'رییس حسابداری', 'بازرگانی و تولیدی فیروز طب زمان', 'تمام وقت', 'واردات و صادرات', NULL, 1395, NULL, 1397, NULL, NULL, NULL, 'استقرار سیستم سپیدار، آموزش پرسنل و نظارت بر عملکرد آن. انجام حسابرسی داخلی، محاسبه دقیق حقوق و دستمزد، بهای تمام شده تولید و واردات. تهیه اظهارنامه‌های مالیاتی (ارزش افزوده، معاملات فصلی) و لیست بیمه و مالیات حقوق و تکلیفی. شرکت در هیات‌های حل اختلاف مالیاتی و بیمه ای - سند رسی', '2025-12-03 17:19:18', '2025-12-03 17:19:18'),
(7924, 7391, 'رییس حسابداری', 'بازرگانی توسعه تجارت هوشمند فاخر', 'تمام وقت', 'واردات و صادرات', NULL, 1391, NULL, 1395, NULL, NULL, 'سایر موارد', 'ثبت اسناد حسابداری - سند رسی  و انجام بررسی‌های حسابرسی، محاسبه حقوق و دستمزد و بهای تمام شده سفارشات خارجی، تهیه لیست بیمه و مالیات حقوق و تنظیم اظهارنامه ارزش افزوده و معاملات فصلی. همچنین، مسئولیت تنظیم اظهارنامه عملکرد را بر عهده داشتم.-', '2025-12-03 17:23:57', '2025-12-03 17:23:57'),
(7925, 7391, 'حسابدار', 'تولیدی مهر اریا پلیمر پارس', 'تمام وقت', 'تولید و صنایع', NULL, 1387, NULL, 1390, NULL, NULL, 'مسافت طولانی', 'ثبت اسناد حسابداری جاری، شامل خزانه داری، حقوق و دستمزد، تحریر دفاتر قانونی، تهیه گزارشات مدیریتی، رسیدگی به امور انبار، لیست بیمه و مالیات حقوق', '2025-12-03 17:26:03', '2025-12-03 17:26:03'),
(7926, 6273, 'حسابدار', 'ادنا', 'تمام وقت', 'تولید و صنایع', NULL, 1401, NULL, NULL, 1, '25 تا 30 میلیون تومان', 'عدم پیشرفت کاری', 'سابقه کارم حدود ۴ سال است', '2025-12-03 19:44:42', '2025-12-03 19:44:42'),
(7927, 7110, 'حسابدار', 'ارمغان چاشنی توس (آرشیا)', 'تمام وقت', 'تولید و صنایع', NULL, 1402, NULL, 1403, NULL, NULL, 'سایر موارد', 'انجام امور خزانه ، ثبت اسناد دریافت و پرداخت و مغایرت بانکی\nتهیه و ارائه گزارشهای بودجه و مدیریت نقدینگی\nانجام امور مالی و گزارشهای مربوطه\nتهیه و ارائه گزارشهای مالی و مدیریت', '2025-12-03 23:08:41', '2025-12-03 23:08:41'),
(7928, 7110, 'حسابدار', 'تولید و پخش اسباب بازی آقاسی زاده', 'تمام وقت', 'فرهنگی و ورزشی', NULL, 1403, NULL, NULL, 1, NULL, NULL, 'انجام امور خزانه ، مالی ، فروش و انبار\nثبت روزانه اسناد حسابداری\nمحاسبه و تهیه لیست حقوق ، بیمه و مالیات\nتهیه و ارائه گزارشهای مالی و مدیریتی', '2025-12-03 23:09:58', '2025-12-03 23:09:58'),
(7929, 7396, 'مدیر مالی', 'شرکت بهدانه دشت ناز', 'تمام وقت', 'حسابداری', NULL, 1401, NULL, 1404, NULL, '60 تا 70 میلیون تومان', 'مسافت طولانی', 'فعالیت شرکت در زمینه تولید رب فله و بسته بندی و صادرات به کشورهای همسایه بود.', '2025-12-04 01:05:11', '2025-12-04 01:22:36'),
