(7931, 7396, 'سرپرست حسابداری', 'شرکت خدمات مالی و حسابداری', 'تمام وقت', 'حسابداری', NULL, 1398, NULL, 1400, NULL, NULL, 'کافی نبودن حقوق', 'شرکت در زمینه خدمات مالی و حسابرسی فعالیت داشت و پرونده شرکت های خدماتی ، بازرگانی (واردات و صادرات) ، تولیدی بررسی و کنترل میشد', '2025-12-04 01:08:51', '2025-12-04 01:24:28'),
