(8016, 7323, 'حسابدار', 'شرکت باطری سازی نیرو', 'پاره وقت', 'تولید و صنایع', NULL, 1369, NULL, 1371, NULL, NULL, 'سایر موارد', NULL, '2025-12-06 11:08:24', '2025-12-06 11:08:24'),
(8017, 7323, 'سرپرست حسابداری', 'شرکت صنعتی مهرآباد', 'تمام وقت', 'تولید و صنایع', NULL, 1373, NULL, 1386, NULL, NULL, 'سایر موارد', 'شرکت صنعتی مهرآباد -جزو بزرگترین و قدیمی ترین شرکت تابلوسازی برق میباشد.\nمسئولیت: سرپرست رسیدگی -رسیدگی  اسناد و مدارک ارسالی به امور مالی - صورتحسابها و قرارداد های خرید و فروش -تنخواه گردان ها -تطبیق حساب و مغایرت گیری با تامین کنندگان و مشتریان-\nتهیه صورتهای مالی و یادداشتهای پیوست و پاسخگویی به حسابرسان مستقل', '2025-12-06 11:10:33', '2025-12-06 11:24:55'),
(8018, 7323, 'حسابدار', 'شرکت نصب نیرو', 'تمام وقت', 'نیرو', NULL, 1388, NULL, 1391, NULL, NULL, 'سایر موارد', 'شرکت نصب نیرو (گروه مپنا)پیمانکار ساخت پست و خطوط انتقال برق و نیروگاه \nمسئولیت : حسابدار پروژه های پیمانکاری- مسئول حسابداری اموال و دارایی های ثابت\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n9', '2025-12-06 11:17:31', '2025-12-06 11:17:31'),
(8019, 7323, 'حسابدار', 'شرکت پیمانیر', 'تمام وقت', 'نیرو', NULL, 1391, NULL, 1395, NULL, NULL, 'سایر موارد', 'شرکت پیمانیر پیمانکار  ساخت پست و خطوط انتقال برق و بهره برداری نیروگاه میباشد.\nمسئولیت : امور حسابداری پیمانکاری -پیگیری امور مالیاتی و بیمه تامین اجتماعی پروژه ها-تهیه صورتهای مالی و پاسخگویی به حسابرسان مستقل.', '2025-12-06 11:30:42', '2025-12-06 11:30:42'),
(8020, 7323, 'حسابدار', 'شرکت صانیر', 'تمام وقت', 'نیرو', NULL, 1395, NULL, 1396, NULL, NULL, 'سایر موارد', 'شرکت صانیر -پیمانکار اجرای پروژه های آب و برق و تاسیسات در خارج از کشور میباشد.\nمسئولیت : رسیدگی اسناد حسابداری', '2025-12-06 11:48:15', '2025-12-06 11:48:15'),
(8021, 7323, 'حسابدار', 'شرکت توسعه صنایع نفت و انرژی قشم', 'تمام وقت', 'نفت و گاز', NULL, 1395, NULL, 1396, NULL, NULL, 'سایر موارد', 'شرکت توسعه نفت و انرژی قشم تابعه شرکت نفت و پیمانکار حفاری و استخراج نفت میباشد.\nمسئولیت:سرپرست خزانه داری -انجام کلیه امور خزانه داری -تهیه صورت مغایرات بانکی و گزارش موجودی روزانه بانکها -مراجعه به بانکها جهت انجام کلیه امور بانکی', '2025-12-06 11:54:58', '2025-12-06 11:54:58'),
(8022, 7323, 'حسابدار', 'خدمات مالی همپیشگان', 'تمام وقت', 'خدمات حسابداری', NULL, 1397, NULL, 1398, NULL, NULL, 'سایر موارد', 'مسئولیت : انجام امور حسابداری در شرکتهای طرف قرارداد', '2025-12-06 11:56:56', '2025-12-06 11:56:56'),
(8023, 7323, 'رییس حسابداری', 'شرکت آکام بافت سیوان', 'تمام وقت', 'تولید و صنایع', NULL, 1398, NULL, 1403, NULL, '25 تا 30 میلیون تومان', 'سایر موارد', 'شرکت آکام بافت سیوان -فعال در زمینه خرید نخ و تولید و فروش پارچه به صورت عمده میباشد.\nمسئولیت : انجام کلیه امور حسابداری و مالی، صدور اسنادحسابداری انبار-خرید-خزانه داری-فروش و حقوق و دستمزد با استفاده از نرم افزار سپیدار.\n- تحریر دفاتر قانونی-روزنامه و کل-تهیه گزارش و ارسال و بارگزاری اظهارنامه مالیات عملکرد-ارزش افزوده گزارش فصلی ماده 169 و فهرست حقوق ماهانه به دارایی و بیمه تامین اجتماعی.\n- تهیه گزارشات قیمت تمام شده محصولات تولیدی\n-تهیه گزارش مالی و یادداشتهای پیوست \n-پاسخگویی و تعامل با حسابرسان مستقل و ممیزان سازمان امور مالیاتی\n- مراجعه به ادارات دارایی و بیمه تامین اجتماعی جهت دفاع و حل مسایل بیمه و مالیاتی', '2025-12-06 12:08:46', '2025-12-06 12:08:46'),
(8024, 7323, 'حسابدار', 'شرکت پیمابرق', 'تمام وقت', 'نیرو', NULL, 1403, NULL, 1404, NULL, '40 تا 45 میلیون تومان', 'سایر موارد', 'شرکت پیمابرق فعال در حوزه برق -نصب و راه اندازی پست و خطوط انتقال برق میباشد.\nمسئولیت: حسابداری پیمانکاری-رسیدگی به صورت وضعیت های پیمانکاران فرعی- صورتحساب های خرید و تنخواه گردان پروژه ها و صدور اسناد مربوطه', '2025-12-06 12:14:25', '2025-12-06 12:14:25'),
