(8034, 7466, 'مدیر مالی', 'سپنتا', 'تمام وقت', 'حسابداری', NULL, 1394, NULL, NULL, 1, '45 تا 50 میلیون تومان', NULL, 'کلیه عملیات مربوط به سامانه مودیان\nلیست دیسک بیمه کارکنان،شرکت در هیئت های بدوی \nمعاملات فصلی ،ارزش افزوده\nهمکاری با حسابرسان شرکت\nحقوق دستمزد سنوات عیدی و...مربوط به کارکنان شرکت\nرسیدگی به کلیه عملیات انبار\nنظارت بر کار کلیه حسابداری خزانه تنخواه و انبار', '2025-12-06 13:45:22', '2025-12-06 13:57:02'),
(8035, 7466, 'رییس حسابداری', 'طرح گستر پویش', 'تمام وقت', 'حسابداری', NULL, 1401, NULL, NULL, 1, '30 تا 35 میلیون تومان', NULL, NULL, '2025-12-06 13:48:53', '2025-12-06 13:48:53'),
(8037, 7467, 'مدیر مالی', 'نیکسام - کارن هوبر', 'تمام وقت', 'کالای مصرفی و خوراکی', NULL, 1400, NULL, NULL, 1, '35 تا 40 میلیون تومان', 'سایر موارد', 'فعالیتهای من در مجموعه عبارتند از :\nنظارت و اجرای تمامی امور حسابداری و امور مالیاتی بیمه ای و تکالیف قانونی شامل : امور لیست حقوق و دستمزد - لیست بیمه تامین اجتماعی - لیست مالیات حقوق - سامانه مودیان - ماده 169 - جامع تجارت - اظهارنامه مالیاتی و صورتهای مالی -همینطور شرکت در جلسات اداره دارایی و بیمه بابت دفاعیه و لایحه های اجرایی\nهمینطور در یکی دیگر از شرکتهای مجموعه با همین فعالیت نیز شاغل بودم   \n\"شرکتهای مذکور بجا مانده از یک شرکت بزرگ ورشکسته میباشند . و متاسفانه قادر به ادامه فعالیت نمیباشند مابقی مطالب حضورا در مصاحبه عرض خواهد شد \" شرکتهای مذکور در امور پخش مواد غذایی شامل سس نوشابه چای و قهوه فعالیت داشتند که با توجه به ورشکستگی مدیران مجموعه در آستانه انحلال میباشند و فعلا بنده حدود یک ماه است بصورت دورکاری نگهداری حسابها را بر عهده دارم در صورت شاغل شدن این امر نیز خاتمه می یابد .\nبا توجه به تسلط کافی بر موضوعات ذکر شده خواهان همکاری با مجموعه شما میباشم . با تشکر', '2025-12-06 14:24:54', '2025-12-06 14:24:54'),
(8038, 7467, 'سرپرست حسابداری', 'فرحو', 'تمام وقت', 'معماری و عمران', NULL, 1398, NULL, 1400, NULL, '12 تا 15 میلیون تومان', 'کافی نبودن حقوق', 'مسئولیت :\nمدیریت و اجرای کلیه امور اداری استخدام قراردادهای پرسنلی ، استعفا و خاتمه قرارداد و تسویه کامل حقوق مزایا ، تهیه و ارسال لیست بیمه تامین اجتماعی و مالیات حقوق ، امورمالی : حسابداری خزانه ، فروش ، مالیاتی ، حقوق و دستمزد ، تکالیف قانونی ارش افزوده معاملات فصلی اظهارنامه مالیاتی ، ردیف پیمانها ، صورتوضعیت های پروژه و ....', '2025-12-06 14:26:53', '2025-12-06 14:26:53'),
(8039, 7467, 'سرپرست حسابداری', 'شباهنگ - فیدایران - گرانش', 'پاره وقت', 'گردشگری و هتل ها', NULL, 1394, NULL, 1398, NULL, 'توافقی', 'سایر موارد', 'مسئولیت :\nامور اداری و مالی مجموعه : از شروع استخدام و عقد قرارداد پرسنل و لیست بیمه تامین اجتماعی مالیات حقوق ، حقوق و دستمزد و تسویه کامل عیدی پاداش و سنوات ، انجام و نظارت بر امور مالی خزانه داری ، فروش ، کلیه امور مالیاتی و تکالیف قانونی ، عقد قرارداد پیمانکاری و امور مربوط به ردیف پیمان و ...\nمجموعه شباهنگ : گردشگری و هتل\nفیدایران :  مشاوره، طراحی و ساخت ماشین آلات تولید خوراک دام و طیور ...\nگرانش : مشاوره و تبلیغات تلویزیونی و درون شهری', '2025-12-06 14:30:51', '2025-12-06 14:30:51'),
