(8066, 7491, 'حسابدار', 'شرکت بازرگانی سیما شکوه کیش', 'تمام وقت', 'واردات و صادرات', NULL, 1394, NULL, 1398, NULL, NULL, NULL, 'حسابدار خزانه\n\nشرکت سیما شکوه کیش\n\nاردیبهشت ۱۳۹۴ - اردیبهشت ۱۳۹۸\n\nدریافت و ثبت چک ها و اسناد دریافتنی\n\nمغایرت گیری بانک‌ها\n\nآشنایی کامل با سامانه های بانک ها( آنلاین و مراجعه حضوری)\n\nآشنایی و کار با سامانه صیادی\n\nارائه گزارش های نقدینگی و حساب بانک‌ها به مدیریت\n\nپیگیری و گزارش چک های برگشتی و ثبت نشده\n\nمراجعه حضوری به ادارات و بانک‌ها جهت کارهای بانکی و تسهیلات\n\nکنترل و ثبت اسناد تنخواه', '2025-12-07 10:39:55', '2025-12-07 10:39:55'),
(8067, 7491, 'سرپرست حسابداری', 'شرکت بازرگانی سیما شکوه کيش', 'تمام وقت', 'واردات و صادرات', NULL, 1398, NULL, 1402, NULL, NULL, NULL, 'سرپرست حسابدار فروش\n\nشرکت سیما شکوه کیش\n\nاردیبهشت ۱۳۹۸ - اردیبهشت ۱۴۰۲\n\nثبت فاکتور های فروش؛ پیش فاکتور ؛فاکتور برگشت از فروش\n\nکنترل و ثبت تخفیفات مطعلق به مشتریان با توجه به نوع کالا و زمان تسویه حساب\n\nبررسی و کنترل دائمی حساب های فروش مشتریان\n\nارائه گزارشات فروش به مدیر شرکت\n\nکنترل و ارتباط با واحد انبار جهت خروج کالاها\n\nتهیه صورتحساب های مشتریان جهت اعلام مانده حساب ها و مدت تسویه مشتریان\n\nثبت اسناد دریافت حساب ها از مشتریان\n\nتهیه راس اسناد دریافتی از مشتریان و تطابق آن با مدت تعیین شده توسط شرکت\n\nنگهداری و طبقه بندی کلیه اسناد فروش', '2025-12-07 10:41:23', '2025-12-07 10:41:23'),
(8068, 7491, 'حسابدار', 'پخش دارو گستر نخبگان (هلدینگ نوفیکو)', 'تمام وقت', 'خدمات درمانی، پزشکی و سلامت', NULL, 1402, NULL, 1404, NULL, '25 تا 30 میلیون تومان', 'مسائل شخصی', 'حسابدار فروش\n\nپخش دارو گستر نخبگان ( هلدینگ دارویی نوفیکو )\n\nکنترل فاکتورهای فروش و حواله های انبار\n\nثبت و کنترل اسناد دریافتنی و تسویه های نقدی\n\nثبت و کنترل تخفیفات و تخفیفات موردی\n\nپیگیری وصول مطالبات و حساب های باز\n\nکنترل و تطبیق حساب های مشتریان\n\nارتباط با پرسنل انبار و پرسنل فروش سازمانی\n\nمغایرت گیری حساب بانک های شعبه و ستاد\n\nکنترل تنخواه و تنخواه گردانی شعب', '2025-12-07 10:44:36', '2025-12-07 10:44:36'),
