(8095, 7533, 'حسابدار', 'موسسه صنعتی گوشت مشهد', 'تمام وقت', 'حسابداری', NULL, 1393, NULL, 1398, NULL, 'قانون کار', 'سایر موارد', NULL, '2025-12-08 11:42:12', '2025-12-08 11:42:12'),
(8096, 7533, 'رییس حسابداری', 'شرکت به ایمن سیر رضوی', 'پاره وقت', 'حسابداری', NULL, 1398, NULL, NULL, 1, '25 تا 30 میلیون تومان', 'ساعت کاری طولانی', NULL, '2025-12-08 11:43:18', '2025-12-08 11:43:18'),
(8097, 7374, 'مدیر مالی', 'ارتقا جامه برتر', 'تمام وقت', 'حسابداری', NULL, 1403, NULL, 1404, NULL, '70 تا 80 میلیون تومان', 'مسائل شخصی', 'هلدینگ تدبیر سبز - مدیرمالی 1403\nشرکت حسابرسی تراز ارقام و تندیس پردازش هزاره سوم 1390 الی 1399\nو بسیاری دیگر از شرکت ها \nتوانایی ها  : \n-	برنامه ریزی ، سازماندهی و مدیریت تیم مالی \n-	تهیه صورت های مالی در زمان های مورد نیاز ( 3 ماهه – 6 ماهه – پایان دوره ) برای بار گذاری در سامانه کدال \n-	برنامه ریزی و کنترل بودجه \n-	پیگیری فرایند امور مالیاتی و اطمینان از انطباق فعالیت ها با قوانین و مقررات مالیاتی و تامین اجتماعی \n-	تهیه گزارشات مالی مقایسه ای و کنترل و آنالیز هزینه ها \n-	تهیه بودجه عملیاتی ، cash flow جهت ارزیابی و تطبیق با میزان رشد مورد انتظار \n-	تسلط بر سامانه مودیان ، سامانه مالیات حقوق ، سامانه تامین اجتماعی \n-	تهیه BOM محصول و اجرا در سیستم\n-	-	مدیریت و نظارت بر امور مربوط به تهیه و ارسال گزارشات فصلی ، حقوق و دستمزد ؛ اظهارنامه ارزش افزوده و عملکرد \n-	مدیریت و نظارت بر ارسال فاکتورهای خرید و فروش  در  سامانه مودیان و هماهنگی آن با سیستم مالی و بررسی و ارسال دفاتر الکترونیک در موعد مقرر\n-	مدیریت و نظارت و هماهنگی با حسابرسان داخلی و خارج از سازمان', '2025-12-08 11:51:59', '2025-12-08 11:51:59'),
(8098, 5880, 'حسابدار', 'دانش بنیان شبیه سازان شریف', 'تمام وقت', 'حسابداری', NULL, 1400, NULL, NULL, 1, '30 تا 35 میلیون تومان', 'ساعت کاری طولانی', NULL, '2025-12-08 12:40:22', '2025-12-08 12:40:22'),
