(8101, 7540, 'حسابدار', 'بیمه رهنمود نمایندگی بیمه ایران', 'تمام وقت', 'حسابداری', NULL, 1399, NULL, 1401, NULL, 'قانون کار', 'سایر موارد', NULL, '2025-12-08 17:14:23', '2025-12-08 17:14:39'),
(8102, 7540, 'حسابدار', 'شرکت جاوید ریحان ستاره', 'تمام وقت', 'حسابداری', NULL, 1401, NULL, 1402, NULL, '12 تا 15 میلیون تومان', 'مسائل شخصی', '_مسلط به نرم افزار مالی راهکاران سیستم و سپیدار\n_مسلط به مغایرت گیری بانک ها و حساب اشخاص\n_مسلط به مفاهیم و ثبت اسناد روزانه حسابداری\n_مسلط به تهیه گزارش اظهارنامه ارزش افزوده و گزارشات فصلی\n_مسلط به ثبت اسناد دریافت و پرداخت,ثبت اسناد مربوط به تنخواه گردان,خزانه و اسناد خرید و فروش\n_مسلط به دفترنوسی (کل و روزنامه)\n_مسلط به بایگانی منظم مدارک مالی\n_مسلط به کنترل و بستن حساب ها\n_آشنایی با حسابداری صنعتی و بهای تمام شده کاﻻهای تولیدی', '2025-12-08 17:17:11', '2025-12-08 17:17:11'),
(8103, 7540, 'حسابدار', 'شرکت توسعه تجارت عروج', 'تمام وقت', 'حسابداری', NULL, 1403, NULL, 1403, NULL, '15 تا 20 میلیون تومان', 'مسافت طولانی', '_مسلط به نرم افزار مالی آهن افزار و نوید در حوزه فوﻻد\n_مسلط به مغایرت گیری بانک ها و حساب اشخاص\n_مسلط به مفاهیم و ثبت اسناد روزانه حسابداری\n_مسلط به ثبت اسناد دریافت و پرداخت,ثبت اسناد مربوط به تنخواه گردان,خزانه و اسناد خرید و فروش\n_مسلط به بایگانی منظم مدارک\n_مسلط به حسابداری خزانه و کنترل و گزارش گری نقدینگی مجموعه', '2025-12-08 17:19:12', '2025-12-08 17:19:12'),
(8104, 7540, 'حسابدار', 'شرکت بازار نهاده خلیج فارس', 'تمام وقت', 'حسابداری', NULL, 1403, NULL, NULL, 1, '35 تا 40 میلیون تومان', NULL, 'مسلط به نرم افزار مالی سپیدار سیستم\nمسلط به سامانه مودیان\nانجام امور مربوط به حقوق و دستمزد\nارسال لیست بیمه و مالیات حقوق\nثبت اسناد دریافت و پرداخت,ثبت اسناد مربوط به تنخواه گردان و اسناد خرید و فروش\nتهیه و تنظیم اظهارنامه عملکرد شرکت\nانجام امور مربوط به دفاتر تجاری الکترونیکی', '2025-12-08 17:20:50', '2025-12-08 18:00:58'),
(8105, 7547, 'حسابدار', 'بهرویش', 'تمام وقت', 'حسابداری', NULL, 1401, NULL, NULL, 1, '25 تا 30 میلیون تومان', NULL, NULL, '2025-12-08 20:14:14', '2025-12-08 20:14:14'),
(8106, 6773, 'حسابدار', 'شرکت سازه گستران دادا سازه', 'تمام وقت', 'حسابداری', NULL, 1400, NULL, NULL, 1, '30 تا 35 میلیون تومان', 'عدم پیشرفت کاری', 'شرکت پیشگام صنعت زیبایی به عنوان حسابدار و مشاور مالیاتی به صورت پروژه ای مشغول به همکاری می باشم', '2025-12-08 23:14:28', '2025-12-08 23:14:28'),
(8107, 4985, 'حسابدار', 'شرکت صنعت پالایش رهام', 'تمام وقت', 'حسابداری', NULL, 1398, NULL, 1401, NULL, '12 تا 15 میلیون تومان', 'عدم پیشرفت کاری', NULL, '2025-12-09 10:20:35', '2025-12-09 10:20:35'),
