(8207, 7644, 'حسابدار', 'قارچ نمونه', 'تمام وقت', 'کشاورزی', NULL, 1404, NULL, NULL, 1, 'توافقی', NULL, NULL, '2025-12-10 08:12:19', '2025-12-10 08:12:19'),
(8208, 7645, 'حسابدار', 'شرکت چاپ و نشر بانک ملی ایران', 'تمام وقت', 'حسابداری', NULL, 1402, NULL, 1404, NULL, '15 تا 20 میلیون تومان', 'سایر موارد', '•     ثبت و کنترل اسناد حسابداری روزانه شامل دریافتنی‌ها، پرداختنی‌ها، هزینه‌ها و درآمدها\n	•	تهیه و تنظیم گزارش‌های مالی دوره‌ای و ارائه آن به مدیر مالی\n	•	انجام مغایرت‌گیری‌های بانکی و رفع اختلاف حساب‌ها\n	•	صدور فاکتورهای فروش و خرید و پیگیری تسویه‌حساب‌ها\n	•	ارتباط با مشتریان و تأمین‌کنندگان جهت دریافت و پرداخت‌ها\n	•	بایگانی و آرشیو منظم اسناد مالی و مدارک حسابداری\n	•	همکاری در تهیه اظهارنامه‌های مالیاتی، ارزش افزوده و گزارشات فصلی\n	•	کار با نرم‌افزارهای حسابداری راهکاران سیستم و سپیدار\n      •       محاسبه حقوق و دستمزد\n      •       ارائه لیست های بیمه و مالیات حقوق', '2025-12-10 08:20:46', '2025-12-10 08:20:46');
INSERT INTO `resume_priors` (`id`, `user_id`, `title`, `company_name`, `employment_type`, `activity_type`, `start_month`, `start_year`, `end_month`, `end_year`, `still_busy`, `last_salary`, `leaving_reason`, `description`, `created_at`, `updated_at`) VALUES
(8209, 7645, 'حسابدار', 'شرکت دژپاد', 'تمام وقت', 'حسابداری', NULL, 1403, NULL, NULL, 1, '25 تا 30 میلیون تومان', NULL, 'ثبت و پیگیری روزانه فاکتورهای فروش و برگشت از فروش\n	•	کنترل و تطبیق اسناد فروش با حواله‌های انبار و گزارش تولید\n	•	هماهنگی با واحد فروش برای صدور پیش‌فاکتور، فاکتور نهایی و تسویه‌حساب مشتریان\n	•	پیگیری دریافت‌ها و مدیریت حساب‌های دریافتنی\n	•	تهیه گزارش‌های دوره‌ای فروش و ارائه تحلیل‌های لازم برای مدیریت\n	•      تهیه اظهارنامه ارزش افزوده، گزارشات فصلی و اسناد مرتبط\n	•	صدور اسناد حسابداری مربوط به فروش، تخفیفات، اضافات و برگشت‌ها\n	•	مغایرت‌گیری حساب مشتریان و رفع اختلافات مالی\n	•	بایگانی و آرشیو منظم اسناد فروش و مدارک حسابداری', '2025-12-10 08:23:59', '2025-12-10 08:23:59'),
(8210, 7645, 'حسابدار', 'شرکت تعاونی تجارت گستر نگاه پویا', 'تمام وقت', 'حسابداری', NULL, 1403, NULL, 1404, NULL, '15 تا 20 میلیون تومان', 'سایر موارد', '•	تهیه، محاسبه و کنترل لیست حقوق و دستمزد ماهانه کارکنان\n	•	محاسبه اضافه‌کاری، کسرکار، مرخصی، مأموریت و مزایای قانونی\n	•	محاسبه و ارسال لیست بیمه تأمین اجتماعی و مالیات حقوق\n	•	تهیه اسناد هزینه حقوق و ثبت آن در سیستم حسابداری\n	•	رسیدگی به پرونده کاری کارکنان و بایگانی سوابق پرسنلی\n	•	همکاری در تهیه قراردادها و احکام کارگزینی و به‌روزرسانی اطلاعات پرسنلی\n	•	کنترل کارکرد پرسنل براساس حضور و غیاب\n	•	پاسخگویی به کارکنان در مورد حقوق، مزایا و سوابق بیمه\n\n	•	ثبت و کنترل اسناد حسابداری مربوط به پروژه‌ها', '2025-12-10 08:26:25', '2025-12-10 08:26:25'),
(8211, 7648, 'مدیر مالی', 'مفید  دارو', 'تمام وقت', 'خدمات درمانی، پزشکی و سلامت', NULL, 1399, NULL, NULL, 1, '50 تا 60 میلیون تومان', NULL, NULL, '2025-12-10 09:26:47', '2025-12-10 09:26:47'),
