(8323, 7729, 'رییس حسابداری', 'شرکت فروشگاه زنجیره ای رفاه (دفتر مرکزی)', 'تمام وقت', 'حسابداری', NULL, 1400, NULL, NULL, 1, '50 تا 60 میلیون تومان', 'عدم پیشرفت کاری', '- مدیریت و نظارت بر تیم حسابداری\n- تهیه و تجزیه و تحلیل گزارش‌های مالی\n- اطمینان از رعایت استانداردهای حسابداری\n- همکاری با بخش‌های مختلف سازمان\n- بهبود فرآیندهای مالی و حسابداری', '2025-12-13 10:02:00', '2025-12-13 10:06:05'),
(8324, 7729, 'حسابدار', 'شرکت رفاه (دفتر مرکزی)', 'تمام وقت', 'حسابداری', NULL, 1387, NULL, 1399, NULL, '30 تا 35 میلیون تومان', 'سایر موارد', 'کارشناس ارشد مالی در شرکت فروشگاه های زنجیره ای رفاه (دفتر مرکزی)\nکنترل اسناد مالی\nتهیه یادداشت های صورت های مالی\nارسال اظهارنامه مالیاتی\nسامانه کدال(بورس) ،جهت ارسال اطلاعات مالی', '2025-12-13 10:05:36', '2025-12-13 10:05:36'),
