(8350, 7765, 'حسابدار', 'کامل برچسب', 'تمام وقت', 'حسابداری', NULL, 1394, NULL, 1398, NULL, NULL, 'مسائل شخصی', NULL, '2025-12-13 15:16:57', '2025-12-13 15:16:57'),
(8351, 7765, 'حسابدار', 'کارا پیشه بین الملل', 'دورکاری', 'حسابداری', NULL, 1400, NULL, NULL, 1, NULL, NULL, 'به صورت دورکاری و پاره وقت مشغول هستم', '2025-12-13 15:17:57', '2025-12-13 15:17:57'),
(8352, 7768, 'کمک حسابدار', 'بوتان', 'تمام وقت', 'تولید و صنایع', NULL, 1401, NULL, 1403, NULL, '15 تا 20 میلیون تومان', 'عدم پیشرفت کاری', 'عنوان شغلی اینجانب در شرکت بوتان کارمند اداری بود.\n\nسوابق دیگر:\nفعالیت در بخش انبار شرکت ایتوک(بسته بندی قطعات خودرو) که شامل:\nکنترل ورود و خروج کالا در انبار، پیگیری دریافت ، ثبت و ضبط اسناد مربوطه به انبار در سیستم حسابداری بهین سیستم ، کنترل موجودی انبار،رسیدگی به موجودی انبار ها و صورت برداری از کالاهای موجود و آگاه کردن بخش تأمین برای تجدید سفارش ، ثبت و ضبط گزارش تولید و نیز ایجاد و محاسبه فرمول ساخت برای تمامی کالاهای موجود در انبار، انجام بایگانی و نگهداری اسناد مثبته و کنترل و شمارش آن ها و نیز تطبیق اسناد در پایان سال مالی با سیستم حسابداری و در نهایت تایید آن ها ، همکاری و مشارکت در انبار گردانی و ثبت و ضبط اسناد مربوط  به آن در سیستم حسابداری بهین سیستم ، کار با دستگاه لیبل زن و ساخت لیبل برای کالاهای موجود در انبار،کار با نرم افزار فراتکنو (مسئول پیگیری ورود و خروج و کارکرد پرسنل)\n\nوسوابق کاری دیگر در زمان دانشجویی اول مثل فعالیت در بخش چاپ خانه دانشگاه، فعالیت در بخش اداری شرکت خدمات نظافتی آرمان،  فروشندگی در فروشگاه کیف و کفش', '2025-12-13 15:48:43', '2025-12-13 16:02:15'),
(8353, 7770, 'حسابدار', 'احیا استیل', 'پاره وقت', 'حسابداری', NULL, 1403, NULL, 1404, NULL, '25 تا 30 میلیون تومان', 'نداشتن بیمه', NULL, '2025-12-13 15:52:01', '2025-12-13 15:52:01'),
