(8447, 7852, 'مشاور مالی', 'هوراد حساب', 'تمام وقت', 'خدمات حسابداری', NULL, 1399, NULL, NULL, 1, '45 تا 50 میلیون تومان', NULL, 'مدیریت مالی شرکت های مختلف مثل \nایران نوشت \nفطرس\nلومیک\nو.....', '2025-12-14 12:24:23', '2025-12-14 12:24:23'),
(8448, 7853, 'حسابدار', 'صنایع غدایی تحفه', 'تمام وقت', 'کالای مصرفی و خوراکی', NULL, 1402, NULL, 1404, NULL, '35 تا 40 میلیون تومان', 'عدم پیشرفت کاری', 'کنترل ورود و خروج کالا در انبار و بررسی لیست قیمت‌های مرتبط با کالاهای ورودی\nانجام فرآیند خرید و تأمین کالا از تأمین‌کنندگان و رفع مغایرت‌های مالی با طرف حساب‌ها\nبررسی صورتحساب‌های خرید در سامانه مودیان و انجام عملیات تأیید یا عدم تأیید آن‌ها\nکنترل و رسیدگی به گزارش‌های تنخواه و مستندات هزینه‌ای\nتهیه و تنظیم گزارش‌های ارزش افزوده و معاملات فصلی مطابق با ضوابط مالیاتی\nبارگذاری و ارسال اطلاعات مالی در سامانه‌های مربوطه (سازمان امور مالیاتی و سامانه مودیان)\nمستندسازی خریدها و نگهداری فایل فیزیکی و دیجیتال اسناد\nتهیه گزارش‌های دوره‌ای از خریدها و مانده تنخواه\nکنترل تطابق فاکتور با قرارداد یا سفارش خرید\nثبت اسناد خرید در نرم‌افزار حسابداری\nثبت اسناد پرداخت و دریافت مرتبط با خرید\nتهیه ترازهای معین و کل مرتبط با حساب‌های خرید\nتنظیم برنامه پرداخت دوره‌ای به تأمین‌کنندگان\nهمکاری با مدیر مالی برای تأمین بودجه خرید و صورتهای مالی ماهانه جهت ارائه به هیئت مدیره', '2025-12-14 12:33:09', '2025-12-14 12:33:09'),
(8449, 7764, 'مدیر مالی', 'غزال تجارت اروند', 'پاره وقت', 'حمل و نقل، لجستیک و انبارداری', NULL, 1403, NULL, 1404, NULL, '15 تا 20 میلیون تومان', 'سایر موارد', 'عدم فعالیت شرکت به دلیل نوسان نرخ ارز', '2025-12-14 12:38:28', '2025-12-14 12:38:28'),
