(8457, 7861, 'رییس حسابداری', 'توسعه راه تجارت سانیان', 'تمام وقت', 'حسابداری', NULL, 1402, NULL, 1403, NULL, '20 تا 25 میلیون تومان', 'سایر موارد', 'شرکت مربوط به خدمات حسابداری بود به دلیل جابه جایی مکان شرکت به شهر دیگر امکان همکاری نبود ولی به صورت دور کاری همچنان همکاری داریم', '2025-12-14 13:09:43', '2025-12-14 13:09:43'),
(8458, 7866, 'حسابدار', 'تدبیر محاسبان متفکر', 'کارآموزی', 'خدمات حسابداری', NULL, 1403, NULL, 1404, NULL, 'قانون کار', 'سایر موارد', 'اصول حسابداری\nتسلط به نرم افزار هلوو سپیدار \nثبت فاکتور خرید و فروش \nثبت اسناد \nثبت اسناد بانک و مغایرت گیری\nمالیات حقوق \nمالیات ارزش افزوده\nتحریر دفاتر قانونی', '2025-12-14 13:18:16', '2025-12-14 13:18:16'),
(8459, 7869, 'حسابدار صنعتی', 'لوله و پروفیل سپنتا تهران', 'تمام وقت', 'تولید و صنایع', NULL, 1400, NULL, NULL, 1, '35 تا 40 میلیون تومان', 'سایر موارد', NULL, '2025-12-14 13:24:15', '2025-12-14 13:24:15'),
(8460, 7853, 'حسابدار', 'پایایازه پاسارگاد', 'تمام وقت', 'معماری و عمران', NULL, 1398, NULL, 1402, NULL, '15 تا 20 میلیون تومان', 'ساعت کاری طولانی', 'بمدت سه سال باسمت کارشناس خزانه داری\nثبت و پیگیری دریافت‌های نقدی و انتقالات بانکی\nصدور چک‌های پرداختی و تنظیم تاریخ سررسیدها\nمدیریت وجوه نقد، کنترل موجودی صندوق و ثبت تنخواه گردان\nهماهنگی با بانک برای نقل و انتقال وجوه و ثبت سندهای بانکی\nکنترل دقیق مانده حساب‌های بانکی و تهیه صورت مغایرت بانکی\nثبت سندهای دریافت و پرداخت در نرم‌افزار حسابداری\nتهیه گزارش جریان نقدی و مانده حساب‌ها به صورت روزانه یا هفتگی\nبایگانی مستندات مالی مربوط به خزانه‌داری\nکنترل پرداخت‌های دوره‌ای شامل اجاره، بیمه، اقساط و ...\nتهیه نامه‌های بانکی، ضمانت‌نامه‌ها و فرم‌های تسهیلات\nهماهنگی برای برداشت یا واریز نقدی و پیگیری اسناد برگشتی\n2سال در حوزه حقوق ودستمزد\nمحاسبه حقوق پایه، اضافه‌کار، عیدی، سنوات، مرخصی و سایر مزایا\nاعمال کسورات قانونی\nتهیه لیست بیمه تأمین اجتماعی و بارگذاری در سامانه‌های مربوطه\nتهیه و ارسال لیست مالیات حقوق به سازمان امور مالیاتی\nکار با نرم‌افزارهای حقوق و دستمزد (همکاران سیستم)\nتهیه گزارش‌های پرسنلی برای مدیران (گزارش کارکرد، سابقه، هزینه منابع انسانی و...)', '2025-12-14 13:26:23', '2025-12-14 13:26:23'),
(8461, 7870, 'رییس حسابداری', 'صنایع فولاد مشیز بردسیر', 'تمام وقت', 'حسابداری', NULL, 1399, NULL, 1402, NULL, '35 تا 40 میلیون تومان', 'سایر موارد', 'مسئول حسابداری حقوق و دستمزد ، محاسبه حقوق و دستمزد و تسویه حساب پرسنل و تهیه و ارائه دیسکت های مربوط به بیمه تامین اجتماعی و سازمان امور مالیاتی مالیات و حسابداری اموال دارایی ثابت و انجام امورات مریوط به موضوع ماده 38 بیمه تامین اجتماعی', '2025-12-14 13:27:05', '2025-12-14 13:29:48'),
(8462, 7870, 'حسابرس', 'سازمان تامین اجتماعی', 'تمام وقت', 'حسابداری', NULL, 1396, NULL, 1399, NULL, 'توافقی', 'سایر موارد', 'حسابرس داخلی سازمان تامین اجتماعی و انجام حسابرسی مالی ، عملیاتی و رعایت  شرکت های زیر مجموعه و ادارات کل استان ها', '2025-12-14 13:28:25', '2025-12-14 13:29:54'),
(8463, 7870, 'رییس حسابداری', 'پارمیس نگین اوستا', 'تمام وقت', 'حسابداری', NULL, 1402, NULL, NULL, 1, '60 تا 70 میلیون تومان', NULL, 'انجام امورات مربوط به محاسبه حقوق و دستمزد و تسویه حساب پرسنل و تهیه و ارائه دیسکت های مربوط به بیمه تامین اجتماعی و سازمان امور مالیاتی و رسیدگی و کنترل  اسناد بازرگانی و مالی جهت ثبت در سیستم مالی و مغایرت گیری بانک ها و شرکت ها و ارائه گزارش های مدیریتی انجام کلیه امور مالیاتی اعم از سامانه جامع تجارت  و اظهارنامه عملکرد سامانه مودیان و ارزش افزوده', '2025-12-14 13:29:40', '2025-12-14 13:29:40'),
