(8475, 7889, 'حسابدار', 'ماهان درمان', 'پاره وقت', 'حسابداری', NULL, 1395, NULL, 1398, NULL, 'توافقی', 'مسائل شخصی', 'در حیطه حسابداری (لیست بیمه- لیست حقوق- ثبت ارزش افزوده و اظهار نامه و معاملات فصلی و کلیه کارهای روتین روزانه ) و در قسمت فروش و اداری کارشناس فروش و خرید و فروش کالاها -امور داخلی شرکت بر عهده اینجانب بوده است', '2025-12-14 14:11:02', '2025-12-14 14:11:02'),
(8476, 7889, 'حسابدار', 'گروه خودرویی دلیلی', 'پاره وقت', 'حسابداری', NULL, 1398, NULL, 1399, NULL, '9 تا 12 میلیون تومان', 'سایر موارد', 'تهیه گزارش بودجه بندی ماهانه-\nتهیه گزارش خرید و فروش\nثبت معاملات فصلی\nلیست حقوق و بیمه پرسنل\nمغایرت گیری کالاهای انبار\nثبت اسناد روزانه و مغایرت گیری بانکی\nثبت ارزش افزوده و اظهار نامه', '2025-12-14 14:11:53', '2025-12-14 14:11:53'),
(8477, 7853, 'حسابدار', 'تابان تابلو شرق', 'تمام وقت', 'معماری و عمران', NULL, 1397, NULL, 1398, NULL, 'قانون کار', 'تاخیر در پرداخت', 'من بعنوان حسابدار در بخش مالی این شرکت مشغول بکار هسم حدود وظایف تعیین شده شامل تنخواه ،مغایرت بانکی و دریافت و پرداخت سندای روزانه می باشد .من بدنبال پیشرفت کاری و ارتقا شغلی در حوزه مالی ومالیاتی می باشم که همه اسرار ورموز حسابداری بیاموزم.', '2025-12-14 14:12:21', '2025-12-14 14:12:21'),
(8478, 7889, 'حسابدار', 'کانون اگهی تبلیغاتی کاوا', 'پاره وقت', 'حسابداری', NULL, 1401, NULL, 1403, NULL, '12 تا 15 میلیون تومان', 'سایر موارد', 'ثبت و صدور فاکتور فروش\nثبت اسناد خرید و فروش\nثبت اسناد روزانه\nمغایرت گیری بانک\nثبت ورود و خروج کالاهای انبار\nثبت لیست حقوق و بیمه پرسنل\nارزش افزوده و اظهار نامه\nثبت معاملات فصلی', '2025-12-14 14:12:45', '2025-12-14 14:12:45'),
(8479, 7889, 'حسابدار', 'شرکت آتیه نگر', 'پروژه ای', 'حسابداری', NULL, 1394, NULL, 1398, NULL, '9 تا 12 میلیون تومان', 'مسائل شخصی', 'کمک حسابدار- ثبت ارزش افزوده و اظهار نامه و معاملات فصلی - مغایرت گیری بانک‌ها و حساب افراد', '2025-12-14 14:13:41', '2025-12-14 14:13:41'),
