(8661, 8016, 'سرپرست حسابداری', 'شرکت پیشرو تجهیز ستاره ملل', 'پاره وقت', 'معماری و عمران', NULL, 1403, NULL, NULL, 1, NULL, NULL, 'ارسال لیست بیمه و مالیات حقوق\nتهیه و تنظیم اظهارنامه ارزش افزوده\nتهیه و ارسال گزارشات معاملات فصلی\nتهیه و ارسال لیست بیمه تامین اجتماعی\nثبت اسناد حسابداری\nمغایرت گیری بانکی\nانجام امور مالیاتی و اعتراض به برگ رسیدگی\nمسلط به حسابداری حقوق و دستمزد\nتهیه و ارسال اظهارنامه عملکرد\nتجربه کار با سیستم تایم شیت علم و صنعت و کنترل تردد ها\nاماده سازی مدارک رسیدگی\nمسلط به سایت تعاون کار و سابقه دفاع در شکایات\nمسلط به سایت تامین اجتماعی و دفاع در هیئت و تعدیل بدهی\nانجام امور تنخواه داری و نظارت بر کار تنخواه\nپاسخ گویی به حسابرس\nانجام تکالیف سامانه مودیان', '2025-12-15 09:05:44', '2025-12-15 09:33:02'),
(8662, 8134, 'سرپرست حسابداری', 'آمود راه', 'تمام وقت', 'حسابداری', NULL, 1403, NULL, NULL, 1, '20 تا 25 میلیون تومان', NULL, NULL, '2025-12-15 09:05:59', '2025-12-15 09:05:59'),
(8663, 8132, 'حسابدار', 'تعاونی فولاد علویجه', 'تمام وقت', 'حسابداری', NULL, 1402, NULL, NULL, 1, 'توافقی', NULL, NULL, '2025-12-15 09:09:59', '2025-12-15 09:09:59'),
(8664, 8016, 'سرپرست حسابداری', 'مرکز رسانه ای شیرازه', 'پاره وقت', 'رسانه و انتشارات', NULL, 1403, NULL, 1404, NULL, NULL, NULL, 'ارسال لیست بیمه و مالیات حقوق\nتهیه و تنظیم اظهارنامه ارزش افزوده\nتهیه و ارسال گزارشات معاملات فصلی\nتهیه و ارسال لیست بیمه تامین اجتماعی\nثبت اسناد حسابداری\nمغایرت گیری بانکی\nانجام امور مالیاتی و اعتراض به برگ رسیدگی\nمسلط به حسابداری حقوق و دستمزد\nتهیه و ارسال اظهارنامه عملکرد\nتجربه کار با سیستم تایم شیت علم و صنعت و کنترل تردد ها\nاماده سازی مدارک رسیدگی\nمسلط به سایت تعاون کار و سابقه دفاع در شکایات\nمسلط به سایت تامین اجتماعی و دفاع در هیئت و تعدیل بدهی\nانجام امور تنخواه داری و نظارت بر کار تنخواه\nپاسخ گویی به حسابرس\nانجام تکالیف سامانه مودیان', '2025-12-15 09:15:10', '2025-12-15 09:33:11'),
(8665, 8135, 'حسابدار', 'سایان پور', 'تمام وقت', 'حسابداری', NULL, 1396, NULL, 1398, NULL, '12 تا 15 میلیون تومان', 'عدم پیشرفت کاری', 'حسابداری حقوق و دستمزد\nحسابداری مالیاتی و بیمه ای(ارزش افزوده-گزارش فصلی-مالیات حقوق-بیمه ماهیانه-انواع برگه تشخیص و قطعی و ...و نحوه برخود با آن)\nحسابداری صنعتی\nبودجه بندی مالی\nحسابداری مقدماتی و ثبت کلیه اسناد و گزارش دهی به مدیران\nمغایرت بانکی\nتحریر دفاتر\nتهیه و ارسال اظهارنامه عمومی سالیانه\nتهیه و تحلیل صورت های مالی\nارتباط با مشتریان و کنترل حساب ها و تحریر و ارسال فاکتور ها رسمی\nنرم افزار مالی در این شرکت رایورز', '2025-12-15 09:15:40', '2025-12-15 09:15:40'),
(8666, 8137, 'رییس حسابداری', 'شركت زرين ستاره پارسا مهر', 'تمام وقت', 'خدمات حسابداری', NULL, 1402, NULL, NULL, 1, '25 تا 30 میلیون تومان', NULL, NULL, '2025-12-15 09:15:45', '2025-12-15 09:15:45'),
(8667, 8016, 'حسابدار', 'سازمان تبلیغات-فرهنگی(امریه سربازی)', 'تمام وقت', 'رسانه و انتشارات', NULL, 1403, NULL, NULL, 1, NULL, NULL, NULL, '2025-12-15 09:17:12', '2025-12-15 09:20:29'),
(8668, 8135, 'رییس حسابداری', 'مهندسین مشاور پارس پرنون', 'پاره وقت', 'حسابداری', NULL, 1398, NULL, NULL, 1, '25 تا 30 میلیون تومان', NULL, 'حسابداری حقوق و دستمزد\nحسابداری مالیاتی و بیمه ای(ارزش افزوده-گزارش فصلی-مالیات حقوق-بیمه ماهیانه-انواع برگه تشخیص و قطعی و ...و نحوه برخود با آن)\nحسابداری پیمانکاری(مقادیر حسن انجام کار-بیمه عمرانی و غ عمرانی-ارزش افزوده و...پروژه ها)\nبودجه بندی مالی\nحسابداری مقدماتی و ثبت کلیه اسناد و گزارش دهی به مدیران\nتهیه صورت مغایرت بانکی\nتحریر دفاتر\nتهیه و ارسال اظهارنامه عمومی سالیانه\nتهیه و تحلیل صورت های مالی\nارتباط با مشتریان و کنترل حساب ها و تحریر و ارسال فاکتور ها رسمی\nمفاصاحساب و امور مربوط به آن\nتهیه صورت وضعیت های فنی و نفر ماهی پروژه ها\nاز زمان مشمول شدن در خدمت به صورت پاره وقت و جنبه کنترلی و راه اندازی سیستم سپیدار\nنرم افزار مالی در این شرکت آرپا و سپیدار\nانتقال سیستم و کدینگ های حسابداری از نرم افزار آرپا به سپیدار \nاستقرار کدینگ مالی در نرم افزار سپیدار', '2025-12-15 09:17:45', '2025-12-15 09:25:46'),
(8669, 8016, 'حسابدار', 'کیامکی جلفا', 'تمام وقت', 'معماری و عمران', NULL, 1401, NULL, 1402, NULL, NULL, 'تاخیر در پرداخت', NULL, '2025-12-15 09:18:48', '2025-12-15 12:09:18'),
(8670, 8135, 'رییس حسابداری', 'کاریز فیدار پویا', 'پاره وقت', 'حسابداری', NULL, 1398, NULL, NULL, 1, '25 تا 30 میلیون تومان', NULL, NULL, '2025-12-15 09:19:35', '2025-12-15 09:19:35'),
(8671, 8016, 'حسابدار', 'مهندسین مشاور رهرو', 'تمام وقت', 'معماری و عمران', NULL, 1399, NULL, 1402, NULL, NULL, 'تاخیر در پرداخت', NULL, '2025-12-15 09:21:54', '2025-12-15 09:21:54'),
(8672, 8135, 'رییس حسابداری', 'ستاد اقامه نماز کشور', 'پاره وقت', 'حسابداری', NULL, 1401, NULL, NULL, 1, '40 تا 45 میلیون تومان', NULL, 'گروزه نرم افزار مالی همکاران سیستم در این سازمان\nحسابداری دولتی \nحسابداری حقوق و دستمزد  \nمالیات حقوق و بیمه ماهیانه \nسند و تنظیم اسناد مالی \nانجام امور تنخواه گردان و ثبت و ضبط اسناد تنخواه \nبررسی سود و زیان پروژه های استانی \nتهیه صورت مغایرت بانکی \nتهیه اظهارنامه های مالیاتی\nتهیه شالوده صورت های مالی براساس استاندارد های جدید \nانبار گردانی و حسابداری انبار \nثبت نامه و کار با اتوماسیون اداری \nانجام امور مالیاتی دارایی و سازمان تامین اجتماعی\nتحریر دفاتر قانونی\nامور مربوط به بانک و ثبت چک در سامانه صیاد\nهتل نیایش زیر مجموعه ستاد اقامه نماز با دو نرم افزار آسا و رایین و انتقال سیستم بین این دو نرم افزار', '2025-12-15 09:25:37', '2025-12-15 09:27:13'),
(8673, 6743, 'حسابدار', 'بازرگاني طوبي', 'تمام وقت', 'حسابداری', NULL, 1399, NULL, 1404, NULL, '25 تا 30 میلیون تومان', 'عدم پیشرفت کاری', 'مدیریت کامل حساب‌های مالی\n	•	تهیه گزارش‌های مالی برای مدیریت\n	•	تحلیل هزینه‌ها و درآمدها\n	•	تهیه اظهارنامه‌های مالیاتی\n	•	آموزش و راهنمایی کارآموزان', '2025-12-15 09:28:41', '2025-12-28 14:51:34'),
