(8874, 8316, 'حسابدار', 'گروه دارویی برکت', 'تمام وقت', 'سرمایه گذاری و تحلیل کسب و کار', NULL, 1402, NULL, NULL, 1, '45 تا 50 میلیون تومان', NULL, 'تهیه صورتهای مالی جداگانه و تلفیقی؛ همکاری مستمر با حسابرسان جهت دریافت گزارش مقبول\nانجام امور مالی، مالیاتی و بیمه‌ای هلدینگ\nانجام کلیه امور دریافت و پرداخت و ارائه گزارش های مدیریتی\nانجام کلیه امور مرتبط با حقوق و دستمزد پرسنل، ارسال لیست بیمه و مالیات حقوق ماهانه\nتنظیم و ارسال کلیه اظهارنامه های مالیاتی شامل اظهارنامه عملکرد موضوع ماده 110 ق م.م؛ ارزش افزوده، صورت معاملات فصلی و کلیه امور مرتبط با سامانه مودیان \nتحلیل و بررسی صورت‌های مالی و ارائه گزارشات به مدیریت\nبرقراری ارتباط با سایر واحدهای سازمانی برای بهبود فرآیندهای مالی\nبررسی و کنترل حساب‌ها و ارائه راهکارهای بهینه‌سازی مالی\nآموزش و راهنمایی کارکنان جدید در زمینه نرم‌افزارهای مالی و حسابداری', '2025-12-17 15:42:09', '2025-12-17 15:42:09'),
(8875, 8316, 'ناظر مالی', 'سازمان بازرسی کل کشور', 'تمام وقت', 'استاندارد و کنترل کیفیت', NULL, 1400, NULL, 1401, NULL, '12 تا 15 میلیون تومان', 'کافی نبودن حقوق', 'مدیریت و هماهنگی پروژه‌های تیمی برای بهبود کارایی و بهره‌وری\nتحلیل داده‌ها و ارائه گزارش‌های ماهانه برای ارزیابی عملکرد سازمان\nتوسعه و بهبود فرآیندهای داخلی با هدف کاهش هزینه‌ها و زمان\nآموزش و راهنمایی اعضای جدید در زمینه روش‌های کاری و مقررات سازمان\nبرگزاری جلسات منظم با تیم‌های مختلف برای تسهیل ارتباط و همکاری بین بخش‌ها', '2025-12-17 15:44:17', '2025-12-17 15:44:17'),
(8876, 8316, 'حسابدار', 'انجمن نفت ایران', 'تمام وقت', 'نفت و گاز', NULL, 1398, NULL, 1400, NULL, '12 تا 15 میلیون تومان', 'عدم پیشرفت کاری', 'مسئول کلیه امور مالی و حسابداری انجمن نفت ایران و نهاد صدور گواهینامه کیفیت\nتهیه و تنظیم قراردادهای کار موقت پرسنل و مسئول انجام کلیه امور حقوق و دستمزد کارکنان شرکت از قبیل ارسال لیست بیمه و لیست مالیات بر حقوق کارکنان در موعد مقرر\nانجام تکالیف قانونی مربوط به ارسال اظهارنامه ارزش افزوده و تکالیف قانونی موضوع ماده 169 مکرر ق م م (معاملات فصلی) در پایان هر فصل\nمسلط به انجام حسابداری پیمانکاری دو طرفه و قراردادهای پیمانکاری موضوع ماده 38 قانون تامین اجتماعی و سایر امور جانبی از قبیل دریافت ردیف پیمان، اخذ مفاصا حساب و...\nآشنایی کامل و انجام امور ثبتی شرکت از قبیل ثبت آگهی تغییرات، اظهارنامه پلمپ دفاتر قانونی موضوع آیین نامه ماده 97 ق م م\nمراجعه به سازمان امور مالیاتی و تامین اجتماعی جهت پیگیری موارد مطروحه در هیئت‌های بدوی و تجدید نظر', '2025-12-17 15:45:19', '2025-12-17 15:45:19'),
(8877, 8316, 'حسابدار', 'پارک علم و فناوری پردیس', 'تمام وقت', 'دولتی', NULL, 1396, NULL, 1398, NULL, '9 تا 12 میلیون تومان', 'مسافت طولانی', 'با توجه به دولتی بودن ماهیت پارک در این مدت تسلطی بر انجام حسابداری دولتی پیدا کردم. در این مدت وظایف گوناگونی از قبیل: مسئول کلیه امور حسابداری مرتبط با درآمدها در پارک؛ مسئول ارائه گزارش به نهادهای نظارتی نظیر وزارت امور اقتصاد و دارایی در خصوص مطالبات و بدهی های سه ماهه و سالانه در سامانه سماد و...', '2025-12-17 15:46:32', '2025-12-17 15:46:32'),
