(8981, 4270, 'سرپرست حسابداری', 'شرکت پرهام آذین براداران', 'پاره وقت', 'کالای مصرفی و خوراکی', NULL, 1400, NULL, 1403, NULL, '20 تا 25 میلیون تومان', 'مسافت طولانی', 'محاسبات حقوق ودستمزد ،-مالیات حقوق - بیمه ، انجام ونظارت بر سامانه مودیان _سامانه جامع تجارت ، سامانه جامع انبارها _ معاملات فصلی _ اظهارنامه ارزش افزوده _ تنخواه\nنظارت بر اسناد حسابداری وحسابداری فروش', '2025-12-21 23:21:39', '2025-12-27 11:36:02'),
(8982, 4270, 'سرپرست حسابداری', 'شرکت کیمیا تجارت حیات', 'پاره وقت', 'کالای مصرفی و خوراکی', NULL, 1398, NULL, 1400, NULL, '15 تا 20 میلیون تومان', 'سایر موارد', 'صدور اسناد حسابداری _ انبار گردانی _ معاملات فصلی _ ارزش افزوده _ مالیات حقوق _ تنخواه _ مغایرت گیری حسابها و حساب‌های بانکی_ سامانه جامع انبارها', '2025-12-21 23:23:13', '2025-12-27 11:31:28'),
(8983, 4270, 'سرپرست حسابداری', 'بازار روز کوثر', 'پاره وقت', 'کالای مصرفی و خوراکی', NULL, 1395, NULL, 1397, NULL, '12 تا 15 میلیون تومان', 'مسائل شخصی', 'تنظیم لیست حقوق و دستمزد _ بررسی تسویه حسابهای شرکتها _ حسابهای مربوط به غرفه ها _ بررسی کارتهای اعتباری _ تنخواه _ لیست بیمه _ مغایرت گیری حسابهای بانکی_ نظارت بر اسناد حسابداری', '2025-12-21 23:24:43', '2025-12-27 11:33:12'),
(8984, 4270, 'حسابدار', 'شرکت نیک پخش برادران', 'پاره وقت', 'کالای مصرفی و خوراکی', NULL, 1381, NULL, 1395, NULL, '9 تا 12 میلیون تومان', 'سایر موارد', 'فاکتورهای خرید و فروش _ تسویه حسابها _ تنخواه _ انبارگردانی _ تنظیم لیست حقوق و دستمزد _ صدور اسناد حسابداری _ بایگانی', '2025-12-21 23:26:10', '2025-12-27 11:34:44'),
(8985, 8410, 'حسابدار', 'شرکت نیکان', 'تمام وقت', 'واردات و صادرات', NULL, 1375, NULL, 1376, NULL, NULL, NULL, 'شرکت بازرگانی و واردات\nمسئول صدور اسناد حسابداری \nمسئول تنخواه گردان \nمسئول محاسبه حقوق و دستمزد \nمسئول خزانه داری', '2025-12-22 10:51:24', '2025-12-22 10:51:24'),
(8986, 8410, 'حسابدار', 'شرکت تولیدی آناهیتا', 'تمام وقت', 'تولید و صنایع', NULL, 1376, NULL, 1380, NULL, NULL, NULL, 'شرکت تولیدی و بازرگانی\nتک حسابدار و مسئول انجام کلیه امورمالی از جمله تنخواه گردان، حقوق و دستمزد، صدور اسناد ، بیمه تامین اجتماعلی و ....\nنرم افزار حسابداری سند پرداز', '2025-12-22 10:52:48', '2025-12-22 10:52:48'),
(8987, 8410, 'رییس حسابداری', 'پرسا رایانه', 'تمام وقت', 'کامپیوتر، فناوری اطلاعات و اینترنت', NULL, 1380, NULL, 1382, NULL, NULL, NULL, 'فعالیت شرکت تولیدی و بازرگانی\nمسئول بررسی اسناد حسابداری و تهیه گزارشات خواسته شده توسط مدیر مالی ، رسیدگی به تنخواه و کنترل و رسیدگی به لیست حقوق و دستمزد پرسنل\nنرم افزار حسابداری رایورز', '2025-12-22 10:54:10', '2025-12-22 10:54:10'),
(8988, 8410, 'مدیر مالی', 'شرکت تجاری بازرگانی پتروسیف', 'تمام وقت', 'نفت و گاز', NULL, 1382, NULL, 1398, NULL, NULL, NULL, 'شرکت بازرگانی بین المللی دارای شعب خارجی\nمدیریت مالی و اداری شرکت و مسئول کنترل ، پیگیری و انجام کلیه فرآیند مالی و مالیاتی شرکت ، مدیریت نقدینگی ، تشکیل و رهبری تیم مالی ، شرکت در هیاتهای حل اختلاف مالیاتی و بیمه و پیگیری پرونده های مالیاتی و بیمه ای شرکت ، تهیه صورتهای مالی و ارائه در مجمع عمومی صاحبان سهام ، طراحی و ارائه گزارشات مالی مورد نیاز مدیرعامل و هیات مدیره ،تهیه گزارش فعالیت هیات مدیره و ارائه در مجمع عمومی سالیانه، مشارکت در تهیه گزارش توجیهی افزایش سرمایه ، تعامل با بانکها و اخذ و تمدید حد اعتباری سالانه و اخذ ضمانتنامه و گشایش اعتبار اسنادی ، نظارت و انجام کلیه نقل و انتقالات ارزی شرکت ، نگهداری از حسابهای طرف حسابهای ارزی و ....\nنرم افزار همکاران سیستم ماژولهای حسابداری ، انبار، خرید و فروش ، حقوق و دستمزد، زیر سیستم ارزی ، خزانه داری', '2025-12-22 10:55:49', '2025-12-22 10:55:49'),
(8989, 8410, 'مدیر مالی', 'شرکت بین المللی پتروتکسان', 'تمام وقت', 'نفت و گاز', NULL, 1398, NULL, 1400, NULL, NULL, NULL, 'شرکت پیمانکاری حوزه نفت و گاز\nتشکیل و رهبری تیم مالی شرکت، بررسی اسناد حسابداری ، کنترل و تایید اظهارنامه های مالیاتی و مالیات بر ارزش افزوده و لیست بیمه تامین اجتماعی و حقوق و دستمزد، نظارت و کنترل خزانه داری ، مذاکره و تعامل با بانکها به جهت اخذ تسهیلات و ضمانتنامه های بانکی ، کنترل و مدیریت نقدینگی ریالی و ارزی شرکت ، و انجام کلیه نقل و انتقالات ارزی ، پیگیری دریافت مطالبات از کارفرمایان، کنترل گزارشات ، اصلاح و به روز رسانی حساب کارفرمایان ( ارزی و ریالی) و پیمانکاران (ارزی و ریالی) ، رسیدگی به حسابها ، کنترل و رسیدگی به دفاتر شرکتهای زیرمجموعه ، خرید و استقرار ماژولهای جدید نرم افزار راهکاران ، مشارکت در تهیه صورتهای مالی و گزارشات مربوطه ، همکاری با حسابرسان و اخذ گزارش حسابرسی ، شرکت در جلسات مجامع عمومی شرکت و شرکتهای تابعه ، ....\nنرم افزار راهکاران سیستم ماژولهای حسابداری، انبار، زیر سیستم ارزی، حقوق و دستمزد، خزانه داری', '2025-12-22 10:57:33', '2025-12-22 10:57:33'),
(8990, 8410, 'مدیر مالی', 'شرکت فولاد امیر کبیر خزر', 'تمام وقت', 'تولید و صنایع', NULL, 1400, NULL, 1401, NULL, NULL, NULL, 'شرکت تولیدی\nبررسی و کنترل حساب طرف حسابها و دفاتر مربوط سنوات گذشته، اصلاح و به روز رسانی حسابها ، بررسی و کنترل حساب مشارکت جاری و مشارکتهای قبلی ، بررسی و کنترل بهای تمام شده ماهانه و گزارش سود و ریان ماهانه و سود و زیان مشارکت ، مدیریت نقدینگی شرکت، طراحی و ارائه گزارشات مدیریت و ارائه به هیات مدیره و مدیرعامل ، پیگیری و اصلاح پرونده ها و گزارشات مالیاتی سنوات قبل و جاری شرکت، شرکت در هیاتهای مربوط به پرونده های سازمان تامین اجتماعی تا دریافت رای مطلوب، مذاکره با سازمانها و نهادهای مربوطه و ترتیب رفع بدهی ها و تقسیط بدهی های گذشته شرکت به سازمان امورمالیاتی و سازمان تامین اجتماعی،  کنترل و تایید گزارشات و اظهارنامه های مالیات بر ارزش افزوده و مالیات عملکرد شرکت، استقرار نرم افزار جدید که قبلا خریداری شده بود و استقرار نیافته بوده است، به روزرسانی و اصلاح ساختار گردش کار مالی با دیگر واحدهای شرکت ، کار با نرم افزار سیاق و همکاری در استقرار نرم افزار ایریسا', '2025-12-22 10:58:59', '2025-12-22 10:58:59'),
(8991, 8410, 'مدیر مالی', 'شرکت بازرگانی خرد آریا', 'تمام وقت', 'واردات و صادرات', NULL, 1401, NULL, 1402, NULL, NULL, NULL, 'شرکت بازرگانی\nاصلاح و به روزرسانی   سیستم مالی و حسابهای شرکت (ارزی و ریالی) ، اصلاح تیم مالی شرکت ، پیگیری و اصلاح روند پرونده های مالیاتی شرکت ، کنترل و تایید گزارشات اظهار نامه مالیات بر ارزش افزوده و مالیات عملکرد ، پیگیری پرونده های مالیاتی شرکت ، پیگیری پرونده های تامین اجتماعی شرکت ، تهیه لوایح دفاعیه و شرکت در جلسات هیاتهای حل اختلاف بیمه و مالیات، همکاری با مدیرعامل جهت بهینه سازی امور در دست اجرا و تعریف روال کار سازمانی و علی الخصوص واحد مالی و بازرگانی شرکت، ایجاد سیستم برای محاسبه بهای تمام شده کالاهای خریداری شده، تهیه صورتهای مالی و مشارکت در فرآیند حسابرسی و اخذ گزارش حسابرسی\nنرم افزار سپیدار ماژولهای حسابداری ، انبار و حقوق و دستمزد', '2025-12-22 11:00:10', '2025-12-22 11:00:10'),
(8992, 8410, 'مدیر مالی', 'شرکت آریا پیشرو قرن', 'تمام وقت', 'نفت و گاز', NULL, 1403, NULL, NULL, 1, NULL, NULL, 'مدیر مالی طرح PDH - PP مربوط به شرکت پتروشیمی پارس که اینجانب به عنوان مدیر مالی طرح از طرف شرکت آریا پیشرو قرن (مدیریت طرح ) مشغول به کار میباشم و طرح شامل چندین پروژه با پیمانکاران مختلف میباشد.', '2025-12-22 11:01:45', '2025-12-22 11:01:45'),
