(9215, 8685, 'حسابدار', 'تجهیزصنعت نصیرپور', 'تمام وقت', 'واردات و صادرات', NULL, 1398, NULL, 1401, NULL, 'توافقی', 'نداشتن بیمه', 'به مدت 3سال به عنوان حسابدار در شرکت تجهیزصنعت نصیرپور در شیراز مشغول به کار  شدم و سال آخر به عنوان مسول امور مالی همان شرکت مشغول بودم در آخر به دلیل نداشتن بیمه استفا دادم.', '2025-12-26 18:16:45', '2025-12-26 18:16:45'),
