(9257, 8725, 'حسابدار', 'بیمارستان ولیعصر تبریز', 'تمام وقت', 'خدمات درمانی، پزشکی و سلامت', NULL, 1397, NULL, NULL, 1, '30 تا 35 میلیون تومان', 'سایر موارد', 'مشغول هستم', '2025-12-27 08:55:34', '2025-12-27 09:12:50'),
(9258, 8728, 'کمک حسابدار', 'داتیس آسانسور فران', 'پاره وقت', 'معماری و عمران', NULL, 1403, NULL, 1404, NULL, NULL, 'کافی نبودن حقوق', 'به علت بیمه نشدن و کافی نبودن حقوق \nو من دانشجو بودم قبول نمیکردن که بیمه بشم \nمن کمک حسابدار بودم \nو فاکتور و بانک و مغایرت بانک و واریز و پرداخت \nدریافت چک و ثبت چک', '2025-12-27 09:21:30', '2025-12-27 09:21:30'),
(9259, 8728, 'حسابرس', 'حسابرسی آپادانا', 'پاره وقت', 'خدمات حسابداری', NULL, 1404, NULL, NULL, 1, '15 تا 20 میلیون تومان', NULL, 'من می‌خوام در کنار حسابرسی کار حسابداری رو به صورت پاره وقت انجام بدم \nوظایف \nوارد کردن کاربرگ\nعطف زدن \nو....', '2025-12-27 09:24:02', '2025-12-27 09:24:02'),
(9260, 8727, 'حسابدار', 'ایران رهجو .تهران', 'تمام وقت', 'حسابداری', NULL, 1387, NULL, 1392, NULL, 'توافقی', 'سایر موارد', 'از سال ۹۴ در قزوین فعالیت داشته ام\nچای دبش که در آن مشغول به کار بوده \nو\nشرکت برج و باروی قزوین، \nآزمایشگاه فنی و مکانیک خاک چهلستون،\nشرکت مهندسی معماری محیط \nکه به صورت دور کاری وپروژه ای در آن مشغول به کار میباشم', '2025-12-27 09:45:17', '2025-12-27 09:50:44'),
(9261, 8733, 'حسابدار', 'گروه قطعات خودرویی عظام', 'تمام وقت', 'خودروسازی', NULL, 1402, NULL, NULL, 1, '45 تا 50 میلیون تومان', NULL, 'از سال 1402 در شرکت گروه قطعات خودرویی عظام مشغول ب کار هستم \nحسابداری فروش - کارشناس مالی و در حال حاضر کارشناس حقوق و دستمزد هستم', '2025-12-27 09:56:45', '2025-12-27 09:56:45'),
(9262, 8733, 'سرپرست حسابداری', 'کیمیا تدبیر', 'تمام وقت', 'خودروسازی', NULL, 1401, NULL, 1402, NULL, '12 تا 15 میلیون تومان', 'مسائل شخصی', NULL, '2025-12-27 09:57:39', '2025-12-27 09:57:39'),
(9263, 8733, 'حسابدار', 'پتروناک', 'تمام وقت', 'نفت و گاز', NULL, 1399, NULL, 1401, NULL, '9 تا 12 میلیون تومان', 'عدم پیشرفت کاری', 'کارشناس خزانه و حسابداری فروش', '2025-12-27 09:58:22', '2025-12-27 09:58:22'),
(9264, 8731, 'رییس حسابداری', 'شرکت روند آب آذر', 'تمام وقت', 'خدمات حسابداری', NULL, 1388, NULL, 1398, NULL, 'توافقی', 'سایر موارد', 'حسابدار مالی در شرکت فن آوران جغاتو به صورت پروژه‌ای \nحسابدار مالی و مالیاتی در شرکت آباد بنای فاخر به صورت پروژه ای \nحسابدار مالی در شرکت فانار به صورت پروژه ای', '2025-12-27 10:05:17', '2025-12-27 10:05:17'),
(9265, 8732, 'حسابدار', 'میلاک', 'تمام وقت', 'تولید و صنایع', NULL, 1400, NULL, 1402, NULL, 'توافقی', 'سایر موارد', 'امور اداری\nاداره کار و بیمه و بانک\nحقوق دستمزد\nلیست بیمه\nنرم افزار حضور و غیاب علم و صنعت\nنرم افزار اکسل و سپیدار بخش حقوق دستمزد', '2025-12-27 10:05:30', '2025-12-27 10:05:30'),
(9266, 8732, 'حسابدار', 'ریخته گری افرا', 'تمام وقت', 'تولید و صنایع', NULL, 1402, NULL, 1403, NULL, '9 تا 12 میلیون تومان', 'کافی نبودن حقوق', 'حسابدار خرید و فروش\nوثبت اسناد\nبانرم افزار آسان', '2025-12-27 10:08:09', '2025-12-27 10:08:09'),
(9267, 8732, 'حسابدار', 'قائم سوله', 'تمام وقت', 'تولید و صنایع', NULL, 1402, NULL, NULL, 1, '20 تا 25 میلیون تومان', NULL, 'حسابدار خرید و فروش\nحسابدار حقوق و دستمزد\nامور اداری\nارسال لیست بیمه\nثبت اسناد\nامور بانکی\nچک و تنخواه و بانک و پرداخت و دریافت\nکار با نرم افزار هلو و اسان', '2025-12-27 10:12:57', '2025-12-27 10:13:42'),
