(9316, 8813, 'حسابدار', 'فروشگاه فرش و موکت', 'پاره وقت', 'حسابداری', NULL, 1401, NULL, NULL, 1, '12 تا 15 میلیون تومان', NULL, 'در مجموعه حسابداری ناجی / سرپرست حسابدار\nدر مجموعه حسابداری نوین  / سرپرست حسابدار\nدر رستوران سیبو \nصنایع چوب عبداله پور \nتو شرکت پیمانکاری\nسمت حسابدار\nالان در حال حاضر در فروشگاه فرش و موکت بصورت پاره وقت مشغول هستم', '2025-12-28 18:53:08', '2025-12-28 19:12:39'),
