(9359, 6042, 'سرپرست حسابداری', 'گرین وب سامانه نوین', 'تمام وقت', 'خدمات حسابداری', NULL, 1396, NULL, 1403, NULL, '20 تا 25 میلیون تومان', 'سایر موارد', NULL, '2025-12-29 14:52:31', '2025-12-29 14:52:47'),
(9360, 8854, 'کمک حسابدار', 'بازنشستگان ارتش', 'تمام وقت', 'حسابداری', NULL, 1403, NULL, 1404, NULL, 'توافقی', 'عدم پیشرفت کاری', NULL, '2025-12-29 19:29:16', '2025-12-29 19:29:16'),
(9361, 8854, 'حسابدار', 'شرکت حسابرسی', 'تمام وقت', 'حسابداری', NULL, 1404, NULL, 1404, NULL, 'توافقی', 'مسائل شخصی', NULL, '2025-12-29 19:30:16', '2025-12-29 19:30:16'),
(9362, 8853, 'حسابدار', 'بازرگانی پارس آمنا قشم', 'تمام وقت', 'واردات و صادرات', NULL, 1396, NULL, 1402, NULL, '12 تا 15 میلیون تومان', 'مسائل شخصی', 'این شرکت وارد کننده مواد اولیه کاشی و سرامیک می باشد. در طول سالیان کلیه وظایف حسابداری به عهده اینجانب بوده که شامل:\nثبت کلیه تراکنش های بانکی و صدور اسناد حسابداری.\nآماده کردن گزارشات ارزش افزوده و معاملات فصلی.\nکار با سامانه مودیان.\nتهیه اظهارنامه مالیاتی عملکرد و اجاره.\nآشنایی با پروسه های مالیاتی از برگ تشخیص تا برگ قطعی و هیأت های مالیاتی.\nتهیه لایحه مالیاتی، مدارک مربوطه و شرکت در جلسات با ممیز و هییت های مالیاتی.\nانجام امور اداری ،بایگانی و نامه نگاری.\nتهیه و تحلیل صورت های مالی.\nتحریر دفاتر روزنامه و کل و نحوه ثبت دفاتر.\nپروسه ی پایان سال مالی شامل تهیه ترازهای آزمایشی، صدور اسناد موقت و دایم و...\nارسال لیست بیمه و مالیات در سامانه های مربوطه.\nمحاسبات حقوق، مالیات حقوق، بیمه و مزایا.\nآشنایی با روند کاری حسابرسان و تعامل با ایشان.\nمسلط به نرم افزار حسابداری امین سیستم. آشنا با نرم افزار سپیدار، نوسا، تدبیر و پیوست.\nصدور فاکتور فروش و ثبت سامانه مویان.\nرفع مغایرت با مشتریان، پیگیری مانده حسابها.\nثبت چک های صیادی، عملیات خزانه داری و پیگیری چک های برگشتت\nمحاسبات بهای تمام شده', '2025-12-29 19:42:22', '2025-12-29 19:42:22'),
(9363, 8857, 'حسابدار', 'داتا ارتباط', 'تمام وقت', 'حسابداری', NULL, 1403, NULL, NULL, 1, '15 تا 20 میلیون تومان', NULL, NULL, '2025-12-29 20:32:29', '2025-12-29 20:32:29'),
(9364, 8855, 'حسابدار', 'تولیدی چرم پارس', 'تمام وقت', 'تولید و صنایع', NULL, 1397, NULL, 1401, NULL, 'قانون کار', 'عدم پیشرفت کاری', '4 سال تجربه حسابداری با نرم افزار سپیدار در ماژول های خرید و فروش،تامین کنندگان و انبار،حسابداری و دریافت و پرداخت بودم و گزارش سازی در اکسل و کارهای بانکی و ثبت سند و پیگیری مطالبات را انجام میدادم.تجربه خیلی خوبی بود ولی فرصت افزایش حقوق و ارتقا سمت به من داده نشد.', '2025-12-29 20:35:40', '2025-12-29 20:35:40'),
