(9453, 8972, 'رییس حسابداری', 'استیل برنز اپادانو', 'پاره وقت', 'نفت و گاز', NULL, 1400, NULL, NULL, 1, '15 تا 20 میلیون تومان', NULL, 'دارای 15 سال سابقه‌ی مستمر و تخصصی در حوزه‌ی حسابداری مالی، با تجربه‌ی عملی در اصناف و شرکت‌های متنوع از جمله بازار اتصالات،لوازم یدکی، پوشاک، پارچه و واحدهای تولیدی. تسلط کامل به امور مالی شرکت‌ها، از جمله کنترل حساب‌ها، مغایرت‌گیری بانکی، تهیه گزارش‌های مالی، بهای تمام‌شده، تنظیم قراردادها، امور مالیاتی، بیمه، حقوق و دستمزد، و تحلیل‌های مالی دقیق.\nآشنا با قوانین مالیاتی، دفاتر قانونی. مسلط به مجموعه‌ای از نرم‌افزارهای مالی و حسابداری شامل: سپیدار، محک، پارمیس، هلو، شایگان و دیگر نرم‌افزارهای رایج این حوزه. همچنین توانمند در استفاده‌ی حرفه‌ای از نرم‌افزارهای Word، Excel، PowerPoint و OneNote.\nدر حال حاضر به‌عنوان مدیر مالی پاره‌وقت با چهار شرکت فعال در حوزه‌های مختلف همکاری دارم:\nاستیل برنز آپادانا\nکارگِت\nمؤسسه اقدام برای کاهش آلام\nتجارت فن آوران گستر\nتوانایی مدیریت هم‌زمان چند مجموعه‌ی مالی، نظم و دقت بالا، سرعت عمل در حل مسائل مالی، و استقلال کاری، از ویژگی‌های برجسته‌ای است که امکان فعالیت حرفه‌ای و موفق به‌صورت پاره‌وقت را برای من فراهم کرده است.', '2026-01-03 13:54:19', '2026-01-03 13:54:19'),
(9454, 8973, 'حسابدار', 'پروتئینی برادران صالحی،شرکت پرند توس', 'پاره وقت', 'حسابداری', NULL, 1399, NULL, NULL, 1, '15 تا 20 میلیون تومان', NULL, NULL, '2026-01-03 14:42:26', '2026-01-03 14:42:26'),
