(9460, 8980, 'حسابدار', 'کاشان رایانه', 'تمام وقت', 'خدمات حسابداری', NULL, 1376, NULL, 1380, NULL, NULL, NULL, NULL, '2026-01-04 07:10:39', '2026-01-04 07:10:39'),
