(9462, 8980, 'حسابدار', 'مجموعه شرکتهای مهندسین عمران مارون', 'تمام وقت', 'خدمات حسابداری', NULL, 1385, NULL, 1390, NULL, NULL, NULL, '- بررسی و ثبت اسناد مالی ، گزارش گیری و تهیه صورتهای مالی \n- پشتیبانی پروژه های عمرانی در زمینه حسابداری و هزینه یابی', '2026-01-04 07:12:27', '2026-01-04 07:12:27'),
(9463, 8980, 'رییس حسابداری', 'صنایع بتنی و فلزی گسترش ماناساز آبیک', 'تمام وقت', 'خدمات حسابداری', NULL, 1390, NULL, 1395, NULL, NULL, NULL, '- طراحی و اجرای سیستم مالی یکپارچه برای دفتر مرکزی و کارگاهها\n- تهیه بهای تمام شده تیرهای بتنی و گزارش های تحلیلی مالی\n- تهیه صورتهای مالی و گزارش های مدیریتی و بودجه عملیاتی\n- اصلاح اسناد مالی سنواتی و بستن حسابها\n- استقرار و مدیریت کامل راهکاران همکاران سیستم و ماژولهای مالی و آموزش تیم مالی\n- مدیزیت حسابداری پیمانکاری و صنعتی ، انبارگردانی ، و تعیین خط مشی صدور اسناد مالی', '2026-01-04 07:14:59', '2026-01-04 07:14:59'),
(9464, 8980, 'حسابدار', 'شرکت گسترش و نوسازی صنایع ایرانیان مانا', 'تمام وقت', 'خدمات حسابداری', NULL, 1395, NULL, NULL, 1, NULL, NULL, '- استقرار و مدیریت سیستم راهکاران تحت وب و ماژولهای مالی .\n- طراحی کدینگ استاندارد مالی ، انبار و دارایی ثابت .\n- تهیه صورتهای مالی ، گزارش های مدیریتی و بودجه عملیاتی .\n- حسابداری پیمانکاری و کنترل هزینه پروژه ها\n- مسئول انبارگردانی و کنترل اموال در سطح شرکت\n- تهیه و ارسال اظهارنامه های مالیاتی ، ارزش افزوده و سامانه مودیان\n- پاسخگویی به حسابرس ها و ممیزین مالیاتی و تامین اجتماعی', '2026-01-04 07:15:45', '2026-01-04 07:15:45'),
(9465, 5799, 'کمک حسابدار', 'موسسه اعتباری توسعه', 'تمام وقت', 'وکالت و حقوقی', NULL, 1397, NULL, 1398, NULL, NULL, NULL, 'مدیریت تنخواه و هزینه های جاری شرکت \nثبت فاکتور های خرید و فروش\nثبت هزینه ها و درآمدها\nتهیه و بایگانی اسناد مالی\nانجام امور بانکی و خزانه داری', '2026-01-04 08:51:38', '2026-01-04 08:51:38'),
(9466, 5799, 'حسابدار', 'استارت آپ 2806', 'تمام وقت', 'تبلیغات، بازاریابی و برند سازی', NULL, 1398, NULL, 1400, NULL, NULL, NULL, 'مدیریت تنخواه و هزینه های جاری شرکت \nثبت فاکتور های خرید و فروش\nثبت هزینه ها و درآمدها\nتهیه و بایگانی اسناد مالی\nانجام امور بانکی و خزانه داری', '2026-01-04 08:53:01', '2026-01-04 08:53:01'),
(9467, 5799, 'حسابدار', 'عمران تحکیم فیدار پیشرو', 'تمام وقت', 'معماری و عمران', NULL, 1400, NULL, 1401, NULL, NULL, NULL, 'ثبت و کنترل کلیه اسناد مالی پروژه‌ها\nکنترل و ثبت فاکتورها و صورت‌حساب پیمانکاران\nتنظیم لیست حقوق و دستمزد پرسنل کارگاه و دفتر مرکزی، ارسال بیمه و مالیات حقوق\nصدور و کنترل اسناد بانکی (چک‌ها، حواله‌ها، وصول مطالبات از کارفرما)\nنگهداری دفاتر قانونی و تهیه گزارشات فصلی ماده 169 ق.م.م', '2026-01-04 08:54:21', '2026-01-04 08:54:21'),
(9468, 5799, 'حسابدار', 'هلدینگ تامین سرمایه سلامت', 'تمام وقت', 'خدمات درمانی، پزشکی و سلامت', NULL, 1402, NULL, 1402, NULL, NULL, NULL, '• کنترل و ثبت دقیق کلیه عملیات بانکی\n• تهیه، بررسی و تطبیق صورت‌های مغایرت بانکی\n• مدیریت چک‌ها و اسناد دریافتنی و پرداختنی\n• هماهنگی مستمر با بانک‌ها و پیگیری امور مرتبط\n• انجام پرداخت‌ها و دریافت‌ها مطابق مقررات مالی شرکت\n• ثبت، بایگانی و نگهداری منظم اسناد و مدارک پرداختنی', '2026-01-04 08:55:43', '2026-01-04 08:55:43'),
(9469, 5799, 'حسابدار', 'آژانس رسانه ای وارکت', 'تمام وقت', 'رسانه و انتشارات', NULL, 1403, NULL, NULL, 1, NULL, 'کافی نبودن حقوق', '• تهیه و تنظیم اسناد و مدارک حسابداری\n• تهیه و کنترل صورت مغایرت بانکی\n• تنظیم و ارسال اظهارنامه‌های عملکرد و مالیات بر ارزش افزوده\n• تسلط بر سامانه مؤدیان و درگاه‌های مالیاتی مرتبط\n• آشنایی کافی با قوانین مالیاتی، بیمه و الزامات حسابداری', '2026-01-04 08:57:04', '2026-01-04 08:57:04'),
(9470, 8982, 'حسابدار', 'موسسه اندیشه توانای علوی', 'تمام وقت', 'منابع انسانی', NULL, 1402, NULL, NULL, 1, '20 تا 25 میلیون تومان', NULL, NULL, '2026-01-04 09:37:00', '2026-01-04 09:37:00'),
(9471, 8984, 'حسابدار', 'قبلا کارآموزی شرکت بیمه تامین اجتماعی', 'پاره وقت', 'حسابداری', NULL, 1404, NULL, NULL, 1, NULL, NULL, 'فعلا که هنوز وارد کار نشدم \nوالان دنبال کارآموزی هستم و وارد بازارکار بشم که زودتر برم سرکار کار کنم و حقوق در بیارم', '2026-01-04 09:59:15', '2026-01-04 09:59:15'),
