(9539, 6237, 'حسابدار', 'نصب سازه مقاوم', 'تمام وقت', 'حسابداری', NULL, 1403, NULL, 1404, NULL, '20 تا 25 میلیون تومان', 'سایر موارد', NULL, '2026-01-07 08:05:51', '2026-01-07 08:05:51'),
(9540, 9056, 'حسابدار', 'کاشی و سرامیک برلیان', 'تمام وقت', 'تولید و صنایع', NULL, 1402, NULL, NULL, 1, NULL, NULL, 'از شهریور ماه سال 1402 به عنوان حسابرس داخلی در شرکت کاشی و سرامیک برلیان رفسنجان مشغول فعالیت شدم. وظایف من شامل کنترل دستور پرداخت‌ها، اعلامیه های واریزی، تهیه و کنترل گزارشات فصلی و ماهیانه، مقایسه گزارشات فروش و موارد مشابه می‌شد. هم اکنون به عنوان حسابدار انبار نیز در این شرکت مشغول به کار هستم. وظایف حسابداری انبار عبارتند از ثبت اسناد خرید و مصرف انبار، کنترل رسید انبار و ارائه گزارشات اصلاح کدینگ و اختلاف نرخ.', '2026-01-07 08:12:31', '2026-01-07 08:12:31'),
(9541, 9056, 'حسابدار', 'نوین پنجره اطلس کویر', 'پاره وقت', 'تولید و صنایع', NULL, 1402, NULL, NULL, 1, NULL, NULL, 'به عنوان حسابدار در شرکت نوین پنجره اطلس کویر به صورت پاره وقت، مسئولیت ثبت فاکتورهای خرید و فروش، ارسال صورت وضعیت کارکرد قراردادها، ارسال فاکتورهای سامانه مودیان و انجام امور جاری حسابداری را بر عهده دارم.', '2026-01-07 08:15:39', '2026-01-07 08:15:39'),
(9542, 9056, 'حسابدار', 'بازرگانی بمانی', 'پاره وقت', 'کشاورزی', NULL, 1402, NULL, NULL, 1, NULL, NULL, 'در بازرگانی بمانی به عنوان حسابدارپاره وقت، وظایف من شامل ثبت فاکتورهای خرید و فروش پسته در بازارهای داخلی و صادراتی، ثبت کدهای تولیدی انواع پسته و کنترل دقیق ورودی و خروجی محصولات انبار میباشد.', '2026-01-07 08:16:39', '2026-01-07 08:16:39'),
(9543, 9056, 'حسابدار', 'جواهری پور میرزایی', 'پاره وقت', 'سرمایه گذاری و تحلیل کسب و کار', NULL, 1403, NULL, 1404, NULL, NULL, NULL, 'به عنوان حسابدار در جواهری پور میرزایی به صورت پاره وقت مشغول به کار بودم. وظایف من شامل ثبت و کنترل فاکتورهای خرید و فروش طلا، مغایرت گیری با طرف حساب های بانکی و کیفی و آب‌شده طلافروشی بود.', '2026-01-07 08:18:09', '2026-01-07 08:18:09'),
(9544, 9056, 'حسابدار', 'تعاونی روستایی اسلام', 'تمام وقت', 'کشاورزی', NULL, 1399, NULL, 1402, NULL, NULL, 'مسائل شخصی', 'به عنوان حسابدار در شرکت تعاونی روستایی اسلام مشغول به کار بوده و تا پایان تیرماه 1402 مسئولیت‌های مرتبط با امور مالی را بر عهده داشتم. این شرکت در زمینه ارائه خدمات خدماتی و بازرگانی، صنایع تبدیلی، بسته بندی و توزیع محصولات کشاورزی و دامی فعالیت می‌نماید.', '2026-01-07 08:19:04', '2026-01-07 09:43:54'),
(9545, 9056, 'کمک حسابدار', 'صندوق کار آفرینی امید', 'کارآموزی', 'مالی و اعتباری', NULL, 1397, NULL, 1399, NULL, NULL, NULL, 'به مدت دو سال به عنوان کارآموز در صندوق کارآفرینی امید فعالیت نمودم. وظایف من شامل افتتاح حساب مشتریان، وصول مطالبات، پرداخت وام و انجام امور بانکی بود.', '2026-01-07 08:20:38', '2026-01-07 08:20:38'),
(9546, 9056, 'حسابدار', 'دبیرانجمن علمی-دانشجویی دانشگاه', 'کارآموزی', 'آموزش، مدارس و دانشگاهها', NULL, 1393, NULL, 1398, NULL, NULL, NULL, 'به عنوان دبیر انجمن علمی-دانشجویی دانشگاه پیام نور، همزمان با تحصیل، از تاریخ ذکر شده همکاری خود را آغاز نمودم. وظایف من در این دوره شامل برگزاری جلسات آموزشی برای دانشجویان، برگزاری نمایشگاه کتاب و کارگاه های آموزشی، سردبیری نشریه انجمن علمی، چاپ و انتشار گاهنامه دانشجویی، تدریس نرم افزارهای حسابداری به دیگر دانشجویان، شرکت در جلسات هم اندیشی و جلسات فرهنگی با معاون امور فرهنگی و ریاست دانشگاه بود. در طول این همکاری، تسلط بر نرم افزارهای حسابداری، مهارت تدریس دانشجویی و آشنایی با فنون سخنرانی و گفتگو در جمع دانشجویی را کسب نمودم.', '2026-01-07 08:22:21', '2026-01-07 08:22:21'),
(9547, 9056, 'حسابدار', 'تعاونی خدماتی فنی مهندسی افق فردا', 'تمام وقت', 'تبلیغات، بازاریابی و برند سازی', NULL, 1393, NULL, 1397, NULL, NULL, NULL, 'در کنار فعالیت‌های هلال احمر و تحصیل در دانشگاه پیام نور، به عنوان کارمند بخش حسابداری و بازاریابی در شرکت تعاونی خدماتی فنی مهندسی افق فردا مشغول به کار شدم. وظایف من شامل تهیه طرح‌های توجیهی با نرم افزارهای Excel و Word، نامه نگاری با ادارات و شرکت‌های داخلی، تایپ طرح‌های توجیهی، پر کردن فرم‌های جهاد کشاورزی و نظام مهندسی، ثبت انواع برند های تجاری، پشتیبانی سایت‌های تجاری و پیگیری امور اداری بود. در این مدت، به طور کامل با نرم افزار Excel آشنا شدم و مهارت کافی در نرم افزارهای حسابداری پاتریس و هلو کسب کردم. همچنین تسلط بر اینترنت، آشنایی با GPS، نرم افزارهای 3Dmax، Google Earth و Map source را بدست آوردم. علاوه بر آن، آشنایی کامل با نحوه صدور انواع مجوز های کشاورزی و صنعتی، ثبت برند و پشتیبانی سایت‌های تجاری را به دست آوردم.', '2026-01-07 08:23:25', '2026-01-07 09:44:03'),
(9548, 9056, 'کمک حسابدار', 'جمعیت هلال احمر', 'کارآموزی', 'سازمانهای مردم نهاد', NULL, 1392, NULL, 1395, NULL, NULL, NULL, 'به عنوان کارمند روابط عمومی هلال احمر، از تاریخ ذکر شده در پست، مسئولیت‌های ذیل را بر عهده داشتم:\n• ثبت نام اعضا و تشکیل پرونده آن‌ها\n• نگارش نامه‌ها به ادارات مختلف\n• تکمیل گزارش کار روزانه، هفتگی و ماهانه\n• تایپ و صدور گواهینامه‌ها\n• شرکت در دوره‌های امدادی\nدر این دوره، توانستم مهارت‌های زیر را کسب کنم:\n• تایپ سریع و تسلط بر نرم‌افزار Word\n• شیوه نگارش نامه‌های اداری\n• آشنایی با نرم‌افزارهای طراحی گرافیکی مانند فتوشاپ\n• تسلط بر مهارت جستجوی پیشرفته در اینترنت', '2026-01-07 08:24:32', '2026-01-07 08:24:32'),
(9549, 8958, 'کمک حسابدار', 'دماگستران', 'تمام وقت', 'حسابداری', NULL, 1402, NULL, 1403, NULL, 'توافقی', 'سایر موارد', 'سابقه ی کار در دفتر انتشارات به عنوان مسئول انتشارات.', '2026-01-07 16:26:55', '2026-01-09 14:56:40'),
