(9567, 9080, 'سرپرست حسابداری', 'گل پخش اول', 'تمام وقت', 'کالای مصرفی و خوراکی', NULL, 1388, NULL, 1392, NULL, NULL, 'سایر موارد', 'ثبت اسناد و مدارک مالی در سیستم\nانجام کلیه امور خزانه داری (ثبت اسناد و وجوه نقد خزانه و انتقال آنها به بانک)\nتهیه گزارشات فصلی آفلاین و ارزش افزوده شعبه', '2026-01-28 14:36:25', '2026-01-28 14:36:25'),
(9568, 9080, 'حسابرس', 'شونیز (داداش برادر)', 'تمام وقت', 'کالای مصرفی و خوراکی', NULL, 1393, NULL, 1398, NULL, NULL, 'مسائل شخصی', 'کنترل اسناد و مدارک شرکتهای زیر مجموعه\nانجام ماموریت جهت حسابرسی داخلی ( کنترل اسناد مالی ، شمارش وانبارگردانی ، کنترل اسناد صندوق و تنخواه ،...)\nتهیه گزارشات فصلی و ارزش افزوده شرکتها \nانبار گردانی و بستن حسابهای پایان سال کارخانه', '2026-01-28 14:37:51', '2026-01-28 14:37:51'),
(9569, 9080, 'رییس حسابداری', 'آرمان رایان پویا', 'تمام وقت', 'کامپیوتر، فناوری اطلاعات و اینترنت', NULL, 1398, NULL, NULL, 1, NULL, 'مسائل شخصی', 'کارشناس ارشد حسابداری بهای تمام شده و سفارشات خارجی\nسرپرست کلیه واحد‌های حسابداری خزانه،فروش،انبار،...\nتهیه و گزارش گزارشات مدیریتی \n محاسبات نرخ ارز و بهای تمام شده کالاهای وارداتی و تسعیر ارز\nتهیه گزارشات فصلی ارزش افزوده و سامانه خرید و فروش فصلی \nتهیه اسناد مدارک جهت رسیدگی سازمانهای دولتی (دارایی،بیمه,گمرک)\nحضور در سازمانهای دولتی(دارایی،بیمه) جهت هیئت های رسیدگی کننده\nتهیه کلیه کاربرگ های اکسل مالی ضروری جهت گزارش دهی آنی به مدیران ارشد سازمان\nتهیه صورت سود و زیان ، تهیه صورتهای مالی و نسبت‌های حسابداری\nتحلیل حسابها و تهیه گزارشات مدیریتی', '2026-01-28 14:39:20', '2026-01-28 14:39:20'),
(9570, 9082, 'مدیر مالی', 'تجهیز صنعت سفیر', 'پاره وقت', 'خدمات حسابداری', NULL, 1388, NULL, NULL, 1, '12 تا 15 میلیون تومان', NULL, 'انجام کلیه امور مالیاتی شرکت', '2026-01-29 06:37:22', '2026-01-29 06:37:22'),
(9571, 9082, 'مدیر مالی', 'ارمغان پاک نیروانا', 'پاره وقت', 'خدمات حسابداری', NULL, 1394, NULL, NULL, 1, '40 تا 45 میلیون تومان', NULL, 'انجام کلیه امور مالیاتی شرکت', '2026-01-29 06:49:16', '2026-01-29 06:49:16'),
(9572, 3612, 'حسابدار', 'شرکت عمارت سازه سورنا', 'تمام وقت', 'حسابداری', NULL, 1404, NULL, NULL, 1, '30 تا 35 میلیون تومان', NULL, 'انجام همه ی امور جاری حسابداری و تکالیف قانونی مربوط به حسابداری شرکت های پیمانکاری ( حقوق 30 میلیون تومان مطبق با لیست بیمه ) ( نرم افزار: سپیدار )', '2026-01-29 16:39:57', '2026-01-29 16:45:54'),
(9573, 3612, 'حسابدار', 'شرکت البرز صنعت مبنا', 'تمام وقت', 'حسابداری', NULL, 1403, NULL, 1403, NULL, '20 تا 25 میلیون تومان', 'عدم پیشرفت کاری', 'من در این مدت محاسبه حقوق و دستمزد، ارسال لیست بیمه و مالیات حقوق، بررسی و ثبت حساب‌های دریافتنی و پرداختنی، اسناد دریافتنی و پرداختنی، تهیه صورتحساب، اطمینان از صحت پرداخت‌ها و مبالغ و سوابق، ثبت و بایگانی فاکتورهای معاملات نقدی و تطبیق فاکتورها و شناسایی مغایرت‌ها، سامانه مودیان،  جمع آوری داده‌ها برای اظهارنامه مالیات بر درآمد و اظهارنامه ارزش افزوده، صورت مغایرات بانکی ماهانه، ثبت درآمد و هزینه ها در سیستم حسابداری، بستن حساب‌های موقت و تهیه تراز اختتامی، پرینت و تنظیم گزارش های مالی جهت ارسال به مدیران، بجز ارسال اظهارنامه و بهای تمام شده را انجام میدادم. (حقوق: 20 میلیون تومان) ( نرم افزار: هلو )', '2026-01-29 16:41:52', '2026-01-29 16:50:05'),
(9574, 3612, 'کمک حسابدار', 'شرکت پالایش شیمی سورنا', 'تمام وقت', 'حسابداری', NULL, 1401, NULL, 1402, NULL, '12 تا 15 میلیون تومان', 'مسافت طولانی', 'اینجانب با کمک به بخش حسابداری، حفظ و بهبود فرآیند حسابداری سازمان، مدیریت ارتباط بین سازمان و مشتریان، انجام امور اولیه دفترداری و اداری مانند تشکیل پرونده، ورود اطلاعات، پاسخگویی به تلفن، ارتباط با مشتریان و فروشندگان از طریق تلفن، ایمیل و حضوری، تهیه اسنادی برای حسابدار شرکت، پردازش درخواست‌های واریز و برداشت برای تایید حسابدار و ثبت انواع فاکتور و رسیدها، ثبت سند حسابداری نقش ایفا میکردم.(حقوق: 15 میلیون تومان) (نرم افزار: رافع )', '2026-01-29 16:44:55', '2026-01-29 16:54:58'),
(9575, 3612, 'صندوقدار', 'شرکت سامان اندیشان امرتات', 'تمام وقت', 'حسابداری', NULL, 1398, NULL, 1400, NULL, 'قانون کار', 'عدم پیشرفت کاری', 'بنده در این مجموعه ابتدا به عنوان صندوقدار و سپس به عنوان خزانه دار کار میکردم.(حقوق: بالاتر از وزارت کار) (نرم افزار: ماندگار)', '2026-01-29 16:48:45', '2026-01-29 16:55:37'),
(9576, 3612, 'کمک حسابدار', 'شرکت آرتین پویا پرداز قاف', 'تمام وقت', 'حسابداری', NULL, 1397, NULL, 1398, NULL, 'قانون کار', 'عدم پیشرفت کاری', 'بنده در این مدت به عنوان کارمند اداری مالی ثبت فاکتور و بایگانی اسناد مالی را انجام میدادم. (حقوق: وزارت کار)(نرم افزار هلو)', '2026-01-29 16:51:59', '2026-01-29 16:51:59'),
