(9590, 9095, 'کمک حسابدار', 'موسسه حسابرسی افاق کاوشگران', 'پاره وقت', 'خدمات حسابداری', NULL, 1404, NULL, 1404, NULL, 'قانون کار', 'سایر موارد', 'دلیل بیرون اومدنم از کار‌ دانشگاه بود که شهر‌دیگه بود و دورکاری نداشتن', '2026-01-31 23:59:26', '2026-02-01 00:02:02'),
