(9592, 9096, 'مدیر مالی', 'پولاد دژسهند', 'پروژه ای', 'حسابداری', NULL, 1386, NULL, 1404, NULL, 'بیش از 80 میلیون تومان', 'تاخیر در پرداخت', 'مسلط به قوانین مالیاتی  وبیمه و شرکت در جلسات هیات حل اختلاف مالیاتی وشرکتهای زیادی کار کرده ام', '2026-02-01 08:41:03', '2026-02-01 08:41:03'),
