(9595, 6797, 'حسابدار', 'برق و صنعت مغان', 'تمام وقت', 'تولید و صنایع', NULL, 1394, NULL, 1401, NULL, '15 تا 20 میلیون تومان', 'سایر موارد', NULL, '2026-02-02 06:49:15', '2026-02-02 06:49:15'),
(9596, 9104, 'حسابدار', 'شرکت لیمون چینی آراد', 'تمام وقت', 'حسابداری', NULL, 1399, NULL, NULL, 1, '20 تا 25 میلیون تومان', 'تاخیر در پرداخت', 'علاوه بر تاخیر در پرداخت\nبرای پیشرفت کاری نیز ترک کار میکنم\nحوزه هایی که فعالیت کردم:\n۱)حسابداری مالی\n۲)حقوق و دستمزد\n۳)ارسال لیست بیمه و مالیات\n۴)حسابداری بهای تمام شده\n۵)حسابداری انبار\n۶)حسابداری فروش', '2026-02-02 07:05:28', '2026-02-02 07:27:59'),
(9597, 9105, 'حسابدار', 'آموزشگاه ایران‌مهر', 'تمام وقت', 'حسابداری', NULL, 1395, NULL, 1398, NULL, NULL, NULL, 'و چند شرکت معتبر دیگر', '2026-02-02 07:11:44', '2026-02-02 07:11:44'),
(9598, 9107, 'حسابدار', 'شرکت سیم و کابل برتر', 'تمام وقت', 'خدمات حسابداری', NULL, 1403, NULL, 1404, NULL, '20 تا 25 میلیون تومان', 'سایر موارد', 'دیگر ترم های آخر دانشگاه بودم و کلاس های حسابداری فشرده میرفتم وقت برای کار کردن نداشتم و سال مالی که تمام شد تسویه کردم.', '2026-02-02 07:33:50', '2026-02-02 07:49:32'),
(9599, 9107, 'حسابدار', 'شرکت نیرو کابل البرز', 'تمام وقت', 'خدمات حسابداری', NULL, 1402, NULL, 1403, NULL, '15 تا 20 میلیون تومان', 'سایر موارد', 'تولید کارخانه بسیار زیاد بود و بنده دست تنها نمی‌توانستم تمامی خدمات حسابداری و حسابرسی داخلی و بهای تمام شده را هندل کنم . و به کارخانه سیم کابل دیگری در همان نزدیکی تغییر کار دادم.', '2026-02-02 07:36:18', '2026-02-02 07:36:18');
